const GospelVerse gospel_verses[] = {
    {"Mateo", "Mt", 1, 1, "Libro del origen de Jesucristo, hijo de David, hijo de Abrahan."},
    {"Mateo", "Mt", 1, 2, "Abrahan engendro a Isaac, Isaac engendro a Jacob, Jacob engendro a Juda y a sus hermanos."},
    {"Mateo", "Mt", 1, 3, "Juda engendro, de Tamar, a Fares y a Zara, Fares engendro a Esron, Esron engendro a Aran,"},
    {"Mateo", "Mt", 1, 4, "Aran engendro a Aminadab, Aminadab engendro a Naason, Naason engendro a Salmon,"},
    {"Mateo", "Mt", 1, 5, "Salmon engendro, de Rajab, a Booz; Booz engendro, de Rut, a Obed; Obed engendro a Jese,"},
    {"Mateo", "Mt", 1, 6, "Jese engendro a David, el rey. David, de la mujer de Urias, engendro a Salomon,"},
    {"Mateo", "Mt", 1, 7, "Salomon engendro a Roboan, Roboan engendro a Abias, Abias engendro a Asaf,"},
    {"Mateo", "Mt", 1, 8, "Asaf engendro a Josafat, Josafat engendro a Joran, Joran engendro a Ozias,"},
    {"Mateo", "Mt", 1, 9, "Ozias engendro a Joatan, Joatan engendro a Acaz, Acaz engendro a Ezequias,"},
    {"Mateo", "Mt", 1, 10, "Ezequias engendro a Manases, Manases engendro a Amos, Amos engendro a Josias;"},
    {"Mateo", "Mt", 1, 11, "Josias engendro a Jeconias y a sus hermanos, cuando el destierro de Babilonia."},
    {"Mateo", "Mt", 1, 12, "Despues del destierro de Babilonia, Jeconias engendro a Salatiel, Salatiel engendro a Zorobabel,"},
    {"Mateo", "Mt", 1, 13, "Zorobabel engendro a Abiud, Abiud engendro a Eliaquin, Eliaquin engendro a Azor,"},
    {"Mateo", "Mt", 1, 14, "Azor engendro a Sadoc, Sadoc engendro a Aquin, Aquin engendro a Eliud,"},
    {"Mateo", "Mt", 1, 15, "Eliud engendro a Eleazar, Eleazar engendro a Matan, Matan engendro a Jacob;"},
    {"Mateo", "Mt", 1, 16, "y Jacob engendro a Jose, el esposo de Maria, de la cual nacio Jesus, llamado Cristo."},
    {"Mateo", "Mt", 1, 17, "Asi, las generaciones desde Abrahan a David fueron en total catorce; desde David hasta la deportacion a Babilonia, catorce; y desde la deportacion a Babilonia hasta el Cristo, catorce."},
    {"Mateo", "Mt", 1, 18, "La generacion de Jesucristo fue de esta manera: Maria, su madre, estaba desposada con Jose y, antes de vivir juntos, resulto que ella esperaba un hijo por obra del Espiritu Santo."},
    {"Mateo", "Mt", 1, 19, "Jose, su esposo, como era justo y no queria difamarla, decidio repudiarla en privado."},
    {"Mateo", "Mt", 1, 20, "Pero, apenas habia tomado esta resolucion, se le aparecio en sue\177os un angel del Se\177or que le dijo: \"Jose, hijo de David, no temas acoger a Maria, tu mujer, porque la criatura que hay en ella viene del Espiritu Santo."},
    {"Mateo", "Mt", 1, 21, "Dara a luz un hijo y tu le pondras por nombre Jesus, porque el salvara a su pueblo de sus pecados\"."},
    {"Mateo", "Mt", 1, 22, "Todo esto sucedio para que se cumpliese lo que habia dicho el Se\177or por medio del profeta:"},
    {"Mateo", "Mt", 1, 23, "\"Mirad: la virgen concebira y dara a luz un hijo y le pondran por nombre Enmanuel, que significa \"Dios-con-nosotros\"\"."},
    {"Mateo", "Mt", 1, 24, "Cuando Jose se desperto, hizo lo que le habia mandado el angel del Se\177or y acogio a su mujer."},
    {"Mateo", "Mt", 1, 25, "Y sin haberla conocido, ella dio a luz un hijo al que puso por nombre Jesus."},
    {"Mateo", "Mt", 2, 1, "Habiendo nacido Jesus en Belen de Judea en tiempos del rey Herodes, unos magos de Oriente se presentaron en Jerusalen"},
    {"Mateo", "Mt", 2, 2, "preguntando: \"Donde esta el Rey de los judios que ha nacido? Porque hemos visto salir su estrella y venimos a adorarlo\"."},
    {"Mateo", "Mt", 2, 3, "Al enterarse el rey Herodes, se sobresalto y toda Jerusalen con el;"},
    {"Mateo", "Mt", 2, 4, "convoco a los sumos sacerdotes y a los escribas del pais, y les pregunto donde tenia que nacer el Mesias."},
    {"Mateo", "Mt", 2, 5, "Ellos le contestaron: \"En Belen de Judea, porque asi lo ha escrito el profeta:"},
    {"Mateo", "Mt", 2, 6, "\"Y tu, Belen, tierra de Juda, no eres ni mucho menos la ultima de las poblaciones de Juda, pues de ti saldra un jefe que pastoreara a mi pueblo Israel\"\"."},
    {"Mateo", "Mt", 2, 7, "Entonces Herodes llamo en secreto a los magos para que le precisaran el tiempo en que habia aparecido la estrella,"},
    {"Mateo", "Mt", 2, 8, "y los mando a Belen, diciendoles: \"Id y averiguad cuidadosamente que hay del ni\177o y, cuando lo encontreis, avisadme, para ir yo tambien a adorarlo\"."},
    {"Mateo", "Mt", 2, 9, "Ellos, despues de oir al rey, se pusieron en camino y, de pronto, la estrella que habian visto salir comenzo a guiarlos hasta que vino a pararse encima de donde estaba el ni\177o."},
    {"Mateo", "Mt", 2, 10, "Al ver la estrella, se llenaron de inmensa alegria."},
    {"Mateo", "Mt", 2, 11, "Entraron en la casa, vieron al ni\177o con Maria, su madre, y cayendo de rodillas lo adoraron; despues, abriendo sus cofres, le ofrecieron regalos: oro, incienso y mirra."},
    {"Mateo", "Mt", 2, 12, "Y habiendo recibido en sue\177os un oraculo, para que no volvieran a Herodes, se retiraron a su tierra por otro camino."},
    {"Mateo", "Mt", 2, 13, "Cuando ellos se retiraron, el angel del Se\177or se aparecio en sue\177os a Jose y le dijo: \"Levantate, toma al ni\177o y a su madre y huye a Egipto; quedate alli hasta que yo te avise, porque Herodes va a buscar al ni\177o para matarlo\"."},
    {"Mateo", "Mt", 2, 14, "Jose se levanto, tomo al ni\177o y a su madre, de noche, se fue a Egipto"},
    {"Mateo", "Mt", 2, 15, "y se quedo hasta la muerte de Herodes para que se cumpliese lo que dijo el Se\177or por medio del profeta: \"De Egipto llame a mi hijo\"."},
    {"Mateo", "Mt", 2, 16, "Al verse burlado por los magos, Herodes monto en colera y mando matar a todos los ni\177os de dos a\177os para abajo, en Belen y sus alrededores, calculando el tiempo por lo que habia averiguado de los magos."},
    {"Mateo", "Mt", 2, 17, "Entonces se cumplio lo dicho por medio del profeta Jeremias:"},
    {"Mateo", "Mt", 2, 18, "\"Un grito se oye en Rama, llanto y lamentos grandes; es Raquel que llora por sus hijos y rehusa el consuelo, porque ya no viven\"."},
    {"Mateo", "Mt", 2, 19, "Cuando murio Herodes, el angel del Se\177or se aparecio de nuevo en sue\177os a Jose en Egipto"},
    {"Mateo", "Mt", 2, 20, "y le dijo: \"Levantate, coge al ni\177o y a su madre y vuelve a la tierra de Israel, porque han muerto los que atentaban contra la vida del ni\177o\"."},
    {"Mateo", "Mt", 2, 21, "Se levanto, tomo al ni\177o y a su madre y volvio a la tierra de Israel."},
    {"Mateo", "Mt", 2, 22, "Pero al enterarse de que Arquelao reinaba en Judea como sucesor de su padre Herodes tuvo miedo de ir alla. Y avisado en sue\177os se retiro a Galilea"},
    {"Mateo", "Mt", 2, 23, "y se establecio en una ciudad llamada Nazaret. Asi se cumplio lo dicho por medio de los profetas, que se llamaria nazareno."},
    {"Mateo", "Mt", 3, 1, "Por aquellos dias, Juan el Bautista se presenta en el desierto de Judea, predicando:"},
    {"Mateo", "Mt", 3, 2, "\"Convertios, porque esta cerca el reino de los cielos\"."},
    {"Mateo", "Mt", 3, 3, "Este es el que anuncio el profeta Isaias diciendo: \"Voz del que grita en el desierto: / \"Preparad el camino del Se\177or, / allanad sus senderos\"\"."},
    {"Mateo", "Mt", 3, 4, "Juan llevaba un vestido de piel de camello, con una correa de cuero a la cintura, y se alimentaba de saltamontes y miel silvestre."},
    {"Mateo", "Mt", 3, 5, "Y acudia a el toda la gente de Jerusalen, de Judea y de la comarca del Jordan;"},
    {"Mateo", "Mt", 3, 6, "confesaban sus pecados y el los bautizaba en el Jordan."},
    {"Mateo", "Mt", 3, 7, "Al ver que muchos fariseos y saduceos venian a que los bautizara, les dijo: \"Raza de viboras!, quien os ha ense\177ado a escapar del castigo inminente?"},
    {"Mateo", "Mt", 3, 8, "Dad el fruto que pide la conversion."},
    {"Mateo", "Mt", 3, 9, "Y no os hagais ilusiones, pensando: \"Tenemos por padre a Abrahan\", pues os digo que Dios es capaz de sacar hijos de Abrahan de estas piedras."},
    {"Mateo", "Mt", 3, 10, "Ya toca el hacha la raiz de los arboles, y todo arbol que no de buen fruto sera talado y echado al fuego."},
    {"Mateo", "Mt", 3, 11, "Yo os bautizo con agua para que os convirtais; pero el que viene detras de mi es mas fuerte que yo y no merezco ni llevarle las sandalias. El os bautizara con Espiritu Santo y fuego."},
    {"Mateo", "Mt", 3, 12, "El tiene el bieldo en la mano: aventara su parva, reunira su trigo en el granero y quemara la paja en una hoguera que no se apaga\"."},
    {"Mateo", "Mt", 3, 13, "Por entonces viene Jesus desde Galilea al Jordan y se presenta a Juan para que lo bautice."},
    {"Mateo", "Mt", 3, 14, "Pero Juan intentaba disuadirlo diciendole: \"Soy yo el que necesito que tu me bautices, y tu acudes a mi?\"."},
    {"Mateo", "Mt", 3, 15, "Jesus le contesto: \"Dejalo ahora. Conviene que asi cumplamos toda justicia\". Entonces Juan se lo permitio."},
    {"Mateo", "Mt", 3, 16, "Apenas se bautizo Jesus, salio del agua; se abrieron los cielos y vio que el Espiritu de Dios bajaba como una paloma y se posaba sobre el."},
    {"Mateo", "Mt", 3, 17, "Y vino una voz de los cielos que decia: \"Este es mi Hijo amado, en quien me complazco\"."},
    {"Mateo", "Mt", 4, 1, "Entonces Jesus fue llevado al desierto por el Espiritu para ser tentado por el diablo."},
    {"Mateo", "Mt", 4, 2, "Y despues de ayunar cuarenta dias con sus cuarenta noches, al fin sintio hambre."},
    {"Mateo", "Mt", 4, 3, "El tentador se le acerco y le dijo: \"Si eres Hijo de Dios, di que estas piedras se conviertan en panes\"."},
    {"Mateo", "Mt", 4, 4, "Pero el le contesto: \"Esta escrito: \"No solo de pan vive el hombre, sino de toda palabra que sale de la boca de Dios\"\"."},
    {"Mateo", "Mt", 4, 5, "Entonces el diablo lo llevo a la ciudad santa, lo puso en el alero del templo"},
    {"Mateo", "Mt", 4, 6, "y le dijo: \"Si eres Hijo de Dios, tirate abajo, porque esta escrito: \"Ha dado ordenes a sus angeles acerca de ti y te sostendran en sus manos, para que tu pie no tropiece con las piedras\"\"."},
    {"Mateo", "Mt", 4, 7, "Jesus le dijo: \"Tambien esta escrito: \"No tentaras al Se\177or, tu Dios\"\"."},
    {"Mateo", "Mt", 4, 8, "De nuevo el diablo lo llevo a un monte altisimo y le mostro los reinos del mundo y su gloria,"},
    {"Mateo", "Mt", 4, 9, "y le dijo: \"Todo esto te dare, si te postras y me adoras\"."},
    {"Mateo", "Mt", 4, 10, "Entonces le dijo Jesus: \"Vete, Satanas, porque esta escrito: \"Al Se\177or, tu Dios, adoraras y a el solo daras culto\"\"."},
    {"Mateo", "Mt", 4, 11, "Entonces lo dejo el diablo, y he aqui que se acercaron los angeles y lo servian."},
    {"Mateo", "Mt", 4, 12, "Al enterarse Jesus de que habian arrestado a Juan se retiro a Galilea."},
    {"Mateo", "Mt", 4, 13, "Dejando Nazaret se establecio en Cafarnaun, junto al mar, en el territorio de Zabulon y Neftali,"},
    {"Mateo", "Mt", 4, 14, "para que se cumpliera lo dicho por medio del profeta Isaias:"},
    {"Mateo", "Mt", 4, 15, "\"Tierra de Zabulon y tierra de Neftali, camino del mar, al otro lado del Jordan, Galilea de los gentiles."},
    {"Mateo", "Mt", 4, 16, "El pueblo que habitaba en tinieblas vio una luz grande; a los que habitaban en tierra y sombras de muerte, una luz les brillo\"."},
    {"Mateo", "Mt", 4, 17, "Desde entonces comenzo Jesus a predicar diciendo: \"Convertios, porque esta cerca el reino de los cielos\"."},
    {"Mateo", "Mt", 4, 18, "Paseando junto al mar de Galilea vio a dos hermanos, a Simon, llamado Pedro, y a Andres, que estaban echando la red en el mar, pues eran pescadores."},
    {"Mateo", "Mt", 4, 19, "Les dijo: \"Venid en pos de mi y os hare pescadores de hombres\"."},
    {"Mateo", "Mt", 4, 20, "Inmediatamente dejaron las redes y lo siguieron."},
    {"Mateo", "Mt", 4, 21, "Y pasando adelante vio a otros dos hermanos, a Santiago, hijo de Zebedeo, y a Juan, su hermano, que estaban en la barca repasando las redes con Zebedeo, su padre, y los llamo."},
    {"Mateo", "Mt", 4, 22, "Inmediatamente dejaron la barca y a su padre y lo siguieron."},
    {"Mateo", "Mt", 4, 23, "Jesus recorria toda Galilea ense\177ando en sus sinagogas, proclamando el evangelio del reino y curando toda enfermedad y toda dolencia en el pueblo."},
    {"Mateo", "Mt", 4, 24, "Su fama se extendio por toda Siria y le traian todos los enfermos aquejados de toda clase de enfermedades y dolores, endemoniados, lunaticos y paraliticos. Y el los curo."},
    {"Mateo", "Mt", 4, 25, "Y lo seguian multitudes venidas de Galilea, Decapolis, Jerusalen, Judea y Transjordania."},
    {"Mateo", "Mt", 5, 1, "Al ver Jesus el gentio, subio al monte, se sento y se acercaron sus discipulos;"},
    {"Mateo", "Mt", 5, 2, "y, abriendo su boca, les ense\177aba diciendo:"},
    {"Mateo", "Mt", 5, 3, "\"Bienaventurados los pobres en el espiritu, porque de ellos es el reino de los cielos."},
    {"Mateo", "Mt", 5, 4, "Bienaventurados los mansos, porque ellos heredaran la tierra."},
    {"Mateo", "Mt", 5, 5, "Bienaventurados los que lloran, porque ellos seran consolados."},
    {"Mateo", "Mt", 5, 6, "Bienaventurados los que tienen hambre y sed de la justicia, porque ellos quedaran saciados."},
    {"Mateo", "Mt", 5, 7, "Bienaventurados los misericordiosos, porque ellos alcanzaran misericordia."},
    {"Mateo", "Mt", 5, 8, "Bienaventurados los limpios de corazon, porque ellos veran a Dios."},
    {"Mateo", "Mt", 5, 9, "Bienaventurados los que trabajan por la paz, porque ellos seran llamados hijos de Dios."},
    {"Mateo", "Mt", 5, 10, "Bienaventurados los perseguidos por causa de la justicia, porque de ellos es el reino de los cielos."},
    {"Mateo", "Mt", 5, 11, "Bienaventurados vosotros cuando os insulten y os persigan y os calumnien de cualquier modo por mi causa."},
    {"Mateo", "Mt", 5, 12, "Alegraos y regocijaos, porque vuestra recompensa sera grande en el cielo, que de la misma manera persiguieron a los profetas anteriores a vosotros."},
    {"Mateo", "Mt", 5, 13, "Vosotros sois la sal de la tierra. Pero si la sal se vuelve sosa, con que la salaran? No sirve mas que para tirarla fuera y que la pise la gente."},
    {"Mateo", "Mt", 5, 14, "Vosotros sois la luz del mundo. No se puede ocultar una ciudad puesta en lo alto de un monte."},
    {"Mateo", "Mt", 5, 15, "Tampoco se enciende una lampara para meterla debajo del celemin, sino para ponerla en el candelero y que alumbre a todos los de casa."},
    {"Mateo", "Mt", 5, 16, "Brille asi vuestra luz ante los hombres, para que vean vuestras buenas obras y den gloria a vuestro Padre que esta en los cielos."},
    {"Mateo", "Mt", 5, 17, "No creais que he venido a abolir la Ley y los Profetas: no he venido a abolir, sino a dar plenitud."},
    {"Mateo", "Mt", 5, 18, "En verdad os digo que antes pasaran el cielo y la tierra que deje de cumplirse hasta la ultima letra o tilde de la ley."},
    {"Mateo", "Mt", 5, 19, "El que se salte uno solo de los preceptos menos importantes y se lo ense\177e asi a los hombres sera el menos importante en el reino de los cielos. Pero quien los cumpla y ense\177e sera grande en el reino de los cielos."},
    {"Mateo", "Mt", 5, 20, "Porque os digo que si vuestra justicia no es mayor que la de los escribas y fariseos, no entrareis en el reino de los cielos."},
    {"Mateo", "Mt", 5, 21, "Habeis oido que se dijo a los antiguos: \"No mataras\", y el que mate sera reo de juicio."},
    {"Mateo", "Mt", 5, 22, "Pero yo os digo: todo el que se deja llevar de la colera contra su hermano sera procesado. Y si uno llama a su hermano \"imbecil\", tendra que comparecer ante el Sanedrin, y si lo llama \"necio\", merece la condena de la gehenna del fuego."},
    {"Mateo", "Mt", 5, 23, "Por tanto, si cuando vas a presentar tu ofrenda sobre el altar, te acuerdas alli mismo de que tu hermano tiene quejas contra ti,"},
    {"Mateo", "Mt", 5, 24, "deja alli tu ofrenda ante el altar y vete primero a reconciliarte con tu hermano, y entonces vuelve a presentar tu ofrenda."},
    {"Mateo", "Mt", 5, 25, "Con el que te pone pleito procura arreglarte enseguida, mientras vais todavia de camino, no sea que te entregue al juez y el juez al alguacil, y te metan en la carcel."},
    {"Mateo", "Mt", 5, 26, "En verdad te digo que no saldras de alli hasta que hayas pagado el ultimo centimo."},
    {"Mateo", "Mt", 5, 27, "Habeis oido que se dijo: \"No cometeras adulterio\"."},
    {"Mateo", "Mt", 5, 28, "Pero yo os digo: todo el que mira a una mujer deseandola, ya ha cometido adulterio con ella en su corazon."},
    {"Mateo", "Mt", 5, 29, "Si tu ojo derecho te induce a pecar, sacatelo y tiralo. Mas te vale perder un miembro que ser echado entero en la gehenna."},
    {"Mateo", "Mt", 5, 30, "Si tu mano derecha te induce a pecar, cortatela y tirala, porque mas te vale perder un miembro que ir a parar entero a la gehenna."},
    {"Mateo", "Mt", 5, 31, "Se dijo: \"El que repudie a su mujer, que le de acta de repudio\"."},
    {"Mateo", "Mt", 5, 32, "Pero yo os digo que si uno repudia a su mujer -no hablo de union ilegitima- la induce a cometer adulterio, y el que se casa con la repudiada comete adulterio."},
    {"Mateo", "Mt", 5, 33, "Tambien habeis oido que se dijo a los antiguos: \"No juraras en falso\" y \"Cumpliras tus juramentos al Se\177or\"."},
    {"Mateo", "Mt", 5, 34, "Pero yo os digo que no jureis en absoluto: ni por el cielo, que es el trono de Dios;"},
    {"Mateo", "Mt", 5, 35, "ni por la tierra, que es estrado de sus pies; ni por Jerusalen, que es la ciudad del Gran Rey."},
    {"Mateo", "Mt", 5, 36, "Ni jures por tu cabeza, pues no puedes volver blanco o negro un solo cabello."},
    {"Mateo", "Mt", 5, 37, "Que vuestro hablar sea si, si, no, no. Lo que pasa de ahi viene del Maligno."},
    {"Mateo", "Mt", 5, 38, "Habeis oido que se dijo: \"Ojo por ojo, diente por diente\"."},
    {"Mateo", "Mt", 5, 39, "Pero yo os digo: no hagais frente al que os agravia. Al contrario, si uno te abofetea en la mejilla derecha, presentale la otra;"},
    {"Mateo", "Mt", 5, 40, "al que quiera ponerte pleito para quitarte la tunica, dale tambien el manto;"},
    {"Mateo", "Mt", 5, 41, "a quien te requiera para caminar una milla, acompa\177ale dos;"},
    {"Mateo", "Mt", 5, 42, "a quien te pide, dale, y al que te pide prestado, no lo rehuyas."},
    {"Mateo", "Mt", 5, 43, "Habeis oido que se dijo: \"'Amaras a tu projimo' y aborreceras a tu enemigo\"."},
    {"Mateo", "Mt", 5, 44, "Pero yo os digo: amad a vuestros enemigos y rezad por los que os persiguen,"},
    {"Mateo", "Mt", 5, 45, "para que seais hijos de vuestro Padre celestial, que hace salir su sol sobre malos y buenos, y manda la lluvia a justos e injustos."},
    {"Mateo", "Mt", 5, 46, "Porque, si amais a los que os aman, que premio tendreis? No hacen lo mismo tambien los publicanos?"},
    {"Mateo", "Mt", 5, 47, "Y, si saludais solo a vuestros hermanos, que haceis de extraordinario? No hacen lo mismo tambien los gentiles?"},
    {"Mateo", "Mt", 5, 48, "Por tanto, sed perfectos, como vuestro Padre celestial es perfecto."},
    {"Mateo", "Mt", 6, 1, "Cuidad de no practicar vuestra justicia delante de los hombres para ser vistos por ellos; de lo contrario no teneis recompensa de vuestro Padre celestial."},
    {"Mateo", "Mt", 6, 2, "Por tanto, cuando hagas limosna, no mandes tocar la trompeta ante ti, como hacen los hipocritas en las sinagogas y por las calles para ser honrados por la gente; en verdad os digo que ya han recibido su recompensa."},
    {"Mateo", "Mt", 6, 3, "Tu, en cambio, cuando hagas limosna, que no sepa tu mano izquierda lo que hace tu derecha;"},
    {"Mateo", "Mt", 6, 4, "asi tu limosna quedara en secreto y tu Padre, que ve en lo secreto, te recompensara."},
    {"Mateo", "Mt", 6, 5, "Cuando oreis, no seais como los hipocritas, a quienes les gusta orar de pie en las sinagogas y en las esquinas de las plazas, para que los vean los hombres. En verdad os digo que ya han recibido su recompensa."},
    {"Mateo", "Mt", 6, 6, "Tu, en cambio, cuando ores, entra en tu cuarto, cierra la puerta y ora a tu Padre, que esta en lo secreto, y tu Padre, que ve en lo secreto, te lo recompensara."},
    {"Mateo", "Mt", 6, 7, "Cuando receis, no useis muchas palabras, como los gentiles, que se imaginan que por hablar mucho les haran caso."},
    {"Mateo", "Mt", 6, 8, "No seais como ellos, pues vuestro Padre sabe lo que os hace falta antes de que lo pidais."},
    {"Mateo", "Mt", 6, 9, "Vosotros orad asi: \"Padre nuestro que estas en el cielo, / santificado sea tu nombre,"},
    {"Mateo", "Mt", 6, 10, "venga a nosotros tu reino, / hagase tu voluntad en la tierra como en el cielo,"},
    {"Mateo", "Mt", 6, 11, "danos hoy nuestro pan de cada dia,"},
    {"Mateo", "Mt", 6, 12, "perdona nuestras ofensas, / como tambien nosotros perdonamos a los que nos ofenden,"},
    {"Mateo", "Mt", 6, 13, "no nos dejes caer en la tentacion, / y libranos del mal\"."},
    {"Mateo", "Mt", 6, 14, "Porque si perdonais a los hombres sus ofensas, tambien os perdonara vuestro Padre celestial,"},
    {"Mateo", "Mt", 6, 15, "pero si no perdonais a los hombres, tampoco vuestro Padre perdonara vuestras ofensas."},
    {"Mateo", "Mt", 6, 16, "Cuando ayuneis, no pongais cara triste, como los hipocritas que desfiguran sus rostros para hacer ver a los hombres que ayunan. En verdad os digo que ya han recibido su paga."},
    {"Mateo", "Mt", 6, 17, "Tu, en cambio, cuando ayunes, perfumate la cabeza y lavate la cara,"},
    {"Mateo", "Mt", 6, 18, "para que tu ayuno lo note, no los hombres, sino tu Padre, que esta en lo escondido; y tu Padre, que ve en lo escondido, te recompensara."},
    {"Mateo", "Mt", 6, 19, "No atesoreis para vosotros tesoros en la tierra, donde la polilla y la carcoma los roen y donde los ladrones abren boquetes y los roban."},
    {"Mateo", "Mt", 6, 20, "Haceos tesoros en el cielo, donde no hay polilla ni carcoma que los roen, ni ladrones que abren boquetes y roban."},
    {"Mateo", "Mt", 6, 21, "Porque donde esta tu tesoro, alli estara tu corazon."},
    {"Mateo", "Mt", 6, 22, "La lampara del cuerpo es el ojo. Si tu ojo esta sano, tu cuerpo entero tendra luz;"},
    {"Mateo", "Mt", 6, 23, "pero si tu ojo esta enfermo, tu cuerpo entero estara a oscuras. Si, pues, la luz que hay en ti esta oscura, cuanta sera la oscuridad!"},
    {"Mateo", "Mt", 6, 24, "Nadie puede servir a dos se\177ores. Porque despreciara a uno y amara al otro; o, al contrario, se dedicara al primero y no hara caso del segundo. No podeis servir a Dios y al dinero."},
    {"Mateo", "Mt", 6, 25, "Por eso os digo: no esteis agobiados por vuestra vida pensando que vais a comer, ni por vuestro cuerpo pensando con que os vais a vestir. No vale mas la vida que el alimento, y el cuerpo que el vestido?"},
    {"Mateo", "Mt", 6, 26, "Mirad los pajaros del cielo: no siembran ni siegan, ni almacenan y, sin embargo, vuestro Padre celestial los alimenta. No valeis vosotros mas que ellos?"},
    {"Mateo", "Mt", 6, 27, "Quien de vosotros, a fuerza de agobiarse, podra a\177adir una hora al tiempo de su vida?"},
    {"Mateo", "Mt", 6, 28, "Por que os agobiais por el vestido? Fijaos como crecen los lirios del campo: ni trabajan ni hilan."},
    {"Mateo", "Mt", 6, 29, "Y os digo que ni Salomon, en todo su fasto, estaba vestido como uno de ellos."},
    {"Mateo", "Mt", 6, 30, "Pues si a la hierba, que hoy esta en el campo y ma\177ana se arroja al horno, Dios la viste asi, no hara mucho mas por vosotros, gente de poca fe?"},
    {"Mateo", "Mt", 6, 31, "No andeis agobiados pensando que vais a comer, o que vais a beber, o con que os vais a vestir."},
    {"Mateo", "Mt", 6, 32, "Los paganos se afanan por esas cosas. Ya sabe vuestro Padre celestial que teneis necesidad de todo eso."},
    {"Mateo", "Mt", 6, 33, "Buscad sobre todo el reino de Dios y su justicia; y todo esto se os dara por a\177adidura."},
    {"Mateo", "Mt", 6, 34, "Por tanto, no os agobieis por el ma\177ana, porque el ma\177ana traera su propio agobio. A cada dia le basta su desgracia."},
    {"Mateo", "Mt", 7, 1, "No juzgueis, para que no seais juzgados."},
    {"Mateo", "Mt", 7, 2, "Porque sereis juzgados como juzgueis vosotros, y la medida que useis, la usaran con vosotros."},
    {"Mateo", "Mt", 7, 3, "Por que te fijas en la mota que tiene tu hermano en el ojo y no reparas en la viga que llevas en el tuyo?"},
    {"Mateo", "Mt", 7, 4, "Como puedes decirle a tu hermano: \"Dejame que te saque la mota del ojo\", teniendo una viga en el tuyo?"},
    {"Mateo", "Mt", 7, 5, "Hipocrita: sacate primero la viga del ojo; entonces veras claro y podras sacar la mota del ojo de tu hermano."},
    {"Mateo", "Mt", 7, 6, "No deis lo santo a los perros, ni les echeis vuestras perlas a los cerdos; no sea que las pisoteen con sus patas y despues se revuelvan para destrozaros."},
    {"Mateo", "Mt", 7, 7, "Pedid y se os dara, buscad y encontrareis, llamad y se os abrira;"},
    {"Mateo", "Mt", 7, 8, "porque todo el que pide recibe, quien busca encuentra y al que llama se le abre."},
    {"Mateo", "Mt", 7, 9, "Si a alguno de vosotros le pide su hijo pan, le dara una piedra?;"},
    {"Mateo", "Mt", 7, 10, "y si le pide pescado, le dara una serpiente?"},
    {"Mateo", "Mt", 7, 11, "Pues si vosotros, aun siendo malos, sabeis dar cosas buenas a vuestros hijos, cuanto mas vuestro Padre que esta en los cielos dara cosas buenas a los que le piden!"},
    {"Mateo", "Mt", 7, 12, "Asi, pues, todo lo que deseais que los demas hagan con vosotros, hacedlo vosotros con ellos; pues esta es la Ley y los Profetas."},
    {"Mateo", "Mt", 7, 13, "Entrad por la puerta estrecha. Porque ancha es la puerta y espacioso el camino que lleva a la perdicion, y muchos entran por ellos."},
    {"Mateo", "Mt", 7, 14, "Que estrecha es la puerta y que angosto el camino que lleva a la vida! Y pocos dan con ellos."},
    {"Mateo", "Mt", 7, 15, "Cuidado con los profetas falsos; se acercan con piel de oveja, pero por dentro son lobos rapaces."},
    {"Mateo", "Mt", 7, 16, "Por sus frutos los conocereis. Acaso se cosechan uvas de las zarzas o higos de los cardos?"},
    {"Mateo", "Mt", 7, 17, "Asi, todo arbol sano da frutos buenos; pero el arbol da\177ado da frutos malos."},
    {"Mateo", "Mt", 7, 18, "Un arbol sano no puede dar frutos malos, ni un arbol da\177ado dar frutos buenos."},
    {"Mateo", "Mt", 7, 19, "El arbol que no da fruto bueno se tala y se echa al fuego."},
    {"Mateo", "Mt", 7, 20, "Es decir, que por sus frutos los conocereis."},
    {"Mateo", "Mt", 7, 21, "No todo el que me dice \"Se\177or, Se\177or\" entrara en el reino de los cielos, sino el que hace la voluntad de mi Padre que esta en los cielos."},
    {"Mateo", "Mt", 7, 22, "Aquel dia muchos diran: \"Se\177or, Se\177or, no hemos profetizado en tu nombre y en tu nombre hemos echado demonios, y no hemos hecho en tu nombre muchos milagros?\"."},
    {"Mateo", "Mt", 7, 23, "Entonces yo les declarare: \"Nunca os he conocido. Alejaos de mi, los que obrais la iniquidad\"."},
    {"Mateo", "Mt", 7, 24, "El que escucha estas palabras mias y las pone en practica se parece a aquel hombre prudente que edifico su casa sobre roca."},
    {"Mateo", "Mt", 7, 25, "Cayo la lluvia, se desbordaron los rios, soplaron los vientos y descargaron contra la casa; pero no se hundio, porque estaba cimentada sobre roca."},
    {"Mateo", "Mt", 7, 26, "El que escucha estas palabras mias y no las pone en practica se parece a aquel hombre necio que edifico su casa sobre arena."},
    {"Mateo", "Mt", 7, 27, "Cayo la lluvia, se desbordaron los rios, soplaron los vientos y rompieron contra la casa, y se derrumbo. Y su ruina fue grande\"."},
    {"Mateo", "Mt", 7, 28, "Al terminar Jesus este discurso, la gente estaba admirada de su ense\177anza,"},
    {"Mateo", "Mt", 7, 29, "porque les ense\177aba con autoridad y no como sus escribas."},
    {"Mateo", "Mt", 8, 1, "Al bajar Jesus del monte, lo siguio mucha gente."},
    {"Mateo", "Mt", 8, 2, "En esto, se le acerco un leproso, se arrodillo y le dijo: \"Se\177or, si quieres, puedes limpiarme\"."},
    {"Mateo", "Mt", 8, 3, "Extendio la mano y lo toco diciendo: \"Quiero, queda limpio\". Y enseguida quedo limpio de la lepra."},
    {"Mateo", "Mt", 8, 4, "Jesus le dijo: \"No se lo digas a nadie, pero ve a presentarte al sacerdote y entrega la ofrenda que mando Moises, para que les sirva de testimonio\"."},
    {"Mateo", "Mt", 8, 5, "Al entrar Jesus en Cafarnaun, un centurion se le acerco rogandole:"},
    {"Mateo", "Mt", 8, 6, "\"Se\177or, tengo en casa un criado que esta en cama paralitico y sufre mucho\"."},
    {"Mateo", "Mt", 8, 7, "Le contesto: \"Voy yo a curarlo\"."},
    {"Mateo", "Mt", 8, 8, "Pero el centurion le replico: \"Se\177or, no soy digno de que entres bajo mi techo. Basta que lo digas de palabra, y mi criado quedara sano."},
    {"Mateo", "Mt", 8, 9, "Porque yo tambien vivo bajo disciplina y tengo soldados a mis ordenes; y le digo a uno: \"Ve\", y va; al otro: \"Ven\", y viene; a mi criado: \"Haz esto\", y lo hace\"."},
    {"Mateo", "Mt", 8, 10, "Al oirlo, Jesus quedo admirado y dijo a los que lo seguian: \"En verdad os digo que en Israel no he encontrado en nadie tanta fe."},
    {"Mateo", "Mt", 8, 11, "Os digo que vendran muchos de oriente y occidente y se sentaran con Abrahan, Isaac y Jacob en el reino de los cielos;"},
    {"Mateo", "Mt", 8, 12, "en cambio, a los hijos del reino los echaran fuera, a las tinieblas. Alli sera el llanto y el rechinar de dientes\"."},
    {"Mateo", "Mt", 8, 13, "Y dijo Jesus al centurion: \"Vete; que te suceda segun has creido\". Y en aquel momento se puso bueno el criado."},
    {"Mateo", "Mt", 8, 14, "Al llegar Jesus a la casa de Pedro, vio a su suegra en cama con fiebre;"},
    {"Mateo", "Mt", 8, 15, "le toco su mano y se le paso la fiebre; se levanto y se puso a servirle."},
    {"Mateo", "Mt", 8, 16, "Al anochecer, le llevaron muchos endemoniados; el, con su palabra, expulso los espiritus y curo a todos los enfermos"},
    {"Mateo", "Mt", 8, 17, "para que se cumpliera lo dicho por medio del profeta Isaias: \"El tomo nuestras dolencias y cargo con nuestras enfermedades\"."},
    {"Mateo", "Mt", 8, 18, "Viendo Jesus que lo rodeaba mucha gente, dio orden de cruzar a la otra orilla."},
    {"Mateo", "Mt", 8, 19, "Se le acerco un escriba y le dijo: \"Maestro, te seguire adonde vayas\"."},
    {"Mateo", "Mt", 8, 20, "Jesus le respondio: \"Las zorras tienen madrigueras y los pajaros nidos, pero el Hijo del hombre no tiene donde reclinar la cabeza\"."},
    {"Mateo", "Mt", 8, 21, "Otro, que era de los discipulos, le dijo: \"Se\177or, dejame ir primero a enterrar a mi padre\"."},
    {"Mateo", "Mt", 8, 22, "Jesus le replico: \"Tu, sigueme y deja que los muertos entierren a sus muertos\"."},
    {"Mateo", "Mt", 8, 23, "Subio Jesus a la barca, y sus discipulos lo siguieron."},
    {"Mateo", "Mt", 8, 24, "En esto se produjo una tempestad tan fuerte, que la barca desaparecia entre las olas; el dormia."},
    {"Mateo", "Mt", 8, 25, "Se acercaron y lo despertaron gritandole: \"Se\177or, salvanos, que perecemos!\"."},
    {"Mateo", "Mt", 8, 26, "El les dice: \"Por que teneis miedo, hombres de poca fe?\". Se puso en pie, increpo a los vientos y al mar y vino una gran calma."},
    {"Mateo", "Mt", 8, 27, "Los hombres se decian asombrados: \"Quien es este, que hasta el viento y el mar lo obedecen?\"."},
    {"Mateo", "Mt", 8, 28, "Llego Jesus a la otra orilla, a la region de los gadarenos. Desde los sepulcros dos endemoniados salieron a su encuentro; eran tan furiosos que nadie se atrevia a transitar por aquel camino."},
    {"Mateo", "Mt", 8, 29, "Y le dijeron a gritos: \"Que tenemos que ver nosotros contigo, Hijo de Dios? Has venido aqui a atormentarnos antes de tiempo?\"."},
    {"Mateo", "Mt", 8, 30, "A cierta distancia, una gran piara de cerdos estaba paciendo."},
    {"Mateo", "Mt", 8, 31, "Los demonios le rogaron: \"Si nos echas, mandanos a la piara\"."},
    {"Mateo", "Mt", 8, 32, "Jesus les dijo: \"Id\". Salieron y se metieron en los cerdos. Y la piara entera se abalanzo acantilado abajo al mar y murieron en las aguas."},
    {"Mateo", "Mt", 8, 33, "Los porquerizos huyeron al pueblo y lo contaron todo, incluyendo lo de los endemoniados."},
    {"Mateo", "Mt", 8, 34, "Entonces el pueblo entero salio a donde estaba Jesus y, al verlo, le rogaron que se marchara de su pais."},
    {"Mateo", "Mt", 9, 1, "Subio Jesus a una barca, cruzo a la otra orilla y fue a su ciudad."},
    {"Mateo", "Mt", 9, 2, "En esto le presentaron un paralitico, acostado en una camilla. Viendo la fe que tenian, dijo al paralitico: \"Animo, hijo!, tus pecados te son perdonados\"."},
    {"Mateo", "Mt", 9, 3, "Algunos de los escribas se dijeron: \"Este blasfema\"."},
    {"Mateo", "Mt", 9, 4, "Jesus, sabiendo lo que pensaban, les dijo: \"Por que pensais mal en vuestros corazones?"},
    {"Mateo", "Mt", 9, 5, "Que es mas facil, decir: \"Tus pecados te son perdonados\", o decir: \"Levantate y echa a andar\"?"},
    {"Mateo", "Mt", 9, 6, "Pues, para que veais que el Hijo del hombre tiene potestad en la tierra para perdonar pecados -entonces dice al paralitico-: \"Ponte en pie, coge tu camilla y vete a tu casa\"\"."},
    {"Mateo", "Mt", 9, 7, "Se puso en pie y se fue a su casa."},
    {"Mateo", "Mt", 9, 8, "Al ver esto, la gente quedo sobrecogida y alababa a Dios, que da a los hombres tal potestad."},
    {"Mateo", "Mt", 9, 9, "Al pasar vio Jesus a un hombre llamado Mateo sentado al mostrador de los impuestos, y le dijo: \"Sigueme\". El se levanto y lo siguio."},
    {"Mateo", "Mt", 9, 10, "Y estando en la casa, sentado a la mesa, muchos publicanos y pecadores, que habian acudido, se sentaban con Jesus y sus discipulos."},
    {"Mateo", "Mt", 9, 11, "Los fariseos, al verlo, preguntaron a los discipulos: \"Como es que vuestro maestro come con publicanos y pecadores?\"."},
    {"Mateo", "Mt", 9, 12, "Jesus lo oyo y dijo: \"No tienen necesidad de medico los sanos, sino los enfermos."},
    {"Mateo", "Mt", 9, 13, "Andad, aprended lo que significa \"Misericordia quiero y no sacrificio\": que no he venido a llamar a justos sino a pecadores\"."},
    {"Mateo", "Mt", 9, 14, "Los discipulos de Juan se le acercan a Jesus, preguntandole: \"Por que nosotros y los fariseos ayunamos a menudo y, en cambio, tus discipulos no ayunan?\"."},
    {"Mateo", "Mt", 9, 15, "Jesus les dijo: \"Es que pueden guardar luto los amigos del esposo, mientras el esposo esta con ellos? Llegaran dias en que les arrebataran al esposo, y entonces ayunaran."},
    {"Mateo", "Mt", 9, 16, "Nadie echa un remiendo de pa\177o sin remojar a un manto pasado; porque la pieza tira del manto y deja un roto peor."},
    {"Mateo", "Mt", 9, 17, "Tampoco se echa vino nuevo en odres viejos; porque revientan los odres: se derrama el vino y los odres se estropean; el vino nuevo se echa en odres nuevos y asi las dos cosas se conservan\"."},
    {"Mateo", "Mt", 9, 18, "Mientras les decia esto, se acerco un jefe de los judios que se arrodillo ante el y le dijo: \"Mi hija acaba de morir. Pero ven tu, impon tu mano sobre ella y vivira\"."},
    {"Mateo", "Mt", 9, 19, "Jesus se levanto y lo siguio con sus discipulos."},
    {"Mateo", "Mt", 9, 20, "Entre tanto, una mujer que sufria flujos de sangre desde hacia doce a\177os, se le acerco por detras y le toco la orla del manto,"},
    {"Mateo", "Mt", 9, 21, "pensando que con solo tocarle el manto se curaria."},
    {"Mateo", "Mt", 9, 22, "Jesus se volvio y al verla le dijo: \"Animo, hija! Tu fe te ha salvado\". Y en aquel momento quedo curada la mujer."},
    {"Mateo", "Mt", 9, 23, "Jesus llego a casa de aquel jefe y, al ver a los flautistas y el alboroto de la gente,"},
    {"Mateo", "Mt", 9, 24, "dijo: \"Retiraos! La ni\177a no esta muerta, esta dormida\". Se reian de el."},
    {"Mateo", "Mt", 9, 25, "Cuando echaron a la gente, entro el, cogio a la ni\177a de la mano y ella se levanto."},
    {"Mateo", "Mt", 9, 26, "La noticia se divulgo por toda aquella comarca."},
    {"Mateo", "Mt", 9, 27, "Cuando Jesus salia de alli, dos ciegos lo seguian gritando: \"Ten compasion de nosotros, hijo de David\"."},
    {"Mateo", "Mt", 9, 28, "Al llegar a la casa se le acercaron los ciegos y Jesus les dijo: \"Creeis que puedo hacerlo?\". Contestaron: \"Si, Se\177or\"."},
    {"Mateo", "Mt", 9, 29, "Entonces les toco los ojos, diciendo: \"Que os suceda conforme a vuestra fe\"."},
    {"Mateo", "Mt", 9, 30, "Y se les abrieron los ojos. Jesus les ordeno severamente: \"Cuidado con que lo sepa alguien!\"."},
    {"Mateo", "Mt", 9, 31, "Pero ellos, al salir, hablaron de el por toda la comarca."},
    {"Mateo", "Mt", 9, 32, "Estaban ellos todavia saliendo cuando le llevaron a Jesus un endemoniado mudo."},
    {"Mateo", "Mt", 9, 33, "Y despues de echar al demonio, el mudo hablo. La gente decia admirada: \"Nunca se ha visto en Israel cosa igual\"."},
    {"Mateo", "Mt", 9, 34, "En cambio, los fariseos decian: \"Este echa los demonios con el poder del jefe de los demonios\"."},
    {"Mateo", "Mt", 9, 35, "Jesus recorria todas las ciudades y aldeas, ense\177ando en sus sinagogas, proclamando el evangelio del reino y curando toda enfermedad y toda dolencia."},
    {"Mateo", "Mt", 9, 36, "Al ver a las muchedumbres, se compadecia de ellas, porque estaban extenuadas y abandonadas, \"como ovejas que no tienen pastor\"."},
    {"Mateo", "Mt", 9, 37, "Entonces dice a sus discipulos: \"La mies es abundante, pero los trabajadores son pocos;"},
    {"Mateo", "Mt", 9, 38, "rogad, pues, al Se\177or de la mies que mande trabajadores a su mies\"."},
    {"Mateo", "Mt", 10, 1, "Llamo a sus doce discipulos y les dio autoridad para expulsar espiritus inmundos y curar toda enfermedad y toda dolencia."},
    {"Mateo", "Mt", 10, 2, "Estos son los nombres de los doce apostoles: el primero, Simon, llamado Pedro, y Andres, su hermano; Santiago, el de Zebedeo, y Juan, su hermano;"},
    {"Mateo", "Mt", 10, 3, "Felipe y Bartolome, Tomas y Mateo el publicano; Santiago el de Alfeo, y Tadeo;"},
    {"Mateo", "Mt", 10, 4, "Simon el de Cana, y Judas Iscariote, el que lo entrego."},
    {"Mateo", "Mt", 10, 5, "A estos doce los envio Jesus con estas instrucciones: \"No vayais a tierra de paganos ni entreis en las ciudades de Samaria,"},
    {"Mateo", "Mt", 10, 6, "sino id a las ovejas descarriadas de Israel."},
    {"Mateo", "Mt", 10, 7, "Id y proclamad que ha llegado el reino de los cielos."},
    {"Mateo", "Mt", 10, 8, "Curad enfermos, resucitad muertos, limpiad leprosos, arrojad demonios. Gratis habeis recibido, dad gratis."},
    {"Mateo", "Mt", 10, 9, "No os procureis en la faja oro, plata ni cobre;"},
    {"Mateo", "Mt", 10, 10, "ni tampoco alforja para el camino, ni dos tunicas, ni sandalias, ni baston; bien merece el obrero su sustento."},
    {"Mateo", "Mt", 10, 11, "Cuando entreis en una ciudad o aldea, averiguad quien hay alli de confianza y quedaos en su casa hasta que os vayais."},
    {"Mateo", "Mt", 10, 12, "Al entrar en una casa, saludadla con la paz;"},
    {"Mateo", "Mt", 10, 13, "si la casa se lo merece, vuestra paz vendra a ella. Si no se lo merece, la paz volvera a vosotros."},
    {"Mateo", "Mt", 10, 14, "Si alguno no os recibe o no escucha vuestras palabras, al salir de su casa o de la ciudad, sacudid el polvo de los pies."},
    {"Mateo", "Mt", 10, 15, "En verdad os digo que el dia del juicio les sera mas llevadero a Sodoma y Gomorra, que a aquella ciudad."},
    {"Mateo", "Mt", 10, 16, "Mirad que yo os envio como ovejas entre lobos; por eso, sed sagaces como serpientes y sencillos como palomas."},
    {"Mateo", "Mt", 10, 17, "Pero cuidado con la gente!, porque os entregaran a los tribunales, os azotaran en las sinagogas"},
    {"Mateo", "Mt", 10, 18, "y os haran comparecer ante gobernadores y reyes por mi causa, para dar testimonio ante ellos y ante los gentiles."},
    {"Mateo", "Mt", 10, 19, "Cuando os entreguen, no os preocupeis de lo que vais a decir o de como lo direis: en aquel momento se os sugerira lo que teneis que decir,"},
    {"Mateo", "Mt", 10, 20, "porque no sereis vosotros los que hableis, sino que el Espiritu de vuestro Padre hablara por vosotros."},
    {"Mateo", "Mt", 10, 21, "El hermano entregara al hermano a la muerte, el padre al hijo; se rebelaran los hijos contra sus padres y los mataran."},
    {"Mateo", "Mt", 10, 22, "Y sereis odiados por todos a causa de mi nombre; pero el que persevere hasta el final, se salvara."},
    {"Mateo", "Mt", 10, 23, "Cuando os persigan en una ciudad, huid a otra. En verdad os digo que no terminareis con las ciudades de Israel antes de que vuelva el Hijo del hombre."},
    {"Mateo", "Mt", 10, 24, "Un discipulo no es mas que su maestro, ni un esclavo mas que su amo;"},
    {"Mateo", "Mt", 10, 25, "ya le basta al discipulo con ser como su maestro y al esclavo como su amo. Si al due\177o de casa lo han llamado Belzebu, cuanto mas a los criados!"},
    {"Mateo", "Mt", 10, 26, "No les tengais miedo, porque nada hay encubierto, que no llegue a descubrirse; ni nada hay escondido, que no llegue a saberse."},
    {"Mateo", "Mt", 10, 27, "Lo que os digo en la oscuridad, decidlo a la luz, y lo que os digo al oido, pregonadlo desde la azotea."},
    {"Mateo", "Mt", 10, 28, "No tengais miedo a los que matan el cuerpo, pero no pueden matar el alma. No; temed al que puede llevar a la perdicion alma y cuerpo en la gehenna."},
    {"Mateo", "Mt", 10, 29, "No se venden un par de gorriones por un centimo? Y, sin embargo, ni uno solo cae al suelo sin que lo disponga vuestro Padre."},
    {"Mateo", "Mt", 10, 30, "Pues vosotros hasta los cabellos de la cabeza teneis contados."},
    {"Mateo", "Mt", 10, 31, "Por eso, no tengais miedo: valeis mas vosotros que muchos gorriones."},
    {"Mateo", "Mt", 10, 32, "A quien se declare por mi ante los hombres, yo tambien me declarare por el ante mi Padre que esta en los cielos."},
    {"Mateo", "Mt", 10, 33, "Y si uno me niega ante los hombres, yo tambien lo negare ante mi Padre que esta en los cielos."},
    {"Mateo", "Mt", 10, 34, "No penseis que he venido a la tierra a sembrar paz: no he venido a sembrar paz, sino espada."},
    {"Mateo", "Mt", 10, 35, "He venido a enemistar al hombre con su padre, a la hija con su madre, a la nuera con su suegra;"},
    {"Mateo", "Mt", 10, 36, "los enemigos de cada uno seran los de su propia casa."},
    {"Mateo", "Mt", 10, 37, "El que quiere a su padre o a su madre mas que a mi, no es digno de mi; el que quiere a su hijo o a su hija mas que a mi, no es digno de mi;"},
    {"Mateo", "Mt", 10, 38, "y el que no carga con su cruz y me sigue, no es digno de mi."},
    {"Mateo", "Mt", 10, 39, "El que encuentre su vida la perdera, y el que pierda su vida por mi, la encontrara."},
    {"Mateo", "Mt", 10, 40, "El que os recibe a vosotros, me recibe a mi, y el que me recibe, recibe al que me ha enviado;"},
    {"Mateo", "Mt", 10, 41, "el que recibe a un profeta porque es profeta, tendra recompensa de profeta; y el que recibe a un justo porque es justo, tendra recompensa de justo."},
    {"Mateo", "Mt", 10, 42, "El que de a beber, aunque no sea mas que un vaso de agua fresca, a uno de estos peque\177os, solo porque es mi discipulo, en verdad os digo que no perdera su recompensa\"."},
    {"Mateo", "Mt", 11, 1, "Cuando Jesus acabo de dar instrucciones a sus doce discipulos, partio de alli para ense\177ar y predicar en sus ciudades."},
    {"Mateo", "Mt", 11, 2, "Juan, que habia oido en la carcel las obras del Mesias, mando a sus discipulos a preguntarle:"},
    {"Mateo", "Mt", 11, 3, "\"Eres tu el que ha de venir o tenemos que esperar a otro?\"."},
    {"Mateo", "Mt", 11, 4, "Jesus les respondio: \"Id a anunciar a Juan lo que estais viendo y oyendo:"},
    {"Mateo", "Mt", 11, 5, "los ciegos ven y los cojos andan; los leprosos quedan limpios y los sordos oyen; los muertos resucitan y los pobres son evangelizados."},
    {"Mateo", "Mt", 11, 6, "Y bienaventurado el que no se escandalice de mi!\"."},
    {"Mateo", "Mt", 11, 7, "Al irse ellos, Jesus se puso a hablar a la gente sobre Juan: \"Que salisteis a contemplar en el desierto, una ca\177a sacudida por el viento?"},
    {"Mateo", "Mt", 11, 8, "O que salisteis a ver, un hombre vestido con lujo? Mirad, los que visten con lujo habitan en los palacios."},
    {"Mateo", "Mt", 11, 9, "Entonces, a que salisteis?, a ver a un profeta? Si, os digo, y mas que profeta."},
    {"Mateo", "Mt", 11, 10, "Este es de quien esta escrito: \"Yo envio a mi mensajero delante de ti, el cual preparara tu camino ante ti\"."},
    {"Mateo", "Mt", 11, 11, "En verdad os digo que no ha nacido de mujer uno mas grande que Juan el Bautista; aunque el mas peque\177o en el reino de los cielos es mas grande que el."},
    {"Mateo", "Mt", 11, 12, "Desde los dias de Juan el Bautista hasta ahora el reino de los cielos sufre violencia y los violentos lo arrebatan."},
    {"Mateo", "Mt", 11, 13, "Los Profetas y la Ley han profetizado hasta que vino Juan;"},
    {"Mateo", "Mt", 11, 14, "el es Elias, el que tenia que venir, con tal que querais admitirlo."},
    {"Mateo", "Mt", 11, 15, "El que tenga oidos, que oiga."},
    {"Mateo", "Mt", 11, 16, "A quien comparare esta generacion? Se asemeja a unos ni\177os sentados en la plaza, que gritan diciendo:"},
    {"Mateo", "Mt", 11, 17, "\"Hemos tocado la flauta, y no habeis bailado; hemos entonado lamentaciones, y no habeis llorado\"."},
    {"Mateo", "Mt", 11, 18, "Porque vino Juan, que ni comia ni bebia, y dicen: \"Tiene un demonio\"."},
    {"Mateo", "Mt", 11, 19, "Vino el Hijo del hombre, que come y bebe, y dicen: \"Ahi teneis a un comilon y borracho, amigo de publicanos y pecadores\". Pero la sabiduria se ha acreditado por sus obras\"."},
    {"Mateo", "Mt", 11, 20, "Entonces se puso Jesus a recriminar a las ciudades donde habia hecho la mayor parte de sus milagros, porque no se habian convertido:"},
    {"Mateo", "Mt", 11, 21, "\"Ay de ti, Corozain, ay de ti, Betsaida! Si en Tiro y en Sidon se hubieran hecho los milagros que en vosotras, hace tiempo que se habrian convertido, cubiertas de sayal y ceniza."},
    {"Mateo", "Mt", 11, 22, "Pues os digo que el dia del juicio les sera mas llevadero a Tiro y a Sidon que a vosotras."},
    {"Mateo", "Mt", 11, 23, "Y tu, Cafarnaun, piensas escalar el cielo? Bajaras al abismo. Porque si en Sodoma se hubieran hecho los milagros que en ti, habria durado hasta hoy."},
    {"Mateo", "Mt", 11, 24, "Pues os digo que el dia del juicio le sera mas llevadero a Sodoma que a ti\"."},
    {"Mateo", "Mt", 11, 25, "En aquel momento tomo la palabra Jesus y dijo: \"Te doy gracias, Padre, Se\177or del cielo y de la tierra, porque has escondido estas cosas a los sabios y entendidos, y se las has revelado a los peque\177os."},
    {"Mateo", "Mt", 11, 26, "Si, Padre, asi te ha parecido bien."},
    {"Mateo", "Mt", 11, 27, "Todo me ha sido entregado por mi Padre, y nadie conoce al Hijo mas que el Padre, y nadie conoce al Padre sino el Hijo y aquel a quien el Hijo se lo quiera revelar."},
    {"Mateo", "Mt", 11, 28, "Venid a mi todos los que estais cansados y agobiados, y yo os aliviare."},
    {"Mateo", "Mt", 11, 29, "Tomad mi yugo sobre vosotros y aprended de mi, que soy manso y humilde de corazon, y encontrareis descanso para vuestras almas."},
    {"Mateo", "Mt", 11, 30, "Porque mi yugo es llevadero y mi carga ligera\"."},
    {"Mateo", "Mt", 12, 1, "En aquel tiempo atraveso Jesus en sabado un sembrado; los discipulos, que tenian hambre, empezaron a arrancar espigas y a comerselas."},
    {"Mateo", "Mt", 12, 2, "Los fariseos, al verlo, le dijeron: \"Mira, tus discipulos estan haciendo una cosa que no esta permitida en sabado\"."},
    {"Mateo", "Mt", 12, 3, "Les replico: \"No habeis leido lo que hizo David, cuando el y sus hombres sintieron hambre?"},
    {"Mateo", "Mt", 12, 4, "Entro en la casa de Dios y comieron de los panes de la proposicion, cosa que no les estaba permitida ni a el ni a sus compa\177eros, sino solo a los sacerdotes."},
    {"Mateo", "Mt", 12, 5, "Y no habeis leido en la ley que los sacerdotes pueden violar el sabado en el templo sin incurrir en culpa?"},
    {"Mateo", "Mt", 12, 6, "Pues os digo que aqui hay uno que es mas que el templo."},
    {"Mateo", "Mt", 12, 7, "Si comprendierais lo que significa \"quiero misericordia y no sacrificio\", no condenariais a los inocentes."},
    {"Mateo", "Mt", 12, 8, "Porque el Hijo del hombre es se\177or del sabado\"."},
    {"Mateo", "Mt", 12, 9, "Se dirigio a otro lugar y entro en su sinagoga."},
    {"Mateo", "Mt", 12, 10, "Habia alli un hombre que tenia una mano paralizada. Entonces preguntaron a Jesus para poder acusarlo: \"Esta permitido curar en sabado?\"."},
    {"Mateo", "Mt", 12, 11, "El les respondio: \"Supongamos que uno de vosotros tiene una oveja y que un sabado se le cae en una zanja, no la agarra y la saca?"},
    {"Mateo", "Mt", 12, 12, "Pues, cuanto mas vale un hombre que una oveja! Por lo tanto, esta permitido hacer bien en sabado\"."},
    {"Mateo", "Mt", 12, 13, "Entonces le dijo al hombre: \"Extiende tu mano\". La extendio y quedo restablecida, sana como la otra."},
    {"Mateo", "Mt", 12, 14, "Al salir de la sinagoga, los fariseos planearon el modo de acabar con Jesus."},
    {"Mateo", "Mt", 12, 15, "Pero Jesus se entero, se marcho de alli y muchos lo siguieron. El los curo a todos,"},
    {"Mateo", "Mt", 12, 16, "mandandoles que no lo descubrieran."},
    {"Mateo", "Mt", 12, 17, "Asi se cumplio lo dicho por medio del profeta Isaias:"},
    {"Mateo", "Mt", 12, 18, "\"Mirad a mi siervo, mi elegido, mi amado, en quien me complazco. Sobre el pondre mi espiritu para que anuncie el derecho a las naciones."},
    {"Mateo", "Mt", 12, 19, "No porfiara, no gritara, nadie escuchara su voz por las calles."},
    {"Mateo", "Mt", 12, 20, "La ca\177a cascada no la quebrara, la mecha vacilante no la apagara, hasta llevar el derecho a la victoria;"},
    {"Mateo", "Mt", 12, 21, "en su nombre esperaran las naciones\"."},
    {"Mateo", "Mt", 12, 22, "Entonces le fue presentado un endemoniado ciego y mudo, y lo curo, de suerte que el mudo hablaba y veia."},
    {"Mateo", "Mt", 12, 23, "Y toda la multitud asombrada decia: \"No sera este el hijo de David?\"."},
    {"Mateo", "Mt", 12, 24, "Pero los fariseos al oirlo dijeron: \"Este expulsa los demonios con el poder de Belzebu, principe de los demonios\"."},
    {"Mateo", "Mt", 12, 25, "Pero el, dandose cuenta de sus pensamientos, les dijo: \"Todo reino dividido internamente va a la ruina y toda ciudad o casa dividida internamente no se mantiene en pie."},
    {"Mateo", "Mt", 12, 26, "Si Satanas expulsa a Satanas esta dividido contra si mismo, como va a subsistir su reino?"},
    {"Mateo", "Mt", 12, 27, "Y si yo expulso los demonios con el poder de Belzebu, vuestros hijos con el poder de quien los expulsan? Por eso ellos os juzgaran."},
    {"Mateo", "Mt", 12, 28, "Pero si yo expulso a los demonios por el Espiritu de Dios, es que ha llegado a vosotros el reino de Dios."},
    {"Mateo", "Mt", 12, 29, "Como podra uno entrar en la casa de un hombre fuerte y llevarse su ajuar, si no ata primero al fuerte?"},
    {"Mateo", "Mt", 12, 30, "El que no esta conmigo esta contra mi, y el que no recoge conmigo, desparrama."},
    {"Mateo", "Mt", 12, 31, "Por eso os digo que cualquier pecado o blasfemia seran perdonados a los hombres, pero la blasfemia contra el Espiritu no sera perdonada."},
    {"Mateo", "Mt", 12, 32, "Y quien diga una palabra contra el Hijo del hombre sera perdonado, pero quien hable contra el Espiritu Santo no sera perdonado ni en este mundo ni en el otro."},
    {"Mateo", "Mt", 12, 33, "Plantad un arbol bueno y el fruto sera bueno; plantad un arbol malo y el fruto sera malo; porque el arbol se conoce por su fruto."},
    {"Mateo", "Mt", 12, 34, "Raza de viboras, como podeis decir cosas buenas si sois malos? Porque de lo que rebosa el corazon habla la boca."},
    {"Mateo", "Mt", 12, 35, "El hombre bueno saca del caudal bueno cosas buenas, pero el hombre malo saca del caudal malo cosas malas."},
    {"Mateo", "Mt", 12, 36, "En verdad os digo que el hombre dara cuenta en el dia del juicio de cualquier palabra inconsiderada que haya dicho."},
    {"Mateo", "Mt", 12, 37, "Porque por tus palabras seras declarado justo o por tus palabras seras condenado\"."},
    {"Mateo", "Mt", 12, 38, "Entonces algunos escribas y fariseos le dijeron: \"Maestro, queremos ver un milagro tuyo\"."},
    {"Mateo", "Mt", 12, 39, "El les contesto: \"Esta generacion perversa y adultera exige una se\177al; pues no se le dara mas signo que el del profeta Jonas."},
    {"Mateo", "Mt", 12, 40, "Tres dias y tres noches estuvo Jonas en el vientre del cetaceo: pues tres dias y tres noches estara el Hijo del hombre en el seno de la tierra."},
    {"Mateo", "Mt", 12, 41, "Los hombres de Ninive se alzaran en el juicio contra esta generacion y haran que la condenen; porque ellos se convirtieron con la proclamacion de Jonas, y aqui hay uno que es mas que Jonas."},
    {"Mateo", "Mt", 12, 42, "Cuando juzguen a esta generacion, la reina del Sur se levantara y hara que la condenen, porque ella vino desde los confines de la tierra, para escuchar la sabiduria de Salomon, y aqui hay uno que es mas que Salomon."},
    {"Mateo", "Mt", 12, 43, "Cuando el espiritu inmundo sale del hombre anda vagando por lugares aridos en busca de reposo y no lo encuentra."},
    {"Mateo", "Mt", 12, 44, "Entonces dice: \"Volvere a mi casa de donde sali\". Y al volver la encuentra deshabitada, barrida y arreglada."},
    {"Mateo", "Mt", 12, 45, "Entonces va y toma consigo otros siete espiritus peores que el y se mete a habitar alli; y el final de aquel hombre resulta peor que el comienzo. Asi le sucedera a esta generacion malvada\"."},
    {"Mateo", "Mt", 12, 46, "Todavia estaba Jesus hablando a la gente, cuando su madre y sus hermanos se presentaron fuera, tratando de hablar con el."},
    {"Mateo", "Mt", 12, 47, "Uno se lo aviso: \"Tu madre y tus hermanos estan fuera y quieren hablar contigo\"."},
    {"Mateo", "Mt", 12, 48, "Pero el contesto al que le avisaba: \"Quien es mi madre y quienes son mis hermanos?\"."},
    {"Mateo", "Mt", 12, 49, "Y, extendiendo su mano hacia sus discipulos, dijo: \"Estos son mi madre y mis hermanos."},
    {"Mateo", "Mt", 12, 50, "El que haga la voluntad de mi Padre que esta en los cielos, ese es mi hermano y mi hermana y mi madre\"."},
    {"Mateo", "Mt", 13, 1, "Aquel dia salio Jesus de casa y se sento junto al mar."},
    {"Mateo", "Mt", 13, 2, "Y acudio a el tanta gente que tuvo que subirse a una barca; se sento y toda la gente se quedo de pie en la orilla."},
    {"Mateo", "Mt", 13, 3, "Les hablo muchas cosas en parabolas: \"Salio el sembrador a sembrar."},
    {"Mateo", "Mt", 13, 4, "Al sembrar, una parte cayo al borde del camino; vinieron los pajaros y se la comieron."},
    {"Mateo", "Mt", 13, 5, "Otra parte cayo en terreno pedregoso, donde apenas tenia tierra, y como la tierra no era profunda broto enseguida;"},
    {"Mateo", "Mt", 13, 6, "pero en cuanto salio el sol, se abraso y por falta de raiz se seco."},
    {"Mateo", "Mt", 13, 7, "Otra cayo entre abrojos, que crecieron y la ahogaron."},
    {"Mateo", "Mt", 13, 8, "Otra cayo en tierra buena y dio fruto: una, ciento; otra, sesenta; otra, treinta."},
    {"Mateo", "Mt", 13, 9, "El que tenga oidos, que oiga\"."},
    {"Mateo", "Mt", 13, 10, "Se le acercaron los discipulos y le preguntaron: \"Por que les hablas en parabolas?\"."},
    {"Mateo", "Mt", 13, 11, "El les contesto: \"A vosotros se os han dado a conocer los secretos del reino de los cielos y a ellos no."},
    {"Mateo", "Mt", 13, 12, "Porque al que tiene se le dara y tendra de sobra, y al que no tiene, se le quitara hasta lo que tiene."},
    {"Mateo", "Mt", 13, 13, "Por eso les hablo en parabolas, porque miran sin ver y escuchan sin oir ni entender."},
    {"Mateo", "Mt", 13, 14, "Asi se cumple en ellos la profecia de Isaias: \"Oireis con los oidos sin entender; mirareis con los ojos sin ver;"},
    {"Mateo", "Mt", 13, 15, "porque esta embotado el corazon de este pueblo, son duros de oido, han cerrado los ojos; para no ver con los ojos, ni oir con los oidos, ni entender con el corazon, ni convertirse para que yo los cure\"."},
    {"Mateo", "Mt", 13, 16, "Pero bienaventurados vuestros ojos porque ven y vuestros oidos porque oyen."},
    {"Mateo", "Mt", 13, 17, "En verdad os digo que muchos profetas y justos desearon ver lo que veis y no lo vieron, y oir lo que ois y no lo oyeron."},
    {"Mateo", "Mt", 13, 18, "Vosotros, pues, oid lo que significa la parabola del sembrador:"},
    {"Mateo", "Mt", 13, 19, "si uno escucha la palabra del reino sin entenderla, viene el Maligno y roba lo sembrado en su corazon. Esto significa lo sembrado al borde del camino."},
    {"Mateo", "Mt", 13, 20, "Lo sembrado en terreno pedregoso significa el que escucha la palabra y la acepta enseguida con alegria;"},
    {"Mateo", "Mt", 13, 21, "pero no tiene raices, es inconstante, y en cuanto viene una dificultad o persecucion por la palabra, enseguida sucumbe."},
    {"Mateo", "Mt", 13, 22, "Lo sembrado entre abrojos significa el que escucha la palabra; pero los afanes de la vida y la seduccion de las riquezas ahogan la palabra y se queda esteril."},
    {"Mateo", "Mt", 13, 23, "Lo sembrado en tierra buena significa el que escucha la palabra y la entiende; ese da fruto y produce ciento o sesenta o treinta por uno\"."},
    {"Mateo", "Mt", 13, 24, "Les propuso otra parabola: \"El reino de los cielos se parece a un hombre que sembro buena semilla en su campo;"},
    {"Mateo", "Mt", 13, 25, "pero, mientras los hombres dormian, un enemigo fue y sembro ciza\177a en medio del trigo y se marcho."},
    {"Mateo", "Mt", 13, 26, "Cuando empezaba a verdear y se formaba la espiga aparecio tambien la ciza\177a."},
    {"Mateo", "Mt", 13, 27, "Entonces fueron los criados a decirle al amo: \"Se\177or, no sembraste buena semilla en tu campo? De donde sale la ciza\177a?\"."},
    {"Mateo", "Mt", 13, 28, "El les dijo: \"Un enemigo lo ha hecho\". Los criados le preguntan: \"Quieres que vayamos a arrancarla?\"."},
    {"Mateo", "Mt", 13, 29, "Pero el les respondio: \"No, que al recoger la ciza\177a podeis arrancar tambien el trigo."},
    {"Mateo", "Mt", 13, 30, "Dejadlos crecer juntos hasta la siega y cuando llegue la siega dire a los segadores: arrancad primero la ciza\177a y atadla en gavillas para quemarla, y el trigo almacenadlo en mi granero\"\"."},
    {"Mateo", "Mt", 13, 31, "Les propuso otra parabola: \"El reino de los cielos se parece a un grano de mostaza que uno toma y siembra en su campo;"},
    {"Mateo", "Mt", 13, 32, "aunque es la mas peque\177a de las semillas, cuando crece es mas alta que las hortalizas; se hace un arbol hasta el punto de que vienen los pajaros del cielo a anidar en sus ramas\"."},
    {"Mateo", "Mt", 13, 33, "Les dijo otra parabola: \"El reino de los cielos se parece a la levadura; una mujer la amasa con tres medidas de harina, hasta que todo fermenta\"."},
    {"Mateo", "Mt", 13, 34, "Jesus dijo todo esto a la gente en parabolas y sin parabolas no les hablaba nada,"},
    {"Mateo", "Mt", 13, 35, "para que se cumpliera lo dicho por medio del profeta: \"Abrire mi boca diciendo parabolas; anunciare lo secreto desde la fundacion del mundo\"."},
    {"Mateo", "Mt", 13, 36, "Luego dejo a la gente y se fue a casa. Los discipulos se le acercaron a decirle: \"Explicanos la parabola de la ciza\177a en el campo\"."},
    {"Mateo", "Mt", 13, 37, "El les contesto: \"El que siembra la buena semilla es el Hijo del hombre;"},
    {"Mateo", "Mt", 13, 38, "el campo es el mundo; la buena semilla son los ciudadanos del reino; la ciza\177a son los partidarios del Maligno;"},
    {"Mateo", "Mt", 13, 39, "el enemigo que la siembra es el diablo; la cosecha es el final de los tiempos y los segadores los angeles."},
    {"Mateo", "Mt", 13, 40, "Lo mismo que se arranca la ciza\177a y se echa al fuego, asi sera al final de los tiempos:"},
    {"Mateo", "Mt", 13, 41, "el Hijo del hombre enviara a sus angeles y arrancaran de su reino todos los escandalos y a todos los que obran iniquidad,"},
    {"Mateo", "Mt", 13, 42, "y los arrojaran al horno de fuego; alli sera el llanto y el rechinar de dientes."},
    {"Mateo", "Mt", 13, 43, "Entonces los justos brillaran como el sol en el reino de su Padre. El que tenga oidos, que oiga."},
    {"Mateo", "Mt", 13, 44, "El reino de los cielos se parece a un tesoro escondido en el campo: el que lo encuentra, lo vuelve a esconder y, lleno de alegria, va a vender todo lo que tiene y compra el campo."},
    {"Mateo", "Mt", 13, 45, "El reino de los cielos se parece tambien a un comerciante de perlas finas,"},
    {"Mateo", "Mt", 13, 46, "que al encontrar una de gran valor se va a vender todo lo que tiene y la compra."},
    {"Mateo", "Mt", 13, 47, "El reino de los cielos se parece tambien a la red que echan en el mar y recoge toda clase de peces:"},
    {"Mateo", "Mt", 13, 48, "cuando esta llena, la arrastran a la orilla, se sientan y reunen los buenos en cestos y los malos los tiran."},
    {"Mateo", "Mt", 13, 49, "Lo mismo sucedera al final de los tiempos: saldran los angeles, separaran a los malos de los buenos"},
    {"Mateo", "Mt", 13, 50, "y los echaran al horno de fuego. Alli sera el llanto y el rechinar de dientes."},
    {"Mateo", "Mt", 13, 51, "Habeis entendido todo esto?\". Ellos le responden: \"Si\"."},
    {"Mateo", "Mt", 13, 52, "El les dijo: \"Pues bien, un escriba que se ha hecho discipulo del reino de los cielos es como un padre de familia que va sacando de su tesoro lo nuevo y lo antiguo\"."},
    {"Mateo", "Mt", 13, 53, "Cuando Jesus acabo estas parabolas, partio de alli."},
    {"Mateo", "Mt", 13, 54, "Fue a su ciudad y se puso a ense\177ar en su sinagoga. La gente decia admirada: \"De donde saca este esa sabiduria y esos milagros?"},
    {"Mateo", "Mt", 13, 55, "No es el hijo del carpintero? No es su madre Maria, y sus hermanos Santiago, Jose, Simon y Judas?"},
    {"Mateo", "Mt", 13, 56, "No viven aqui todas sus hermanas? Entonces, de donde saca todo eso?\"."},
    {"Mateo", "Mt", 13, 57, "Y se escandalizaban a causa de el. Jesus les dijo: \"Solo en su tierra y en su casa desprecian a un profeta\"."},
    {"Mateo", "Mt", 13, 58, "Y no hizo alli muchos milagros, por su falta de fe."},
    {"Mateo", "Mt", 14, 1, "En aquel tiempo, oyo el tetrarca Herodes lo que se contaba de Jesus"},
    {"Mateo", "Mt", 14, 2, "y dijo a sus cortesanos: \"Ese es Juan el Bautista, que ha resucitado de entre los muertos, y por eso las fuerzas milagrosas actuan en el\"."},
    {"Mateo", "Mt", 14, 3, "Es que Herodes habia mandado prender a Juan y lo habia metido en la carcel encadenado, por motivo de Herodias, mujer de su hermano Filipo;"},
    {"Mateo", "Mt", 14, 4, "porque Juan le decia que no le era licito vivir con ella."},
    {"Mateo", "Mt", 14, 5, "Queria mandarlo matar, pero tuvo miedo de la gente, que lo tenia por profeta."},
    {"Mateo", "Mt", 14, 6, "El dia del cumplea\177os de Herodes, la hija de Herodias danzo delante de todos y le gusto tanto a Herodes,"},
    {"Mateo", "Mt", 14, 7, "que juro darle lo que pidiera."},
    {"Mateo", "Mt", 14, 8, "Ella, instigada por su madre, le dijo: \"Dame ahora mismo en una bandeja la cabeza de Juan el Bautista\"."},
    {"Mateo", "Mt", 14, 9, "El rey lo sintio, pero, por el juramento y los invitados, ordeno que se la dieran,"},
    {"Mateo", "Mt", 14, 10, "y mando decapitar a Juan en la carcel."},
    {"Mateo", "Mt", 14, 11, "Trajeron la cabeza en una bandeja, se la entregaron a la joven y ella se la llevo a su madre."},
    {"Mateo", "Mt", 14, 12, "Sus discipulos recogieron el cadaver, lo enterraron, y fueron a contarselo a Jesus."},
    {"Mateo", "Mt", 14, 13, "Al enterarse Jesus se marcho de alli en barca, a solas, a un lugar desierto. Cuando la gente lo supo, lo siguio por tierra desde los poblados."},
    {"Mateo", "Mt", 14, 14, "Al desembarcar vio Jesus una multitud, se compadecio de ella y curo a los enfermos."},
    {"Mateo", "Mt", 14, 15, "Como se hizo tarde, se acercaron los discipulos a decirle: \"Estamos en despoblado y es muy tarde, despide a la multitud para que vayan a las aldeas y se compren comida\"."},
    {"Mateo", "Mt", 14, 16, "Jesus les replico: \"No hace falta que vayan, dadles vosotros de comer\"."},
    {"Mateo", "Mt", 14, 17, "Ellos le replicaron: \"Si aqui no tenemos mas que cinco panes y dos peces\"."},
    {"Mateo", "Mt", 14, 18, "Les dijo: \"Traedmelos\"."},
    {"Mateo", "Mt", 14, 19, "Mando a la gente que se recostara en la hierba y tomando los cinco panes y los dos peces, alzando la mirada al cielo, pronuncio la bendicion, partio los panes y se los dio a los discipulos; los discipulos se los dieron a la gente."},
    {"Mateo", "Mt", 14, 20, "Comieron todos y se saciaron y recogieron doce cestos llenos de sobras."},
    {"Mateo", "Mt", 14, 21, "Comieron unos cinco mil hombres, sin contar mujeres y ni\177os."},
    {"Mateo", "Mt", 14, 22, "Enseguida Jesus apremio a sus discipulos a que subieran a la barca y se le adelantaran a la otra orilla, mientras el despedia a la gente."},
    {"Mateo", "Mt", 14, 23, "Y despues de despedir a la gente subio al monte a solas para orar. Llegada la noche estaba alli solo."},
    {"Mateo", "Mt", 14, 24, "Mientras tanto la barca iba ya muy lejos de tierra, sacudida por las olas, porque el viento era contrario."},
    {"Mateo", "Mt", 14, 25, "A la cuarta vela de la noche se les acerco Jesus andando sobre el mar."},
    {"Mateo", "Mt", 14, 26, "Los discipulos, viendole andar sobre el agua, se asustaron y gritaron de miedo, diciendo que era un fantasma."},
    {"Mateo", "Mt", 14, 27, "Jesus les dijo enseguida: \"Animo, soy yo, no tengais miedo!\"."},
    {"Mateo", "Mt", 14, 28, "Pedro le contesto: \"Se\177or, si eres tu, mandame ir a ti sobre el agua\"."},
    {"Mateo", "Mt", 14, 29, "El le dijo: \"Ven\". Pedro bajo de la barca y echo a andar sobre el agua acercandose a Jesus;"},
    {"Mateo", "Mt", 14, 30, "pero, al sentir la fuerza del viento, le entro miedo, empezo a hundirse y grito: \"Se\177or, salvame\"."},
    {"Mateo", "Mt", 14, 31, "Enseguida Jesus extendio la mano, lo agarro y le dijo: \"Hombre de poca fe! Por que has dudado?\"."},
    {"Mateo", "Mt", 14, 32, "En cuanto subieron a la barca amaino el viento."},
    {"Mateo", "Mt", 14, 33, "Los de la barca se postraron ante el diciendo: \"Realmente eres Hijo de Dios\"."},
    {"Mateo", "Mt", 14, 34, "Terminada la travesia, llegaron a tierra en Genesaret."},
    {"Mateo", "Mt", 14, 35, "Y los hombres de aquel lugar apenas lo reconocieron, pregonaron la noticia por toda aquella comarca y le trajeron a todos los enfermos."},
    {"Mateo", "Mt", 14, 36, "Le pedian tocar siquiera la orla de su manto. Y cuantos la tocaban quedaban curados."},
    {"Mateo", "Mt", 15, 1, "Entonces se acercaron a Jesus unos fariseos y escribas de Jerusalen y le preguntaron:"},
    {"Mateo", "Mt", 15, 2, "\"Por que tus discipulos quebrantan la tradicion de nuestros mayores y no se lavan las manos antes de comer?\"."},
    {"Mateo", "Mt", 15, 3, "El les respondio: \"Por que quebrantais vosotros el mandato de Dios en nombre de vuestra tradicion?"},
    {"Mateo", "Mt", 15, 4, "Pues Dios dijo: \"Honra al padre y a la madre\" y \"El que maldiga al padre o a la madre es reo de muerte\"."},
    {"Mateo", "Mt", 15, 5, "Pero vosotros decis: \"Si uno dice al padre o a la madre: 'Los bienes con que podria ayudarte son ofrenda sagrada',"},
    {"Mateo", "Mt", 15, 6, "ya no tiene que honrar a su padre o a su madre\". Y asi invalidais el mandato de Dios en nombre de vuestra tradicion."},
    {"Mateo", "Mt", 15, 7, "Bien profetizo Isaias de vosotros, hipocritas, diciendo:"},
    {"Mateo", "Mt", 15, 8, "\"Este pueblo me honra con los labios, pero su corazon esta lejos de mi."},
    {"Mateo", "Mt", 15, 9, "El culto que me dan esta vacio, porque la doctrina que ense\177an son preceptos humanos\"\"."},
    {"Mateo", "Mt", 15, 10, "Y, llamando a la gente, les dijo: \"Escuchad y entended:"},
    {"Mateo", "Mt", 15, 11, "no mancha al hombre lo que entra por la boca, sino lo que sale de la boca, eso es lo que mancha al hombre\"."},
    {"Mateo", "Mt", 15, 12, "Se acercaron los discipulos y le dijeron: \"Sabes que los fariseos se han escandalizado al oirte?\"."},
    {"Mateo", "Mt", 15, 13, "Respondio el: \"La planta que no haya plantado mi Padre celestial, sera arrancada de raiz."},
    {"Mateo", "Mt", 15, 14, "Dejadlos, son ciegos, guias de ciegos. Y si un ciego guia a otro ciego, los dos caeran en el hoyo\"."},
    {"Mateo", "Mt", 15, 15, "Pedro le dijo: \"Explicanos esta parabola\"."},
    {"Mateo", "Mt", 15, 16, "El les dijo: \"Tambien vosotros seguis sin entender?"},
    {"Mateo", "Mt", 15, 17, "No comprendeis que todo lo que entra por la boca pasa al vientre y se expulsa en la letrina?,"},
    {"Mateo", "Mt", 15, 18, "pero lo que sale de la boca brota del corazon; y esto es lo que hace impuro al hombre,"},
    {"Mateo", "Mt", 15, 19, "porque del corazon salen pensamientos perversos, homicidios, adulterios, fornicaciones, robos, difamaciones, blasfemias."},
    {"Mateo", "Mt", 15, 20, "Estas cosas son las que hacen impuro al hombre. Pero el comer sin lavarse las manos no hace impuro al hombre\"."},
    {"Mateo", "Mt", 15, 21, "Jesus salio y se retiro a la region de Tiro y Sidon."},
    {"Mateo", "Mt", 15, 22, "Entonces una mujer cananea, saliendo de uno de aquellos lugares, se puso a gritarle: \"Ten compasion de mi, Se\177or Hijo de David. Mi hija tiene un demonio muy malo\"."},
    {"Mateo", "Mt", 15, 23, "El no le respondio nada. Entonces los discipulos se le acercaron a decirle: \"Atiendela, que viene detras gritando\"."},
    {"Mateo", "Mt", 15, 24, "El les contesto: \"Solo he sido enviado a las ovejas descarriadas de Israel\"."},
    {"Mateo", "Mt", 15, 25, "Ella se acerco y se postro ante el diciendo: \"Se\177or, ayudame\"."},
    {"Mateo", "Mt", 15, 26, "El le contesto: \"No esta bien tomar el pan de los hijos y echarselo a los perritos\"."},
    {"Mateo", "Mt", 15, 27, "Pero ella repuso: \"Tienes razon, Se\177or; pero tambien los perritos se comen las migajas que caen de la mesa de los amos\"."},
    {"Mateo", "Mt", 15, 28, "Jesus le respondio: \"Mujer, que grande es tu fe: que se cumpla lo que deseas\". En aquel momento quedo curada su hija."},
    {"Mateo", "Mt", 15, 29, "Desde alli Jesus se dirigio al mar de Galilea, subio al monte y se sento en el."},
    {"Mateo", "Mt", 15, 30, "Acudio a el mucha gente llevando tullidos, ciegos, lisiados, sordomudos y muchos otros; los ponian a sus pies y el los curaba."},
    {"Mateo", "Mt", 15, 31, "La gente se admiraba al ver hablar a los mudos, sanos a los lisiados, andar a los tullidos y con vista a los ciegos, y daban gloria al Dios de Israel."},
    {"Mateo", "Mt", 15, 32, "Jesus llamo a sus discipulos y les dijo: \"Siento compasion de la gente, porque llevan ya tres dias conmigo y no tienen que comer. Y no quiero despedirlos en ayunas, no sea que desfallezcan en el camino\"."},
    {"Mateo", "Mt", 15, 33, "Los discipulos le dijeron: \"De donde vamos a sacar en un despoblado panes suficientes para saciar a tanta gente?\"."},
    {"Mateo", "Mt", 15, 34, "Jesus les dijo: \"Cuantos panes teneis?\". Ellos contestaron: \"Siete y algunos peces\"."},
    {"Mateo", "Mt", 15, 35, "El mando a la gente que se sentara en el suelo."},
    {"Mateo", "Mt", 15, 36, "Tomo los siete panes y los peces, pronuncio la accion de gracias, los partio y los fue dando a los discipulos, y los discipulos a la gente."},
    {"Mateo", "Mt", 15, 37, "Comieron todos hasta saciarse y recogieron las sobras: siete canastos llenos."},
    {"Mateo", "Mt", 15, 38, "Los que comieron eran cuatro mil hombres, sin contar mujeres y ni\177os."},
    {"Mateo", "Mt", 15, 39, "Despidio a la multitud, monto en la barca y se dirigio a la region de Magadan."},
    {"Mateo", "Mt", 16, 1, "Se le acercaron los fariseos y saduceos y, para ponerlo a prueba, le pidieron que les mostrase un signo del cielo."},
    {"Mateo", "Mt", 16, 2, "Les contesto: \"Al atardecer decis: \"Va a hacer buen tiempo, porque el cielo esta rojo\"."},
    {"Mateo", "Mt", 16, 3, "Y a la ma\177ana: \"Hoy llovera, porque el cielo esta rojo oscuro\". Sabeis distinguir el aspecto del cielo y no sois capaces de distinguir los signos de los tiempos?"},
    {"Mateo", "Mt", 16, 4, "Esta generacion perversa y adultera exige una se\177al; pues no se le dara mas signo que el de Jonas\". Y dejandolos se marcho."},
    {"Mateo", "Mt", 16, 5, "Al pasar a la otra orilla, a los discipulos se les habia olvidado tomar pan."},
    {"Mateo", "Mt", 16, 6, "Jesus les dijo: \"Estad atentos y guardaos de la levadura de los fariseos y saduceos\"."},
    {"Mateo", "Mt", 16, 7, "Discutian entre ellos diciendo: \"Es porque no hemos cogido panes\"."},
    {"Mateo", "Mt", 16, 8, "Dandose cuenta Jesus dijo: \"Gente de poca fe!, por que andais discutiendo entre vosotros que no teneis panes?"},
    {"Mateo", "Mt", 16, 9, "Aun no entendeis? No os acordais de los cinco panes para los cinco mil?, cuantos cestos sobraron?"},
    {"Mateo", "Mt", 16, 10, "Ni de los siete panes para los cuatro mil?, cuantas canastas sobraron?"},
    {"Mateo", "Mt", 16, 11, "Como no comprendeis que no me referia a los panes? Guardaos de la levadura de los fariseos y saduceos\"."},
    {"Mateo", "Mt", 16, 12, "Entonces comprendieron que no hablaba de guardarse de la levadura del pan, sino de la ense\177anza de los fariseos y saduceos."},
    {"Mateo", "Mt", 16, 13, "Al llegar a la region de Cesarea de Filipo, Jesus pregunto a sus discipulos: \"Quien dice la gente que es el Hijo del hombre?\"."},
    {"Mateo", "Mt", 16, 14, "Ellos contestaron: \"Unos que Juan el Bautista, otros que Elias, otros que Jeremias o uno de los profetas\"."},
    {"Mateo", "Mt", 16, 15, "El les pregunto: \"Y vosotros, quien decis que soy yo?\"."},
    {"Mateo", "Mt", 16, 16, "Simon Pedro tomo la palabra y dijo: \"Tu eres el Mesias, el Hijo del Dios vivo\"."},
    {"Mateo", "Mt", 16, 17, "Jesus le respondio: \"Bienaventurado tu, Simon, hijo de Jonas!, porque eso no te lo ha revelado ni la carne ni la sangre, sino mi Padre que esta en los cielos."},
    {"Mateo", "Mt", 16, 18, "Ahora yo te digo: tu eres Pedro, y sobre esta piedra edificare mi Iglesia, y el poder del infierno no la derrotara."},
    {"Mateo", "Mt", 16, 19, "Te dare las llaves del reino de los cielos; lo que ates en la tierra quedara atado en los cielos, y lo que desates en la tierra quedara desatado en los cielos\"."},
    {"Mateo", "Mt", 16, 20, "Y les mando a los discipulos que no dijesen a nadie que el era el Mesias."},
    {"Mateo", "Mt", 16, 21, "Desde entonces comenzo Jesus a manifestar a sus discipulos que tenia que ir a Jerusalen y padecer alli mucho por parte de los ancianos, sumos sacerdotes y escribas, y que tenia que ser ejecutado y resucitar al tercer dia."},
    {"Mateo", "Mt", 16, 22, "Pedro se lo llevo aparte y se puso a increparlo: \"Lejos de ti tal cosa, Se\177or! Eso no puede pasarte\"."},
    {"Mateo", "Mt", 16, 23, "Jesus se volvio y dijo a Pedro: \"Ponte detras de mi, Satanas! Eres para mi piedra de tropiezo, porque tu piensas como los hombres, no como Dios\"."},
    {"Mateo", "Mt", 16, 24, "Entonces dijo a los discipulos: \"Si alguno quiere venir en pos de mi, que se niegue a si mismo, tome su cruz y me siga."},
    {"Mateo", "Mt", 16, 25, "Porque quien quiera salvar su vida, la perdera; pero el que la pierda por mi, la encontrara."},
    {"Mateo", "Mt", 16, 26, "Pues de que le servira a un hombre ganar el mundo entero, si pierde su alma? O que podra dar para recobrarla?"},
    {"Mateo", "Mt", 16, 27, "Porque el Hijo del hombre vendra, con la gloria de su Padre, entre sus angeles, y entonces pagara a cada uno segun su conducta."},
    {"Mateo", "Mt", 16, 28, "En verdad os digo que algunos de los aqui presentes no gustaran la muerte hasta que vean al Hijo del hombre en su reino\"."},
    {"Mateo", "Mt", 17, 1, "Seis dias mas tarde, Jesus tomo consigo a Pedro, a Santiago y a su hermano Juan, y subio con ellos aparte a un monte alto."},
    {"Mateo", "Mt", 17, 2, "Se transfiguro delante de ellos, y su rostro resplandecia como el sol, y sus vestidos se volvieron blancos como la luz."},
    {"Mateo", "Mt", 17, 3, "De repente se les aparecieron Moises y Elias conversando con el."},
    {"Mateo", "Mt", 17, 4, "Pedro, entonces, tomo la palabra y dijo a Jesus: \"Se\177or, que bueno es que estemos aqui! Si quieres, hare tres tiendas: una para ti, otra para Moises y otra para Elias\"."},
    {"Mateo", "Mt", 17, 5, "Todavia estaba hablando cuando una nube luminosa los cubrio con su sombra y una voz desde la nube decia: \"Este es mi Hijo, el amado, en quien me complazco. Escuchadlo\"."},
    {"Mateo", "Mt", 17, 6, "Al oirlo, los discipulos cayeron de bruces, llenos de espanto."},
    {"Mateo", "Mt", 17, 7, "Jesus se acerco y, tocandolos, les dijo: \"Levantaos, no temais\"."},
    {"Mateo", "Mt", 17, 8, "Al alzar los ojos, no vieron a nadie mas que a Jesus, solo."},
    {"Mateo", "Mt", 17, 9, "Cuando bajaban del monte, Jesus les mando: \"No conteis a nadie la vision hasta que el Hijo del hombre resucite de entre los muertos\"."},
    {"Mateo", "Mt", 17, 10, "Los discipulos le preguntaron: \"Por que dicen los escribas que primero tiene que venir Elias?\"."},
    {"Mateo", "Mt", 17, 11, "El les contesto: \"Elias vendra y lo renovara todo."},
    {"Mateo", "Mt", 17, 12, "Pero os digo que Elias ya ha venido y no lo reconocieron, sino que han hecho con el lo que han querido. Asi tambien el Hijo del hombre va a padecer a manos de ellos\"."},
    {"Mateo", "Mt", 17, 13, "Entonces entendieron los discipulos que se referia a Juan el Bautista."},
    {"Mateo", "Mt", 17, 14, "Cuando volvieron adonde estaba la gente, se acerco a Jesus un hombre que, de rodillas,"},
    {"Mateo", "Mt", 17, 15, "le dijo: \"Se\177or, ten compasion de mi hijo que es lunatico y sufre mucho: muchas veces se cae en el fuego o en el agua."},
    {"Mateo", "Mt", 17, 16, "Se lo he traido a tus discipulos y no han sido capaces de curarlo\"."},
    {"Mateo", "Mt", 17, 17, "Jesus tomo la palabra y dijo: \"Generacion incredula y perversa! Hasta cuando estare con vosotros, hasta cuando tendre que soportaros? Traedmelo\"."},
    {"Mateo", "Mt", 17, 18, "Jesus increpo al demonio y salio; en aquel momento se curo el ni\177o."},
    {"Mateo", "Mt", 17, 19, "Los discipulos se acercaron a Jesus y le preguntaron aparte: \"Y por que no pudimos echarlo nosotros?\"."},
    {"Mateo", "Mt", 17, 20, "Les contesto: \"Por vuestra poca fe. En verdad os digo que, si tuvierais fe como un grano de mostaza, le diriais a aquel monte: \"Trasladate desde ahi hasta aqui\", y se trasladaria. Nada os seria imposible\"."},
    {"Mateo", "Mt", 17, 21, "[\"Esta clase (de demonios) solo se expulsa con la oracion y el ayuno\"]"},
    {"Mateo", "Mt", 17, 22, "Mientras recorrian juntos Galilea, les dijo Jesus: \"El Hijo del hombre sera entregado en manos de los hombres,"},
    {"Mateo", "Mt", 17, 23, "lo mataran, pero resucitara al tercer dia\". Ellos se pusieron muy tristes."},
    {"Mateo", "Mt", 17, 24, "Cuando llegaron a Cafarnaun, los que cobraban el impuesto de las dos dracmas se acercaron a Pedro y le preguntaron: \"Vuestro Maestro no paga las dos dracmas?\"."},
    {"Mateo", "Mt", 17, 25, "Contesto: \"Si\". Cuando llego a casa, Jesus se adelanto a preguntarle: \"Que te parece, Simon? Los reyes del mundo, a quien le cobran impuestos y tasas, a sus hijos o a los extra\177os?\"."},
    {"Mateo", "Mt", 17, 26, "Contesto: \"A los extra\177os\". Jesus le dijo: \"Entonces, los hijos estan exentos."},
    {"Mateo", "Mt", 17, 27, "Sin embargo, para no darles mal ejemplo, ve al mar, echa el anzuelo, coge el primer pez que pique, abrele la boca y encontraras una moneda de plata. Cogela y pagales por mi y por ti\"."},
    {"Mateo", "Mt", 18, 1, "En aquel momento, se acercaron los discipulos a Jesus y le preguntaron: \"Quien es el mayor en el reino de los cielos?\"."},
    {"Mateo", "Mt", 18, 2, "El llamo a un ni\177o, lo puso en medio"},
    {"Mateo", "Mt", 18, 3, "y dijo: \"En verdad os digo que, si no os convertis y os haceis como ni\177os, no entrareis en el reino de los cielos."},
    {"Mateo", "Mt", 18, 4, "Por tanto, el que se haga peque\177o como este ni\177o, ese es el mas grande en el reino de los cielos."},
    {"Mateo", "Mt", 18, 5, "El que acoge a un ni\177o como este en mi nombre me acoge a mi."},
    {"Mateo", "Mt", 18, 6, "Al que escandalice a uno de estos peque\177os que creen en mi, mas le valdria que le colgasen una piedra de molino al cuello y lo arrojasen al fondo del mar."},
    {"Mateo", "Mt", 18, 7, "Ay del mundo por los escandalos! Es inevitable que sucedan escandalos, pero ay del hombre por el que viene el escandalo!"},
    {"Mateo", "Mt", 18, 8, "Si tu mano o tu pie te induce a pecar, cortatelo y arrojalo de ti. Mas te vale entrar en la vida manco o cojo que con las dos manos o los dos pies ser arrojado al fuego eterno."},
    {"Mateo", "Mt", 18, 9, "Y si tu ojo te induce a pecar, sacalo y arrojalo de ti. Mas te vale entrar en la vida con un solo ojo que con los dos ser arrojado a la gehenna del fuego."},
    {"Mateo", "Mt", 18, 10, "Cuidado con despreciar a uno de estos peque\177os, porque os digo que sus angeles estan viendo siempre en los cielos el rostro de mi Padre celestial."},
    {"Mateo", "Mt", 18, 11, "[Pues el Hijo del hombre ha venido a salvar lo que estaba perdido.]"},
    {"Mateo", "Mt", 18, 12, "Que os parece? Suponed que un hombre tiene cien ovejas: si una se le pierde, no deja las noventa y nueve en los montes y va en busca de la perdida?"},
    {"Mateo", "Mt", 18, 13, "Y si la encuentra, en verdad os digo que se alegra mas por ella que por las noventa y nueve que no se habian extraviado."},
    {"Mateo", "Mt", 18, 14, "Igualmente, no es voluntad de vuestro Padre que esta en el cielo que se pierda ni uno de estos peque\177os."},
    {"Mateo", "Mt", 18, 15, "Si tu hermano peca contra ti, reprendelo estando los dos a solas. Si te hace caso, has salvado a tu hermano."},
    {"Mateo", "Mt", 18, 16, "Si no te hace caso, llama a otro o a otros dos, para que todo el asunto quede confirmado por boca de dos o tres testigos."},
    {"Mateo", "Mt", 18, 17, "Si no les hace caso, diselo a la comunidad, y si no hace caso ni siquiera a la comunidad, consideralo como un pagano o un publicano."},
    {"Mateo", "Mt", 18, 18, "En verdad os digo que todo lo que ateis en la tierra quedara atado en los cielos, y todo lo que desateis en la tierra quedara desatado en los cielos."},
    {"Mateo", "Mt", 18, 19, "Os digo, ademas, que si dos de vosotros se ponen de acuerdo en la tierra para pedir algo, se lo dara mi Padre que esta en los cielos."},
    {"Mateo", "Mt", 18, 20, "Porque donde dos o tres estan reunidos en mi nombre, alli estoy yo en medio de ellos\"."},
    {"Mateo", "Mt", 18, 21, "Acercandose Pedro a Jesus le pregunto: \"Se\177or, si mi hermano me ofende, cuantas veces tengo que perdonarlo? Hasta siete veces?\"."},
    {"Mateo", "Mt", 18, 22, "Jesus le contesta: \"No te digo hasta siete veces, sino hasta setenta veces siete."},
    {"Mateo", "Mt", 18, 23, "Por esto, se parece el reino de los cielos a un rey que quiso ajustar las cuentas con sus criados."},
    {"Mateo", "Mt", 18, 24, "Al empezar a ajustarlas, le presentaron uno que debia diez mil talentos."},
    {"Mateo", "Mt", 18, 25, "Como no tenia con que pagar, el se\177or mando que lo vendieran a el con su mujer y sus hijos y todas sus posesiones, y que pagara asi."},
    {"Mateo", "Mt", 18, 26, "El criado, arrojandose a sus pies, le suplicaba diciendo: \"Ten paciencia conmigo y te lo pagare todo\"."},
    {"Mateo", "Mt", 18, 27, "Se compadecio el se\177or de aquel criado y lo dejo marchar, perdonandole la deuda."},
    {"Mateo", "Mt", 18, 28, "Pero al salir, el criado aquel encontro a uno de sus compa\177eros que le debia cien denarios y, agarrandolo, lo estrangulaba diciendo: \"Pagame lo que me debes\"."},
    {"Mateo", "Mt", 18, 29, "El compa\177ero, arrojandose a sus pies, le rogaba diciendo: \"Ten paciencia conmigo y te lo pagare\"."},
    {"Mateo", "Mt", 18, 30, "Pero el se nego y fue y lo metio en la carcel hasta que pagara lo que debia."},
    {"Mateo", "Mt", 18, 31, "Sus compa\177eros, al ver lo ocurrido, quedaron consternados y fueron a contarle a su se\177or todo lo sucedido."},
    {"Mateo", "Mt", 18, 32, "Entonces el se\177or lo llamo y le dijo: \"Siervo malvado! Toda aquella deuda te la perdone porque me lo rogaste."},
    {"Mateo", "Mt", 18, 33, "No debias tu tambien tener compasion de tu compa\177ero, como yo tuve compasion de ti?\"."},
    {"Mateo", "Mt", 18, 34, "Y el se\177or, indignado, lo entrego a los verdugos hasta que pagara toda la deuda."},
    {"Mateo", "Mt", 18, 35, "Lo mismo hara con vosotros mi Padre celestial, si cada cual no perdona de corazon a su hermano\"."},
    {"Mateo", "Mt", 19, 1, "Cuando acabo Jesus estos discursos, partio de Galilea y vino a la region de Judea, al otro lado del Jordan."},
    {"Mateo", "Mt", 19, 2, "Lo seguia una gran multitud y el los curaba alli."},
    {"Mateo", "Mt", 19, 3, "Se acercaron a Jesus unos fariseos y le preguntaron, para ponerlo a prueba: \"Es licito a un hombre repudiar a su mujer por cualquier motivo?\"."},
    {"Mateo", "Mt", 19, 4, "El les respondio: \"No habeis leido que el Creador, en el principio, los creo hombre y mujer,"},
    {"Mateo", "Mt", 19, 5, "y dijo: \"Por eso dejara el hombre a su padre y a su madre, y se unira a su mujer, y seran los dos una sola carne\"?"},
    {"Mateo", "Mt", 19, 6, "De modo que ya no son dos, sino una sola carne. Pues lo que Dios ha unido, que no lo separe el hombre\"."},
    {"Mateo", "Mt", 19, 7, "Ellos insistieron: \"Y por que mando Moises darle acta de divorcio y repudiarla?\"."},
    {"Mateo", "Mt", 19, 8, "El les contesto: \"Por la dureza de vuestro corazon os permitio Moises repudiar a vuestras mujeres; pero, al principio, no era asi."},
    {"Mateo", "Mt", 19, 9, "Pero yo os digo que, si uno repudia a su mujer -no hablo de union ilegitima- y se casa con otra, comete adulterio\"."},
    {"Mateo", "Mt", 19, 10, "Los discipulos le replicaron: \"Si esa es la situacion del hombre con la mujer, no trae cuenta casarse\"."},
    {"Mateo", "Mt", 19, 11, "Pero el les dijo: \"No todos entienden esto, solo los que han recibido ese don."},
    {"Mateo", "Mt", 19, 12, "Hay eunucos que salieron asi del vientre de su madre, a otros los hicieron los hombres, y hay quienes se hacen eunucos ellos mismos por el reino de los cielos. El que pueda entender, entienda\"."},
    {"Mateo", "Mt", 19, 13, "Entonces le presentaron unos ni\177os a Jesus para que les impusiera las manos y orase, pero los discipulos los rega\177aban."},
    {"Mateo", "Mt", 19, 14, "Jesus dijo: \"Dejadlos, no impidais a los ni\177os acercarse a mi; de los que son como ellos es el reino de los cielos\"."},
    {"Mateo", "Mt", 19, 15, "Les impuso las manos y se marcho de alli."},
    {"Mateo", "Mt", 19, 16, "Se acerco uno a Jesus y le pregunto: \"Maestro, que tengo que hacer de bueno para obtener la vida eterna?\"."},
    {"Mateo", "Mt", 19, 17, "Jesus le contesto: \"Por que me preguntas que es bueno? Uno solo es Bueno. Mira, si quieres entrar en la vida, guarda los mandamientos\"."},
    {"Mateo", "Mt", 19, 18, "El le pregunto: \"Cuales?\". Jesus le contesto: \"No mataras, no cometeras adulterio, no robaras, no daras falso testimonio,"},
    {"Mateo", "Mt", 19, 19, "honra a tu padre y a tu madre, y ama a tu projimo como a ti mismo\"."},
    {"Mateo", "Mt", 19, 20, "El joven le dijo: \"Todo eso lo he cumplido. Que me falta?\"."},
    {"Mateo", "Mt", 19, 21, "Jesus le contesto: \"Si quieres ser perfecto, anda, vende tus bienes, da el dinero a los pobres -asi tendras un tesoro en el cielo- y luego ven y sigueme\"."},
    {"Mateo", "Mt", 19, 22, "Al oir esto, el joven se fue triste, porque era muy rico."},
    {"Mateo", "Mt", 19, 23, "Entonces Jesus dijo a sus discipulos: \"En verdad os digo que dificilmente entrara un rico en el reino de los cielos."},
    {"Mateo", "Mt", 19, 24, "Lo repito: mas facil le es a un camello pasar por el ojo de una aguja, que a un rico entrar en el reino de los cielos\"."},
    {"Mateo", "Mt", 19, 25, "Al oirlo, los discipulos dijeron espantados: \"Entonces, quien puede salvarse?\"."},
    {"Mateo", "Mt", 19, 26, "Jesus se les quedo mirando y les dijo: \"Es imposible para los hombres, pero Dios lo puede todo\"."},
    {"Mateo", "Mt", 19, 27, "Entonces dijo Pedro a Jesus: \"Ya ves, nosotros lo hemos dejado todo y te hemos seguido; que nos va a tocar?\"."},
    {"Mateo", "Mt", 19, 28, "Jesus les dijo: \"En verdad os digo: cuando llegue la renovacion y el Hijo del hombre se siente en el trono de su gloria, tambien vosotros, los que me habeis seguido, os sentareis en doce tronos para juzgar a las doce tribus de Israel."},
    {"Mateo", "Mt", 19, 29, "Todo el que por mi deja casa, hermanos o hermanas, padre o madre, hijos o tierras, recibira cien veces mas y heredara la vida eterna."},
    {"Mateo", "Mt", 19, 30, "Pero muchos primeros seran ultimos y muchos ultimos primeros."},
    {"Mateo", "Mt", 20, 1, "Pues el reino de los cielos se parece a un propietario que al amanecer salio a contratar jornaleros para su vi\177a."},
    {"Mateo", "Mt", 20, 2, "Despues de ajustarse con ellos en un denario por jornada, los mando a la vi\177a."},
    {"Mateo", "Mt", 20, 3, "Salio otra vez a media ma\177ana, vio a otros que estaban en la plaza sin trabajo"},
    {"Mateo", "Mt", 20, 4, "y les dijo: \"Id tambien vosotros a mi vi\177a y os pagare lo debido\"."},
    {"Mateo", "Mt", 20, 5, "Ellos fueron. Salio de nuevo hacia mediodia y a media tarde, e hizo lo mismo."},
    {"Mateo", "Mt", 20, 6, "Salio al caer la tarde y encontro a otros, parados, y les dijo: \"Como es que estais aqui el dia entero sin trabajar?\"."},
    {"Mateo", "Mt", 20, 7, "Le respondieron: \"Nadie nos ha contratado\". El les dijo: \"Id tambien vosotros a mi vi\177a\"."},
    {"Mateo", "Mt", 20, 8, "Cuando oscurecio, el due\177o dijo al capataz: \"Llama a los jornaleros y pagales el jornal, empezando por los ultimos y acabando por los primeros\"."},
    {"Mateo", "Mt", 20, 9, "Vinieron los del atardecer y recibieron un denario cada uno."},
    {"Mateo", "Mt", 20, 10, "Cuando llegaron los primeros, pensaban que recibirian mas, pero ellos tambien recibieron un denario cada uno."},
    {"Mateo", "Mt", 20, 11, "Al recibirlo se pusieron a protestar contra el amo:"},
    {"Mateo", "Mt", 20, 12, "\"Estos ultimos han trabajado solo una hora y los has tratado igual que a nosotros, que hemos aguantado el peso del dia y el bochorno\"."},
    {"Mateo", "Mt", 20, 13, "El replico a uno de ellos: \"Amigo, no te hago ninguna injusticia. No nos ajustamos en un denario?"},
    {"Mateo", "Mt", 20, 14, "Toma lo tuyo y vete. Quiero darle a este ultimo igual que a ti."},
    {"Mateo", "Mt", 20, 15, "Es que no tengo libertad para hacer lo que quiera en mis asuntos? O vas a tener tu envidia porque yo soy bueno?\"."},
    {"Mateo", "Mt", 20, 16, "Asi, los ultimos seran primeros y los primeros, ultimos\"."},
    {"Mateo", "Mt", 20, 17, "Mientras iba subiendo Jesus a Jerusalen, tomando aparte a los Doce, les dijo por el camino:"},
    {"Mateo", "Mt", 20, 18, "\"Mirad, estamos subiendo a Jerusalen, y el Hijo del hombre va a ser entregado a los sumos sacerdotes y a los escribas, y lo condenaran a muerte"},
    {"Mateo", "Mt", 20, 19, "y lo entregaran a los gentiles, para que se burlen de el, lo azoten y lo crucifiquen; y al tercer dia resucitara\"."},
    {"Mateo", "Mt", 20, 20, "Entonces se le acerco la madre de los hijos de Zebedeo con sus hijos y se postro para hacerle una peticion."},
    {"Mateo", "Mt", 20, 21, "El le pregunto: \"Que deseas?\". Ella contesto: \"Ordena que estos dos hijos mios se sienten en tu reino, uno a tu derecha y el otro a tu izquierda\"."},
    {"Mateo", "Mt", 20, 22, "Pero Jesus replico: \"No sabeis lo que pedis. Podeis beber el caliz que yo he de beber?\". Contestaron: \"Podemos\"."},
    {"Mateo", "Mt", 20, 23, "El les dijo: \"Mi caliz lo bebereis; pero sentarse a mi derecha o a mi izquierda no me toca a mi concederlo, es para aquellos para quienes lo tiene reservado mi Padre\"."},
    {"Mateo", "Mt", 20, 24, "Los otros diez, al oir aquello, se indignaron contra los dos hermanos."},
    {"Mateo", "Mt", 20, 25, "Y llamandolos, Jesus les dijo: \"Sabeis que los jefes de los pueblos los tiranizan y que los grandes los oprimen."},
    {"Mateo", "Mt", 20, 26, "No sera asi entre vosotros: el que quiera ser grande entre vosotros, que sea vuestro servidor,"},
    {"Mateo", "Mt", 20, 27, "y el que quiera ser primero entre vosotros, que sea vuestro esclavo."},
    {"Mateo", "Mt", 20, 28, "Igual que el Hijo del hombre no ha venido a ser servido sino a servir y a dar su vida en rescate por muchos\"."},
    {"Mateo", "Mt", 20, 29, "Y al salir de Jerico le siguio una gran muchedumbre."},
    {"Mateo", "Mt", 20, 30, "Dos ciegos que estaban sentados al borde del camino oyeron que Jesus pasaba y se pusieron a gritar: \"Ten compasion de nosotros, Se\177or, Hijo de David!\"."},
    {"Mateo", "Mt", 20, 31, "La muchedumbre los increpo para que se callaran, pero ellos gritaban mas fuerte: \"Ten compasion de nosotros, Se\177or, Hijo de David!\"."},
    {"Mateo", "Mt", 20, 32, "Entonces Jesus se detuvo, los llamo y les dijo: \"Que quereis que os haga?\"."},
    {"Mateo", "Mt", 20, 33, "Le respondieron: \"Se\177or, que se abran nuestros ojos\"."},
    {"Mateo", "Mt", 20, 34, "Compadecido, Jesus les toco los ojos, y al punto recobraron la vista y lo siguieron."},
    {"Mateo", "Mt", 21, 1, "Cuando se acercaban a Jerusalen y llegaron a Betfage, en el monte de los Olivos, envio a dos discipulos"},
    {"Mateo", "Mt", 21, 2, "diciendoles: \"Id a la aldea de enfrente, encontrareis enseguida una borrica atada con su pollino, los desatais y me los traeis."},
    {"Mateo", "Mt", 21, 3, "Si alguien os dice algo, contestadle que el Se\177or los necesita y los devolvera pronto\"."},
    {"Mateo", "Mt", 21, 4, "Esto ocurrio para que se cumpliese lo dicho por medio del profeta:"},
    {"Mateo", "Mt", 21, 5, "\"Decid a la hija de Sion: \"Mira a tu rey, que viene a ti, humilde, montado en una borrica, en un pollino, hijo de acemila\"\"."},
    {"Mateo", "Mt", 21, 6, "Fueron los discipulos e hicieron lo que les habia mandado Jesus:"},
    {"Mateo", "Mt", 21, 7, "trajeron la borrica y el pollino, echaron encima sus mantos, y Jesus se monto."},
    {"Mateo", "Mt", 21, 8, "La multitud alfombro el camino con sus mantos; algunos cortaban ramas de arboles y alfombraban la calzada."},
    {"Mateo", "Mt", 21, 9, "Y la gente que iba delante y detras gritaba: \"Hosanna al Hijo de David! Bendito el que viene en nombre del Se\177or! Hosanna en las alturas!\"."},
    {"Mateo", "Mt", 21, 10, "Al entrar en Jerusalen, toda la ciudad se sobresalto preguntando: \"Quien es este?\"."},
    {"Mateo", "Mt", 21, 11, "La multitud contestaba: \"Es el profeta Jesus, de Nazaret de Galilea\"."},
    {"Mateo", "Mt", 21, 12, "Entro Jesus en el templo y echo fuera a todos los que vendian y compraban en el templo, volco las mesas de los cambistas y los puestos de los vendedores de palomas."},
    {"Mateo", "Mt", 21, 13, "Y les dijo: \"Esta escrito: \"Mi casa sera casa de oracion, pero vosotros la habeis hecho una cueva de bandidos\"\"."},
    {"Mateo", "Mt", 21, 14, "Se le acercaron en el templo ciegos y cojos, y los curo."},
    {"Mateo", "Mt", 21, 15, "Pero los sumos sacerdotes y los escribas, al ver los milagros que habia hecho y a los ni\177os que gritaban en el templo \"Hosanna al Hijo de David!\", se indignaron"},
    {"Mateo", "Mt", 21, 16, "y le dijeron: \"Oyes lo que dicen estos?\". Y Jesus les respondio: \"Si; no habeis leido nunca: \"De la boca de los peque\177uelos y de los ni\177os de pecho sacare una alabanza\"?\"."},
    {"Mateo", "Mt", 21, 17, "Y dejandolos salio de la ciudad, a Betania, donde paso la noche."},
    {"Mateo", "Mt", 21, 18, "De ma\177ana, camino de la ciudad, tuvo hambre."},
    {"Mateo", "Mt", 21, 19, "Viendo una higuera junto al camino se acerco, pero no encontro en ella nada mas que hojas y le dijo: \"Que nunca jamas brote fruto de ti!\". E inmediatamente se seco la higuera."},
    {"Mateo", "Mt", 21, 20, "Al verlo los discipulos se admiraron y decian: \"Como es que la higuera se ha secado de repente?\"."},
    {"Mateo", "Mt", 21, 21, "Jesus les dijo: \"En verdad os digo que si tuvierais fe y no vacilaseis, no solo hariais lo de la higuera, sino que diriais a este monte: \"Quitate y arrojate al mar\", y asi se realizaria."},
    {"Mateo", "Mt", 21, 22, "Todo lo que pidais orando con fe, lo recibireis\"."},
    {"Mateo", "Mt", 21, 23, "Jesus llego al templo y, mientras ense\177aba, se le acercaron los sumos sacerdotes y los ancianos del pueblo para preguntarle: \"Con que autoridad haces esto? Quien te ha dado semejante autoridad?\"."},
    {"Mateo", "Mt", 21, 24, "Jesus les replico: \"Os voy a hacer yo tambien una pregunta; si me la contestais, os dire yo tambien con que autoridad hago esto."},
    {"Mateo", "Mt", 21, 25, "El bautismo de Juan de donde venia, del cielo o de los hombres?\". Ellos se pusieron a deliberar: \"Si decimos \"del cielo\", nos dira: \"Por que no le habeis creido?\"."},
    {"Mateo", "Mt", 21, 26, "Si le decimos \"de los hombres\", tememos a la gente; porque todos tienen a Juan por profeta\"."},
    {"Mateo", "Mt", 21, 27, "Y respondieron a Jesus: \"No sabemos\". El, por su parte, les dijo: \"Pues tampoco yo os digo con que autoridad hago esto."},
    {"Mateo", "Mt", 21, 28, "Que os parece? Un hombre tenia dos hijos. Se acerco al primero y le dijo: \"Hijo, ve hoy a trabajar en la vi\177a\"."},
    {"Mateo", "Mt", 21, 29, "El le contesto: \"No quiero\". Pero despues se arrepintio y fue."},
    {"Mateo", "Mt", 21, 30, "Se acerco al segundo y le dijo lo mismo. El le contesto: \"Voy, se\177or\". Pero no fue."},
    {"Mateo", "Mt", 21, 31, "Quien de los dos cumplio la voluntad de su padre?\". Contestaron: \"El primero\". Jesus les dijo: \"En verdad os digo que los publicanos y las prostitutas van por delante de vosotros en el reino de Dios."},
    {"Mateo", "Mt", 21, 32, "Porque vino Juan a vosotros ense\177andoos el camino de la justicia y no le creisteis; en cambio, los publicanos y prostitutas le creyeron. Y, aun despues de ver esto, vosotros no os arrepentisteis ni le creisteis\"."},
    {"Mateo", "Mt", 21, 33, "Escuchad otra parabola: \"Habia un propietario que planto una vi\177a, la rodeo con una cerca, cavo en ella un lagar, construyo una torre, la arrendo a unos labradores y se marcho lejos."},
    {"Mateo", "Mt", 21, 34, "Llegado el tiempo de los frutos, envio sus criados a los labradores para percibir los frutos que le correspondian."},
    {"Mateo", "Mt", 21, 35, "Pero los labradores, agarrando a los criados, apalearon a uno, mataron a otro y a otro lo apedrearon."},
    {"Mateo", "Mt", 21, 36, "Envio de nuevo otros criados, mas que la primera vez, e hicieron con ellos lo mismo."},
    {"Mateo", "Mt", 21, 37, "Por ultimo, les mando a su hijo diciendose: \"Tendran respeto a mi hijo\"."},
    {"Mateo", "Mt", 21, 38, "Pero los labradores, al ver al hijo se dijeron: \"Este es el heredero: venid, lo matamos y nos quedamos con su herencia\"."},
    {"Mateo", "Mt", 21, 39, "Y agarrandolo, lo sacaron fuera de la vi\177a y lo mataron."},
    {"Mateo", "Mt", 21, 40, "Cuando vuelva el due\177o de la vi\177a, que hara con aquellos labradores?\"."},
    {"Mateo", "Mt", 21, 41, "Le contestan: \"Hara morir de mala muerte a esos malvados y arrendara la vi\177a a otros labradores que le entreguen los frutos a su tiempo\"."},
    {"Mateo", "Mt", 21, 42, "Y Jesus les dice: \"No habeis leido nunca en la Escritura: \"La piedra que desecharon los arquitectos es ahora la piedra angular. Es el Se\177or quien lo ha hecho, ha sido un milagro patente\"?"},
    {"Mateo", "Mt", 21, 43, "Por eso os digo que se os quitara a vosotros el reino de Dios y se dara a un pueblo que produzca sus frutos."},
    {"Mateo", "Mt", 21, 44, "Y el que cayere sobre esta piedra se destrozara, y a aquel sobre quien cayere, lo aplastara\"."},
    {"Mateo", "Mt", 21, 45, "Los sumos sacerdotes y los fariseos, al oir sus parabolas, comprendieron que hablaba de ellos."},
    {"Mateo", "Mt", 21, 46, "Y, aunque intentaban echarle mano, temieron a la gente, que lo tenia por profeta."},
    {"Mateo", "Mt", 22, 1, "Volvio a hablarles Jesus en parabolas, diciendo:"},
    {"Mateo", "Mt", 22, 2, "\"El reino de los cielos se parece a un rey que celebraba la boda de su hijo;"},
    {"Mateo", "Mt", 22, 3, "mando a sus criados para que llamaran a los convidados, pero no quisieron ir."},
    {"Mateo", "Mt", 22, 4, "Volvio a mandar otros criados encargandoles que dijeran a los convidados: \"Tengo preparado el banquete, he matado terneros y reses cebadas y todo esta a punto. Venid a la boda\"."},
    {"Mateo", "Mt", 22, 5, "Pero ellos no hicieron caso; uno se marcho a sus tierras, otro a sus negocios,"},
    {"Mateo", "Mt", 22, 6, "los demas agarraron a los criados y los maltrataron y los mataron."},
    {"Mateo", "Mt", 22, 7, "El rey monto en colera, envio sus tropas, que acabaron con aquellos asesinos y prendieron fuego a la ciudad."},
    {"Mateo", "Mt", 22, 8, "Luego dijo a sus criados: \"La boda esta preparada, pero los convidados no se la merecian."},
    {"Mateo", "Mt", 22, 9, "Id ahora a los cruces de los caminos y a todos los que encontreis, llamadlos a la boda\"."},
    {"Mateo", "Mt", 22, 10, "Los criados salieron a los caminos y reunieron a todos los que encontraron, malos y buenos. La sala del banquete se lleno de comensales."},
    {"Mateo", "Mt", 22, 11, "Cuando el rey entro a saludar a los comensales, reparo en uno que no llevaba traje de fiesta"},
    {"Mateo", "Mt", 22, 12, "y le dijo: \"Amigo, como has entrado aqui sin el vestido de boda?\". El otro no abrio la boca."},
    {"Mateo", "Mt", 22, 13, "Entonces el rey dijo a los servidores: \"Atadlo de pies y manos y arrojadlo fuera, a las tinieblas. Alli sera el llanto y el rechinar de dientes\"."},
    {"Mateo", "Mt", 22, 14, "Porque muchos son los llamados, pero pocos los elegidos\"."},
    {"Mateo", "Mt", 22, 15, "Entonces se retiraron los fariseos y llegaron a un acuerdo para comprometer a Jesus con una pregunta."},
    {"Mateo", "Mt", 22, 16, "Le enviaron algunos discipulos suyos, con unos herodianos, y le dijeron: \"Maestro, sabemos que eres sincero y que ense\177as el camino de Dios conforme a la verdad, sin que te importe nadie, porque no te fijas en apariencias."},
    {"Mateo", "Mt", 22, 17, "Dinos, pues, que opinas: es licito pagar impuesto al Cesar o no?\"."},
    {"Mateo", "Mt", 22, 18, "Comprendiendo su mala voluntad, les dijo Jesus: \"Hipocritas, por que me tentais?"},
    {"Mateo", "Mt", 22, 19, "Ense\177adme la moneda del impuesto\". Le presentaron un denario."},
    {"Mateo", "Mt", 22, 20, "El les pregunto: \"De quien son esta imagen y esta inscripcion?\"."},
    {"Mateo", "Mt", 22, 21, "Le respondieron: \"Del Cesar\". Entonces les replico: \"Pues dad al Cesar lo que es del Cesar y a Dios lo que es de Dios\"."},
    {"Mateo", "Mt", 22, 22, "Al oirlo se maravillaron y dejandolo se fueron."},
    {"Mateo", "Mt", 22, 23, "En aquella ocasion se le acercaron unos saduceos, los que dicen que no hay resurreccion, y le preguntaron:"},
    {"Mateo", "Mt", 22, 24, "\"Maestro, Moises mando que cuando uno muere sin hijos, su hermano se case con la viuda para dar descendencia a su hermano."},
    {"Mateo", "Mt", 22, 25, "Pues bien, habia entre nosotros siete hermanos. El primero se caso, murio sin hijos y dejo su mujer a su hermano."},
    {"Mateo", "Mt", 22, 26, "Lo mismo paso con el segundo y con el tercero hasta el septimo."},
    {"Mateo", "Mt", 22, 27, "Despues de todos murio la mujer."},
    {"Mateo", "Mt", 22, 28, "Cuando llegue la resurreccion, de cual de los siete sera mujer? Porque los siete han estado casados con ella\"."},
    {"Mateo", "Mt", 22, 29, "Les contesto Jesus: \"Estais equivocados porque no entendeis las Escrituras ni el poder de Dios."},
    {"Mateo", "Mt", 22, 30, "Cuando resuciten, ni los hombres se casaran ni las mujeres tomaran esposo; seran como angeles en el cielo."},
    {"Mateo", "Mt", 22, 31, "Y a proposito de la resurreccion de los muertos, no habeis leido lo que os dice Dios:"},
    {"Mateo", "Mt", 22, 32, "\"Yo soy el Dios de Abrahan y el Dios de Isaac y el Dios de Jacob\"? No es Dios de muertos, sino de vivos\"."},
    {"Mateo", "Mt", 22, 33, "Al oirlo la gente se admiraba de su ense\177anza."},
    {"Mateo", "Mt", 22, 34, "Los fariseos, al oir que habia hecho callar a los saduceos, se reunieron en un lugar"},
    {"Mateo", "Mt", 22, 35, "y uno de ellos, un doctor de la ley, le pregunto para ponerlo a prueba:"},
    {"Mateo", "Mt", 22, 36, "\"Maestro, cual es el mandamiento principal de la ley?\"."},
    {"Mateo", "Mt", 22, 37, "El le dijo: \"\"Amaras al Se\177or tu Dios con todo tu corazon, con toda tu alma, con toda tu mente\"."},
    {"Mateo", "Mt", 22, 38, "Este mandamiento es el principal y primero."},
    {"Mateo", "Mt", 22, 39, "El segundo es semejante a el: \"Amaras a tu projimo como a ti mismo\"."},
    {"Mateo", "Mt", 22, 40, "En estos dos mandamientos se sostienen toda la Ley y los Profetas\"."},
    {"Mateo", "Mt", 22, 41, "Estando reunidos los fariseos, les propuso Jesus una cuestion:"},
    {"Mateo", "Mt", 22, 42, "\"Que pensais acerca del Mesias? De quien es hijo?\". Le respondieron: \"De David\"."},
    {"Mateo", "Mt", 22, 43, "El les dijo: \"Como entonces David, movido por el Espiritu, lo llama Se\177or diciendo:"},
    {"Mateo", "Mt", 22, 44, "\"Dijo el Se\177or a mi Se\177or: sientate a mi derecha y hare de tus enemigos estrado de tus pies\"?"},
    {"Mateo", "Mt", 22, 45, "Si David lo llama Se\177or, como puede ser hijo suyo?\"."},
    {"Mateo", "Mt", 22, 46, "Y ninguno pudo responderle nada ni se atrevio nadie en adelante a plantearle mas cuestiones."},
    {"Mateo", "Mt", 23, 1, "Entonces Jesus hablo a la gente y a sus discipulos,"},
    {"Mateo", "Mt", 23, 2, "diciendo: \"En la catedra de Moises se han sentado los escribas y los fariseos:"},
    {"Mateo", "Mt", 23, 3, "haced y cumplid todo lo que os digan; pero no hagais lo que ellos hacen, porque ellos dicen, pero no hacen."},
    {"Mateo", "Mt", 23, 4, "Lian fardos pesados y se los cargan a la gente en los hombros, pero ellos no estan dispuestos a mover un dedo para empujar."},
    {"Mateo", "Mt", 23, 5, "Todo lo que hacen es para que los vea la gente: alargan las filacterias y agrandan las orlas del manto;"},
    {"Mateo", "Mt", 23, 6, "les gustan los primeros puestos en los banquetes y los asientos de honor en las sinagogas;"},
    {"Mateo", "Mt", 23, 7, "que les hagan reverencias en las plazas y que la gente los llame rabbi."},
    {"Mateo", "Mt", 23, 8, "Vosotros, en cambio, no os dejeis llamar rabbi, porque uno solo es vuestro maestro y todos vosotros sois hermanos."},
    {"Mateo", "Mt", 23, 9, "Y no llameis padre vuestro a nadie en la tierra, porque uno solo es vuestro Padre, el del cielo."},
    {"Mateo", "Mt", 23, 10, "No os dejeis llamar maestros, porque uno solo es vuestro maestro, el Mesias."},
    {"Mateo", "Mt", 23, 11, "El primero entre vosotros sera vuestro servidor."},
    {"Mateo", "Mt", 23, 12, "El que se enaltece sera humillado, y el que se humilla sera enaltecido\"."},
    {"Mateo", "Mt", 23, 13, "\"Ay de vosotros, escribas y fariseos hipocritas, que cerrais a los hombres el reino de los cielos! Ni entrais vosotros, ni dejais entrar a los que quieren."},
    {"Mateo", "Mt", 23, 14, "[Ay de vosotros, escribas y fariseos hipocritas, que devorais los bienes de las viudas con pretexto de largas oraciones! Vuestra sentencia sera por eso mas severa.]"},
    {"Mateo", "Mt", 23, 15, "Ay de vosotros, escribas y fariseos hipocritas, que viajais por tierra y mar para ganar un proselito, y cuando lo conseguis, lo haceis digno de la gehenna el doble que vosotros!"},
    {"Mateo", "Mt", 23, 16, "Ay de vosotros, guias ciegos, que decis: \"Jurar por el templo no obliga, jurar por el oro del templo si obliga\"!"},
    {"Mateo", "Mt", 23, 17, "Necios y ciegos! Que es mas, el oro o el templo que consagra el oro?"},
    {"Mateo", "Mt", 23, 18, "O tambien: \"Jurar por el altar no obliga, jurar por la ofrenda que esta en el altar si obliga\"."},
    {"Mateo", "Mt", 23, 19, "Ciegos! Que es mas, la ofrenda o el altar que consagra la ofrenda?"},
    {"Mateo", "Mt", 23, 20, "Quien jura por el altar, jura por el y por cuanto hay sobre el;"},
    {"Mateo", "Mt", 23, 21, "quien jura por el templo, jura por el y por quien habita en el;"},
    {"Mateo", "Mt", 23, 22, "y quien jura por el cielo, jura por el trono de Dios y tambien por el que esta sentado en el."},
    {"Mateo", "Mt", 23, 23, "Ay de vosotros, escribas y fariseos hipocritas, que pagais el diezmo de la menta, del anis y del comino, y descuidais lo mas grave de la ley: la justicia, la misericordia y la fidelidad! Esto es lo que habria que practicar, aunque sin descuidar aquello."},
    {"Mateo", "Mt", 23, 24, "Guias ciegos, que filtrais el mosquito y os tragais el camello!"},
    {"Mateo", "Mt", 23, 25, "Ay de vosotros, escribas y fariseos hipocritas, que limpiais por fuera la copa y el plato, mientras por dentro estais rebosando de robo y desenfreno!"},
    {"Mateo", "Mt", 23, 26, "Fariseo ciego!, limpia primero la copa por dentro y asi quedara limpia tambien por fuera."},
    {"Mateo", "Mt", 23, 27, "Ay de vosotros, escribas y fariseos hipocritas, que os pareceis a los sepulcros blanqueados! Por fuera tienen buena apariencia, pero por dentro estan llenos de huesos de muertos y de podredumbre;"},
    {"Mateo", "Mt", 23, 28, "lo mismo vosotros: por fuera pareceis justos, pero por dentro estais repletos de hipocresia y crueldad."},
    {"Mateo", "Mt", 23, 29, "Ay de vosotros, escribas y fariseos hipocritas, que edificais sepulcros a los profetas y ornamentais los mausoleos de los justos,"},
    {"Mateo", "Mt", 23, 30, "diciendo: \"Si hubieramos vivido en tiempo de nuestros padres, no habriamos sido complices suyos en el asesinato de los profetas\"!"},
    {"Mateo", "Mt", 23, 31, "Con esto atestiguais en vuestra contra, que sois hijos de los que asesinaron a los profetas."},
    {"Mateo", "Mt", 23, 32, "Colmad tambien vosotros la medida de vuestros padres!"},
    {"Mateo", "Mt", 23, 33, "Serpientes, raza de viboras! Como escapareis del juicio de la gehenna?"},
    {"Mateo", "Mt", 23, 34, "Mirad, yo os envio profetas y sabios y escribas. A unos los matareis y crucificareis, a otros los azotareis en vuestras sinagogas y los perseguireis de ciudad en ciudad."},
    {"Mateo", "Mt", 23, 35, "Asi recaera sobre vosotros toda la sangre inocente derramada sobre la tierra, desde la sangre de Abel el justo hasta la sangre de Zacarias, hijo de Baraquias, a quien matasteis entre el santuario y el altar."},
    {"Mateo", "Mt", 23, 36, "En verdad os digo, todas estas cosas caeran sobre esta generacion\"."},
    {"Mateo", "Mt", 23, 37, "\"Jerusalen, Jerusalen!, que matas a los profetas y apedreas a quienes te han sido enviados, cuantas veces intente reunir a tus hijos, como la gallina reune a los polluelos bajo sus alas, y no habeis querido."},
    {"Mateo", "Mt", 23, 38, "Pues bien, vuestra casa va a quedar desierta."},
    {"Mateo", "Mt", 23, 39, "Os digo que a partir de ahora no me vereis hasta que digais: Bendito el que viene en nombre del Se\177or!\"."},
    {"Mateo", "Mt", 24, 1, "Cuando salio Jesus del templo y caminaba, se le acercaron sus discipulos, que le se\177alaron las edificaciones del templo,"},
    {"Mateo", "Mt", 24, 2, "y el les dijo: \"Veis todo esto? En verdad os digo que sera destruido sin que quede alli piedra sobre piedra\"."},
    {"Mateo", "Mt", 24, 3, "Estaba sentado en el monte de los Olivos y se le acercaron los discipulos en privado y le dijeron: \"Cuando sucederan estas cosas y cual sera el signo de tu venida y del fin de los tiempos?\"."},
    {"Mateo", "Mt", 24, 4, "Jesus les respondio y dijo: \"Estad atentos a que nadie os enga\177e,"},
    {"Mateo", "Mt", 24, 5, "porque vendran muchos en mi nombre, diciendo: \"Yo soy el Mesias\", y enga\177aran a muchos."},
    {"Mateo", "Mt", 24, 6, "Vais a oir hablar de guerras y noticias de guerra. Cuidado, no os alarmeis, porque todo esto ha de suceder, pero todavia no es el final."},
    {"Mateo", "Mt", 24, 7, "Se levantara pueblo contra pueblo y reino contra reino, habra hambre, epidemias y terremotos en diversos lugares;"},
    {"Mateo", "Mt", 24, 8, "todo esto sera el comienzo de los dolores."},
    {"Mateo", "Mt", 24, 9, "Os entregaran al suplicio y os mataran, y por mi causa os odiaran todos los pueblos."},
    {"Mateo", "Mt", 24, 10, "Entonces muchos se escandalizaran y se traicionaran mutuamente, y se odiaran unos a otros."},
    {"Mateo", "Mt", 24, 11, "Apareceran muchos falsos profetas y enga\177aran a mucha gente,"},
    {"Mateo", "Mt", 24, 12, "y, al crecer la maldad, se enfriara el amor en la mayoria;"},
    {"Mateo", "Mt", 24, 13, "pero el que persevere hasta el final se salvara."},
    {"Mateo", "Mt", 24, 14, "Y se anunciara el evangelio del reino en todo el mundo como testimonio para todas las gentes, y entonces vendra el fin."},
    {"Mateo", "Mt", 24, 15, "Cuando veais la abominacion de la desolacion, anunciada por el profeta Daniel, erigida en el lugar santo (el que lee que entienda),"},
    {"Mateo", "Mt", 24, 16, "entonces los que vivan en Judea huyan a los montes,"},
    {"Mateo", "Mt", 24, 17, "el que este en la azotea no baje a recoger nada en casa"},
    {"Mateo", "Mt", 24, 18, "y el que este en el campo no vuelva a recoger el manto."},
    {"Mateo", "Mt", 24, 19, "Ay de las que esten encintas o criando en aquellos dias!"},
    {"Mateo", "Mt", 24, 20, "Orad para que la huida no suceda en invierno o en sabado."},
    {"Mateo", "Mt", 24, 21, "Porque habra una gran tribulacion como jamas ha sucedido desde el principio del mundo hasta hoy, ni la volvera a haber."},
    {"Mateo", "Mt", 24, 22, "Y si no se acortan aquellos dias, nadie podra salvarse. Pero en atencion a los elegidos se abreviaran aquellos dias."},
    {"Mateo", "Mt", 24, 23, "Y si alguno entonces os dice: \"El Mesias esta aqui o alli\", no le creais,"},
    {"Mateo", "Mt", 24, 24, "porque surgiran falsos mesias y falsos profetas, y haran signos y portentos para enga\177ar, si fuera posible, incluso a los elegidos."},
    {"Mateo", "Mt", 24, 25, "Os he prevenido."},
    {"Mateo", "Mt", 24, 26, "Si os dicen: \"Esta en el desierto\", no salgais; \"En los aposentos\", no les creais."},
    {"Mateo", "Mt", 24, 27, "Pues como el relampago aparece en el oriente y brilla hasta el occidente, asi sera la venida del Hijo del hombre."},
    {"Mateo", "Mt", 24, 28, "Donde esta el cadaver, alli se reuniran los buitres."},
    {"Mateo", "Mt", 24, 29, "Inmediatamente despues de la angustia de aquellos dias, el sol se oscurecera, la luna perdera su resplandor, las estrellas caeran del cielo y los astros se tambalearan."},
    {"Mateo", "Mt", 24, 30, "Entonces aparecera en el cielo el signo del Hijo del hombre. Todas las razas del mundo haran duelo y veran venir al Hijo del hombre sobre las nubes del cielo con gran poder y gloria."},
    {"Mateo", "Mt", 24, 31, "Enviara a sus angeles con un gran toque de trompeta y reuniran a sus elegidos de los cuatro vientos, de un extremo al otro del cielo."},
    {"Mateo", "Mt", 24, 32, "Aprended de esta parabola de la higuera: cuando las ramas se ponen tiernas y brotan las yemas, deducis que el verano esta cerca;"},
    {"Mateo", "Mt", 24, 33, "pues cuando veais todas estas cosas, sabed que el esta cerca, a la puerta."},
    {"Mateo", "Mt", 24, 34, "En verdad os digo que no pasara esta generacion sin que todo suceda."},
    {"Mateo", "Mt", 24, 35, "El cielo y la tierra pasaran, pero mis palabras no pasaran."},
    {"Mateo", "Mt", 24, 36, "En cuanto al dia y la hora, nadie lo conoce, ni los angeles de los cielos ni el Hijo, sino solo el Padre."},
    {"Mateo", "Mt", 24, 37, "Cuando venga el Hijo del hombre, pasara como en tiempo de Noe."},
    {"Mateo", "Mt", 24, 38, "En los dias antes del diluvio, la gente comia y bebia, se casaban los hombres y las mujeres tomaban esposo, hasta el dia en que Noe entro en el arca;"},
    {"Mateo", "Mt", 24, 39, "y cuando menos lo esperaban llego el diluvio y se los llevo a todos; lo mismo sucedera cuando venga el Hijo del hombre:"},
    {"Mateo", "Mt", 24, 40, "dos hombres estaran en el campo, a uno se lo llevaran y a otro lo dejaran;"},
    {"Mateo", "Mt", 24, 41, "dos mujeres estaran moliendo, a una se la llevaran y a otra la dejaran."},
    {"Mateo", "Mt", 24, 42, "Por tanto, estad en vela, porque no sabeis que dia vendra vuestro Se\177or."},
    {"Mateo", "Mt", 24, 43, "Comprended que si supiera el due\177o de casa a que hora de la noche viene el ladron, estaria en vela y no dejaria que abrieran un boquete en su casa."},
    {"Mateo", "Mt", 24, 44, "Por eso, estad tambien vosotros preparados, porque a la hora que menos penseis viene el Hijo del hombre."},
    {"Mateo", "Mt", 24, 45, "Quien es el criado fiel y prudente, a quien el se\177or encarga de dar a la servidumbre la comida a sus horas?"},
    {"Mateo", "Mt", 24, 46, "Bienaventurado ese criado, si el se\177or, al llegar, lo encuentra portandose asi."},
    {"Mateo", "Mt", 24, 47, "En verdad os digo que le confiara la administracion de todos sus bienes."},
    {"Mateo", "Mt", 24, 48, "Pero si dijere aquel mal siervo para sus adentros: \"Mi se\177or tarda en llegar\","},
    {"Mateo", "Mt", 24, 49, "y empieza a pegar a sus compa\177eros, y a comer y a beber con los borrachos,"},
    {"Mateo", "Mt", 24, 50, "el dia y la hora que menos se lo espera, llegara el amo"},
    {"Mateo", "Mt", 24, 51, "y lo castigara con rigor y le hara compartir la suerte de los hipocritas. Alli sera el llanto y el rechinar de dientes."},
    {"Mateo", "Mt", 25, 1, "Entonces se parecera el reino de los cielos a diez virgenes que tomaron sus lamparas y salieron al encuentro del esposo."},
    {"Mateo", "Mt", 25, 2, "Cinco de ellas eran necias y cinco eran prudentes."},
    {"Mateo", "Mt", 25, 3, "Las necias, al tomar las lamparas, no se proveyeron de aceite;"},
    {"Mateo", "Mt", 25, 4, "en cambio, las prudentes se llevaron alcuzas de aceite con las lamparas."},
    {"Mateo", "Mt", 25, 5, "El esposo tardaba, les entro sue\177o a todas y se durmieron."},
    {"Mateo", "Mt", 25, 6, "A medianoche se oyo una voz: \"Que llega el esposo, salid a su encuentro!\"."},
    {"Mateo", "Mt", 25, 7, "Entonces se despertaron todas aquellas virgenes y se pusieron a preparar sus lamparas."},
    {"Mateo", "Mt", 25, 8, "Y las necias dijeron a las prudentes: \"Dadnos de vuestro aceite, que se nos apagan las lamparas\"."},
    {"Mateo", "Mt", 25, 9, "Pero las prudentes contestaron: \"Por si acaso no hay bastante para vosotras y nosotras, mejor es que vayais a la tienda y os lo compreis\"."},
    {"Mateo", "Mt", 25, 10, "Mientras iban a comprarlo, llego el esposo, y las que estaban preparadas entraron con el al banquete de bodas, y se cerro la puerta."},
    {"Mateo", "Mt", 25, 11, "Mas tarde llegaron tambien las otras virgenes, diciendo: \"Se\177or, se\177or, abrenos\"."},
    {"Mateo", "Mt", 25, 12, "Pero el respondio: \"En verdad os digo que no os conozco\"."},
    {"Mateo", "Mt", 25, 13, "Por tanto, velad, porque no sabeis el dia ni la hora\"."},
    {"Mateo", "Mt", 25, 14, "\"Es como un hombre que, al irse de viaje, llamo a sus siervos y los dejo al cargo de sus bienes:"},
    {"Mateo", "Mt", 25, 15, "a uno le dejo cinco talentos, a otro dos, a otro uno, a cada cual segun su capacidad; luego se marcho."},
    {"Mateo", "Mt", 25, 16, "El que recibio cinco talentos fue enseguida a negociar con ellos y gano otros cinco."},
    {"Mateo", "Mt", 25, 17, "El que recibio dos hizo lo mismo y gano otros dos."},
    {"Mateo", "Mt", 25, 18, "En cambio, el que recibio uno fue a hacer un hoyo en la tierra y escondio el dinero de su se\177or."},
    {"Mateo", "Mt", 25, 19, "Al cabo de mucho tiempo viene el se\177or de aquellos siervos y se pone a ajustar las cuentas con ellos."},
    {"Mateo", "Mt", 25, 20, "Se acerco el que habia recibido cinco talentos y le presento otros cinco, diciendo: \"Se\177or, cinco talentos me dejaste; mira, he ganado otros cinco\"."},
    {"Mateo", "Mt", 25, 21, "Su se\177or le dijo: \"Bien, siervo bueno y fiel; como has sido fiel en lo poco, te dare un cargo importante; entra en el gozo de tu se\177or\"."},
    {"Mateo", "Mt", 25, 22, "Se acerco luego el que habia recibido dos talentos y dijo: \"Se\177or, dos talentos me dejaste; mira, he ganado otros dos\"."},
    {"Mateo", "Mt", 25, 23, "Su se\177or le dijo: \"Bien, siervo bueno y fiel!; como has sido fiel en lo poco, te dare un cargo importante; entra en el gozo de tu se\177or\"."},
    {"Mateo", "Mt", 25, 24, "Se acerco tambien el que habia recibido un talento y dijo: \"Se\177or, sabia que eres exigente, que siegas donde no siembras y recoges donde no esparces,"},
    {"Mateo", "Mt", 25, 25, "tuve miedo y fui a esconder tu talento bajo tierra. Aqui tienes lo tuyo\"."},
    {"Mateo", "Mt", 25, 26, "El se\177or le respondio: \"Eres un siervo negligente y holgazan. Con que sabias que siego donde no siembro y recojo donde no esparzo?"},
    {"Mateo", "Mt", 25, 27, "Pues debias haber puesto mi dinero en el banco, para que, al volver yo, pudiera recoger lo mio con los intereses."},
    {"Mateo", "Mt", 25, 28, "Quitadle el talento y dadselo al que tiene diez."},
    {"Mateo", "Mt", 25, 29, "Porque al que tiene se le dara y le sobrara, pero al que no tiene, se le quitara hasta lo que tiene."},
    {"Mateo", "Mt", 25, 30, "Y a ese siervo inutil echadlo fuera, a las tinieblas; alli sera el llanto y el rechinar de dientes\"\"."},
    {"Mateo", "Mt", 25, 31, "\"Cuando venga en su gloria el Hijo del hombre, y todos los angeles con el, se sentara en el trono de su gloria"},
    {"Mateo", "Mt", 25, 32, "y seran reunidas ante el todas las naciones. El separara a unos de otros, como un pastor separa las ovejas de las cabras."},
    {"Mateo", "Mt", 25, 33, "Y pondra las ovejas a su derecha y las cabras a su izquierda."},
    {"Mateo", "Mt", 25, 34, "Entonces dira el rey a los de su derecha: \"Venid vosotros, benditos de mi Padre; heredad el reino preparado para vosotros desde la creacion del mundo."},
    {"Mateo", "Mt", 25, 35, "Porque tuve hambre y me disteis de comer, tuve sed y me disteis de beber, fui forastero y me hospedasteis,"},
    {"Mateo", "Mt", 25, 36, "estuve desnudo y me vestisteis, enfermo y me visitasteis, en la carcel y vinisteis a verme\"."},
    {"Mateo", "Mt", 25, 37, "Entonces los justos le contestaran: \"Se\177or, cuando te vimos con hambre y te alimentamos, o con sed y te dimos de beber?;"},
    {"Mateo", "Mt", 25, 38, "cuando te vimos forastero y te hospedamos, o desnudo y te vestimos?;"},
    {"Mateo", "Mt", 25, 39, "cuando te vimos enfermo o en la carcel y fuimos a verte?\"."},
    {"Mateo", "Mt", 25, 40, "Y el rey les dira: \"En verdad os digo que cada vez que lo hicisteis con uno de estos, mis hermanos mas peque\177os, conmigo lo hicisteis\"."},
    {"Mateo", "Mt", 25, 41, "Entonces dira a los de su izquierda: \"Apartaos de mi, malditos, id al fuego eterno preparado para el diablo y sus angeles."},
    {"Mateo", "Mt", 25, 42, "Porque tuve hambre y no me disteis de comer, tuve sed y no me disteis de beber,"},
    {"Mateo", "Mt", 25, 43, "fui forastero y no me hospedasteis, estuve desnudo y no me vestisteis, enfermo y en la carcel y no me visitasteis\"."},
    {"Mateo", "Mt", 25, 44, "Entonces tambien estos contestaran: \"Se\177or, cuando te vimos con hambre o con sed, o forastero o desnudo, o enfermo o en la carcel, y no te asistimos?\"."},
    {"Mateo", "Mt", 25, 45, "El les replicara: \"En verdad os digo: lo que no hicisteis con uno de estos, los mas peque\177os, tampoco lo hicisteis conmigo\"."},
    {"Mateo", "Mt", 25, 46, "Y estos iran al castigo eterno y los justos a la vida eterna\"."},
    {"Mateo", "Mt", 26, 1, "Cuando acabo Jesus todos estos discursos, dijo a sus discipulos:"},
    {"Mateo", "Mt", 26, 2, "\"Sabeis que dentro de dos dias se celebra la Pascua y el Hijo del hombre va a ser entregado para ser crucificado\"."},
    {"Mateo", "Mt", 26, 3, "Entonces se reunieron los sumos sacerdotes y los ancianos del pueblo en la casa del sumo sacerdote, llamado Caifas,"},
    {"Mateo", "Mt", 26, 4, "y se pusieron de acuerdo para prender a Jesus a traicion y darle muerte."},
    {"Mateo", "Mt", 26, 5, "Pero decian: \"Durante la fiesta no, para que no se ocasione un tumulto entre el pueblo\"."},
    {"Mateo", "Mt", 26, 6, "Hallandose Jesus en Betania, en casa de Simon, el leproso,"},
    {"Mateo", "Mt", 26, 7, "se le acerco una mujer llevando un frasco de alabastro con perfume muy caro y lo derramo sobre su cabeza mientras estaba a la mesa."},
    {"Mateo", "Mt", 26, 8, "Al verlo los discipulos se indignaron y dijeron: \"A que viene este derroche?"},
    {"Mateo", "Mt", 26, 9, "Esto se podia haber vendido muy caro y haber dado el producto a los pobres\"."},
    {"Mateo", "Mt", 26, 10, "Dandose cuenta Jesus les dijo: \"Por que molestais a la mujer? Ha hecho conmigo una obra buena."},
    {"Mateo", "Mt", 26, 11, "Porque a los pobres los teneis siempre con vosotros, pero a mi no me teneis siempre."},
    {"Mateo", "Mt", 26, 12, "Al derramar el perfume sobre mi cuerpo, estaba preparando mi sepultura."},
    {"Mateo", "Mt", 26, 13, "En verdad os digo que en cualquier parte del mundo donde se proclame este Evangelio se hablara tambien de lo que esta ha hecho, para memoria suya\"."},
    {"Mateo", "Mt", 26, 14, "Entonces uno de los Doce, llamado Judas Iscariote, fue a los sumos sacerdotes"},
    {"Mateo", "Mt", 26, 15, "y les propuso: \"Que estais dispuestos a darme si os lo entrego?\". Ellos se ajustaron con el en treinta monedas de plata."},
    {"Mateo", "Mt", 26, 16, "Y desde entonces andaba buscando ocasion propicia para entregarlo."},
    {"Mateo", "Mt", 26, 17, "El primer dia de los Acimos se acercaron los discipulos a Jesus y le preguntaron: \"Donde quieres que te preparemos la cena de Pascua?\"."},
    {"Mateo", "Mt", 26, 18, "El contesto: \"Id a la ciudad, a casa de quien vosotros sabeis, y decidle: \"El Maestro dice: mi hora esta cerca; voy a celebrar la Pascua en tu casa con mis discipulos\"\"."},
    {"Mateo", "Mt", 26, 19, "Los discipulos cumplieron las instrucciones de Jesus y prepararon la Pascua."},
    {"Mateo", "Mt", 26, 20, "Al atardecer se puso a la mesa con los Doce."},
    {"Mateo", "Mt", 26, 21, "Mientras comian dijo: \"En verdad os digo que uno de vosotros me va a entregar\"."},
    {"Mateo", "Mt", 26, 22, "Ellos, muy entristecidos, se pusieron a preguntarle uno tras otro: \"Soy yo acaso, Se\177or?\"."},
    {"Mateo", "Mt", 26, 23, "El respondio: \"El que ha metido conmigo la mano en la fuente, ese me va a entregar."},
    {"Mateo", "Mt", 26, 24, "El Hijo del hombre se va como esta escrito de el; pero, ay de aquel por quien el Hijo del hombre es entregado!, mas le valdria a ese hombre no haber nacido!\"."},
    {"Mateo", "Mt", 26, 25, "Entonces pregunto Judas, el que lo iba a entregar: \"Soy yo acaso, Maestro?\". El respondio: \"Tu lo has dicho\"."},
    {"Mateo", "Mt", 26, 26, "Mientras comian, Jesus tomo pan y, despues de pronunciar la bendicion, lo partio, lo dio a los discipulos y les dijo: \"Tomad, comed: esto es mi cuerpo\"."},
    {"Mateo", "Mt", 26, 27, "Despues tomo el caliz, pronuncio la accion de gracias y dijo: \"Bebed todos;"},
    {"Mateo", "Mt", 26, 28, "porque esta es mi sangre de la alianza, que es derramada por muchos para el perdon de los pecados."},
    {"Mateo", "Mt", 26, 29, "Y os digo que desde ahora ya no bebere del fruto de la vid hasta el dia que beba con vosotros el vino nuevo en el reino de mi Padre\"."},
    {"Mateo", "Mt", 26, 30, "Despues de cantar el himno salieron para el monte de los Olivos."},
    {"Mateo", "Mt", 26, 31, "Entonces Jesus les dijo: \"Esta noche os vais a escandalizar todos por mi causa, porque esta escrito: \"Herire al pastor y se dispersaran las ovejas del reba\177o\"."},
    {"Mateo", "Mt", 26, 32, "Pero cuando resucite, ire delante de vosotros a Galilea\"."},
    {"Mateo", "Mt", 26, 33, "Pedro replico: \"Aunque todos caigan por tu causa, yo jamas caere\"."},
    {"Mateo", "Mt", 26, 34, "Jesus le dijo: \"En verdad te digo que esta noche, antes de que el gallo cante, me negaras tres veces\"."},
    {"Mateo", "Mt", 26, 35, "Pedro le replico: \"Aunque tenga que morir contigo, no te negare\". Y lo mismo decian los demas discipulos."},
    {"Mateo", "Mt", 26, 36, "Entonces Jesus fue con ellos a un huerto, llamado Getsemani, y dijo a los discipulos: \"Sentaos aqui, mientras voy alla a orar\"."},
    {"Mateo", "Mt", 26, 37, "Y llevandose a Pedro y a los dos hijos de Zebedeo, empezo a sentir tristeza y angustia."},
    {"Mateo", "Mt", 26, 38, "Entonces les dijo: \"Mi alma esta triste hasta la muerte; quedaos aqui y velad conmigo\"."},
    {"Mateo", "Mt", 26, 39, "Y adelantandose un poco cayo rostro en tierra y oraba diciendo: \"Padre mio, si es posible, que pase de mi este caliz. Pero no se haga como yo quiero, sino como quieres tu\"."},
    {"Mateo", "Mt", 26, 40, "Y volvio a los discipulos y los encontro dormidos. Dijo a Pedro: \"No habeis podido velar una hora conmigo?"},
    {"Mateo", "Mt", 26, 41, "Velad y orad para no caer en la tentacion, pues el espiritu esta pronto, pero la carne es debil\"."},
    {"Mateo", "Mt", 26, 42, "De nuevo se aparto por segunda vez y oraba diciendo: \"Padre mio, si este caliz no puede pasar sin que yo lo beba, hagase tu voluntad\"."},
    {"Mateo", "Mt", 26, 43, "Y viniendo otra vez, los encontro dormidos, porque sus ojos se cerraban de sue\177o."},
    {"Mateo", "Mt", 26, 44, "Dejandolos de nuevo, por tercera vez oraba repitiendo las mismas palabras."},
    {"Mateo", "Mt", 26, 45, "Volvio a los discipulos, los encontro dormidos y les dijo: \"Ya podeis dormir y descansar. Mirad, esta cerca la hora y el Hijo del hombre va a ser entregado en manos de los pecadores."},
    {"Mateo", "Mt", 26, 46, "Levantaos, vamos! Ya esta cerca el que me entrega\"."},
    {"Mateo", "Mt", 26, 47, "Todavia estaba hablando, cuando aparecio Judas, uno de los Doce, acompa\177ado de un tropel de gente, con espadas y palos, enviado por los sumos sacerdotes y los ancianos del pueblo."},
    {"Mateo", "Mt", 26, 48, "El traidor les habia dado esta contrase\177a: \"Al que yo bese, ese es: prendedlo\"."},
    {"Mateo", "Mt", 26, 49, "Despues se acerco a Jesus y le dijo: \"Salve, Maestro!\". Y lo beso."},
    {"Mateo", "Mt", 26, 50, "Pero Jesus le contesto: \"Amigo, a que vienes?\". Entonces se acercaron a Jesus y le echaron mano y lo prendieron."},
    {"Mateo", "Mt", 26, 51, "Uno de los que estaban con el agarro la espada, la desenvaino y de un tajo le corto la oreja al criado del sumo sacerdote."},
    {"Mateo", "Mt", 26, 52, "Jesus le dijo: \"Envaina la espada: que todos los que empu\177an espada, a espada moriran."},
    {"Mateo", "Mt", 26, 53, "Piensas tu que no puedo acudir a mi Padre? El me mandaria enseguida mas de doce legiones de angeles."},
    {"Mateo", "Mt", 26, 54, "Como se cumplirian entonces las Escrituras que dicen que esto tiene que pasar?\"."},
    {"Mateo", "Mt", 26, 55, "Entonces dijo Jesus a la gente: \"Habeis salido a prenderme con espadas y palos como si fuera un bandido? A diario me sentaba en el templo a ense\177ar y, sin embargo, no me prendisteis."},
    {"Mateo", "Mt", 26, 56, "Pero todo esto ha sucedido para que se cumplieran las Escrituras de los profetas\". En aquel momento todos los discipulos lo abandonaron y huyeron."},
    {"Mateo", "Mt", 26, 57, "Los que prendieron a Jesus lo condujeron a casa de Caifas, el sumo sacerdote, donde se habian reunido los escribas y los ancianos."},
    {"Mateo", "Mt", 26, 58, "Pedro lo seguia de lejos hasta el palacio del sumo sacerdote y, entrando dentro, se sento con los criados para ver como terminaba aquello."},
    {"Mateo", "Mt", 26, 59, "Los sumos sacerdotes y el Sanedrin en pleno buscaban un falso testimonio contra Jesus para condenarlo a muerte"},
    {"Mateo", "Mt", 26, 60, "y no lo encontraban, a pesar de los muchos falsos testigos que comparecian. Finalmente, comparecieron dos"},
    {"Mateo", "Mt", 26, 61, "que declararon: \"Este ha dicho: \"Puedo destruir el templo de Dios y reconstruirlo en tres dias\"\"."},
    {"Mateo", "Mt", 26, 62, "El sumo sacerdote se puso en pie y le dijo: \"No tienes nada que responder? Que son estos cargos que presentan contra ti?\"."},
    {"Mateo", "Mt", 26, 63, "Pero Jesus callaba. Y el sumo sacerdote le dijo: \"Te conjuro por el Dios vivo a que nos digas si tu eres el Mesias, el Hijo de Dios\"."},
    {"Mateo", "Mt", 26, 64, "Jesus le respondio: \"Tu lo has dicho. Mas aun, yo os digo: desde ahora vereis al Hijo del hombre sentado a la derecha del Poder y que viene sobre las nubes del cielo\"."},
    {"Mateo", "Mt", 26, 65, "Entonces el sumo sacerdote rasgo sus vestiduras diciendo: \"Ha blasfemado. Que necesidad tenemos ya de testigos? Acabais de oir la blasfemia."},
    {"Mateo", "Mt", 26, 66, "Que decidis?\". Y ellos contestaron: \"Es reo de muerte\"."},
    {"Mateo", "Mt", 26, 67, "Entonces le escupieron a la cara y lo abofetearon; otros lo golpearon"},
    {"Mateo", "Mt", 26, 68, "diciendo: \"Haz de profeta, Mesias; dinos quien te ha pegado\"."},
    {"Mateo", "Mt", 26, 69, "Pedro estaba sentado fuera en el patio y se le acerco una criada y le dijo: \"Tambien tu estabas con Jesus el Galileo\"."},
    {"Mateo", "Mt", 26, 70, "El lo nego delante de todos diciendo: \"No se que quieres decir\"."},
    {"Mateo", "Mt", 26, 71, "Y al salir al portal lo vio otra y dijo a los que estaban alli: \"Este estaba con Jesus el Nazareno\"."},
    {"Mateo", "Mt", 26, 72, "Otra vez nego el con juramento: \"No conozco a ese hombre\"."},
    {"Mateo", "Mt", 26, 73, "Poco despues se acercaron los que estaban alli y dijeron a Pedro: \"Seguro; tu tambien eres de ellos, tu acento te delata\"."},
    {"Mateo", "Mt", 26, 74, "Entonces el se puso a echar maldiciones y a jurar diciendo: \"No conozco a ese hombre\". Y enseguida canto un gallo."},
    {"Mateo", "Mt", 26, 75, "Pedro se acordo de aquellas palabras de Jesus: \"Antes de que cante el gallo me negaras tres veces\". Y saliendo afuera, lloro amargamente."},
    {"Mateo", "Mt", 27, 1, "Al hacerse de dia, todos los sumos sacerdotes y los ancianos del pueblo se reunieron para preparar la condena a muerte de Jesus."},
    {"Mateo", "Mt", 27, 2, "Y atandolo lo llevaron y lo entregaron a Pilato, el gobernador."},
    {"Mateo", "Mt", 27, 3, "Entonces Judas, el traidor, viendo que lo habian condenado, se arrepintio y devolvio las treinta monedas de plata a los sumos sacerdotes y ancianos"},
    {"Mateo", "Mt", 27, 4, "diciendo: \"He pecado entregando sangre inocente\". Pero ellos dijeron: \"A nosotros que? Alla tu!\"."},
    {"Mateo", "Mt", 27, 5, "El, arrojando las monedas de plata en el templo, se marcho; y fue y se ahorco."},
    {"Mateo", "Mt", 27, 6, "Los sacerdotes, recogiendo las monedas de plata, dijeron: \"No es licito echarlas en el arca de las ofrendas porque son precio de sangre\"."},
    {"Mateo", "Mt", 27, 7, "Y, despues de discutirlo, compraron con ellas el Campo del Alfarero para cementerio de forasteros."},
    {"Mateo", "Mt", 27, 8, "Por eso aquel campo se llama todavia \"Campo de Sangre\"."},
    {"Mateo", "Mt", 27, 9, "Asi se cumplio lo dicho por medio del profeta Jeremias: \"Y tomaron las treinta monedas de plata, el precio de uno que fue tasado, segun la tasa de los hijos de Israel,"},
    {"Mateo", "Mt", 27, 10, "y pagaron con ellas el Campo del Alfarero, como me lo habia ordenado el Se\177or\"."},
    {"Mateo", "Mt", 27, 11, "Jesus fue llevado ante el gobernador, y el gobernador le pregunto: \"Eres tu el rey de los judios?\". Jesus respondio: \"Tu lo dices\"."},
    {"Mateo", "Mt", 27, 12, "Y mientras lo acusaban los sumos sacerdotes y los ancianos no contestaba nada."},
    {"Mateo", "Mt", 27, 13, "Entonces Pilato le pregunto: \"No oyes cuantos cargos presentan contra ti?\"."},
    {"Mateo", "Mt", 27, 14, "Como no contestaba a ninguna pregunta, el gobernador estaba muy extra\177ado."},
    {"Mateo", "Mt", 27, 15, "Por la fiesta, el gobernador solia liberar un preso, el que la gente quisiera."},
    {"Mateo", "Mt", 27, 16, "Tenia entonces un preso famoso, llamado Barrabas."},
    {"Mateo", "Mt", 27, 17, "Cuando la gente acudio, dijo Pilato: \"A quien quereis que os suelte, a Barrabas o a Jesus, a quien llaman el Mesias?\"."},
    {"Mateo", "Mt", 27, 18, "Pues sabia que se lo habian entregado por envidia."},
    {"Mateo", "Mt", 27, 19, "Y mientras estaba sentado en el tribunal, su mujer le mando a decir: \"No te metas con ese justo porque esta noche he sufrido mucho so\177ando con el\"."},
    {"Mateo", "Mt", 27, 20, "Pero los sumos sacerdotes y los ancianos convencieron a la gente para que pidieran la libertad de Barrabas y la muerte de Jesus."},
    {"Mateo", "Mt", 27, 21, "El gobernador pregunto: \"A cual de los dos quereis que os suelte?\". Ellos dijeron: \"A Barrabas\"."},
    {"Mateo", "Mt", 27, 22, "Pilato les pregunto: \"Y que hago con Jesus, llamado el Mesias?\". Contestaron todos: \"Sea crucificado\"."},
    {"Mateo", "Mt", 27, 23, "Pilato insistio: \"Pues, que mal ha hecho?\". Pero ellos gritaban mas fuerte: \"Sea crucificado!\"."},
    {"Mateo", "Mt", 27, 24, "Al ver Pilato que todo era inutil y que, al contrario, se estaba formando un tumulto, tomo agua y se lavo las manos ante la gente, diciendo: \"Soy inocente de esta sangre. Alla vosotros!\"."},
    {"Mateo", "Mt", 27, 25, "Todo el pueblo contesto: \"Caiga su sangre sobre nosotros y sobre nuestros hijos!\"."},
    {"Mateo", "Mt", 27, 26, "Entonces les solto a Barrabas; y a Jesus, despues de azotarlo, lo entrego para que lo crucificaran."},
    {"Mateo", "Mt", 27, 27, "Entonces los soldados del gobernador se llevaron a Jesus al pretorio y reunieron alrededor de el a toda la cohorte:"},
    {"Mateo", "Mt", 27, 28, "lo desnudaron y le pusieron un manto de color purpura"},
    {"Mateo", "Mt", 27, 29, "y trenzando una corona de espinas se la ci\177eron a la cabeza y le pusieron una ca\177a en la mano derecha. Y doblando ante el la rodilla, se burlaban de el diciendo: \"Salve, rey de los judios!\"."},
    {"Mateo", "Mt", 27, 30, "Luego le escupian, le quitaban la ca\177a y le golpeaban con ella la cabeza."},
    {"Mateo", "Mt", 27, 31, "Y terminada la burla, le quitaron el manto, le pusieron su ropa y lo llevaron a crucificar."},
    {"Mateo", "Mt", 27, 32, "Al salir, encontraron a un hombre de Cirene, llamado Simon, y lo forzaron a llevar su cruz."},
    {"Mateo", "Mt", 27, 33, "Cuando llegaron al lugar llamado Golgota (que quiere decir lugar de \"la Calavera\"),"},
    {"Mateo", "Mt", 27, 34, "le dieron a beber vino mezclado con hiel; el lo probo, pero no quiso beberlo."},
    {"Mateo", "Mt", 27, 35, "Despues de crucificarlo, se repartieron su ropa echandola a suertes"},
    {"Mateo", "Mt", 27, 36, "y luego se sentaron a custodiarlo."},
    {"Mateo", "Mt", 27, 37, "Encima de la cabeza colocaron un letrero con la acusacion: \"Este es Jesus, el rey de los judios\"."},
    {"Mateo", "Mt", 27, 38, "Crucificaron con el a dos bandidos, uno a la derecha y otro a la izquierda."},
    {"Mateo", "Mt", 27, 39, "Los que pasaban, lo injuriaban, y meneando la cabeza,"},
    {"Mateo", "Mt", 27, 40, "decian: \"Tu que destruyes el templo y lo reconstruyes en tres dias, salvate a ti mismo; si eres Hijo de Dios, baja de la cruz\"."},
    {"Mateo", "Mt", 27, 41, "Igualmente los sumos sacerdotes con los escribas y los ancianos se burlaban tambien diciendo:"},
    {"Mateo", "Mt", 27, 42, "\"A otros ha salvado y el no se puede salvar. Es el Rey de Israel!, que baje ahora de la cruz y le creeremos."},
    {"Mateo", "Mt", 27, 43, "Confio en Dios, que lo libre si es que lo ama, pues dijo: \"Soy Hijo de Dios\"\"."},
    {"Mateo", "Mt", 27, 44, "De la misma manera los bandidos que estaban crucificados con el lo insultaban."},
    {"Mateo", "Mt", 27, 45, "Desde la hora sexta hasta la hora nona vinieron tinieblas sobre toda la tierra."},
    {"Mateo", "Mt", 27, 46, "A la hora nona, Jesus grito con voz potente: Eli, Eli, lema sabaqtani (es decir: \"Dios mio, Dios mio, por que me has abandonado?\")."},
    {"Mateo", "Mt", 27, 47, "Al oirlo algunos de los que estaban alli dijeron: \"Esta llamando a Elias\"."},
    {"Mateo", "Mt", 27, 48, "Enseguida uno de ellos fue corriendo, cogio una esponja empapada en vinagre y, sujetandola en una ca\177a, le dio de beber."},
    {"Mateo", "Mt", 27, 49, "Los demas decian: \"Dejalo, a ver si viene Elias a salvarlo\"."},
    {"Mateo", "Mt", 27, 50, "Jesus, gritando de nuevo con voz potente, exhalo el espiritu."},
    {"Mateo", "Mt", 27, 51, "Entonces el velo del templo se rasgo en dos de arriba abajo; la tierra temblo, las rocas se resquebrajaron,"},
    {"Mateo", "Mt", 27, 52, "las tumbas se abrieron y muchos cuerpos de santos que habian muerto resucitaron"},
    {"Mateo", "Mt", 27, 53, "y, saliendo de las tumbas despues que el resucito, entraron en la ciudad santa y se aparecieron a muchos."},
    {"Mateo", "Mt", 27, 54, "El centurion y sus hombres, que custodiaban a Jesus, al ver el terremoto y lo que pasaba, dijeron aterrorizados: \"Verdaderamente este era Hijo de Dios\"."},
    {"Mateo", "Mt", 27, 55, "Habia alli muchas mujeres que miraban desde lejos, aquellas que habian seguido a Jesus desde Galilea para servirlo;"},
    {"Mateo", "Mt", 27, 56, "entre ellas, Maria la Magdalena y Maria, la madre de Santiago y Jose, y la madre de los hijos de Zebedeo."},
    {"Mateo", "Mt", 27, 57, "Al anochecer llego un hombre rico de Arimatea, llamado Jose, que era tambien discipulo de Jesus."},
    {"Mateo", "Mt", 27, 58, "Este acudio a Pilato a pedirle el cuerpo de Jesus. Y Pilato mando que se lo entregaran."},
    {"Mateo", "Mt", 27, 59, "Jose, tomando el cuerpo de Jesus, lo envolvio en una sabana limpia,"},
    {"Mateo", "Mt", 27, 60, "lo puso en su sepulcro nuevo que se habia excavado en la roca, rodo una piedra grande a la entrada del sepulcro y se marcho."},
    {"Mateo", "Mt", 27, 61, "Maria la Magdalena y la otra Maria se quedaron alli sentadas enfrente del sepulcro."},
    {"Mateo", "Mt", 27, 62, "A la ma\177ana siguiente, pasado el dia de la Preparacion, acudieron en grupo los sumos sacerdotes y los fariseos a Pilato"},
    {"Mateo", "Mt", 27, 63, "y le dijeron: \"Se\177or, nos hemos acordado de que aquel impostor estando en vida anuncio: \"A los tres dias resucitare\"."},
    {"Mateo", "Mt", 27, 64, "Por eso ordena que vigilen el sepulcro hasta el tercer dia, no sea que vayan sus discipulos, se lleven el cuerpo y digan al pueblo: \"Ha resucitado de entre los muertos\". La ultima impostura seria peor que la primera\"."},
    {"Mateo", "Mt", 27, 65, "Pilato contesto: \"Ahi teneis la guardia: id vosotros y asegurad la vigilancia como sabeis\"."},
    {"Mateo", "Mt", 27, 66, "Ellos aseguraron el sepulcro, sellando la piedra y colocando la guardia."},
    {"Mateo", "Mt", 28, 1, "Pasado el sabado, al alborear el primer dia de la semana, fueron Maria la Magdalena y la otra Maria a ver el sepulcro."},
    {"Mateo", "Mt", 28, 2, "Y de pronto temblo fuertemente la tierra, pues un angel del Se\177or, bajando del cielo y acercandose, corrio la piedra y se sento encima."},
    {"Mateo", "Mt", 28, 3, "Su aspecto era de relampago y su vestido blanco como la nieve;"},
    {"Mateo", "Mt", 28, 4, "los centinelas temblaron de miedo y quedaron como muertos."},
    {"Mateo", "Mt", 28, 5, "El angel hablo a las mujeres: \"Vosotras no temais, ya se que buscais a Jesus el crucificado."},
    {"Mateo", "Mt", 28, 6, "No esta aqui: ha resucitado!, como habia dicho. Venid a ver el sitio donde yacia"},
    {"Mateo", "Mt", 28, 7, "e id aprisa a decir a sus discipulos: \"Ha resucitado de entre los muertos y va por delante de vosotros a Galilea. Alli lo vereis\". Mirad, os lo he anunciado\"."},
    {"Mateo", "Mt", 28, 8, "Ellas se marcharon a toda prisa del sepulcro; llenas de miedo y de alegria corrieron a anunciarlo a los discipulos."},
    {"Mateo", "Mt", 28, 9, "De pronto, Jesus les salio al encuentro y les dijo: \"Alegraos\". Ellas se acercaron, le abrazaron los pies y se postraron ante el."},
    {"Mateo", "Mt", 28, 10, "Jesus les dijo: \"No temais: id a comunicar a mis hermanos que vayan a Galilea; alli me veran\"."},
    {"Mateo", "Mt", 28, 11, "Mientras las mujeres iban de camino, algunos de la guardia fueron a la ciudad y comunicaron a los sumos sacerdotes todo lo ocurrido."},
    {"Mateo", "Mt", 28, 12, "Ellos, reunidos con los ancianos, llegaron a un acuerdo y dieron a los soldados una fuerte suma,"},
    {"Mateo", "Mt", 28, 13, "encargandoles: \"Decid que sus discipulos fueron de noche y robaron el cuerpo mientras vosotros dormiais."},
    {"Mateo", "Mt", 28, 14, "Y si esto llega a oidos del gobernador, nosotros nos lo ganaremos y os sacaremos de apuros\"."},
    {"Mateo", "Mt", 28, 15, "Ellos tomaron el dinero y obraron conforme a las instrucciones. Y esta historia se ha ido difundiendo entre los judios hasta hoy."},
    {"Mateo", "Mt", 28, 16, "Los once discipulos se fueron a Galilea, al monte que Jesus les habia indicado."},
    {"Mateo", "Mt", 28, 17, "Al verlo, ellos se postraron, pero algunos dudaron."},
    {"Mateo", "Mt", 28, 18, "Acercandose a ellos, Jesus les dijo: \"Se me ha dado todo poder en el cielo y en la tierra."},
    {"Mateo", "Mt", 28, 19, "Id, pues, y haced discipulos a todos los pueblos, bautizandolos en el nombre del Padre y del Hijo y del Espiritu Santo;"},
    {"Mateo", "Mt", 28, 20, "ense\177andoles a guardar todo lo que os he mandado. Y sabed que yo estoy con vosotros todos los dias, hasta el final de los tiempos\"."},
    {"Marcos", "Mc", 1, 1, "Comienzo del Evangelio de Jesucristo, Hijo de Dios."},
    {"Marcos", "Mc", 1, 2, "Como esta escrito en el profeta Isaias: \"Yo envio a mi mensajero delante de ti, el cual preparara tu camino;"},
    {"Marcos", "Mc", 1, 3, "voz del que grita en el desierto: \"Preparad el camino del Se\177or, enderezad sus senderos\"\";"},
    {"Marcos", "Mc", 1, 4, "se presento Juan en el desierto bautizando y predicando un bautismo de conversion para el perdon de los pecados."},
    {"Marcos", "Mc", 1, 5, "Acudia a el toda la region de Judea y toda la gente de Jerusalen. El los bautizaba en el rio Jordan y confesaban sus pecados."},
    {"Marcos", "Mc", 1, 6, "Juan iba vestido de piel de camello, con una correa de cuero a la cintura y se alimentaba de saltamontes y miel silvestre."},
    {"Marcos", "Mc", 1, 7, "Y proclamaba: \"Detras de mi viene el que es mas fuerte que yo y no merezco agacharme para desatarle la correa de sus sandalias."},
    {"Marcos", "Mc", 1, 8, "Yo os he bautizado con agua, pero el os bautizara con Espiritu Santo\"."},
    {"Marcos", "Mc", 1, 9, "Y sucedio que por aquellos dias llego Jesus desde Nazaret de Galilea y fue bautizado por Juan en el Jordan."},
    {"Marcos", "Mc", 1, 10, "Apenas salio del agua, vio rasgarse los cielos y al Espiritu que bajaba hacia el como una paloma."},
    {"Marcos", "Mc", 1, 11, "Se oyo una voz desde los cielos: \"Tu eres mi Hijo amado, en ti me complazco\"."},
    {"Marcos", "Mc", 1, 12, "A continuacion, el Espiritu lo empujo al desierto."},
    {"Marcos", "Mc", 1, 13, "Se quedo en el desierto cuarenta dias, siendo tentado por Satanas; vivia con las fieras y los angeles lo servian."},
    {"Marcos", "Mc", 1, 14, "Despues de que Juan fue entregado, Jesus se marcho a Galilea a proclamar el Evangelio de Dios;"},
    {"Marcos", "Mc", 1, 15, "decia: \"Se ha cumplido el tiempo y esta cerca el reino de Dios. Convertios y creed en el Evangelio\"."},
    {"Marcos", "Mc", 1, 16, "Pasando junto al mar de Galilea, vio a Simon y a Andres, el hermano de Simon, echando las redes en el mar, pues eran pescadores."},
    {"Marcos", "Mc", 1, 17, "Jesus les dijo: \"Venid en pos de mi y os hare pescadores de hombres\"."},
    {"Marcos", "Mc", 1, 18, "Inmediatamente dejaron las redes y lo siguieron."},
    {"Marcos", "Mc", 1, 19, "Un poco mas adelante vio a Santiago, el de Zebedeo, y a su hermano Juan, que estaban en la barca repasando las redes."},
    {"Marcos", "Mc", 1, 20, "A continuacion los llamo, dejaron a su padre Zebedeo en la barca con los jornaleros y se marcharon en pos de el."},
    {"Marcos", "Mc", 1, 21, "Y entran en Cafarnaun y, al sabado siguiente, entra en la sinagoga a ense\177ar;"},
    {"Marcos", "Mc", 1, 22, "estaban asombrados de su ense\177anza, porque les ense\177aba con autoridad y no como los escribas."},
    {"Marcos", "Mc", 1, 23, "Habia precisamente en su sinagoga un hombre que tenia un espiritu inmundo y se puso a gritar:"},
    {"Marcos", "Mc", 1, 24, "\"Que tenemos que ver nosotros contigo, Jesus Nazareno? Has venido a acabar con nosotros? Se quien eres: el Santo de Dios\"."},
    {"Marcos", "Mc", 1, 25, "Jesus lo increpo: \"Callate y sal de el!\"."},
    {"Marcos", "Mc", 1, 26, "El espiritu inmundo lo retorcio violentamente y, dando un grito muy fuerte, salio de el."},
    {"Marcos", "Mc", 1, 27, "Todos se preguntaron estupefactos: \"Que es esto? Una ense\177anza nueva expuesta con autoridad. Incluso manda a los espiritus inmundos y lo obedecen\"."},
    {"Marcos", "Mc", 1, 28, "Su fama se extendio enseguida por todas partes, alcanzando la comarca entera de Galilea."},
    {"Marcos", "Mc", 1, 29, "Y enseguida, al salir ellos de la sinagoga, fue con Santiago y Juan a la casa de Simon y Andres."},
    {"Marcos", "Mc", 1, 30, "La suegra de Simon estaba en cama con fiebre, e inmediatamente le hablaron de ella."},
    {"Marcos", "Mc", 1, 31, "El se acerco, la cogio de la mano y la levanto. Se le paso la fiebre y se puso a servirles."},
    {"Marcos", "Mc", 1, 32, "Al anochecer, cuando se puso el sol, le llevaron todos los enfermos y endemoniados."},
    {"Marcos", "Mc", 1, 33, "La poblacion entera se agolpaba a la puerta."},
    {"Marcos", "Mc", 1, 34, "Curo a muchos enfermos de diversos males y expulso muchos demonios; y como los demonios lo conocian, no les permitia hablar."},
    {"Marcos", "Mc", 1, 35, "Se levanto de madrugada, cuando todavia estaba muy oscuro, se marcho a un lugar solitario y alli se puso a orar."},
    {"Marcos", "Mc", 1, 36, "Simon y sus compa\177eros fueron en su busca y,"},
    {"Marcos", "Mc", 1, 37, "al encontrarlo, le dijeron: \"Todo el mundo te busca\"."},
    {"Marcos", "Mc", 1, 38, "El les responde: \"Vamonos a otra parte, a las aldeas cercanas, para predicar tambien alli; que para eso he salido\"."},
    {"Marcos", "Mc", 1, 39, "Asi recorrio toda Galilea, predicando en sus sinagogas y expulsando los demonios."},
    {"Marcos", "Mc", 1, 40, "Se le acerca un leproso, suplicandole de rodillas: \"Si quieres, puedes limpiarme\"."},
    {"Marcos", "Mc", 1, 41, "Compadecido, extendio la mano y lo toco diciendo: \"Quiero: queda limpio\"."},
    {"Marcos", "Mc", 1, 42, "La lepra se le quito inmediatamente y quedo limpio."},
    {"Marcos", "Mc", 1, 43, "El lo despidio, encargandole severamente:"},
    {"Marcos", "Mc", 1, 44, "\"No se lo digas a nadie; pero para que conste, ve a presentarte al sacerdote y ofrece por tu purificacion lo que mando Moises, para que les sirva de testimonio\"."},
    {"Marcos", "Mc", 1, 45, "Pero cuando se fue, empezo a pregonar bien alto y a divulgar el hecho, de modo que Jesus ya no podia entrar abiertamente en ningun pueblo; se quedaba fuera, en lugares solitarios; y aun asi acudian a el de todas partes."},
    {"Marcos", "Mc", 2, 1, "Cuando a los pocos dias volvio Jesus a Cafarnaun, se supo que estaba en casa."},
    {"Marcos", "Mc", 2, 2, "Acudieron tantos que no quedaba sitio ni a la puerta. Y les proponia la palabra."},
    {"Marcos", "Mc", 2, 3, "Y vinieron trayendole un paralitico llevado entre cuatro"},
    {"Marcos", "Mc", 2, 4, "y, como no podian presentarselo por el gentio, levantaron la techumbre encima de donde el estaba, abrieron un boquete y descolgaron la camilla donde yacia el paralitico."},
    {"Marcos", "Mc", 2, 5, "Viendo Jesus la fe que tenian, le dice al paralitico: \"Hijo, tus pecados te son perdonados\"."},
    {"Marcos", "Mc", 2, 6, "Unos escribas, que estaban alli sentados, pensaban para sus adentros:"},
    {"Marcos", "Mc", 2, 7, "\"Por que habla este asi? Blasfema. Quien puede perdonar pecados, sino solo uno, Dios?\"."},
    {"Marcos", "Mc", 2, 8, "Jesus se dio cuenta enseguida de lo que pensaban y les dijo: \"Por que pensais eso?"},
    {"Marcos", "Mc", 2, 9, "Que es mas facil, decir al paralitico: \"Tus pecados te son perdonados\", o decir: \"Levantate, coge la camilla y echa a andar\"?"},
    {"Marcos", "Mc", 2, 10, "Pues, para que veais que el Hijo del hombre tiene autoridad en la tierra para perdonar pecados -dice al paralitico-:"},
    {"Marcos", "Mc", 2, 11, "\"Te digo: levantate, coge tu camilla y vete a tu casa\"\"."},
    {"Marcos", "Mc", 2, 12, "Se levanto, cogio inmediatamente la camilla y salio a la vista de todos. Se quedaron atonitos y daban gloria a Dios, diciendo: \"Nunca hemos visto una cosa igual\"."},
    {"Marcos", "Mc", 2, 13, "Salio de nuevo a la orilla del mar; toda la gente acudia a el y les ense\177aba."},
    {"Marcos", "Mc", 2, 14, "Al pasar vio a Levi, el de Alfeo, sentado al mostrador de los impuestos, y le dice: \"Sigueme\". Se levanto y lo siguio."},
    {"Marcos", "Mc", 2, 15, "Sucedio que, mientras estaba el sentado a la mesa en casa de Levi, muchos publicanos y pecadores se sentaban con Jesus y sus discipulos, pues eran ya muchos los que lo seguian."},
    {"Marcos", "Mc", 2, 16, "Los escribas de los fariseos, al ver que comia con pecadores y publicanos, decian a sus discipulos: \"Por que come con publicanos y pecadores?\"."},
    {"Marcos", "Mc", 2, 17, "Jesus lo oyo y les dijo: \"No necesitan medico los sanos, sino los enfermos. No he venido a llamar a justos, sino a pecadores\"."},
    {"Marcos", "Mc", 2, 18, "Como los discipulos de Juan y los fariseos estaban ayunando, vinieron unos y le preguntaron a Jesus: \"Los discipulos de Juan y los discipulos de los fariseos ayunan. Por que los tuyos no?\"."},
    {"Marcos", "Mc", 2, 19, "Jesus les contesta: \"Es que pueden ayunar los amigos del esposo, mientras el esposo esta con ellos? Mientras el esposo esta con ellos, no pueden ayunar."},
    {"Marcos", "Mc", 2, 20, "Llegaran dias en que les arrebataran al esposo, y entonces ayunaran en aquel dia."},
    {"Marcos", "Mc", 2, 21, "Nadie echa un remiendo de pa\177o sin remojar a un manto pasado; porque la pieza tira del manto -lo nuevo de lo viejo- y deja un roto peor."},
    {"Marcos", "Mc", 2, 22, "Tampoco se echa vino nuevo en odres viejos; porque el vino revienta los odres, y se pierden el vino y los odres; a vino nuevo, odres nuevos\"."},
    {"Marcos", "Mc", 2, 23, "Sucedio que un sabado atravesaba el un sembrado, y sus discipulos, mientras caminaban, iban arrancando espigas."},
    {"Marcos", "Mc", 2, 24, "Los fariseos le preguntan: \"Mira, por que hacen en sabado lo que no esta permitido?\"."},
    {"Marcos", "Mc", 2, 25, "El les responde: \"No habeis leido nunca lo que hizo David, cuando el y sus hombres se vieron faltos y con hambre,"},
    {"Marcos", "Mc", 2, 26, "como entro en la casa de Dios, en tiempo del sumo sacerdote Abiatar, comio de los panes de la proposicion, que solo esta permitido comer a los sacerdotes, y se los dio tambien a quienes estaban con el?\"."},
    {"Marcos", "Mc", 2, 27, "Y les decia: \"El sabado se hizo para el hombre y no el hombre para el sabado;"},
    {"Marcos", "Mc", 2, 28, "asi que el Hijo del hombre es se\177or tambien del sabado\"."},
    {"Marcos", "Mc", 3, 1, "Entro otra vez en la sinagoga y habia alli un hombre que tenia una mano paralizada."},
    {"Marcos", "Mc", 3, 2, "Lo estaban observando, para ver si lo curaba en sabado y acusarlo."},
    {"Marcos", "Mc", 3, 3, "Entonces le dice al hombre que tenia la mano paralizada: \"Levantate y ponte ahi en medio\"."},
    {"Marcos", "Mc", 3, 4, "Y a ellos les pregunta: \"Que esta permitido en sabado?, hacer lo bueno o lo malo?, salvarle la vida a un hombre o dejarlo morir?\". Ellos callaban."},
    {"Marcos", "Mc", 3, 5, "Echando en torno una mirada de ira y dolido por la dureza de su corazon, dice al hombre: \"Extiende la mano\". La extendio y su mano quedo restablecida."},
    {"Marcos", "Mc", 3, 6, "En cuanto salieron, los fariseos se confabularon con los herodianos para acabar con el."},
    {"Marcos", "Mc", 3, 7, "Jesus se retiro con sus discipulos a la orilla del mar y lo siguio una gran muchedumbre de Galilea."},
    {"Marcos", "Mc", 3, 8, "Al enterarse de las cosas que hacia, acudia mucha gente de Judea, Jerusalen, Idumea, Transjordania y cercanias de Tiro y Sidon."},
    {"Marcos", "Mc", 3, 9, "Encargo a sus discipulos que le tuviesen preparada una barca, no lo fuera a estrujar el gentio."},
    {"Marcos", "Mc", 3, 10, "Como habia curado a muchos, todos los que sufrian de algo se le echaban encima para tocarlo."},
    {"Marcos", "Mc", 3, 11, "Los espiritus inmundos, cuando lo veian, se postraban ante el y gritaban: \"Tu eres el Hijo de Dios\"."},
    {"Marcos", "Mc", 3, 12, "Pero el les prohibia severamente que lo diesen a conocer."},
    {"Marcos", "Mc", 3, 13, "Jesus subio al monte, llamo a los que quiso y se fueron con el."},
    {"Marcos", "Mc", 3, 14, "E instituyo doce para que estuvieran con el y para enviarlos a predicar,"},
    {"Marcos", "Mc", 3, 15, "y que tuvieran autoridad para expulsar a los demonios:"},
    {"Marcos", "Mc", 3, 16, "Simon, a quien puso el nombre de Pedro,"},
    {"Marcos", "Mc", 3, 17, "Santiago el de Zebedeo, y Juan, el hermano de Santiago, a quienes puso el nombre de Boanerges, es decir, los hijos del trueno,"},
    {"Marcos", "Mc", 3, 18, "Andres, Felipe, Bartolome, Mateo, Tomas, Santiago el de Alfeo, Tadeo, Simon el de Cana"},
    {"Marcos", "Mc", 3, 19, "y Judas Iscariote, el que lo entrego."},
    {"Marcos", "Mc", 3, 20, "Llega a casa y de nuevo se junta tanta gente que no los dejaban ni comer."},
    {"Marcos", "Mc", 3, 21, "Al enterarse su familia, vinieron a llevarselo, porque se decia que estaba fuera de si."},
    {"Marcos", "Mc", 3, 22, "Y los escribas que habian bajado de Jerusalen decian: \"Tiene dentro a Belzebu y expulsa a los demonios con el poder del jefe de los demonios\"."},
    {"Marcos", "Mc", 3, 23, "El los invito a acercarse y les hablaba en parabolas: \"Como va a echar Satanas a Satanas?"},
    {"Marcos", "Mc", 3, 24, "Un reino dividido internamente no puede subsistir;"},
    {"Marcos", "Mc", 3, 25, "una familia dividida no puede subsistir."},
    {"Marcos", "Mc", 3, 26, "Si Satanas se rebela contra si mismo, para hacerse la guerra, no puede subsistir, esta perdido."},
    {"Marcos", "Mc", 3, 27, "Nadie puede meterse en casa de un hombre forzudo para arramblar con su ajuar, si primero no lo ata; entonces podra arramblar con la casa."},
    {"Marcos", "Mc", 3, 28, "En verdad os digo, todo se les podra perdonar a los hombres: los pecados y cualquier blasfemia que digan;"},
    {"Marcos", "Mc", 3, 29, "pero el que blasfeme contra el Espiritu Santo no tendra perdon jamas, cargara con su pecado para siempre\"."},
    {"Marcos", "Mc", 3, 30, "Se referia a los que decian que tenia dentro un espiritu inmundo."},
    {"Marcos", "Mc", 3, 31, "Llegan su madre y sus hermanos y, desde fuera, lo mandaron llamar."},
    {"Marcos", "Mc", 3, 32, "La gente que tenia sentada alrededor le dice: \"Mira, tu madre y tus hermanos y tus hermanas estan fuera y te buscan\"."},
    {"Marcos", "Mc", 3, 33, "El les pregunta: \"Quienes son mi madre y mis hermanos?\"."},
    {"Marcos", "Mc", 3, 34, "Y mirando a los que estaban sentados alrededor, dice: \"Estos son mi madre y mis hermanos."},
    {"Marcos", "Mc", 3, 35, "El que haga la voluntad de Dios, ese es mi hermano y mi hermana y mi madre\"."},
    {"Marcos", "Mc", 4, 1, "Jesus se puso a ense\177ar otra vez junto al mar. Acudio un gentio tan enorme, que tuvo que subirse a una barca y, ya en el mar, se sento; y el gentio se quedo en tierra junto al mar."},
    {"Marcos", "Mc", 4, 2, "Les ense\177aba muchas cosas con parabolas y les decia instruyendolos:"},
    {"Marcos", "Mc", 4, 3, "\"Escuchad: salio el sembrador a sembrar;"},
    {"Marcos", "Mc", 4, 4, "al sembrar, algo cayo al borde del camino, vinieron los pajaros y se lo comieron."},
    {"Marcos", "Mc", 4, 5, "Otra parte cayo en terreno pedregoso, donde apenas tenia tierra; como la tierra no era profunda, broto enseguida;"},
    {"Marcos", "Mc", 4, 6, "pero en cuanto salio el sol, se abraso y, por falta de raiz, se seco."},
    {"Marcos", "Mc", 4, 7, "Otra parte cayo entre abrojos; los abrojos crecieron, la ahogaron y no dio grano."},
    {"Marcos", "Mc", 4, 8, "El resto cayo en tierra buena; nacio, crecio y dio grano; y la cosecha fue del treinta o del sesenta o del ciento por uno\"."},
    {"Marcos", "Mc", 4, 9, "Y a\177adio: \"El que tenga oidos para oir, que oiga\"."},
    {"Marcos", "Mc", 4, 10, "Cuando se quedo a solas, los que lo rodeaban y los Doce le preguntaban el sentido de las parabolas."},
    {"Marcos", "Mc", 4, 11, "El les dijo: \"A vosotros se os ha dado el misterio del reino de Dios; en cambio a los de fuera todo se les presenta en parabolas,"},
    {"Marcos", "Mc", 4, 12, "para que \"por mas que miren, no vean, por mas que oigan, no entiendan, no sea que se conviertan y sean perdonados\"\"."},
    {"Marcos", "Mc", 4, 13, "Y a\177adio: \"No entendeis esta parabola? Pues como vais a conocer todas las demas?"},
    {"Marcos", "Mc", 4, 14, "El sembrador siembra la palabra."},
    {"Marcos", "Mc", 4, 15, "Hay unos que estan al borde del camino donde se siembra la palabra; pero en cuanto la escuchan, viene Satanas y se lleva la palabra sembrada en ellos."},
    {"Marcos", "Mc", 4, 16, "Hay otros que reciben la semilla como terreno pedregoso; son los que al escuchar la palabra enseguida la acogen con alegria,"},
    {"Marcos", "Mc", 4, 17, "pero no tienen raices, son inconstantes, y cuando viene una dificultad o persecucion por la palabra, enseguida sucumben."},
    {"Marcos", "Mc", 4, 18, "Hay otros que reciben la semilla entre abrojos; estos son los que escuchan la palabra,"},
    {"Marcos", "Mc", 4, 19, "pero los afanes de la vida, la seduccion de las riquezas y el deseo de todo lo demas los invaden, ahogan la palabra, y se queda esteril."},
    {"Marcos", "Mc", 4, 20, "Los otros son los que reciben la semilla en tierra buena; escuchan la palabra, la aceptan y dan una cosecha del treinta o del sesenta o del ciento por uno\"."},
    {"Marcos", "Mc", 4, 21, "Les decia: \"Se trae la lampara para meterla debajo del celemin o debajo de la cama?, no es para ponerla en el candelero?"},
    {"Marcos", "Mc", 4, 22, "No hay nada escondido, sino para que sea descubierto; no hay nada oculto, sino para que salga a la luz."},
    {"Marcos", "Mc", 4, 23, "El que tenga oidos para oir, que oiga\"."},
    {"Marcos", "Mc", 4, 24, "Les dijo tambien: \"Atencion a lo que estais oyendo: la medida que useis la usaran con vosotros, y con creces."},
    {"Marcos", "Mc", 4, 25, "Porque al que tiene se le dara, y al que no tiene se le quitara hasta lo que tiene\"."},
    {"Marcos", "Mc", 4, 26, "Y decia: \"El reino de Dios se parece a un hombre que echa semilla en la tierra."},
    {"Marcos", "Mc", 4, 27, "El duerme de noche y se levanta de ma\177ana; la semilla germina y va creciendo, sin que el sepa como."},
    {"Marcos", "Mc", 4, 28, "La tierra va produciendo fruto sola: primero los tallos, luego la espiga, despues el grano."},
    {"Marcos", "Mc", 4, 29, "Cuando el grano esta a punto, se mete la hoz, porque ha llegado la siega\"."},
    {"Marcos", "Mc", 4, 30, "Dijo tambien: \"Con que podemos comparar el reino de Dios? Que parabola usaremos?"},
    {"Marcos", "Mc", 4, 31, "Con un grano de mostaza: al sembrarlo en la tierra es la semilla mas peque\177a,"},
    {"Marcos", "Mc", 4, 32, "pero despues de sembrada crece, se hace mas alta que las demas hortalizas y echa ramas tan grandes que los pajaros del cielo pueden anidar a su sombra\"."},
    {"Marcos", "Mc", 4, 33, "Con muchas parabolas parecidas les exponia la palabra, acomodandose a su entender."},
    {"Marcos", "Mc", 4, 34, "Todo se lo exponia con parabolas, pero a sus discipulos se lo explicaba todo en privado."},
    {"Marcos", "Mc", 4, 35, "Aquel dia, al atardecer, les dice Jesus: \"Vamos a la otra orilla\"."},
    {"Marcos", "Mc", 4, 36, "Dejando a la gente, se lo llevaron en barca, como estaba; otras barcas lo acompa\177aban."},
    {"Marcos", "Mc", 4, 37, "Se levanto una fuerte tempestad y las olas rompian contra la barca hasta casi llenarla de agua."},
    {"Marcos", "Mc", 4, 38, "El estaba en la popa, dormido sobre un cabezal. Lo despertaron, diciendole: \"Maestro, no te importa que perezcamos?\"."},
    {"Marcos", "Mc", 4, 39, "Se puso en pie, increpo al viento y dijo al mar: \"Silencio, enmudece!\". El viento ceso y vino una gran calma."},
    {"Marcos", "Mc", 4, 40, "El les dijo: \"Por que teneis miedo? Aun no teneis fe?\"."},
    {"Marcos", "Mc", 4, 41, "Se llenaron de miedo y se decian unos a otros: \"Pero quien es este? Hasta el viento y el mar lo obedecen!\"."},
    {"Marcos", "Mc", 5, 1, "Y llegaron a la otra orilla del mar, a la region de los gerasenos."},
    {"Marcos", "Mc", 5, 2, "Apenas desembarco, le salio al encuentro, de entre los sepulcros, un hombre poseido de espiritu inmundo."},
    {"Marcos", "Mc", 5, 3, "Y es que vivia entre los sepulcros; ni con cadenas podia ya nadie sujetarlo;"},
    {"Marcos", "Mc", 5, 4, "muchas veces lo habian sujetado con cepos y cadenas, pero el rompia las cadenas y destrozaba los cepos, y nadie tenia fuerza para dominarlo."},
    {"Marcos", "Mc", 5, 5, "Se pasaba el dia y la noche en los sepulcros y en los montes, gritando e hiriendose con piedras."},
    {"Marcos", "Mc", 5, 6, "Viendo de lejos a Jesus, echo a correr, se postro ante el"},
    {"Marcos", "Mc", 5, 7, "y grito con voz potente: \"Que tienes que ver conmigo, Jesus, Hijo de Dios altisimo? Por Dios te lo pido, no me atormentes\"."},
    {"Marcos", "Mc", 5, 8, "Porque Jesus le estaba diciendo: \"Espiritu inmundo, sal de este hombre\"."},
    {"Marcos", "Mc", 5, 9, "Y le pregunto: \"Como te llamas?\". El respondio: \"Me llamo Legion, porque somos muchos\"."},
    {"Marcos", "Mc", 5, 10, "Y le rogaba con insistencia que no los expulsara de aquella comarca."},
    {"Marcos", "Mc", 5, 11, "Habia cerca una gran piara de cerdos paciendo en la falda del monte."},
    {"Marcos", "Mc", 5, 12, "Los espiritus le rogaron: \"Envianos a los cerdos para que entremos en ellos\"."},
    {"Marcos", "Mc", 5, 13, "El se lo permitio. Los espiritus inmundos salieron del hombre y se metieron en los cerdos; y la piara, unos dos mil, se abalanzo acantilado abajo al mar y se ahogo en el mar."},
    {"Marcos", "Mc", 5, 14, "Los porquerizos huyeron y dieron la noticia en la ciudad y en los campos. Y la gente fue a ver que habia pasado."},
    {"Marcos", "Mc", 5, 15, "Se acercaron a Jesus y vieron al endemoniado que habia tenido la legion, sentado, vestido y en su juicio. Y se asustaron."},
    {"Marcos", "Mc", 5, 16, "Los que lo habian visto les contaron lo que habia pasado al endemoniado y a los cerdos."},
    {"Marcos", "Mc", 5, 17, "Ellos le rogaban que se marchase de su comarca."},
    {"Marcos", "Mc", 5, 18, "Mientras se embarcaba, el que habia estado poseido por el demonio le pidio que le permitiese estar con el."},
    {"Marcos", "Mc", 5, 19, "Pero no se lo permitio, sino que le dijo: \"Vete a casa con los tuyos y anunciales lo que el Se\177or ha hecho contigo y que ha tenido misericordia de ti\"."},
    {"Marcos", "Mc", 5, 20, "El hombre se marcho y empezo a proclamar por la Decapolis lo que Jesus habia hecho con el; todos se admiraban."},
    {"Marcos", "Mc", 5, 21, "Jesus atraveso de nuevo en barca a la otra orilla, se le reunio mucha gente a su alrededor y se quedo junto al mar."},
    {"Marcos", "Mc", 5, 22, "Se acerco un jefe de la sinagoga, que se llamaba Jairo, y, al verlo, se echo a sus pies,"},
    {"Marcos", "Mc", 5, 23, "rogandole con insistencia: \"Mi ni\177a esta en las ultimas; ven, impon las manos sobre ella, para que se cure y viva\"."},
    {"Marcos", "Mc", 5, 24, "Se fue con el y lo seguia mucha gente que lo apretujaba."},
    {"Marcos", "Mc", 5, 25, "Habia una mujer que padecia flujos de sangre desde hacia doce a\177os."},
    {"Marcos", "Mc", 5, 26, "Habia sufrido mucho a manos de los medicos y se habia gastado en eso toda su fortuna; pero, en vez de mejorar, se habia puesto peor."},
    {"Marcos", "Mc", 5, 27, "Oyo hablar de Jesus y, acercandose por detras, entre la gente, le toco el manto,"},
    {"Marcos", "Mc", 5, 28, "pensando: \"Con solo tocarle el manto curare\"."},
    {"Marcos", "Mc", 5, 29, "Inmediatamente se seco la fuente de sus hemorragias y noto que su cuerpo estaba curado."},
    {"Marcos", "Mc", 5, 30, "Jesus, notando que habia salido fuerza de el, se volvio enseguida, en medio de la gente y preguntaba: \"Quien me ha tocado el manto?\"."},
    {"Marcos", "Mc", 5, 31, "Los discipulos le contestaban: \"Ves como te apretuja la gente y preguntas: \"Quien me ha tocado?\"\"."},
    {"Marcos", "Mc", 5, 32, "El seguia mirando alrededor, para ver a la que habia hecho esto."},
    {"Marcos", "Mc", 5, 33, "La mujer se acerco asustada y temblorosa, al comprender lo que le habia ocurrido, se le echo a los pies y le confeso toda la verdad."},
    {"Marcos", "Mc", 5, 34, "El le dice: \"Hija, tu fe te ha salvado. Vete en paz y queda curada de tu enfermedad\"."},
    {"Marcos", "Mc", 5, 35, "Todavia estaba hablando, cuando llegaron de casa del jefe de la sinagoga para decirle: \"Tu hija se ha muerto. Para que molestar mas al maestro?\"."},
    {"Marcos", "Mc", 5, 36, "Jesus alcanzo a oir lo que hablaban y le dijo al jefe de la sinagoga: \"No temas; basta que tengas fe\"."},
    {"Marcos", "Mc", 5, 37, "No permitio que lo acompa\177ara nadie, mas que Pedro, Santiago y Juan, el hermano de Santiago."},
    {"Marcos", "Mc", 5, 38, "Llegan a casa del jefe de la sinagoga y encuentra el alboroto de los que lloraban y se lamentaban a gritos"},
    {"Marcos", "Mc", 5, 39, "y despues de entrar les dijo: \"Que estrepito y que lloros son estos? La ni\177a no esta muerta; esta dormida\"."},
    {"Marcos", "Mc", 5, 40, "Se reian de el. Pero el los echo fuera a todos y, con el padre y la madre de la ni\177a y sus acompa\177antes, entro donde estaba la ni\177a,"},
    {"Marcos", "Mc", 5, 41, "la cogio de la mano y le dijo: Talitha qumi (que significa: \"Contigo hablo, ni\177a, levantate\")."},
    {"Marcos", "Mc", 5, 42, "La ni\177a se levanto inmediatamente y echo a andar; tenia doce a\177os. Y quedaron fuera de si llenos de estupor."},
    {"Marcos", "Mc", 5, 43, "Les insistio en que nadie se enterase; y les dijo que dieran de comer a la ni\177a."},
    {"Marcos", "Mc", 6, 1, "Saliendo de alli se dirigio a su ciudad y lo seguian sus discipulos."},
    {"Marcos", "Mc", 6, 2, "Cuando llego el sabado, empezo a ense\177ar en la sinagoga; la multitud que lo oia se preguntaba asombrada: \"De donde saca todo eso? Que sabiduria es esa que le ha sido dada? Y esos milagros que realizan sus manos?"},
    {"Marcos", "Mc", 6, 3, "No es este el carpintero, el hijo de Maria, hermano de Santiago y Jose y Judas y Simon? Y sus hermanas no viven con nosotros aqui?\". Y se escandalizaban a cuenta de el."},
    {"Marcos", "Mc", 6, 4, "Les decia: \"No desprecian a un profeta mas que en su tierra, entre sus parientes y en su casa\"."},
    {"Marcos", "Mc", 6, 5, "No pudo hacer alli ningun milagro, solo curo algunos enfermos imponiendoles las manos."},
    {"Marcos", "Mc", 6, 6, "Y se admiraba de su falta de fe. Y recorria los pueblos de alrededor ense\177ando."},
    {"Marcos", "Mc", 6, 7, "Llamo a los Doce y los fue enviando de dos en dos, dandoles autoridad sobre los espiritus inmundos."},
    {"Marcos", "Mc", 6, 8, "Les encargo que llevaran para el camino un baston y nada mas, pero ni pan, ni alforja, ni dinero suelto en la faja;"},
    {"Marcos", "Mc", 6, 9, "que llevasen sandalias, pero no una tunica de repuesto."},
    {"Marcos", "Mc", 6, 10, "Y decia: \"Quedaos en la casa donde entreis, hasta que os vayais de aquel sitio."},
    {"Marcos", "Mc", 6, 11, "Y si un lugar no os recibe ni os escucha, al marcharos sacudios el polvo de los pies, en testimonio contra ellos\"."},
    {"Marcos", "Mc", 6, 12, "Ellos salieron a predicar la conversion,"},
    {"Marcos", "Mc", 6, 13, "echaban muchos demonios, ungian con aceite a muchos enfermos y los curaban."},
    {"Marcos", "Mc", 6, 14, "Como la fama de Jesus se habia extendido, el rey Herodes oyo hablar de el. Unos decian: \"Juan el Bautista ha resucitado de entre los muertos y por eso las fuerzas milagrosas actuan en el\"."},
    {"Marcos", "Mc", 6, 15, "Otros decian: \"Es Elias\". Otros: \"Es un profeta como los antiguos\"."},
    {"Marcos", "Mc", 6, 16, "Herodes, al oirlo, decia: \"Es Juan, a quien yo decapite, que ha resucitado\"."},
    {"Marcos", "Mc", 6, 17, "Es que Herodes habia mandado prender a Juan y lo habia metido en la carcel encadenado. El motivo era que Herodes se habia casado con Herodias, mujer de su hermano Filipo,"},
    {"Marcos", "Mc", 6, 18, "y Juan le decia que no le era licito tener a la mujer de su hermano."},
    {"Marcos", "Mc", 6, 19, "Herodias aborrecia a Juan y queria matarlo, pero no podia,"},
    {"Marcos", "Mc", 6, 20, "porque Herodes respetaba a Juan, sabiendo que era un hombre justo y santo, y lo defendia. Al escucharlo quedaba muy perplejo, aunque lo oia con gusto."},
    {"Marcos", "Mc", 6, 21, "La ocasion llego cuando Herodes, por su cumplea\177os, dio un banquete a sus magnates, a sus oficiales y a la gente principal de Galilea."},
    {"Marcos", "Mc", 6, 22, "La hija de Herodias entro y danzo, gustando mucho a Herodes y a los convidados. El rey le dijo a la joven: \"Pideme lo que quieras, que te lo dare\"."},
    {"Marcos", "Mc", 6, 23, "Y le juro: \"Te dare lo que me pidas, aunque sea la mitad de mi reino\"."},
    {"Marcos", "Mc", 6, 24, "Ella salio a preguntarle a su madre: \"Que le pido?\". La madre le contesto: \"La cabeza de Juan el Bautista\"."},
    {"Marcos", "Mc", 6, 25, "Entro ella enseguida, a toda prisa, se acerco al rey y le pidio: \"Quiero que ahora mismo me des en una bandeja la cabeza de Juan el Bautista\"."},
    {"Marcos", "Mc", 6, 26, "El rey se puso muy triste; pero por el juramento y los convidados no quiso desairarla."},
    {"Marcos", "Mc", 6, 27, "Enseguida le mando a uno de su guardia que trajese la cabeza de Juan. Fue, lo decapito en la carcel,"},
    {"Marcos", "Mc", 6, 28, "trajo la cabeza en una bandeja y se la entrego a la joven; la joven se la entrego a su madre."},
    {"Marcos", "Mc", 6, 29, "Al enterarse sus discipulos fueron a recoger el cadaver y lo pusieron en un sepulcro."},
    {"Marcos", "Mc", 6, 30, "Los apostoles volvieron a reunirse con Jesus, y le contaron todo lo que habian hecho y ense\177ado."},
    {"Marcos", "Mc", 6, 31, "El les dijo: \"Venid vosotros a solas a un lugar desierto a descansar un poco\". Porque eran tantos los que iban y venian, que no encontraban tiempo ni para comer."},
    {"Marcos", "Mc", 6, 32, "Se fueron en barca a solas a un lugar desierto."},
    {"Marcos", "Mc", 6, 33, "Muchos los vieron marcharse y los reconocieron; entonces de todas las aldeas fueron corriendo por tierra a aquel sitio y se les adelantaron."},
    {"Marcos", "Mc", 6, 34, "Al desembarcar, Jesus vio una multitud y se compadecio de ella, porque andaban como ovejas que no tienen pastor; y se puso a ense\177arles muchas cosas."},
    {"Marcos", "Mc", 6, 35, "Cuando se hizo tarde se acercaron sus discipulos a decirle: \"Estamos en despoblado y ya es muy tarde."},
    {"Marcos", "Mc", 6, 36, "Despidelos, que vayan a los cortijos y aldeas de alrededor y se compren de comer\"."},
    {"Marcos", "Mc", 6, 37, "El les replico: \"Dadles vosotros de comer\". Ellos le preguntaron: \"Vamos a ir a comprar doscientos denarios de pan para darles de comer?\"."},
    {"Marcos", "Mc", 6, 38, "El les dijo: \"Cuantos panes teneis? Id a ver\". Cuando lo averiguaron le dijeron: \"Cinco, y dos peces\"."},
    {"Marcos", "Mc", 6, 39, "El les mando que la gente se recostara sobre la hierba verde en grupos."},
    {"Marcos", "Mc", 6, 40, "Ellos se acomodaron por grupos de cien y de cincuenta."},
    {"Marcos", "Mc", 6, 41, "Y tomando los cinco panes y los dos peces, alzando la mirada al cielo, pronuncio la bendicion, partio los panes y se los iba dando a los discipulos para que se los sirvieran. Y repartio entre todos los dos peces."},
    {"Marcos", "Mc", 6, 42, "Comieron todos y se saciaron,"},
    {"Marcos", "Mc", 6, 43, "y recogieron las sobras: doce cestos de pan y de peces."},
    {"Marcos", "Mc", 6, 44, "Los que comieron eran cinco mil hombres."},
    {"Marcos", "Mc", 6, 45, "Enseguida apremio a los discipulos a que subieran a la barca y se le adelantaran hacia la orilla de Betsaida, mientras el despedia a la gente."},
    {"Marcos", "Mc", 6, 46, "Y despues de despedirse de ellos, se retiro al monte a orar."},
    {"Marcos", "Mc", 6, 47, "Llegada la noche, la barca estaba en mitad del mar y Jesus, solo, en tierra."},
    {"Marcos", "Mc", 6, 48, "Viendolos fatigados de remar, porque tenian viento contrario, a eso de la cuarta vigilia de la madrugada, fue hacia ellos andando sobre el mar, e hizo ademan de pasar de largo."},
    {"Marcos", "Mc", 6, 49, "Ellos, viendolo andar sobre el mar, pensaron que era un fantasma y dieron un grito,"},
    {"Marcos", "Mc", 6, 50, "porque todos lo vieron y se asustaron. Pero el hablo enseguida con ellos y les dijo: \"Animo, soy yo, no tengais miedo\"."},
    {"Marcos", "Mc", 6, 51, "Entro en la barca con ellos y amaino el viento. Ellos estaban en el colmo del estupor,"},
    {"Marcos", "Mc", 6, 52, "pues no habian comprendido lo de los panes, porque tenian la mente embotada."},
    {"Marcos", "Mc", 6, 53, "Terminada la travesia, llegaron a Genesaret y atracaron."},
    {"Marcos", "Mc", 6, 54, "Apenas desembarcados, lo reconocieron"},
    {"Marcos", "Mc", 6, 55, "y se pusieron a recorrer toda la comarca; cuando se enteraba la gente donde estaba Jesus, le llevaba los enfermos en camillas."},
    {"Marcos", "Mc", 6, 56, "En los pueblos, ciudades o aldeas donde llegaba colocaban a los enfermos en la plaza y le rogaban que les dejase tocar al menos la orla de su manto; y los que la tocaban se curaban."},
    {"Marcos", "Mc", 7, 1, "Se reunieron junto a el los fariseos y algunos escribas venidos de Jerusalen;"},
    {"Marcos", "Mc", 7, 2, "y vieron que algunos discipulos comian con manos impuras, es decir, sin lavarse las manos."},
    {"Marcos", "Mc", 7, 3, "(Pues los fariseos, como los demas judios, no comen sin lavarse antes las manos, restregando bien, aferrandose a la tradicion de sus mayores,"},
    {"Marcos", "Mc", 7, 4, "y al volver de la plaza no comen sin lavarse antes, y se aferran a otras muchas tradiciones, de lavar vasos, jarras y ollas)."},
    {"Marcos", "Mc", 7, 5, "Y los fariseos y los escribas le preguntaron: \"Por que no caminan tus discipulos segun las tradiciones de los mayores y comen el pan con manos impuras?\"."},
    {"Marcos", "Mc", 7, 6, "El les contesto: \"Bien profetizo Isaias de vosotros, hipocritas, como esta escrito: \"Este pueblo me honra con los labios, pero su corazon esta lejos de mi."},
    {"Marcos", "Mc", 7, 7, "El culto que me dan esta vacio, porque la doctrina que ense\177an son preceptos humanos\"."},
    {"Marcos", "Mc", 7, 8, "Dejais a un lado el mandamiento de Dios para aferraros a la tradicion de los hombres\"."},
    {"Marcos", "Mc", 7, 9, "Y a\177adio: \"Anulais el mandamiento de Dios por mantener vuestra tradicion."},
    {"Marcos", "Mc", 7, 10, "Moises dijo: \"Honra a tu padre y a tu madre\" y \"el que maldiga a su padre o a su madre es reo de muerte\"."},
    {"Marcos", "Mc", 7, 11, "Pero vosotros decis: \"Si uno le dice al padre o a la madre: los bienes con que podria ayudarte son corban, es decir, ofrenda sagrada\","},
    {"Marcos", "Mc", 7, 12, "ya no le permitis hacer nada por su padre o por su madre;"},
    {"Marcos", "Mc", 7, 13, "invalidando la palabra de Dios con esa tradicion que os transmitis; y haceis otras muchas cosas semejantes\"."},
    {"Marcos", "Mc", 7, 14, "Llamo Jesus de nuevo a la gente y les dijo: \"Escuchad y entended todos:"},
    {"Marcos", "Mc", 7, 15, "nada que entre de fuera puede hacer al hombre impuro; lo que sale de dentro es lo que hace impuro al hombre\"."},
    {"Marcos", "Mc", 7, 16, "[\"El que tenga oidos para oir que oiga\"]"},
    {"Marcos", "Mc", 7, 17, "Cuando dejo a la gente y entro en casa, le pidieron sus discipulos que les explicara la parabola."},
    {"Marcos", "Mc", 7, 18, "El les dijo: \"Tambien vosotros seguis sin entender? No comprendeis? Nada que entre de fuera puede hacer impuro al hombre,"},
    {"Marcos", "Mc", 7, 19, "porque no entra en el corazon sino en el vientre y se echa en la letrina\". (Con esto declaraba puros todos los alimentos)."},
    {"Marcos", "Mc", 7, 20, "Y siguio: \"Lo que sale de dentro del hombre, eso si hace impuro al hombre."},
    {"Marcos", "Mc", 7, 21, "Porque de dentro, del corazon del hombre, salen los pensamientos perversos, las fornicaciones, robos, homicidios,"},
    {"Marcos", "Mc", 7, 22, "adulterios, codicias, malicias, fraudes, desenfreno, envidia, difamacion, orgullo, frivolidad."},
    {"Marcos", "Mc", 7, 23, "Todas esas maldades salen de dentro y hacen al hombre impuro\"."},
    {"Marcos", "Mc", 7, 24, "Desde alli fue a la region de Tiro. Entro en una casa procurando pasar desapercibido, pero no logro ocultarse."},
    {"Marcos", "Mc", 7, 25, "Una mujer que tenia una hija poseida por un espiritu impuro se entero enseguida, fue a buscarlo y se le echo a los pies."},
    {"Marcos", "Mc", 7, 26, "La mujer era pagana, una fenicia de Siria, y le rogaba que echase el demonio de su hija."},
    {"Marcos", "Mc", 7, 27, "El le dijo: \"Deja que se sacien primero los hijos. No esta bien tomar el pan de los hijos y echarselo a los perritos\"."},
    {"Marcos", "Mc", 7, 28, "Pero ella replico: \"Se\177or, pero tambien los perros, debajo de la mesa, comen las migajas que tiran los ni\177os\"."},
    {"Marcos", "Mc", 7, 29, "El le contesto: \"Anda, vete, que por eso que has dicho, el demonio ha salido de tu hija\"."},
    {"Marcos", "Mc", 7, 30, "Al llegar a su casa, se encontro a la ni\177a echada en la cama; el demonio se habia marchado."},
    {"Marcos", "Mc", 7, 31, "Dejando Jesus el territorio de Tiro, paso por Sidon, camino del mar de Galilea, atravesando la Decapolis."},
    {"Marcos", "Mc", 7, 32, "Y le presentaron un sordo, que, ademas, apenas podia hablar; y le piden que le imponga la mano."},
    {"Marcos", "Mc", 7, 33, "El, apartandolo de la gente, a solas, le metio los dedos en los oidos y con la saliva le toco la lengua."},
    {"Marcos", "Mc", 7, 34, "Y mirando al cielo, suspiro y le dijo: Effeta (esto es, \"abrete\")."},
    {"Marcos", "Mc", 7, 35, "Y al momento se le abrieron los oidos, se le solto la traba de la lengua y hablaba correctamente."},
    {"Marcos", "Mc", 7, 36, "El les mando que no lo dijeran a nadie; pero, cuanto mas se lo mandaba, con mas insistencia lo proclamaban ellos."},
    {"Marcos", "Mc", 7, 37, "Y en el colmo del asombro decian: \"Todo lo ha hecho bien: hace oir a los sordos y hablar a los mudos\"."},
    {"Marcos", "Mc", 8, 1, "Por aquellos dias, como de nuevo se habia reunido mucha gente y no tenian que comer, Jesus llamo a sus discipulos y les dijo:"},
    {"Marcos", "Mc", 8, 2, "\"Siento compasion de la gente, porque llevan ya tres dias conmigo y no tienen que comer,"},
    {"Marcos", "Mc", 8, 3, "y si los despido a sus casas en ayunas, van a desfallecer por el camino. Ademas, algunos han venido desde lejos\"."},
    {"Marcos", "Mc", 8, 4, "Le replicaron sus discipulos: \"Y de donde se puede sacar pan, aqui, en despoblado, para saciar a tantos?\"."},
    {"Marcos", "Mc", 8, 5, "El les pregunto: \"Cuantos panes teneis?\". Ellos contestaron: \"Siete\"."},
    {"Marcos", "Mc", 8, 6, "Mando que la gente se sentara en el suelo y tomando los siete panes, dijo la accion de gracias, los partio y los fue dando a sus discipulos para que los sirvieran. Ellos los sirvieron a la gente."},
    {"Marcos", "Mc", 8, 7, "Tenian tambien unos cuantos peces; y Jesus pronuncio sobre ellos la bendicion, y mando que los sirvieran tambien."},
    {"Marcos", "Mc", 8, 8, "La gente comio hasta quedar saciada y de los trozos que sobraron llenaron siete canastas;"},
    {"Marcos", "Mc", 8, 9, "eran unos cuatro mil y los despidio;"},
    {"Marcos", "Mc", 8, 10, "y enseguida monto en la barca con sus discipulos y se fue a la region de Dalmanuta."},
    {"Marcos", "Mc", 8, 11, "Se presentaron los fariseos y se pusieron a discutir con Jesus; para ponerlo a prueba, le pidieron un signo del cielo."},
    {"Marcos", "Mc", 8, 12, "Jesus dio un profundo suspiro y dijo: \"Por que esta generacion reclama un signo? En verdad os digo que no se le dara un signo a esta generacion\"."},
    {"Marcos", "Mc", 8, 13, "Los dejo, se embarco de nuevo y se fue a la otra orilla."},
    {"Marcos", "Mc", 8, 14, "A los discipulos se les olvido tomar pan y no tenian mas que un pan en la barca."},
    {"Marcos", "Mc", 8, 15, "Y el les ordenaba diciendo: \"Estad atentos, evitad la levadura de los fariseos y de Herodes\"."},
    {"Marcos", "Mc", 8, 16, "Y discutian entre ellos sobre el hecho de que no tenian panes."},
    {"Marcos", "Mc", 8, 17, "Dandose cuenta, les dijo Jesus: \"Por que andais discutiendo que no teneis pan? Aun no entendeis ni comprendeis? Teneis el corazon embotado?"},
    {"Marcos", "Mc", 8, 18, "Teneis ojos y no veis, teneis oidos y no ois? No recordais"},
    {"Marcos", "Mc", 8, 19, "cuantos cestos de sobras recogisteis cuando reparti cinco panes entre cinco mil?\". Ellos contestaron: \"Doce\"."},
    {"Marcos", "Mc", 8, 20, "\"Y cuantas canastas de sobras recogisteis cuando reparti siete entre cuatro mil?\". Le respondieron: \"Siete\"."},
    {"Marcos", "Mc", 8, 21, "El les dijo: \"Y no acabais de comprender?\"."},
    {"Marcos", "Mc", 8, 22, "Llegaron a Betsaida. Y le trajeron a un ciego pidiendole que lo tocase."},
    {"Marcos", "Mc", 8, 23, "El lo saco de la aldea, llevandolo de la mano, le unto saliva en los ojos, le impuso las manos y le pregunto: \"Ves algo?\"."},
    {"Marcos", "Mc", 8, 24, "Levantando los ojos dijo: \"Veo hombres, me parecen arboles, pero andan\"."},
    {"Marcos", "Mc", 8, 25, "Le puso otra vez las manos en los ojos; el hombre miro: estaba curado y veia todo con claridad."},
    {"Marcos", "Mc", 8, 26, "Jesus lo mando a casa diciendole que no entrase en la aldea."},
    {"Marcos", "Mc", 8, 27, "Despues Jesus y sus discipulos se dirigieron a las aldeas de Cesarea de Filipo; por el camino pregunto a sus discipulos: \"Quien dice la gente que soy yo?\"."},
    {"Marcos", "Mc", 8, 28, "Ellos le contestaron: \"Unos, Juan el Bautista; otros, Elias, y otros, uno de los profetas\"."},
    {"Marcos", "Mc", 8, 29, "El les pregunto: \"Y vosotros, quien decis que soy?\". Tomando la palabra Pedro le dijo: \"Tu eres el Mesias\"."},
    {"Marcos", "Mc", 8, 30, "Y les conmino a que no hablaran a nadie acerca de esto."},
    {"Marcos", "Mc", 8, 31, "Y empezo a instruirlos: \"El Hijo del hombre tiene que padecer mucho, ser reprobado por los ancianos, sumos sacerdotes y escribas, ser ejecutado y resucitar a los tres dias\"."},
    {"Marcos", "Mc", 8, 32, "Se lo explicaba con toda claridad. Entonces Pedro se lo llevo aparte y se puso a increparlo."},
    {"Marcos", "Mc", 8, 33, "Pero el se volvio y, mirando a los discipulos, increpo a Pedro: \"Ponte detras de mi, Satanas! Tu piensas como los hombres, no como Dios!\"."},
    {"Marcos", "Mc", 8, 34, "Y llamando a la gente y a sus discipulos les dijo: \"Si alguno quiere venir en pos de mi, que se niegue a si mismo, tome su cruz y me siga."},
    {"Marcos", "Mc", 8, 35, "Porque, quien quiera salvar su vida, la perdera; pero el que pierda su vida por mi y por el Evangelio, la salvara."},
    {"Marcos", "Mc", 8, 36, "Pues de que le sirve a un hombre ganar el mundo entero y perder su alma?"},
    {"Marcos", "Mc", 8, 37, "O que podra dar uno para recobrarla?"},
    {"Marcos", "Mc", 8, 38, "Quien se averguence de mi y de mis palabras en esta generacion adultera y pecadora, tambien el Hijo del hombre se avergonzara de el cuando venga con la gloria de su Padre entre sus santos angeles\"."},
    {"Marcos", "Mc", 9, 1, "Y a\177adio: \"En verdad os digo que algunos de los aqui presentes no gustaran la muerte hasta que vean el reino de Dios en toda su potencia\"."},
    {"Marcos", "Mc", 9, 2, "Seis dias mas tarde Jesus toma consigo a Pedro, a Santiago y a Juan, sube aparte con ellos solos a un monte alto, y se transfiguro delante de ellos."},
    {"Marcos", "Mc", 9, 3, "Sus vestidos se volvieron de un blanco deslumbrador, como no puede dejarlos ningun batanero del mundo."},
    {"Marcos", "Mc", 9, 4, "Se les aparecieron Elias y Moises, conversando con Jesus."},
    {"Marcos", "Mc", 9, 5, "Entonces Pedro tomo la palabra y dijo a Jesus: \"Maestro, que bueno es que estemos aqui! Vamos a hacer tres tiendas, una para ti, otra para Moises y otra para Elias\"."},
    {"Marcos", "Mc", 9, 6, "No sabia que decir, pues estaban asustados."},
    {"Marcos", "Mc", 9, 7, "Se formo una nube que los cubrio y salio una voz de la nube: \"Este es mi Hijo, el amado; escuchadlo\"."},
    {"Marcos", "Mc", 9, 8, "De pronto, al mirar alrededor, no vieron a nadie mas que a Jesus, solo con ellos."},
    {"Marcos", "Mc", 9, 9, "Cuando bajaban del monte, les ordeno que no contasen a nadie lo que habian visto hasta que el Hijo del hombre resucitara de entre los muertos."},
    {"Marcos", "Mc", 9, 10, "Esto se les quedo grabado y discutian que queria decir aquello de resucitar de entre los muertos."},
    {"Marcos", "Mc", 9, 11, "Le preguntaron: \"Por que dicen los escribas que primero tiene que venir Elias?\"."},
    {"Marcos", "Mc", 9, 12, "Les contesto el: \"Elias vendra primero y lo renovara todo. Ahora, por que esta escrito que el Hijo del hombre tiene que padecer mucho y ser despreciado?"},
    {"Marcos", "Mc", 9, 13, "Os digo que Elias ya ha venido y han hecho con el lo que han querido, como estaba escrito acerca de el\"."},
    {"Marcos", "Mc", 9, 14, "Cuando volvieron a donde estaban los demas discipulos, vieron mucha gente alrededor y a unos escribas discutiendo con ellos."},
    {"Marcos", "Mc", 9, 15, "Al ver a Jesus, la gente se sorprendio y corrio a saludarlo."},
    {"Marcos", "Mc", 9, 16, "El les pregunto: \"De que discutis?\"."},
    {"Marcos", "Mc", 9, 17, "Uno de la gente le contesto: \"Maestro, te he traido a mi hijo; tiene un espiritu que no lo deja hablar;"},
    {"Marcos", "Mc", 9, 18, "y cuando lo agarra, lo tira al suelo, echa espumarajos, rechina los dientes y se queda rigido. He pedido a tus discipulos que lo echen y no han sido capaces\"."},
    {"Marcos", "Mc", 9, 19, "El, tomando la palabra, les dice: \"Generacion incredula! Hasta cuando estare con vosotros? Hasta cuando os tendre que soportar? Traedmelo\"."},
    {"Marcos", "Mc", 9, 20, "Se lo llevaron. El espiritu, en cuanto vio a Jesus, retorcio al ni\177o; este cayo por tierra y se revolcaba echando espumarajos."},
    {"Marcos", "Mc", 9, 21, "Jesus pregunto al padre: \"Cuanto tiempo hace que le pasa esto?\". Contesto el: \"Desde peque\177o."},
    {"Marcos", "Mc", 9, 22, "Y muchas veces hasta lo ha echado al fuego y al agua para acabar con el. Si algo puedes, ten compasion de nosotros y ayudanos\"."},
    {"Marcos", "Mc", 9, 23, "Jesus replico: \"Si puedo? Todo es posible al que tiene fe\"."},
    {"Marcos", "Mc", 9, 24, "Entonces el padre del muchacho se puso a gritar: \"Creo, pero ayuda mi falta de fe\"."},
    {"Marcos", "Mc", 9, 25, "Jesus, al ver que acudia gente, increpo al espiritu inmundo, diciendo: \"Espiritu mudo y sordo, yo te lo mando: sal de el y no vuelvas a entrar en el\"."},
    {"Marcos", "Mc", 9, 26, "Gritando y sacudiendolo violentamente, salio. El ni\177o se quedo como un cadaver, de modo que muchos decian que estaba muerto."},
    {"Marcos", "Mc", 9, 27, "Pero Jesus lo levanto cogiendolo de la mano y el ni\177o se puso en pie."},
    {"Marcos", "Mc", 9, 28, "Al entrar en casa, sus discipulos le preguntaron a solas: \"Por que no pudimos echarlo nosotros?\"."},
    {"Marcos", "Mc", 9, 29, "El les respondio: \"Esta especie solo puede salir con oracion\"."},
    {"Marcos", "Mc", 9, 30, "Se fueron de alli y atravesaron Galilea; no queria que nadie se enterase,"},
    {"Marcos", "Mc", 9, 31, "porque iba instruyendo a sus discipulos. Les decia: \"El Hijo del hombre va a ser entregado en manos de los hombres y lo mataran; y despues de muerto, a los tres dias resucitara\"."},
    {"Marcos", "Mc", 9, 32, "Pero no entendian lo que decia, y les daba miedo preguntarle."},
    {"Marcos", "Mc", 9, 33, "Llegaron a Cafarnaun, y una vez en casa, les pregunto: \"De que discutiais por el camino?\"."},
    {"Marcos", "Mc", 9, 34, "Ellos callaban, pues por el camino habian discutido quien era el mas importante."},
    {"Marcos", "Mc", 9, 35, "Se sento, llamo a los Doce y les dijo: \"Quien quiera ser el primero, que sea el ultimo de todos y el servidor de todos\"."},
    {"Marcos", "Mc", 9, 36, "Y tomando un ni\177o, lo puso en medio de ellos, lo abrazo y les dijo:"},
    {"Marcos", "Mc", 9, 37, "\"El que acoge a un ni\177o como este en mi nombre, me acoge a mi; y el que me acoge a mi, no me acoge a mi, sino al que me ha enviado\"."},
    {"Marcos", "Mc", 9, 38, "Juan le dijo: \"Maestro, hemos visto a uno que echaba demonios en tu nombre, y se lo hemos querido impedir, porque no viene con nosotros\"."},
    {"Marcos", "Mc", 9, 39, "Jesus respondio: \"No se lo impidais, porque quien hace un milagro en mi nombre no puede luego hablar mal de mi."},
    {"Marcos", "Mc", 9, 40, "El que no esta contra nosotros esta a favor nuestro."},
    {"Marcos", "Mc", 9, 41, "Y el que os de a beber un vaso de agua porque sois de Cristo, en verdad os digo que no se quedara sin recompensa."},
    {"Marcos", "Mc", 9, 42, "El que escandalice a uno de estos peque\177uelos que creen, mas le valdria que le encajasen en el cuello una piedra de molino y lo echasen al mar."},
    {"Marcos", "Mc", 9, 43, "Si tu mano te induce a pecar, cortatela: mas te vale entrar manco en la vida, que ir con las dos manos a la gehenna, al fuego que no se apaga."},
    {"Marcos", "Mc", 9, 44, ""},
    {"Marcos", "Mc", 9, 45, "Y, si tu pie te induce a pecar, cortatelo: mas te vale entrar cojo en la vida, que ser echado con los dos pies a la gehenna."},
    {"Marcos", "Mc", 9, 46, ""},
    {"Marcos", "Mc", 9, 47, "Y, si tu ojo te induce a pecar, sacatelo: mas te vale entrar tuerto en el reino de Dios, que ser echado con los dos ojos a la gehenna,"},
    {"Marcos", "Mc", 9, 48, "donde el gusano no muere y el fuego no se apaga."},
    {"Marcos", "Mc", 9, 49, "Todos seran salados a fuego."},
    {"Marcos", "Mc", 9, 50, "Buena es la sal; pero si la sal se vuelve sosa, con que la salareis? Tened sal entre vosotros y vivid en paz unos con otros\"."},
    {"Marcos", "Mc", 10, 1, "Y desde alli se marcho a Judea y a Transjordania; otra vez se le fue reuniendo gente por el camino y segun su costumbre les ense\177aba."},
    {"Marcos", "Mc", 10, 2, "Acercandose unos fariseos, le preguntaban para ponerlo a prueba: \"Le es licito al hombre repudiar a su mujer?\"."},
    {"Marcos", "Mc", 10, 3, "El les replico: \"Que os ha mandado Moises?\"."},
    {"Marcos", "Mc", 10, 4, "Contestaron: \"Moises permitio escribir el acta de divorcio y repudiarla\"."},
    {"Marcos", "Mc", 10, 5, "Jesus les dijo: \"Por la dureza de vuestro corazon dejo escrito Moises este precepto."},
    {"Marcos", "Mc", 10, 6, "Pero al principio de la creacion Dios los creo hombre y mujer."},
    {"Marcos", "Mc", 10, 7, "Por eso dejara el hombre a su padre y a su madre, se unira a su mujer"},
    {"Marcos", "Mc", 10, 8, "y seran los dos una sola carne. De modo que ya no son dos, sino una sola carne."},
    {"Marcos", "Mc", 10, 9, "Pues lo que Dios ha unido, que no lo separe el hombre\"."},
    {"Marcos", "Mc", 10, 10, "En casa, los discipulos volvieron a preguntarle sobre lo mismo."},
    {"Marcos", "Mc", 10, 11, "El les dijo: \"Si uno repudia a su mujer y se casa con otra, comete adulterio contra la primera."},
    {"Marcos", "Mc", 10, 12, "Y si ella repudia a su marido y se casa con otro, comete adulterio\"."},
    {"Marcos", "Mc", 10, 13, "Acercaban a Jesus ni\177os para que los tocara, pero los discipulos los rega\177aban."},
    {"Marcos", "Mc", 10, 14, "Al verlo, Jesus se enfado y les dijo: \"Dejad que los ni\177os se acerquen a mi: no se lo impidais, pues de los que son como ellos es el reino de Dios."},
    {"Marcos", "Mc", 10, 15, "En verdad os digo que quien no reciba el reino de Dios como un ni\177o, no entrara en el\"."},
    {"Marcos", "Mc", 10, 16, "Y tomandolos en brazos los bendecia imponiendoles las manos."},
    {"Marcos", "Mc", 10, 17, "Cuando salia Jesus al camino, se le acerco uno corriendo, se arrodillo ante el y le pregunto: \"Maestro bueno, que hare para heredar la vida eterna?\"."},
    {"Marcos", "Mc", 10, 18, "Jesus le contesto: \"Por que me llamas bueno? No hay nadie bueno mas que Dios."},
    {"Marcos", "Mc", 10, 19, "Ya sabes los mandamientos: no mataras, no cometeras adulterio, no robaras, no daras falso testimonio, no estafaras, honra a tu padre y a tu madre\"."},
    {"Marcos", "Mc", 10, 20, "El replico: \"Maestro, todo eso lo he cumplido desde mi juventud\"."},
    {"Marcos", "Mc", 10, 21, "Jesus se quedo mirandolo, lo amo y le dijo: \"Una cosa te falta: anda, vende lo que tienes, daselo a los pobres, asi tendras un tesoro en el cielo, y luego ven y sigueme\"."},
    {"Marcos", "Mc", 10, 22, "A estas palabras, el fruncio el ce\177o y se marcho triste porque era muy rico."},
    {"Marcos", "Mc", 10, 23, "Jesus, mirando alrededor, dijo a sus discipulos: \"Que dificil les sera entrar en el reino de Dios a los que tienen riquezas!\"."},
    {"Marcos", "Mc", 10, 24, "Los discipulos quedaron sorprendidos de estas palabras. Pero Jesus a\177adio: \"Hijos, que dificil es entrar en el reino de Dios!"},
    {"Marcos", "Mc", 10, 25, "Mas facil le es a un camello pasar por el ojo de una aguja, que a un rico entrar en el reino de Dios\"."},
    {"Marcos", "Mc", 10, 26, "Ellos se espantaron y comentaban: \"Entonces, quien puede salvarse?\"."},
    {"Marcos", "Mc", 10, 27, "Jesus se les quedo mirando y les dijo: \"Es imposible para los hombres, no para Dios. Dios lo puede todo\"."},
    {"Marcos", "Mc", 10, 28, "Pedro se puso a decirle: \"Ya ves que nosotros lo hemos dejado todo y te hemos seguido\"."},
    {"Marcos", "Mc", 10, 29, "Jesus dijo: \"En verdad os digo que no hay nadie que haya dejado casa, o hermanos o hermanas, o madre o padre, o hijos o tierras, por mi y por el Evangelio,"},
    {"Marcos", "Mc", 10, 30, "que no reciba ahora, en este tiempo, cien veces mas -casas y hermanos y hermanas y madres e hijos y tierras, con persecuciones- y en la edad futura, vida eterna."},
    {"Marcos", "Mc", 10, 31, "Muchos primeros seran ultimos, y muchos ultimos primeros\"."},
    {"Marcos", "Mc", 10, 32, "Estaban subiendo por el camino hacia Jerusalen y Jesus iba delante de ellos; ellos estaban sorprendidos y los que lo seguian tenian miedo. El tomo aparte otra vez a los Doce y empezo a decirles lo que le iba a suceder:"},
    {"Marcos", "Mc", 10, 33, "\"Mirad, estamos subiendo a Jerusalen, y el Hijo del hombre va a ser entregado a los sumos sacerdotes y a los escribas; lo condenaran a muerte y lo entregaran a los gentiles,"},
    {"Marcos", "Mc", 10, 34, "se burlaran de el, le escupiran, lo azotaran y lo mataran; y a los tres dias resucitara\"."},
    {"Marcos", "Mc", 10, 35, "Se le acercaron los hijos de Zebedeo, Santiago y Juan, y le dijeron: \"Maestro, queremos que nos hagas lo que te vamos a pedir\"."},
    {"Marcos", "Mc", 10, 36, "Les pregunto: \"Que quereis que haga por vosotros?\"."},
    {"Marcos", "Mc", 10, 37, "Contestaron: \"Concedenos sentarnos en tu gloria uno a tu derecha y otro a tu izquierda\"."},
    {"Marcos", "Mc", 10, 38, "Jesus replico: \"No sabeis lo que pedis, podeis beber el caliz que yo he de beber, o bautizaros con el bautismo con que yo me voy a bautizar?\"."},
    {"Marcos", "Mc", 10, 39, "Contestaron: \"Podemos\". Jesus les dijo: \"El caliz que yo voy a beber lo bebereis, y sereis bautizados con el bautismo con que yo me voy a bautizar,"},
    {"Marcos", "Mc", 10, 40, "pero el sentarse a mi derecha o a mi izquierda no me toca a mi concederlo, sino que es para quienes esta reservado\"."},
    {"Marcos", "Mc", 10, 41, "Los otros diez, al oir aquello, se indignaron contra Santiago y Juan."},
    {"Marcos", "Mc", 10, 42, "Jesus, llamandolos, les dijo: \"Sabeis que los que son reconocidos como jefes de los pueblos los tiranizan, y que los grandes los oprimen."},
    {"Marcos", "Mc", 10, 43, "No sera asi entre vosotros: el que quiera ser grande entre vosotros, que sea vuestro servidor;"},
    {"Marcos", "Mc", 10, 44, "y el que quiera ser primero, sea esclavo de todos."},
    {"Marcos", "Mc", 10, 45, "Porque el Hijo del hombre no ha venido a ser servido, sino a servir y dar su vida en rescate por muchos\"."},
    {"Marcos", "Mc", 10, 46, "Y llegan a Jerico. Y al salir el con sus discipulos y bastante gente, un mendigo ciego, Bartimeo (el hijo de Timeo), estaba sentado al borde del camino pidiendo limosna."},
    {"Marcos", "Mc", 10, 47, "Al oir que era Jesus Nazareno, empezo a gritar: \"Hijo de David, Jesus, ten compasion de mi\"."},
    {"Marcos", "Mc", 10, 48, "Muchos lo increpaban para que se callara. Pero el gritaba mas: \"Hijo de David, ten compasion de mi\"."},
    {"Marcos", "Mc", 10, 49, "Jesus se detuvo y dijo: \"Llamadlo\". Llamaron al ciego, diciendole: \"Animo, levantate, que te llama\"."},
    {"Marcos", "Mc", 10, 50, "Solto el manto, dio un salto y se acerco a Jesus."},
    {"Marcos", "Mc", 10, 51, "Jesus le dijo: \"Que quieres que te haga?\". El ciego le contesto: \"Rabbuni, que recobre la vista\"."},
    {"Marcos", "Mc", 10, 52, "Jesus le dijo: \"Anda, tu fe te ha salvado\". Y al momento recobro la vista y lo seguia por el camino."},
    {"Marcos", "Mc", 11, 1, "Cuando se acercaban a Jerusalen, por Betfage y Betania, junto al monte de los Olivos, mando a dos de sus discipulos,"},
    {"Marcos", "Mc", 11, 2, "diciendoles: \"Id a la aldea de enfrente y, en cuanto entreis, encontrareis un pollino atado, que nadie ha montado todavia. Desatadlo y traedlo."},
    {"Marcos", "Mc", 11, 3, "Y si alguien os pregunta por que lo haceis, contestadle: \"El Se\177or lo necesita, y lo devolvera pronto\"\"."},
    {"Marcos", "Mc", 11, 4, "Fueron y encontraron el pollino en la calle atado a una puerta; y lo soltaron."},
    {"Marcos", "Mc", 11, 5, "Algunos de los presentes les preguntaron: \"Que haceis desatando el pollino?\"."},
    {"Marcos", "Mc", 11, 6, "Ellos les contestaron como habia dicho Jesus; y se lo permitieron."},
    {"Marcos", "Mc", 11, 7, "Llevaron el pollino, le echaron encima los mantos, y Jesus se monto."},
    {"Marcos", "Mc", 11, 8, "Muchos alfombraron el camino con sus mantos, otros con ramas cortadas en el campo."},
    {"Marcos", "Mc", 11, 9, "Los que iban delante y detras, gritaban: \"Hosanna! Bendito el que viene en nombre del Se\177or!"},
    {"Marcos", "Mc", 11, 10, "Bendito el reino que llega, el de nuestro padre David! Hosanna en las alturas!\"."},
    {"Marcos", "Mc", 11, 11, "Entro Jesus en Jerusalen, en el templo, lo estuvo observando todo y, como era ya tarde, salio hacia Betania con los Doce."},
    {"Marcos", "Mc", 11, 12, "Al dia siguiente, cuando salian de Betania, sintio hambre."},
    {"Marcos", "Mc", 11, 13, "Vio de lejos una higuera con hojas, y se acerco para ver si encontraba algo; al llegar no encontro mas que hojas, porque no era tiempo de higos."},
    {"Marcos", "Mc", 11, 14, "Entonces le dijo: \"Nunca jamas coma nadie frutos de ti\". Los discipulos lo oyeron."},
    {"Marcos", "Mc", 11, 15, "Llegaron a Jerusalen y, entrando en el templo, se puso a echar a los que vendian y compraban en el templo, volcando las mesas de los cambistas y los puestos de los que vendian palomas."},
    {"Marcos", "Mc", 11, 16, "Y no consentia a nadie transportar objetos por el templo."},
    {"Marcos", "Mc", 11, 17, "Y los instruia diciendo: \"No esta escrito: \"Mi casa sera casa de oracion para todos los pueblos\"? Vosotros en cambio la habeis convertido en cueva de bandidos\"."},
    {"Marcos", "Mc", 11, 18, "Se enteraron los sumos sacerdotes y los escribas y, como le tenian miedo, porque todo el mundo admiraba su ense\177anza, buscaban una manera de acabar con el."},
    {"Marcos", "Mc", 11, 19, "Cuando atardecio, salieron de la ciudad."},
    {"Marcos", "Mc", 11, 20, "A la ma\177ana siguiente, al pasar, vieron la higuera seca de raiz."},
    {"Marcos", "Mc", 11, 21, "Pedro cayo en la cuenta y dijo a Jesus: \"Maestro, mira, la higuera que maldijiste se ha secado\"."},
    {"Marcos", "Mc", 11, 22, "Jesus contesto: \"Tened fe en Dios."},
    {"Marcos", "Mc", 11, 23, "En verdad os digo que si uno dice a este monte: \"Quitate y arrojate al mar\", y no duda en su corazon, sino que cree en que sucedera lo que dice, lo obtendra."},
    {"Marcos", "Mc", 11, 24, "Por eso os digo: todo cuanto pidais en la oracion, creed que os lo han concedido y lo obtendreis."},
    {"Marcos", "Mc", 11, 25, "Y cuando os pongais a orar, perdonad lo que tengais contra otros, para que tambien vuestro Padre del cielo os perdone vuestras culpas\"."},
    {"Marcos", "Mc", 11, 26, "[\"Mas si vosotros no perdonais, tampoco vuestro Padre que esta en los cielos perdonara vuestras ofensas\"]"},
    {"Marcos", "Mc", 11, 27, "Volvieron a Jerusalen y, mientras paseaba por el templo, se le acercaron los sumos sacerdotes, los escribas y los ancianos,"},
    {"Marcos", "Mc", 11, 28, "y le decian: \"Con que autoridad haces esto? Quien te ha dado semejante autoridad para hacer esto?\"."},
    {"Marcos", "Mc", 11, 29, "Jesus les replico: \"Os voy a hacer una pregunta y, si me contestais, os dire con que autoridad hago esto."},
    {"Marcos", "Mc", 11, 30, "El bautismo de Juan era del cielo o de los hombres? Contestadme\"."},
    {"Marcos", "Mc", 11, 31, "Se pusieron a deliberar: \"Si decimos que es del cielo, dira: \"Y por que no le habeis creido?\"."},
    {"Marcos", "Mc", 11, 32, "Pero como vamos a decir que es de los hombres?\". (Temian a la gente, porque todo el mundo estaba convencido de que Juan era un profeta)."},
    {"Marcos", "Mc", 11, 33, "Y respondieron a Jesus: \"No sabemos\". Jesus les replico: \"Pues tampoco yo os digo con que autoridad hago esto\"."},
    {"Marcos", "Mc", 12, 1, "Se puso a hablarles en parabolas: \"Un hombre planto una vi\177a, la rodeo con una cerca, cavo un lagar, construyo una torre, la arrendo a unos labradores y se marcho lejos."},
    {"Marcos", "Mc", 12, 2, "A su tiempo, envio un criado a los labradores, para percibir su tanto del fruto de la vi\177a."},
    {"Marcos", "Mc", 12, 3, "Ellos lo agarraron, lo azotaron y lo despidieron con las manos vacias."},
    {"Marcos", "Mc", 12, 4, "Les envio de nuevo otro criado; a este lo descalabraron e insultaron."},
    {"Marcos", "Mc", 12, 5, "Envio a otro y lo mataron; y a otros muchos, a los que azotaron o los mataron."},
    {"Marcos", "Mc", 12, 6, "Le quedaba uno, su hijo amado. Y lo envio el ultimo, pensando: \"Respetaran a mi hijo\"."},
    {"Marcos", "Mc", 12, 7, "Pero los labradores se dijeron: \"Este es el heredero. Venga, lo matamos y sera nuestra la herencia\"."},
    {"Marcos", "Mc", 12, 8, "Y, agarrandolo, lo mataron y lo arrojaron fuera de la vi\177a."},
    {"Marcos", "Mc", 12, 9, "Que hara el due\177o de la vi\177a? Vendra, hara perecer a los labradores y arrendara la vi\177a a otros."},
    {"Marcos", "Mc", 12, 10, "No habeis leido aquel texto de la Escritura: \"La piedra que desecharon los arquitectos es ahora la piedra angular."},
    {"Marcos", "Mc", 12, 11, "Es el Se\177or quien lo ha hecho, ha sido un milagro patente\"?\"."},
    {"Marcos", "Mc", 12, 12, "Intentaron echarle mano, porque comprendieron que habia dicho la parabola por ellos; pero temieron a la gente y, dejandolo alli, se marcharon."},
    {"Marcos", "Mc", 12, 13, "Le envian algunos de los fariseos y de los herodianos, para cazarlo con una pregunta."},
    {"Marcos", "Mc", 12, 14, "Se acercaron y le dijeron: \"Maestro, sabemos que eres veraz y no te preocupa lo que digan; porque no te fijas en apariencias, sino que ense\177as el camino de Dios conforme a la verdad. Es licito pagar impuesto al Cesar o no? Pagamos o no pagamos?\"."},
    {"Marcos", "Mc", 12, 15, "Adivinando su hipocresia, les replico: \"Por que me tentais? Traedme un denario, que lo vea\"."},
    {"Marcos", "Mc", 12, 16, "Se lo trajeron. Y el les pregunto: \"De quien es esta imagen y esta inscripcion?\". Le contestaron: \"Del Cesar\"."},
    {"Marcos", "Mc", 12, 17, "Jesus les replico: \"Dad al Cesar lo que es del Cesar y a Dios lo que es de Dios\". Y se quedaron admirados."},
    {"Marcos", "Mc", 12, 18, "Se le acercan unos saduceos, los cuales dicen que no hay resurreccion, y le preguntan:"},
    {"Marcos", "Mc", 12, 19, "\"Maestro, Moises nos dejo escrito: \"Si a uno se le muere su hermano, dejando mujer pero no hijos, que se case con la viuda y de descendencia a su hermano\"."},
    {"Marcos", "Mc", 12, 20, "Pues bien, habia siete hermanos: el primero se caso y murio sin hijos;"},
    {"Marcos", "Mc", 12, 21, "el segundo se caso con la viuda y murio tambien sin hijos; lo mismo el tercero;"},
    {"Marcos", "Mc", 12, 22, "y ninguno de los siete dejo hijos. Por ultimo murio la mujer."},
    {"Marcos", "Mc", 12, 23, "Cuando llegue la resurreccion y resuciten, de cual de ellos sera mujer? Porque los siete han estado casados con ella\"."},
    {"Marcos", "Mc", 12, 24, "Jesus les respondio: \"No estais equivocados, por no entender la Escritura ni el poder de Dios?"},
    {"Marcos", "Mc", 12, 25, "Pues cuando resuciten, ni los hombres se casaran ni las mujeres seran dadas en matrimonio, seran como angeles del cielo."},
    {"Marcos", "Mc", 12, 26, "Y a proposito de que los muertos resucitan, no habeis leido en el libro de Moises, en el episodio de la zarza, lo que le dijo Dios: \"Yo soy el Dios de Abrahan, el Dios de Isaac, el Dios de Jacob\"?"},
    {"Marcos", "Mc", 12, 27, "No es Dios de muertos, sino de vivos. Estais muy equivocados\"."},
    {"Marcos", "Mc", 12, 28, "Un escriba que oyo la discusion, viendo lo acertado de la respuesta, se acerco y le pregunto: \"Que mandamiento es el primero de todos?\"."},
    {"Marcos", "Mc", 12, 29, "Respondio Jesus: \"El primero es: \"Escucha, Israel, el Se\177or, nuestro Dios, es el unico Se\177or:"},
    {"Marcos", "Mc", 12, 30, "amaras al Se\177or, tu Dios, con todo tu corazon, con toda tu alma, con toda tu mente, con todo tu ser\"."},
    {"Marcos", "Mc", 12, 31, "El segundo es este: \"Amaras a tu projimo como a ti mismo\". No hay mandamiento mayor que estos\"."},
    {"Marcos", "Mc", 12, 32, "El escriba replico: \"Muy bien, Maestro, sin duda tienes razon cuando dices que el Se\177or es uno solo y no hay otro fuera de el;"},
    {"Marcos", "Mc", 12, 33, "y que amarlo con todo el corazon, con todo el entendimiento y con todo el ser, y amar al projimo como a uno mismo vale mas que todos los holocaustos y sacrificios\"."},
    {"Marcos", "Mc", 12, 34, "Jesus, viendo que habia respondido sensatamente, le dijo: \"No estas lejos del reino de Dios\". Y nadie se atrevio a hacerle mas preguntas."},
    {"Marcos", "Mc", 12, 35, "Mientras ense\177aba en el templo, Jesus pregunto: \"Como dicen los escribas que el Mesias es hijo de David?"},
    {"Marcos", "Mc", 12, 36, "El mismo David, movido por el Espiritu Santo, dice: \"Dijo el Se\177or a mi Se\177or: sientate a mi derecha, y hare de tus enemigos estrado de tus pies\"."},
    {"Marcos", "Mc", 12, 37, "Si el mismo David lo llama Se\177or, como puede ser hijo suyo?\". Una muchedumbre numerosa le escuchaba a gusto."},
    {"Marcos", "Mc", 12, 38, "Y el, instruyendolos, les decia: \"Cuidado con los escribas! Les encanta pasearse con amplio ropaje y que les hagan reverencias en las plazas,"},
    {"Marcos", "Mc", 12, 39, "buscan los asientos de honor en las sinagogas y los primeros puestos en los banquetes;"},
    {"Marcos", "Mc", 12, 40, "y devoran los bienes de las viudas y aparentan hacer largas oraciones. Esos recibiran una condenacion mas rigurosa\"."},
    {"Marcos", "Mc", 12, 41, "Estando Jesus sentado enfrente del tesoro del templo, observaba a la gente que iba echando dinero: muchos ricos echaban mucho;"},
    {"Marcos", "Mc", 12, 42, "se acerco una viuda pobre y echo dos monedillas, es decir, un cuadrante."},
    {"Marcos", "Mc", 12, 43, "Llamando a sus discipulos, les dijo: \"En verdad os digo que esta viuda pobre ha echado en el arca de las ofrendas mas que nadie."},
    {"Marcos", "Mc", 12, 44, "Porque los demas han echado de lo que les sobra, pero esta, que pasa necesidad, ha echado todo lo que tenia para vivir\"."},
    {"Marcos", "Mc", 13, 1, "Y cuando salia del templo le dijo uno de sus discipulos: \"Maestro, mira que piedras y que edificaciones\"."},
    {"Marcos", "Mc", 13, 2, "Jesus le respondio: \"Ves esos grandes edificios?; pues seran destruidos, sin que quede piedra sobre piedra\"."},
    {"Marcos", "Mc", 13, 3, "Y sentado en el monte de los Olivos, enfrente del templo, le preguntaron Pedro, Santiago, Juan y Andres en privado:"},
    {"Marcos", "Mc", 13, 4, "\"Dinos, cuando sucederan estas cosas?, y cual sera el signo de que todo esto esta para cumplirse?\"."},
    {"Marcos", "Mc", 13, 5, "Jesus empezo a decirles: \"Estad atentos para que nadie os enga\177e."},
    {"Marcos", "Mc", 13, 6, "Vendran muchos en mi nombre, diciendo: \"Yo soy\", y enga\177aran a muchos."},
    {"Marcos", "Mc", 13, 7, "Cuando oigais hablar de guerras y noticias de guerra, no os alarmeis. Todo esto ha de suceder, pero no es todavia el final;"},
    {"Marcos", "Mc", 13, 8, "se levantara pueblo contra pueblo y reino contra reino, habra terremotos en diversos lugares, habra hambres. Todo esto sera el comienzo de los dolores."},
    {"Marcos", "Mc", 13, 9, "Mirad por vosotros mismos. Os entregaran a los tribunales, sereis azotados en las sinagogas y comparecereis ante gobernadores y reyes por mi causa, para dar testimonio ante ellos."},
    {"Marcos", "Mc", 13, 10, "Es necesario que se anuncie antes el Evangelio a todos los pueblos."},
    {"Marcos", "Mc", 13, 11, "Pero cuando os conduzcan para entregaros, no os preocupeis por lo que habreis de decir; decid lo que se os inspire en aquel momento. Porque no sereis vosotros los que hableis sino el Espiritu Santo."},
    {"Marcos", "Mc", 13, 12, "Y entregara a la muerte el hermano al hermano y el padre al hijo, y se levantaran hijos contra padres y se daran muerte;"},
    {"Marcos", "Mc", 13, 13, "y sereis odiados por todos a causa de mi nombre, pero quien persevere hasta el fin se salvara."},
    {"Marcos", "Mc", 13, 14, "Cuando veais la abominacion de la desolacion erigida donde no debe (el que lee, que entienda), entonces los que viven en Judea huyan a los montes,"},
    {"Marcos", "Mc", 13, 15, "el que este en la azotea no baje y no entre en casa a coger nada,"},
    {"Marcos", "Mc", 13, 16, "y el que este en el campo no vuelva a recoger su manto."},
    {"Marcos", "Mc", 13, 17, "Ay de las que esten encintas o criando en aquellos dias!"},
    {"Marcos", "Mc", 13, 18, "Orad para que no suceda en invierno."},
    {"Marcos", "Mc", 13, 19, "Porque aquellos dias habra una tribulacion como jamas ha sucedido desde el principio de la creacion, que Dios ha creado, hasta hoy, ni la volvera a haber."},
    {"Marcos", "Mc", 13, 20, "Si el Se\177or no acortase aquellos dias, nadie podra salvarse. Pero en atencion a los elegidos que escogio se abreviaran."},
    {"Marcos", "Mc", 13, 21, "Y si entonces alguno os dice: \"El Mesias esta aqui o alli\", no le creais."},
    {"Marcos", "Mc", 13, 22, "Porque surgiran falsos mesias y falsos profetas, que haran signos y portentos para enga\177ar, si fuera posible, a los elegidos."},
    {"Marcos", "Mc", 13, 23, "Pero vosotros estad atentos, que os he prevenido."},
    {"Marcos", "Mc", 13, 24, "En aquellos dias, despues de esa gran angustia, el sol se oscurecera, la luna no dara su resplandor,"},
    {"Marcos", "Mc", 13, 25, "las estrellas caeran del cielo, los astros se tambalearan."},
    {"Marcos", "Mc", 13, 26, "Entonces veran venir al Hijo del hombre sobre las nubes con gran poder y gloria;"},
    {"Marcos", "Mc", 13, 27, "enviara a los angeles y reunira a sus elegidos de los cuatro vientos, desde el extremo de la tierra hasta el extremo del cielo."},
    {"Marcos", "Mc", 13, 28, "Aprended de esta parabola de la higuera: cuando las ramas se ponen tiernas y brotan las yemas, deducis que el verano esta cerca;"},
    {"Marcos", "Mc", 13, 29, "pues cuando veais vosotros que esto sucede, sabed que el esta cerca, a la puerta."},
    {"Marcos", "Mc", 13, 30, "En verdad os digo que no pasara esta generacion sin que todo suceda."},
    {"Marcos", "Mc", 13, 31, "El cielo y la tierra pasaran, pero mis palabras no pasaran."},
    {"Marcos", "Mc", 13, 32, "En cuanto al dia y la hora, nadie lo conoce, ni los angeles del cielo ni el Hijo, solo el Padre."},
    {"Marcos", "Mc", 13, 33, "Estad atentos, vigilad: pues no sabeis cuando es el momento."},
    {"Marcos", "Mc", 13, 34, "Es igual que un hombre que se fue de viaje, y dejo su casa y dio a cada uno de sus criados su tarea, encargando al portero que velara."},
    {"Marcos", "Mc", 13, 35, "Velad entonces, pues no sabeis cuando vendra el se\177or de la casa, si al atardecer, o a medianoche, o al canto del gallo, o al amanecer:"},
    {"Marcos", "Mc", 13, 36, "no sea que venga inesperadamente y os encuentre dormidos."},
    {"Marcos", "Mc", 13, 37, "Lo que os digo a vosotros, lo digo a todos: Velad!\"."},
    {"Marcos", "Mc", 14, 1, "Faltaban dos dias para la Pascua y los Acimos. Los sumos sacerdotes y los escribas andaban buscando como prender a Jesus a traicion y darle muerte."},
    {"Marcos", "Mc", 14, 2, "Pero decian: \"No durante las fiestas; podria amotinarse el pueblo\"."},
    {"Marcos", "Mc", 14, 3, "Estando Jesus en Betania, en casa de Simon, el leproso, sentado a la mesa, llego una mujer con un frasco de perfume muy caro, de nardo puro; quebro el frasco y se lo derramo sobre la cabeza."},
    {"Marcos", "Mc", 14, 4, "Algunos comentaban indignados: \"A que viene este derroche de perfume?"},
    {"Marcos", "Mc", 14, 5, "Se podia haber vendido por mas de trescientos denarios para darselo a los pobres\". Y reprendian a la mujer."},
    {"Marcos", "Mc", 14, 6, "Pero Jesus replico: \"Dejadla, por que la molestais? Una obra buena ha hecho conmigo."},
    {"Marcos", "Mc", 14, 7, "Porque a los pobres los teneis siempre con vosotros y podeis socorrerlos cuando querais; pero a mi no me teneis siempre."},
    {"Marcos", "Mc", 14, 8, "Ella ha hecho lo que podia: se ha adelantado a embalsamar mi cuerpo para la sepultura."},
    {"Marcos", "Mc", 14, 9, "En verdad os digo que, en cualquier parte del mundo donde se proclame el Evangelio, se hablara de lo que esta ha hecho, para memoria suya\"."},
    {"Marcos", "Mc", 14, 10, "Judas Iscariote, uno de los Doce, fue a los sumos sacerdotes para entregarselo."},
    {"Marcos", "Mc", 14, 11, "Al oirlo, se alegraron y le prometieron darle dinero. El andaba buscando ocasion propicia para entregarlo."},
    {"Marcos", "Mc", 14, 12, "El primer dia de los Acimos, cuando se sacrificaba el cordero pascual, le dijeron a Jesus sus discipulos: \"Donde quieres que vayamos a prepararte la cena de Pascua?\"."},
    {"Marcos", "Mc", 14, 13, "El envio a dos discipulos diciendoles: \"Id a la ciudad, os saldra al paso un hombre que lleva un cantaro de agua; seguidlo,"},
    {"Marcos", "Mc", 14, 14, "y en la casa adonde entre, decidle al due\177o: \"El Maestro pregunta: Cual es la habitacion donde voy a comer la Pascua con mis discipulos?\"."},
    {"Marcos", "Mc", 14, 15, "Os ense\177ara una habitacion grande en el piso de arriba, acondicionada y dispuesta. Preparadnosla alli\"."},
    {"Marcos", "Mc", 14, 16, "Los discipulos se marcharon, llegaron a la ciudad, encontraron lo que les habia dicho y prepararon la Pascua."},
    {"Marcos", "Mc", 14, 17, "Al atardecer fue el con los Doce."},
    {"Marcos", "Mc", 14, 18, "Mientras estaban a la mesa comiendo dijo Jesus: \"En verdad os digo que uno de vosotros me va a entregar: uno que esta comiendo conmigo\"."},
    {"Marcos", "Mc", 14, 19, "Ellos comenzaron a entristecerse y a preguntarle uno tras otro: \"Sere yo?\"."},
    {"Marcos", "Mc", 14, 20, "Respondio: \"Uno de los Doce, el que esta mojando en la misma fuente que yo."},
    {"Marcos", "Mc", 14, 21, "El Hijo del hombre se va, como esta escrito; pero, ay de aquel hombre por quien el Hijo del hombre sera entregado!; mas le valdria a ese hombre no haber nacido!\"."},
    {"Marcos", "Mc", 14, 22, "Mientras comian, tomo pan y, pronunciando la bendicion, lo partio y se lo dio diciendo: \"Tomad, esto es mi cuerpo\"."},
    {"Marcos", "Mc", 14, 23, "Despues tomo el caliz, pronuncio la accion de gracias, se lo dio y todos bebieron."},
    {"Marcos", "Mc", 14, 24, "Y les dijo: \"Esta es mi sangre de la alianza, que es derramada por muchos."},
    {"Marcos", "Mc", 14, 25, "En verdad os digo que no volvere a beber del fruto de la vid hasta el dia que beba el vino nuevo en el reino de Dios\"."},
    {"Marcos", "Mc", 14, 26, "Despues de cantar el himno, salieron para el monte de los Olivos."},
    {"Marcos", "Mc", 14, 27, "Jesus les dijo: \"Todos os escandalizareis, como esta escrito: \"Herire al pastor y se dispersaran las ovejas\"."},
    {"Marcos", "Mc", 14, 28, "Pero cuando resucite, ire delante de vosotros a Galilea\"."},
    {"Marcos", "Mc", 14, 29, "Pedro le replico: \"Aunque todos caigan, yo no\"."},
    {"Marcos", "Mc", 14, 30, "Jesus le dice: \"En verdad te digo que hoy, esta misma noche, antes que el gallo cante dos veces, tu me habras negado tres\"."},
    {"Marcos", "Mc", 14, 31, "Pero el insistia: \"Aunque tenga que morir contigo, no te negare\". Y los demas decian lo mismo."},
    {"Marcos", "Mc", 14, 32, "Llegan a un huerto, que llaman Getsemani, y dice a sus discipulos: \"Sentaos aqui mientras voy a orar\"."},
    {"Marcos", "Mc", 14, 33, "Se lleva consigo a Pedro, a Santiago y a Juan, empezo a sentir espanto y angustia, y les dice:"},
    {"Marcos", "Mc", 14, 34, "\"Mi alma esta triste hasta la muerte. Quedaos aqui y velad\"."},
    {"Marcos", "Mc", 14, 35, "Y, adelantandose un poco, cayo en tierra y rogaba que, si era posible, se alejase de el aquella hora;"},
    {"Marcos", "Mc", 14, 36, "y decia: \"Abba!, Padre: tu lo puedes todo, aparta de mi este caliz. Pero no sea como yo quiero, sino como tu quieres\"."},
    {"Marcos", "Mc", 14, 37, "Vuelve y, al encontrarlos dormidos, dice a Pedro: \"Simon duermes?, no has podido velar una hora?"},
    {"Marcos", "Mc", 14, 38, "Velad y orad, para no caer en tentacion; el espiritu esta pronto, pero la carne es debil\"."},
    {"Marcos", "Mc", 14, 39, "De nuevo se aparto y oraba repitiendo las mismas palabras."},
    {"Marcos", "Mc", 14, 40, "Volvio y los encontro otra vez dormidos, porque sus ojos se les cerraban. Y no sabian que contestarle."},
    {"Marcos", "Mc", 14, 41, "Vuelve por tercera vez y les dice: \"Ya podeis dormir y descansar. Basta! Ha llegado la hora; mirad que el Hijo del hombre va a ser entregado en manos de los pecadores."},
    {"Marcos", "Mc", 14, 42, "Levantaos, vamos! Ya esta cerca el que me entrega\"."},
    {"Marcos", "Mc", 14, 43, "Todavia estaba hablando, cuando se presenta Judas, uno de los Doce, y con el gente con espadas y palos, mandada por los sumos sacerdotes, los escribas y los ancianos."},
    {"Marcos", "Mc", 14, 44, "El traidor les habia dado una contrase\177a, diciendoles: \"Al que yo bese, es el: prendedlo y conducidlo bien sujeto\"."},
    {"Marcos", "Mc", 14, 45, "Y en cuanto llego, acercandosele le dice: \"Rabbi!\". Y lo beso."},
    {"Marcos", "Mc", 14, 46, "Ellos le echaron mano y lo prendieron."},
    {"Marcos", "Mc", 14, 47, "Pero uno de los presentes, desenvainando la espada, de un golpe le corto la oreja al criado del sumo sacerdote."},
    {"Marcos", "Mc", 14, 48, "Jesus tomo la palabra y les dijo: \"Habeis salido a prenderme con espadas y palos, como si fuera un bandido?"},
    {"Marcos", "Mc", 14, 49, "A diario os estaba ense\177ando en el templo y no me detuvisteis. Pero, que se cumplan las Escrituras\"."},
    {"Marcos", "Mc", 14, 50, "Y todos lo abandonaron y huyeron."},
    {"Marcos", "Mc", 14, 51, "Lo iba siguiendo un muchacho envuelto solo en una sabana; y le echaron mano,"},
    {"Marcos", "Mc", 14, 52, "pero el, soltando la sabana, se les escapo desnudo."},
    {"Marcos", "Mc", 14, 53, "Condujeron a Jesus a casa del sumo sacerdote, y se reunieron todos los sumos sacerdotes y los escribas y los ancianos."},
    {"Marcos", "Mc", 14, 54, "Pedro lo fue siguiendo de lejos, hasta el interior del patio del sumo sacerdote; y se sento con los criados a la lumbre para calentarse."},
    {"Marcos", "Mc", 14, 55, "Los sumos sacerdotes y el Sanedrin en pleno buscaban un testimonio contra Jesus, para condenarlo a muerte; y no lo encontraban."},
    {"Marcos", "Mc", 14, 56, "Pues, aunque muchos daban falso testimonio contra el, los testimonios no concordaban."},
    {"Marcos", "Mc", 14, 57, "Y algunos, poniendose de pie, daban falso testimonio contra el diciendo:"},
    {"Marcos", "Mc", 14, 58, "\"Nosotros le hemos oido decir: \"Yo destruire este templo, edificado por manos humanas, y en tres dias construire otro no edificado por manos humanas\"\"."},
    {"Marcos", "Mc", 14, 59, "Pero ni siquiera en esto concordaban los testimonios."},
    {"Marcos", "Mc", 14, 60, "El sumo sacerdote, levantandose y poniendose en el centro, pregunto a Jesus: \"No tienes nada que responder? Que son estos cargos que presentan contra ti?\"."},
    {"Marcos", "Mc", 14, 61, "Pero el callaba, sin dar respuesta. De nuevo le pregunto el sumo sacerdote: \"Eres tu el Mesias, el Hijo del Bendito?\"."},
    {"Marcos", "Mc", 14, 62, "Jesus contesto: \"Yo soy. Y vereis al Hijo del hombre sentado a la derecha del Poder y que viene entre las nubes del cielo\"."},
    {"Marcos", "Mc", 14, 63, "El sumo sacerdote, rasgandose las vestiduras, dice: \"Que necesidad tenemos ya de testigos?\""},
    {"Marcos", "Mc", 14, 64, "Habeis oido la blasfemia. Que os parece?\". Y todos lo declararon reo de muerte."},
    {"Marcos", "Mc", 14, 65, "Algunos se pusieron a escupirlo y, tapandole la cara, lo abofeteaban y le decian: \"Profetiza\". Y los criados le daban bofetadas."},
    {"Marcos", "Mc", 14, 66, "Mientras Pedro estaba abajo en el patio, llega una criada del sumo sacerdote,"},
    {"Marcos", "Mc", 14, 67, "ve a Pedro calentandose, lo mira fijamente y dice: \"Tambien tu estabas con el Nazareno, con Jesus\"."},
    {"Marcos", "Mc", 14, 68, "El lo nego diciendo: \"Ni se ni entiendo lo que dices\". Salio fuera al zaguan y un gallo canto."},
    {"Marcos", "Mc", 14, 69, "La criada, al verlo, volvio a decir a los presentes: \"Este es uno de ellos\"."},
    {"Marcos", "Mc", 14, 70, "Pero el de nuevo lo negaba. Al poco rato, tambien los presentes decian a Pedro: \"Seguro que eres uno de ellos, pues eres galileo\"."},
    {"Marcos", "Mc", 14, 71, "Pero el se puso a echar maldiciones y a jurar: \"No conozco a ese hombre del que hablais\"."},
    {"Marcos", "Mc", 14, 72, "Y enseguida, por segunda vez, canto el gallo. Pedro se acordo de las palabras que le habia dicho Jesus: \"Antes que el gallo cante dos veces, me habras negado tres\", y rompio a llorar."},
    {"Marcos", "Mc", 15, 1, "Apenas se hizo de dia, los sumos sacerdotes con los ancianos, los escribas y el Sanedrin en pleno, hicieron una reunion. Llevaron atado a Jesus y lo entregaron a Pilato."},
    {"Marcos", "Mc", 15, 2, "Pilato le pregunto: \"Eres tu el rey de los judios?\". El respondio: \"Tu lo dices\"."},
    {"Marcos", "Mc", 15, 3, "Y los sumos sacerdotes lo acusaban de muchas cosas."},
    {"Marcos", "Mc", 15, 4, "Pilato le pregunto de nuevo: \"No contestas nada? Mira de cuantas cosas te acusan\"."},
    {"Marcos", "Mc", 15, 5, "Jesus no contesto mas; de modo que Pilato estaba extra\177ado."},
    {"Marcos", "Mc", 15, 6, "Por la fiesta solia soltarles un preso, el que le pidieran."},
    {"Marcos", "Mc", 15, 7, "Estaba en la carcel un tal Barrabas, con los rebeldes que habian cometido un homicidio en la revuelta."},
    {"Marcos", "Mc", 15, 8, "La muchedumbre que se habia reunido comenzo a pedirle lo que era costumbre."},
    {"Marcos", "Mc", 15, 9, "Pilato les pregunto: \"Quereis que os suelte al rey de los judios?\"."},
    {"Marcos", "Mc", 15, 10, "Pues sabia que los sumos sacerdotes se lo habian entregado por envidia."},
    {"Marcos", "Mc", 15, 11, "Pero los sumos sacerdotes soliviantaron a la gente para que pidieran la libertad de Barrabas."},
    {"Marcos", "Mc", 15, 12, "Pilato tomo de nuevo la palabra y les pregunto: \"Que hago con el que llamais rey de los judios?\"."},
    {"Marcos", "Mc", 15, 13, "Ellos gritaron de nuevo: \"Crucificalo\"."},
    {"Marcos", "Mc", 15, 14, "Pilato les dijo: \"Pues que mal ha hecho?\". Ellos gritaron mas fuerte: \"Crucificalo\"."},
    {"Marcos", "Mc", 15, 15, "Y Pilato, queriendo complacer a la gente, les solto a Barrabas; y a Jesus, despues de azotarlo, lo entrego para que lo crucificaran."},
    {"Marcos", "Mc", 15, 16, "Los soldados se lo llevaron al interior del palacio -al pretorio- y convocaron a toda la compa\177ia."},
    {"Marcos", "Mc", 15, 17, "Lo visten de purpura, le ponen una corona de espinas, que habian trenzado,"},
    {"Marcos", "Mc", 15, 18, "y comenzaron a hacerle el saludo: \"Salve, rey de los judios!\"."},
    {"Marcos", "Mc", 15, 19, "Le golpearon la cabeza con una ca\177a, le escupieron; y, doblando las rodillas, se postraban ante el."},
    {"Marcos", "Mc", 15, 20, "Terminada la burla, le quitaron la purpura y le pusieron su ropa. Y lo sacan para crucificarlo."},
    {"Marcos", "Mc", 15, 21, "Pasaba uno que volvia del campo, Simon de Cirene, el padre de Alejandro y de Rufo; y lo obligan a llevar la cruz."},
    {"Marcos", "Mc", 15, 22, "Y conducen a Jesus al Golgota (que quiere decir lugar de \"la Calavera\"),"},
    {"Marcos", "Mc", 15, 23, "y le ofrecian vino con mirra; pero el no lo acepto."},
    {"Marcos", "Mc", 15, 24, "Lo crucifican y se reparten sus ropas, echandolas a suerte, para ver lo que se llevaba cada uno."},
    {"Marcos", "Mc", 15, 25, "Era la hora tercia cuando lo crucificaron."},
    {"Marcos", "Mc", 15, 26, "En el letrero de la acusacion estaba escrito: \"El rey de los judios\"."},
    {"Marcos", "Mc", 15, 27, "Crucificaron con el a dos bandidos, uno a su derecha y otro a su izquierda."},
    {"Marcos", "Mc", 15, 28, "[\"Asi se cumplio la Escritura que dice: \"Lo consideraron como un malhechor\"\"]"},
    {"Marcos", "Mc", 15, 29, "Los que pasaban lo injuriaban, meneando la cabeza y diciendo: \"Tu que destruyes el templo y lo reconstruyes en tres dias,"},
    {"Marcos", "Mc", 15, 30, "salvate a ti mismo bajando de la cruz\"."},
    {"Marcos", "Mc", 15, 31, "De igual modo, tambien los sumos sacerdotes comentaban entre ellos, burlandose: \"A otros ha salvado y a si mismo no se puede salvar."},
    {"Marcos", "Mc", 15, 32, "Que el Mesias, el rey de Israel, baje ahora de la cruz, para que lo veamos y creamos\". Tambien los otros crucificados lo insultaban."},
    {"Marcos", "Mc", 15, 33, "Al llegar la hora sexta toda la region quedo en tinieblas hasta la hora nona."},
    {"Marcos", "Mc", 15, 34, "Y a la hora nona, Jesus clamo con voz potente: Eloi Eloi, lema sabaqtani (que significa: \"Dios mio, Dios mio, por que me has abandonado?\")."},
    {"Marcos", "Mc", 15, 35, "Algunos de los presentes, al oirlo, decian: \"Mira, llama a Elias\"."},
    {"Marcos", "Mc", 15, 36, "Y uno echo a correr y, empapando una esponja en vinagre, la sujeto a una ca\177a, y le daba de beber diciendo: \"Dejad, a ver si viene Elias a bajarlo\"."},
    {"Marcos", "Mc", 15, 37, "Y Jesus, dando un fuerte grito, expiro."},
    {"Marcos", "Mc", 15, 38, "El velo del templo se rasgo en dos, de arriba abajo."},
    {"Marcos", "Mc", 15, 39, "El centurion, que estaba enfrente, al ver como habia expirado, dijo: \"Verdaderamente este hombre era Hijo de Dios\"."},
    {"Marcos", "Mc", 15, 40, "Habia tambien unas mujeres que miraban desde lejos; entre ellas Maria la Magdalena, Maria la madre de Santiago el Menor y de Joset, y Salome,"},
    {"Marcos", "Mc", 15, 41, "las cuales, cuando estaba en Galilea, lo seguian y servian; y otras muchas que habian subido con el a Jerusalen."},
    {"Marcos", "Mc", 15, 42, "Al anochecer, como era el dia de la Preparacion, vispera del sabado,"},
    {"Marcos", "Mc", 15, 43, "vino Jose de Arimatea, miembro noble del Sanedrin, que tambien aguardaba el reino de Dios; se presento decidido ante Pilato y le pidio el cuerpo de Jesus."},
    {"Marcos", "Mc", 15, 44, "Pilato se extra\177o de que hubiera muerto ya; y, llamando al centurion, le pregunto si hacia mucho tiempo que habia muerto."},
    {"Marcos", "Mc", 15, 45, "Informado por el centurion, concedio el cadaver a Jose."},
    {"Marcos", "Mc", 15, 46, "Este compro una sabana y, bajando a Jesus, lo envolvio en la sabana y lo puso en un sepulcro, excavado en una roca, y rodo una piedra a la entrada del sepulcro."},
    {"Marcos", "Mc", 15, 47, "Maria Magdalena y Maria, la madre de Joset, observaban donde lo ponian."},
    {"Marcos", "Mc", 16, 1, "Pasado el sabado, Maria Magdalena, Maria la de Santiago y Salome compraron aromas para ir a embalsamar a Jesus."},
    {"Marcos", "Mc", 16, 2, "Y muy temprano, el primer dia de la semana, al salir el sol, fueron al sepulcro."},
    {"Marcos", "Mc", 16, 3, "Y se decian unas a otras: \"Quien nos correra la piedra de la entrada del sepulcro?\"."},
    {"Marcos", "Mc", 16, 4, "Al mirar, vieron que la piedra estaba corrida y eso que era muy grande."},
    {"Marcos", "Mc", 16, 5, "Entraron en el sepulcro y vieron a un joven sentado a la derecha, vestido de blanco. Y quedaron aterradas."},
    {"Marcos", "Mc", 16, 6, "El les dijo: \"No tengais miedo. Buscais a Jesus el Nazareno, el crucificado? Ha resucitado. No esta aqui. Mirad el sitio donde lo pusieron."},
    {"Marcos", "Mc", 16, 7, "Pero id a decir a sus discipulos y a Pedro: \"El va por delante de vosotros a Galilea. Alli lo vereis, como os dijo\"\"."},
    {"Marcos", "Mc", 16, 8, "Ellas salieron huyendo del sepulcro, pues estaban temblando y fuera de si. Y no dijeron nada a nadie, del miedo que tenian."},
    {"Marcos", "Mc", 16, 9, "Resucitado al amanecer del primer dia de la semana, se aparecio primero a Maria Magdalena, de la que habia echado siete demonios."},
    {"Marcos", "Mc", 16, 10, "Ella fue a anunciarselo a sus compa\177eros, que estaban de duelo y llorando."},
    {"Marcos", "Mc", 16, 11, "Ellos, al oirle decir que estaba vivo y que lo habia visto, no la creyeron."},
    {"Marcos", "Mc", 16, 12, "Despues se aparecio en figura de otro a dos de ellos que iban caminando al campo."},
    {"Marcos", "Mc", 16, 13, "Tambien ellos fueron a anunciarlo a los demas, pero no los creyeron."},
    {"Marcos", "Mc", 16, 14, "Por ultimo, se aparecio Jesus a los Once, cuando estaban a la mesa, y les echo en cara su incredulidad y dureza de corazon, porque no habian creido a los que lo habian visto resucitado."},
    {"Marcos", "Mc", 16, 15, "Y les dijo: \"Id al mundo entero y proclamad el Evangelio a toda la creacion."},
    {"Marcos", "Mc", 16, 16, "El que crea y sea bautizado se salvara; el que no crea sera condenado."},
    {"Marcos", "Mc", 16, 17, "A los que crean, les acompa\177aran estos signos: echaran demonios en mi nombre, hablaran lenguas nuevas,"},
    {"Marcos", "Mc", 16, 18, "cogeran serpientes en sus manos y, si beben un veneno mortal, no les hara da\177o. Impondran las manos a los enfermos, y quedaran sanos\"."},
    {"Marcos", "Mc", 16, 19, "Despues de hablarles, el Se\177or Jesus fue llevado al cielo y se sento a la derecha de Dios."},
    {"Marcos", "Mc", 16, 20, "Ellos se fueron a predicar por todas partes, y el Se\177or cooperaba confirmando la palabra con las se\177ales que los acompa\177aban."},
    {"Lucas", "Lc", 1, 1, "Puesto que muchos han emprendido la tarea de componer un relato de los hechos que se han cumplido entre nosotros,"},
    {"Lucas", "Lc", 1, 2, "como nos los transmitieron los que fueron desde el principio testigos oculares y servidores de la palabra,"},
    {"Lucas", "Lc", 1, 3, "tambien yo he resuelto escribirtelos por su orden, ilustre Teofilo, despues de investigarlo todo diligentemente desde el principio,"},
    {"Lucas", "Lc", 1, 4, "para que conozcas la solidez de las ense\177anzas que has recibido."},
    {"Lucas", "Lc", 1, 5, "En los dias de Herodes, rey de Judea, habia un sacerdote de nombre Zacarias, del turno de Abias, casado con una descendiente de Aaron, cuyo nombre era Isabel."},
    {"Lucas", "Lc", 1, 6, "Los dos eran justos ante Dios, y caminaban sin falta segun los mandamientos y leyes del Se\177or."},
    {"Lucas", "Lc", 1, 7, "No tenian hijos, porque Isabel era esteril, y los dos eran de edad avanzada."},
    {"Lucas", "Lc", 1, 8, "Una vez que oficiaba delante de Dios con el grupo de su turno,"},
    {"Lucas", "Lc", 1, 9, "segun la costumbre de los sacerdotes, le toco en suerte a el entrar en el santuario del Se\177or a ofrecer el incienso;"},
    {"Lucas", "Lc", 1, 10, "la muchedumbre del pueblo estaba fuera rezando durante la ofrenda del incienso."},
    {"Lucas", "Lc", 1, 11, "Y se le aparecio el angel del Se\177or, de pie a la derecha del altar del incienso."},
    {"Lucas", "Lc", 1, 12, "Al verlo, Zacarias se sobresalto y quedo sobrecogido de temor."},
    {"Lucas", "Lc", 1, 13, "Pero el angel le dijo: \"No temas, Zacarias, porque tu ruego ha sido escuchado: tu mujer Isabel te dara un hijo, y le pondras por nombre Juan."},
    {"Lucas", "Lc", 1, 14, "Te llenaras de alegria y gozo, y muchos se alegraran de su nacimiento."},
    {"Lucas", "Lc", 1, 15, "Pues sera grande a los ojos del Se\177or: no bebera vino ni licor; estara lleno del Espiritu Santo ya en el vientre materno,"},
    {"Lucas", "Lc", 1, 16, "y convertira muchos hijos de Israel al Se\177or, su Dios."},
    {"Lucas", "Lc", 1, 17, "Ira delante del Se\177or, con el espiritu y poder de Elias, para convertir los corazones de los padres hacia los hijos, y a los desobedientes, a la sensatez de los justos, para preparar al Se\177or un pueblo bien dispuesto\"."},
    {"Lucas", "Lc", 1, 18, "Zacarias replico al angel: \"Como estare seguro de eso? Porque yo soy viejo, y mi mujer es de edad avanzada\"."},
    {"Lucas", "Lc", 1, 19, "Respondiendo el angel, le dijo: \"Yo soy Gabriel, que sirvo en presencia de Dios; he sido enviado para hablarte y comunicarte esta buena noticia."},
    {"Lucas", "Lc", 1, 20, "Pero te quedaras mudo, sin poder hablar, hasta el dia en que esto suceda, porque no has dado fe a mis palabras, que se cumpliran en su momento oportuno\"."},
    {"Lucas", "Lc", 1, 21, "El pueblo, que estaba aguardando a Zacarias, se sorprendia de que tardase tanto en el santuario."},
    {"Lucas", "Lc", 1, 22, "Al salir no podia hablarles, y ellos comprendieron que habia tenido una vision en el santuario. El les hablaba por se\177as, porque seguia mudo."},
    {"Lucas", "Lc", 1, 23, "Al cumplirse los dias de su servicio en el templo, volvio a casa."},
    {"Lucas", "Lc", 1, 24, "Dias despues concibio Isabel, su mujer, y estuvo sin salir de casa cinco meses, diciendo:"},
    {"Lucas", "Lc", 1, 25, "\"Esto es lo que ha hecho por mi el Se\177or, cuando se ha fijado en mi para quitar mi oprobio ante la gente\"."},
    {"Lucas", "Lc", 1, 26, "En el mes sexto, el angel Gabriel fue enviado por Dios a una ciudad de Galilea llamada Nazaret,"},
    {"Lucas", "Lc", 1, 27, "a una virgen desposada con un hombre llamado Jose, de la casa de David; el nombre de la virgen era Maria."},
    {"Lucas", "Lc", 1, 28, "El angel, entrando en su presencia, dijo: \"Alegrate, llena de gracia, el Se\177or esta contigo\"."},
    {"Lucas", "Lc", 1, 29, "Ella se turbo grandemente ante estas palabras y se preguntaba que saludo era aquel."},
    {"Lucas", "Lc", 1, 30, "El angel le dijo: \"No temas, Maria, porque has encontrado gracia ante Dios."},
    {"Lucas", "Lc", 1, 31, "Concebiras en tu vientre y daras a luz un hijo, y le pondras por nombre Jesus."},
    {"Lucas", "Lc", 1, 32, "Sera grande, se llamara Hijo del Altisimo, el Se\177or Dios le dara el trono de David, su padre;"},
    {"Lucas", "Lc", 1, 33, "reinara sobre la casa de Jacob para siempre, y su reino no tendra fin\"."},
    {"Lucas", "Lc", 1, 34, "Y Maria dijo al angel: \"Como sera eso, pues no conozco varon?\"."},
    {"Lucas", "Lc", 1, 35, "El angel le contesto: \"El Espiritu Santo vendra sobre ti, y la fuerza del Altisimo te cubrira con su sombra; por eso el Santo que va a nacer sera llamado Hijo de Dios."},
    {"Lucas", "Lc", 1, 36, "Tambien tu pariente Isabel ha concebido un hijo en su vejez, y ya esta de seis meses la que llamaban esteril,"},
    {"Lucas", "Lc", 1, 37, "porque para Dios nada hay imposible\"."},
    {"Lucas", "Lc", 1, 38, "Maria contesto: \"He aqui la esclava del Se\177or; hagase en mi segun tu palabra\". Y el angel se retiro."},
    {"Lucas", "Lc", 1, 39, "En aquellos mismos dias, Maria se levanto y se puso en camino de prisa hacia la monta\177a, a una ciudad de Juda;"},
    {"Lucas", "Lc", 1, 40, "entro en casa de Zacarias y saludo a Isabel."},
    {"Lucas", "Lc", 1, 41, "Acontecio que, en cuanto Isabel oyo el saludo de Maria, salto la criatura en su vientre. Se lleno Isabel de Espiritu Santo"},
    {"Lucas", "Lc", 1, 42, "y, levantando la voz, exclamo: \"Bendita tu entre las mujeres, y bendito el fruto de tu vientre!"},
    {"Lucas", "Lc", 1, 43, "Quien soy yo para que me visite la madre de mi Se\177or?"},
    {"Lucas", "Lc", 1, 44, "Pues, en cuanto tu saludo llego a mis oidos, la criatura salto de alegria en mi vientre."},
    {"Lucas", "Lc", 1, 45, "Bienaventurada la que ha creido, porque lo que le ha dicho el Se\177or se cumplira\"."},
    {"Lucas", "Lc", 1, 46, "Maria dijo: \"Proclama mi alma la grandeza del Se\177or,"},
    {"Lucas", "Lc", 1, 47, "se alegra mi espiritu en Dios, mi salvador;"},
    {"Lucas", "Lc", 1, 48, "porque ha mirado la humildad de su esclava. / Desde ahora me felicitaran todas las generaciones,"},
    {"Lucas", "Lc", 1, 49, "porque el Poderoso ha hecho obras grandes en mi: / su nombre es santo,"},
    {"Lucas", "Lc", 1, 50, "y su misericordia llega a sus fieles de generacion en generacion."},
    {"Lucas", "Lc", 1, 51, "El hace proezas con su brazo: / dispersa a los soberbios de corazon,"},
    {"Lucas", "Lc", 1, 52, "derriba del trono a los poderosos / y enaltece a los humildes,"},
    {"Lucas", "Lc", 1, 53, "a los hambrientos los colma de bienes / y a los ricos los despide vacios."},
    {"Lucas", "Lc", 1, 54, "Auxilia a Israel, su siervo, acordandose de la misericordia"},
    {"Lucas", "Lc", 1, 55, "-como lo habia prometido a nuestros padres- / en favor de Abrahan y su descendencia por siempre\"."},
    {"Lucas", "Lc", 1, 56, "Maria se quedo con ella unos tres meses y volvio a su casa."},
    {"Lucas", "Lc", 1, 57, "A Isabel se le cumplio el tiempo del parto y dio a luz un hijo."},
    {"Lucas", "Lc", 1, 58, "Se enteraron sus vecinos y parientes de que el Se\177or le habia hecho una gran misericordia, y se alegraban con ella."},
    {"Lucas", "Lc", 1, 59, "A los ocho dias vinieron a circuncidar al ni\177o, y querian llamarlo Zacarias, como su padre;"},
    {"Lucas", "Lc", 1, 60, "pero la madre intervino diciendo: \"No! Se va a llamar Juan\"."},
    {"Lucas", "Lc", 1, 61, "Y le dijeron: \"Ninguno de tus parientes se llama asi\"."},
    {"Lucas", "Lc", 1, 62, "Entonces preguntaban por se\177as al padre como queria que se llamase."},
    {"Lucas", "Lc", 1, 63, "El pidio una tablilla y escribio: \"Juan es su nombre\". Y todos se quedaron maravillados."},
    {"Lucas", "Lc", 1, 64, "Inmediatamente se le solto la boca y la lengua, y empezo a hablar bendiciendo a Dios."},
    {"Lucas", "Lc", 1, 65, "Los vecinos quedaron sobrecogidos, y se comentaban todos estos hechos por toda la monta\177a de Judea."},
    {"Lucas", "Lc", 1, 66, "Y todos los que los oian reflexionaban diciendo: \"Pues que sera este ni\177o?\". Porque la mano del Se\177or estaba con el."},
    {"Lucas", "Lc", 1, 67, "Entonces Zacarias, su padre, se lleno de Espiritu Santo y profetizo diciendo:"},
    {"Lucas", "Lc", 1, 68, "\"Bendito sea el Se\177or, Dios de Israel, / porque ha visitado y redimido a su pueblo,"},
    {"Lucas", "Lc", 1, 69, "suscitandonos una fuerza de salvacion / en la casa de David, su siervo,"},
    {"Lucas", "Lc", 1, 70, "segun lo habia predicho desde antiguo / por boca de sus santos profetas."},
    {"Lucas", "Lc", 1, 71, "Es la salvacion que nos libra de nuestros enemigos / y de la mano de todos los que nos odian;"},
    {"Lucas", "Lc", 1, 72, "realizando la misericordia que tuvo con nuestros padres, / recordando su santa alianza"},
    {"Lucas", "Lc", 1, 73, "y el juramento que juro a nuestro padre Abrahan para concedernos"},
    {"Lucas", "Lc", 1, 74, "que, libres de temor, arrancados de la mano de los enemigos, / le sirvamos"},
    {"Lucas", "Lc", 1, 75, "con santidad y justicia, en su presencia, todos nuestros dias."},
    {"Lucas", "Lc", 1, 76, "Y a ti, ni\177o, te llamaran profeta del Altisimo, / porque iras delante del Se\177or a preparar sus caminos,"},
    {"Lucas", "Lc", 1, 77, "anunciando a su pueblo la salvacion / por el perdon de sus pecados."},
    {"Lucas", "Lc", 1, 78, "Por la entra\177able misericordia de nuestro Dios, / nos visitara el sol que nace de lo alto,"},
    {"Lucas", "Lc", 1, 79, "para iluminar a los que viven en tinieblas y en sombra de muerte, / para guiar nuestros pasos por el camino de la paz\"."},
    {"Lucas", "Lc", 1, 80, "El ni\177o crecia y se fortalecia en el espiritu, y vivia en lugares desiertos hasta los dias de su manifestacion a Israel."},
    {"Lucas", "Lc", 2, 1, "Sucedio en aquellos dias que salio un decreto del emperador Augusto, ordenando que se empadronase todo el Imperio."},
    {"Lucas", "Lc", 2, 2, "Este primer empadronamiento se hizo siendo Cirino gobernador de Siria."},
    {"Lucas", "Lc", 2, 3, "Y todos iban a empadronarse, cada cual a su ciudad."},
    {"Lucas", "Lc", 2, 4, "Tambien Jose, por ser de la casa y familia de David, subio desde la ciudad de Nazaret, en Galilea, a la ciudad de David, que se llama Belen, en Judea,"},
    {"Lucas", "Lc", 2, 5, "para empadronarse con su esposa Maria, que estaba encinta."},
    {"Lucas", "Lc", 2, 6, "Y sucedio que, mientras estaban alli, le llego a ella el tiempo del parto"},
    {"Lucas", "Lc", 2, 7, "y dio a luz a su hijo primogenito, lo envolvio en pa\177ales y lo recosto en un pesebre, porque no habia sitio para ellos en la posada."},
    {"Lucas", "Lc", 2, 8, "En aquella misma region habia unos pastores que pasaban la noche al aire libre, velando por turno su reba\177o."},
    {"Lucas", "Lc", 2, 9, "De repente un angel del Se\177or se les presento; la gloria del Se\177or los envolvio de claridad, y se llenaron de gran temor."},
    {"Lucas", "Lc", 2, 10, "El angel les dijo: \"No temais, os anuncio una buena noticia que sera de gran alegria para todo el pueblo:"},
    {"Lucas", "Lc", 2, 11, "hoy, en la ciudad de David, os ha nacido un Salvador, el Mesias, el Se\177or."},
    {"Lucas", "Lc", 2, 12, "Y aqui teneis la se\177al: encontrareis un ni\177o envuelto en pa\177ales y acostado en un pesebre\"."},
    {"Lucas", "Lc", 2, 13, "De pronto, en torno al angel, aparecio una legion del ejercito celestial, que alababa a Dios diciendo:"},
    {"Lucas", "Lc", 2, 14, "\"Gloria a Dios en el cielo, y en la tierra paz a los hombres de buena voluntad\"."},
    {"Lucas", "Lc", 2, 15, "Y sucedio que, cuando los angeles se marcharon al cielo, los pastores se decian unos a otros: \"Vayamos, pues, a Belen, y veamos lo que ha sucedido y que el Se\177or nos ha comunicado\"."},
    {"Lucas", "Lc", 2, 16, "Fueron corriendo y encontraron a Maria y a Jose, y al ni\177o acostado en el pesebre."},
    {"Lucas", "Lc", 2, 17, "Al verlo, contaron lo que se les habia dicho de aquel ni\177o."},
    {"Lucas", "Lc", 2, 18, "Todos los que lo oian se admiraban de lo que les habian dicho los pastores."},
    {"Lucas", "Lc", 2, 19, "Maria, por su parte, conservaba todas estas cosas, meditandolas en su corazon."},
    {"Lucas", "Lc", 2, 20, "Y se volvieron los pastores dando gloria y alabanza a Dios por todo lo que habian oido y visto, conforme a lo que se les habia dicho."},
    {"Lucas", "Lc", 2, 21, "Cuando se cumplieron los ocho dias para circuncidar al ni\177o, le pusieron por nombre Jesus, como lo habia llamado el angel antes de su concepcion."},
    {"Lucas", "Lc", 2, 22, "Cuando se cumplieron los dias de su purificacion, segun la ley de Moises, lo llevaron a Jerusalen para presentarlo al Se\177or,"},
    {"Lucas", "Lc", 2, 23, "de acuerdo con lo escrito en la ley del Se\177or: \"Todo varon primogenito sera consagrado al Se\177or\","},
    {"Lucas", "Lc", 2, 24, "y para entregar la oblacion, como dice la ley del Se\177or: \"un par de tortolas o dos pichones\"."},
    {"Lucas", "Lc", 2, 25, "Habia entonces en Jerusalen un hombre llamado Simeon, hombre justo y piadoso, que aguardaba el consuelo de Israel; y el Espiritu Santo estaba con el."},
    {"Lucas", "Lc", 2, 26, "Le habia sido revelado por el Espiritu Santo que no veria la muerte antes de ver al Mesias del Se\177or."},
    {"Lucas", "Lc", 2, 27, "Impulsado por el Espiritu, fue al templo. Y cuando entraban con el ni\177o Jesus sus padres para cumplir con el lo acostumbrado segun la ley,"},
    {"Lucas", "Lc", 2, 28, "Simeon lo tomo en brazos y bendijo a Dios diciendo:"},
    {"Lucas", "Lc", 2, 29, "\"Ahora, Se\177or, segun tu promesa, / puedes dejar a tu siervo irse en paz."},
    {"Lucas", "Lc", 2, 30, "Porque mis ojos han visto a tu Salvador,"},
    {"Lucas", "Lc", 2, 31, "a quien has presentado ante todos los pueblos:"},
    {"Lucas", "Lc", 2, 32, "luz para alumbrar a las naciones / y gloria de tu pueblo Israel\"."},
    {"Lucas", "Lc", 2, 33, "Su padre y su madre estaban admirados por lo que se decia del ni\177o."},
    {"Lucas", "Lc", 2, 34, "Simeon los bendijo y dijo a Maria, su madre: \"Este ha sido puesto para que muchos en Israel caigan y se levanten; y sera como un signo de contradiccion"},
    {"Lucas", "Lc", 2, 35, "-y a ti misma una espada te traspasara el alma-, para que se pongan de manifiesto los pensamientos de muchos corazones\"."},
    {"Lucas", "Lc", 2, 36, "Habia tambien una profetisa, Ana, hija de Fanuel, de la tribu de Aser, ya muy avanzada en a\177os. De joven habia vivido siete a\177os casada,"},
    {"Lucas", "Lc", 2, 37, "y luego viuda hasta los ochenta y cuatro; no se apartaba del templo, sirviendo a Dios con ayunos y oraciones noche y dia."},
    {"Lucas", "Lc", 2, 38, "Presentandose en aquel momento, alababa tambien a Dios y hablaba del ni\177o a todos los que aguardaban la liberacion de Jerusalen."},
    {"Lucas", "Lc", 2, 39, "Y, cuando cumplieron todo lo que prescribia la ley del Se\177or, se volvieron a Galilea, a su ciudad de Nazaret."},
    {"Lucas", "Lc", 2, 40, "El ni\177o, por su parte, iba creciendo y robusteciendose, lleno de sabiduria; y la gracia de Dios estaba con el."},
    {"Lucas", "Lc", 2, 41, "Sus padres solian ir cada a\177o a Jerusalen por la fiesta de la Pascua."},
    {"Lucas", "Lc", 2, 42, "Cuando cumplio doce a\177os, subieron a la fiesta segun la costumbre"},
    {"Lucas", "Lc", 2, 43, "y, cuando termino, se volvieron; pero el ni\177o Jesus se quedo en Jerusalen, sin que lo supieran sus padres."},
    {"Lucas", "Lc", 2, 44, "Estos, creyendo que estaba en la caravana, anduvieron el camino de un dia y se pusieron a buscarlo entre los parientes y conocidos;"},
    {"Lucas", "Lc", 2, 45, "al no encontrarlo, se volvieron a Jerusalen buscandolo."},
    {"Lucas", "Lc", 2, 46, "Y sucedio que, a los tres dias, lo encontraron en el templo, sentado en medio de los maestros, escuchandolos y haciendoles preguntas."},
    {"Lucas", "Lc", 2, 47, "Todos los que le oian quedaban asombrados de su talento y de las respuestas que daba."},
    {"Lucas", "Lc", 2, 48, "Al verlo, se quedaron atonitos, y le dijo su madre: \"Hijo, por que nos has tratado asi? Tu padre y yo te buscabamos angustiados\"."},
    {"Lucas", "Lc", 2, 49, "El les contesto: \"Por que me buscabais? No sabiais que yo debia estar en las cosas de mi Padre?\"."},
    {"Lucas", "Lc", 2, 50, "Pero ellos no comprendieron lo que les dijo."},
    {"Lucas", "Lc", 2, 51, "El bajo con ellos y fue a Nazaret y estaba sujeto a ellos. Su madre conservaba todo esto en su corazon."},
    {"Lucas", "Lc", 2, 52, "Y Jesus iba creciendo en sabiduria, en estatura y en gracia ante Dios y ante los hombres."},
    {"Lucas", "Lc", 3, 1, "En el a\177o decimoquinto del imperio del emperador Tiberio, siendo Poncio Pilato gobernador de Judea, y Herodes tetrarca de Galilea, y su hermano Filipo tetrarca de Iturea y Traconitide, y Lisanio tetrarca de Abilene,"},
    {"Lucas", "Lc", 3, 2, "bajo el sumo sacerdocio de Anas y Caifas, vino la palabra de Dios sobre Juan, hijo de Zacarias, en el desierto."},
    {"Lucas", "Lc", 3, 3, "Y recorrio toda la comarca del Jordan, predicando un bautismo de conversion para perdon de los pecados,"},
    {"Lucas", "Lc", 3, 4, "como esta escrito en el libro de los oraculos del profeta Isaias: \"Voz del que grita en el desierto: / Preparad el camino del Se\177or, / allanad sus senderos;"},
    {"Lucas", "Lc", 3, 5, "los valles seran rellenados, / los montes y colinas seran rebajados; / lo torcido sera enderezado, / lo escabroso sera camino llano."},
    {"Lucas", "Lc", 3, 6, "Y toda carne vera la salvacion de Dios\"."},
    {"Lucas", "Lc", 3, 7, "A los que venian para ser bautizados les decia: \"Raza de viboras!, quien os ha ense\177ado a escapar del castigo inminente?"},
    {"Lucas", "Lc", 3, 8, "Dad el fruto que pide la conversion. Y no os hagais ilusiones, pensando: \"Tenemos por padre a Abrahan\", pues os digo que Dios es capaz de sacar de estas piedras hijos de Abrahan."},
    {"Lucas", "Lc", 3, 9, "Ya toca el hacha la raiz de los arboles, y todo arbol que no de buen fruto sera talado y echado al fuego\"."},
    {"Lucas", "Lc", 3, 10, "La gente le preguntaba: \"Entonces, que debemos hacer?\"."},
    {"Lucas", "Lc", 3, 11, "El contestaba: \"El que tenga dos tunicas, que comparta con el que no tiene; y el que tenga comida, haga lo mismo\"."},
    {"Lucas", "Lc", 3, 12, "Vinieron tambien a bautizarse unos publicanos y le preguntaron: \"Maestro, que debemos hacer nosotros?\"."},
    {"Lucas", "Lc", 3, 13, "El les contesto: \"No exijais mas de lo establecido\"."},
    {"Lucas", "Lc", 3, 14, "Unos soldados igualmente le preguntaban: \"Y nosotros, que debemos hacer?\". El les contesto: \"No hagais extorsion ni os aprovecheis de nadie con falsas denuncias, sino contentaos con la paga\"."},
    {"Lucas", "Lc", 3, 15, "Como el pueblo estaba expectante, y todos se preguntaban en su interior sobre Juan si no seria el Mesias,"},
    {"Lucas", "Lc", 3, 16, "Juan les respondio dirigiendose a todos: \"Yo os bautizo con agua; pero viene el que es mas fuerte que yo, a quien no merezco desatarle la correa de sus sandalias. El os bautizara con Espiritu Santo y fuego;"},
    {"Lucas", "Lc", 3, 17, "en su mano tiene el bieldo para aventar su parva, reunir su trigo en el granero y quemar la paja en una hoguera que no se apaga\"."},
    {"Lucas", "Lc", 3, 18, "Con estas y otras muchas exhortaciones, anunciaba al pueblo el Evangelio."},
    {"Lucas", "Lc", 3, 19, "El tetrarca Herodes, a quien Juan reprendia por el asunto de Herodias, esposa de su hermano, y por todas las maldades que habia hecho,"},
    {"Lucas", "Lc", 3, 20, "a\177adio a todas ellas la de encerrar a Juan en la carcel."},
    {"Lucas", "Lc", 3, 21, "Y sucedio que, cuando todo el pueblo era bautizado, tambien Jesus fue bautizado; y, mientras oraba, se abrieron los cielos,"},
    {"Lucas", "Lc", 3, 22, "bajo el Espiritu Santo sobre el con apariencia corporal semejante a una paloma y vino una voz del cielo: \"Tu eres mi Hijo, el amado; en ti me complazco\"."},
    {"Lucas", "Lc", 3, 23, "Jesus, al empezar, tenia unos treinta a\177os, y se pensaba que era hijo de Jose, que a su vez era de Heli,"},
    {"Lucas", "Lc", 3, 24, "de Matat, de Levi, de Melqui, de Jannai, de Jose,"},
    {"Lucas", "Lc", 3, 25, "de Matatias, de Amos, de Nahun, de Esli, de Nagai,"},
    {"Lucas", "Lc", 3, 26, "de Maat, de Matatias, de Semein, de Josec, de Joda,"},
    {"Lucas", "Lc", 3, 27, "de Joanan, de Resa, de Zorobabel, de Salatiel, de Neri,"},
    {"Lucas", "Lc", 3, 28, "de Melqui, de Addi, de Cosan, de Elmadan, de Er,"},
    {"Lucas", "Lc", 3, 29, "de Jesus, de Eliezer, de Jorin, de Matat, de Levi,"},
    {"Lucas", "Lc", 3, 30, "de Simeon, de Juda, de Jose, de Jonan, de Eliacin,"},
    {"Lucas", "Lc", 3, 31, "de Melea, de Mena, de Matata, de Natan, de David,"},
    {"Lucas", "Lc", 3, 32, "de Jese, de Jobed, de Booz, de Sala, de Naason,"},
    {"Lucas", "Lc", 3, 33, "de Aminadab, de Admin, de Arni, de Esron, de Fares, de Juda,"},
    {"Lucas", "Lc", 3, 34, "de Jacob, de Isaac, de Abrahan, de Tare, de Nacor,"},
    {"Lucas", "Lc", 3, 35, "de Seruc, de Ragau, de Falec, de Eber, de Sala,"},
    {"Lucas", "Lc", 3, 36, "de Cainan, de Arfaxad, de Sem, de Noe, de Lamec,"},
    {"Lucas", "Lc", 3, 37, "de Matusalen, de Henoc, de Jaret, de Maleleel, de Cainan,"},
    {"Lucas", "Lc", 3, 38, "de Enos, de Set, de Adan, de Dios."},
    {"Lucas", "Lc", 4, 1, "Jesus, lleno del Espiritu Santo, volvio del Jordan y el Espiritu lo fue llevando"},
    {"Lucas", "Lc", 4, 2, "durante cuarenta dias por el desierto, mientras era tentado por el diablo. En todos aquellos dias estuvo sin comer y, al final, sintio hambre."},
    {"Lucas", "Lc", 4, 3, "Entonces el diablo le dijo: \"Si eres Hijo de Dios, di a esta piedra que se convierta en pan\"."},
    {"Lucas", "Lc", 4, 4, "Jesus le contesto: \"Esta escrito: \"No solo de pan vive el hombre\"\"."},
    {"Lucas", "Lc", 4, 5, "Despues, llevandole a lo alto, el diablo le mostro en un instante todos los reinos del mundo"},
    {"Lucas", "Lc", 4, 6, "y le dijo: \"Te dare el poder y la gloria de todo eso, porque a mi me ha sido dado, y yo lo doy a quien quiero."},
    {"Lucas", "Lc", 4, 7, "Si tu te arrodillas delante de mi, todo sera tuyo\"."},
    {"Lucas", "Lc", 4, 8, "Respondiendo Jesus, le dijo: \"Esta escrito: \"Al Se\177or, tu Dios, adoraras y a el solo daras culto\"\"."},
    {"Lucas", "Lc", 4, 9, "Entonces lo llevo a Jerusalen y lo puso en el alero del templo y le dijo: \"Si eres Hijo de Dios, tirate de aqui abajo,"},
    {"Lucas", "Lc", 4, 10, "porque esta escrito: \"Ha dado ordenes a sus angeles acerca de ti, para que te cuiden\","},
    {"Lucas", "Lc", 4, 11, "y tambien: \"Te sostendran en sus manos, para que tu pie no tropiece contra ninguna piedra\"\"."},
    {"Lucas", "Lc", 4, 12, "Respondiendo Jesus, le dijo: \"Esta escrito: \"No tentaras al Se\177or, tu Dios\"\"."},
    {"Lucas", "Lc", 4, 13, "Acabada toda tentacion, el demonio se marcho hasta otra ocasion."},
    {"Lucas", "Lc", 4, 14, "Jesus volvio a Galilea con la fuerza del Espiritu; y su fama se extendio por toda la comarca."},
    {"Lucas", "Lc", 4, 15, "Ense\177aba en las sinagogas, y todos lo alababan."},
    {"Lucas", "Lc", 4, 16, "Fue a Nazaret, donde se habia criado, entro en la sinagoga, como era su costumbre los sabados, y se puso en pie para hacer la lectura."},
    {"Lucas", "Lc", 4, 17, "Le entregaron el rollo del profeta Isaias y, desenrollandolo, encontro el pasaje donde estaba escrito:"},
    {"Lucas", "Lc", 4, 18, "\"El Espiritu del Se\177or esta sobre mi, porque el me ha ungido. Me ha enviado a evangelizar a los pobres, a proclamar a los cautivos la libertad, y a los ciegos, la vista; a poner en libertad a los oprimidos;"},
    {"Lucas", "Lc", 4, 19, "a proclamar el a\177o de gracia del Se\177or\"."},
    {"Lucas", "Lc", 4, 20, "Y, enrollando el rollo y devolviendolo al que lo ayudaba, se sento. Toda la sinagoga tenia los ojos clavados en el."},
    {"Lucas", "Lc", 4, 21, "Y el comenzo a decirles: \"Hoy se ha cumplido esta Escritura que acabais de oir\"."},
    {"Lucas", "Lc", 4, 22, "Y todos le expresaban su aprobacion y se admiraban de las palabras de gracia que salian de su boca. Y decian: \"No es este el hijo de Jose?\"."},
    {"Lucas", "Lc", 4, 23, "Pero Jesus les dijo: \"Sin duda me direis aquel refran: \"Medico, curate a ti mismo\", haz tambien aqui, en tu pueblo, lo que hemos oido que has hecho en Cafarnaun\"."},
    {"Lucas", "Lc", 4, 24, "Y a\177adio: \"En verdad os digo que ningun profeta es aceptado en su pueblo."},
    {"Lucas", "Lc", 4, 25, "Puedo aseguraros que en Israel habia muchas viudas en los dias de Elias, cuando estuvo cerrado el cielo tres a\177os y seis meses y hubo una gran hambre en todo el pais;"},
    {"Lucas", "Lc", 4, 26, "sin embargo, a ninguna de ellas fue enviado Elias sino a una viuda de Sarepta, en el territorio de Sidon."},
    {"Lucas", "Lc", 4, 27, "Y muchos leprosos habia en Israel en tiempos del profeta Eliseo, sin embargo, ninguno de ellos fue curado sino Naaman, el sirio\"."},
    {"Lucas", "Lc", 4, 28, "Al oir esto, todos en la sinagoga se pusieron furiosos"},
    {"Lucas", "Lc", 4, 29, "y, levantandose, lo echaron fuera del pueblo y lo llevaron hasta un precipicio del monte sobre el que estaba edificado su pueblo, con intencion de despe\177arlo."},
    {"Lucas", "Lc", 4, 30, "Pero Jesus se abrio paso entre ellos y seguia su camino."},
    {"Lucas", "Lc", 4, 31, "Y bajo a Cafarnaun, ciudad de Galilea, y los sabados les ense\177aba."},
    {"Lucas", "Lc", 4, 32, "Se quedaban asombrados de su ense\177anza, porque su palabra estaba llena de autoridad."},
    {"Lucas", "Lc", 4, 33, "Habia en la sinagoga un hombre poseido por un espiritu de demonio inmundo y se puso a gritar con fuerte voz:"},
    {"Lucas", "Lc", 4, 34, "\"Basta! Que tenemos que ver nosotros contigo, Jesus Nazareno? Has venido a acabar con nosotros? Se quien eres: el Santo de Dios\"."},
    {"Lucas", "Lc", 4, 35, "Pero Jesus le increpo diciendo: \"Callate y sal de el!\". Entonces el demonio, tirando al hombre por tierra en medio de la gente, salio sin hacerle da\177o."},
    {"Lucas", "Lc", 4, 36, "Quedaron todos asombrados y comentaban entre si: \"Que clase de palabra es esta? Pues da ordenes con autoridad y poder a los espiritus inmundos, y salen\"."},
    {"Lucas", "Lc", 4, 37, "Y su fama se difundia por todos los lugares de la comarca."},
    {"Lucas", "Lc", 4, 38, "Al salir Jesus de la sinagoga, entro en la casa de Simon. La suegra de Simon estaba con fiebre muy alta y le rogaron por ella."},
    {"Lucas", "Lc", 4, 39, "El, inclinandose sobre ella, increpo a la fiebre, y se le paso; ella, levantandose enseguida, se puso a servirles."},
    {"Lucas", "Lc", 4, 40, "Al ponerse el sol, todos cuantos tenian enfermos con diversas dolencias se los llevaban, y el, imponiendo las manos sobre cada uno, los iba curando."},
    {"Lucas", "Lc", 4, 41, "De muchos de ellos salian tambien demonios, que gritaban y decian: \"Tu eres el Hijo de Dios\". Los increpaba y no les dejaba hablar, porque sabian que el era el Mesias."},
    {"Lucas", "Lc", 4, 42, "Al hacerse de dia, salio y se fue a un lugar desierto. La gente lo andaba buscando y, llegando donde estaba, intentaban retenerlo para que no se separara de ellos."},
    {"Lucas", "Lc", 4, 43, "Pero el les dijo: \"Es necesario que proclame el reino de Dios tambien a las otras ciudades, pues para esto he sido enviado\"."},
    {"Lucas", "Lc", 4, 44, "Y predicaba en las sinagogas de Judea."},
    {"Lucas", "Lc", 5, 1, "Una vez que la gente se agolpaba en torno a el para oir la palabra de Dios, estando el de pie junto al lago de Genesaret,"},
    {"Lucas", "Lc", 5, 2, "vio dos barcas que estaban en la orilla; los pescadores, que habian desembarcado, estaban lavando las redes."},
    {"Lucas", "Lc", 5, 3, "Subiendo a una de las barcas, que era la de Simon, le pidio que la apartara un poco de tierra. Desde la barca, sentado, ense\177aba a la gente."},
    {"Lucas", "Lc", 5, 4, "Cuando acabo de hablar, dijo a Simon: \"Rema mar adentro, y echad vuestras redes para la pesca\"."},
    {"Lucas", "Lc", 5, 5, "Respondio Simon y dijo: \"Maestro, hemos estado bregando toda la noche y no hemos recogido nada; pero, por tu palabra, echare las redes\"."},
    {"Lucas", "Lc", 5, 6, "Y, puestos a la obra, hicieron una redada tan grande de peces que las redes comenzaban a reventarse."},
    {"Lucas", "Lc", 5, 7, "Entonces hicieron se\177as a los compa\177eros, que estaban en la otra barca, para que vinieran a echarles una mano. Vinieron y llenaron las dos barcas, hasta el punto de que casi se hundian."},
    {"Lucas", "Lc", 5, 8, "Al ver esto, Simon Pedro se echo a los pies de Jesus diciendo: \"Se\177or, apartate de mi, que soy un hombre pecador\"."},
    {"Lucas", "Lc", 5, 9, "Y es que el estupor se habia apoderado de el y de los que estaban con el, por la redada de peces que habian recogido;"},
    {"Lucas", "Lc", 5, 10, "y lo mismo les pasaba a Santiago y Juan, hijos de Zebedeo, que eran compa\177eros de Simon. Y Jesus dijo a Simon: \"No temas; desde ahora seras pescador de hombres\"."},
    {"Lucas", "Lc", 5, 11, "Entonces sacaron las barcas a tierra y, dejandolo todo, lo siguieron."},
    {"Lucas", "Lc", 5, 12, "Sucedio que, estando el en una de las ciudades, se presento un hombre lleno de lepra; al ver a Jesus, cayendo sobre su rostro, le suplico diciendo: \"Se\177or, si quieres, puedes limpiarme\"."},
    {"Lucas", "Lc", 5, 13, "Y extendiendo la mano, lo toco diciendo: \"Quiero, queda limpio\". Y enseguida la lepra se le quito."},
    {"Lucas", "Lc", 5, 14, "Y el le ordeno no comunicarlo a nadie; y le dijo: \"Ve, presentate al sacerdote y ofrece por tu purificacion segun mando Moises, para que les sirva de testimonio\"."},
    {"Lucas", "Lc", 5, 15, "Se hablaba de el cada vez mas, y acudia mucha gente a oirlo y a que los curara de sus enfermedades."},
    {"Lucas", "Lc", 5, 16, "El, por su parte, solia retirarse a despoblado y se entregaba a la oracion."},
    {"Lucas", "Lc", 5, 17, "Un dia estaba el ense\177ando, y estaban sentados unos fariseos y maestros de la ley, venidos de todas las aldeas de Galilea, Judea y Jerusalen. Y el poder del Se\177or estaba con el para realizar curaciones."},
    {"Lucas", "Lc", 5, 18, "En esto, llegaron unos hombres que traian en una camilla a un hombre paralitico y trataban de introducirlo y colocarlo delante de el."},
    {"Lucas", "Lc", 5, 19, "No encontrando por donde introducirlo a causa del gentio, subieron a la azotea, lo descolgaron con la camilla a traves de las tejas, y lo pusieron en medio, delante de Jesus."},
    {"Lucas", "Lc", 5, 20, "El, viendo la fe de ellos, dijo: \"Hombre, tus pecados estan perdonados\"."},
    {"Lucas", "Lc", 5, 21, "Entonces se pusieron a pensar los escribas y los fariseos: \"Quien es este que dice blasfemias? Quien puede perdonar pecados sino solo Dios?\"."},
    {"Lucas", "Lc", 5, 22, "Pero Jesus, conociendo sus pensamientos, respondio y les dijo:"},
    {"Lucas", "Lc", 5, 23, "\"Que estais pensando en vuestros corazones? Que es mas facil, decir: \"Tus pecados te son perdonados\", o decir: \"Levantate y echa a andar\"?"},
    {"Lucas", "Lc", 5, 24, "Pues, para que veais que el Hijo del hombre tiene poder en la tierra para perdonar pecados -dijo al paralitico-: \"A ti te lo digo, ponte en pie, toma tu camilla y vete a tu casa\"\"."},
    {"Lucas", "Lc", 5, 25, "Y, al punto, levantandose a la vista de ellos, tomo la camilla donde habia estado tendido y se marcho a su casa dando gloria a Dios."},
    {"Lucas", "Lc", 5, 26, "El asombro se apodero de todos y daban gloria a Dios. Y, llenos de temor, decian: \"Hoy hemos visto maravillas\"."},
    {"Lucas", "Lc", 5, 27, "Despues de esto, salio y vio a un publicano llamado Levi, sentado al mostrador de los impuestos, y le dijo: \"Sigueme\"."},
    {"Lucas", "Lc", 5, 28, "El, dejandolo todo, se levanto y lo siguio."},
    {"Lucas", "Lc", 5, 29, "Levi ofrecio en su honor un gran banquete en su casa, y estaban a la mesa con ellos un gran numero de publicanos y otros."},
    {"Lucas", "Lc", 5, 30, "Y murmuraban los fariseos y sus escribas diciendo a los discipulos de Jesus: \"Como es que comeis y bebeis con publicanos y pecadores?\"."},
    {"Lucas", "Lc", 5, 31, "Jesus les respondio: \"No necesitan medico los sanos, sino los enfermos."},
    {"Lucas", "Lc", 5, 32, "No he venido a llamar a los justos, sino a los pecadores a que se conviertan\"."},
    {"Lucas", "Lc", 5, 33, "Pero ellos le dijeron: \"Los discipulos de Juan ayunan a menudo y oran, y los de los fariseos tambien; en cambio, los tuyos, a comer y a beber\"."},
    {"Lucas", "Lc", 5, 34, "Jesus les dijo: \"Acaso podeis hacer ayunar a los invitados a la boda mientras el esposo esta con ellos?"},
    {"Lucas", "Lc", 5, 35, "Llegaran dias en que les arrebataran al esposo, entonces ayunaran en aquellos dias\"."},
    {"Lucas", "Lc", 5, 36, "Les dijo tambien una parabola: \"Nadie recorta una pieza de un manto nuevo para ponersela a un manto viejo; porque, si lo hace, el nuevo se rompe y al viejo no le cuadra la pieza del nuevo."},
    {"Lucas", "Lc", 5, 37, "Nadie echa vino nuevo en odres viejos: porque, si lo hace, el vino nuevo reventara los odres y se derramara, y los odres se estropearan."},
    {"Lucas", "Lc", 5, 38, "A vino nuevo, odres nuevos."},
    {"Lucas", "Lc", 5, 39, "Nadie que cate vino a\177ejo quiere del nuevo, pues dira: \"El a\177ejo es mejor\"\"."},
    {"Lucas", "Lc", 6, 1, "Un sabado, iba el caminando por medio de un sembrado y sus discipulos arrancaban y comian espigas, frotandolas con las manos."},
    {"Lucas", "Lc", 6, 2, "Unos fariseos dijeron: \"Por que haceis en sabado lo que no esta permitido?\"."},
    {"Lucas", "Lc", 6, 3, "Respondiendo Jesus, les dijo: \"No habeis leido lo que hizo David, cuando el y sus compa\177eros sintieron hambre?"},
    {"Lucas", "Lc", 6, 4, "Entro en la casa de Dios, y tomando los panes de la proposicion, que solo esta permitido comer a los sacerdotes, comio el y dio a los que estaban con el\"."},
    {"Lucas", "Lc", 6, 5, "Y les decia: \"El Hijo del hombre es se\177or del sabado\"."},
    {"Lucas", "Lc", 6, 6, "Otro sabado, entro el en la sinagoga y se puso a ense\177ar. Habia alli un hombre que tenia la mano derecha paralizada."},
    {"Lucas", "Lc", 6, 7, "Los escribas y los fariseos estaban al acecho para ver si curaba en sabado, y encontrar de que acusarlo."},
    {"Lucas", "Lc", 6, 8, "Pero el conocia sus pensamientos y dijo al hombre de la mano atrofiada: \"Levantate y ponte en medio\". Y, levantandose, se quedo en pie."},
    {"Lucas", "Lc", 6, 9, "Jesus les dijo: \"Os voy a hacer una pregunta: Que esta permitido en sabado?, hacer el bien o el mal, salvar una vida o destruirla?\"."},
    {"Lucas", "Lc", 6, 10, "Y, echando en torno una mirada a todos, le dijo: \"Extiende tu mano\". El lo hizo y su mano quedo restablecida."},
    {"Lucas", "Lc", 6, 11, "Pero ellos, ciegos por la colera, discutian que habia que hacer con Jesus."},
    {"Lucas", "Lc", 6, 12, "En aquellos dias, Jesus salio al monte a orar y paso la noche orando a Dios."},
    {"Lucas", "Lc", 6, 13, "Cuando se hizo de dia, llamo a sus discipulos, escogio de entre ellos a doce, a los que tambien nombro apostoles:"},
    {"Lucas", "Lc", 6, 14, "Simon, al que puso de nombre Pedro, y Andres, su hermano; Santiago, Juan, Felipe, Bartolome,"},
    {"Lucas", "Lc", 6, 15, "Mateo, Tomas, Santiago el de Alfeo, Simon, llamado el Zelote;"},
    {"Lucas", "Lc", 6, 16, "Judas el de Santiago y Judas Iscariote, que fue el traidor."},
    {"Lucas", "Lc", 6, 17, "Despues de bajar con ellos, se paro en una llanura con un grupo grande de discipulos y una gran muchedumbre del pueblo, procedente de toda Judea, de Jerusalen y de la costa de Tiro y de Sidon."},
    {"Lucas", "Lc", 6, 18, "Venian a oirlo y a que los curara de sus enfermedades; los atormentados por espiritus inmundos quedaban curados,"},
    {"Lucas", "Lc", 6, 19, "y toda la gente trataba de tocarlo, porque salia de el una fuerza que los curaba a todos."},
    {"Lucas", "Lc", 6, 20, "El, levantando los ojos hacia sus discipulos, les decia: \"Bienaventurados los pobres, porque vuestro es el reino de Dios."},
    {"Lucas", "Lc", 6, 21, "Bienaventurados los que ahora teneis hambre, porque quedareis saciados. Bienaventurados los que ahora llorais, porque reireis."},
    {"Lucas", "Lc", 6, 22, "Bienaventurados vosotros cuando os odien los hombres, y os excluyan, y os insulten y proscriban vuestro nombre como infame, por causa del Hijo del hombre."},
    {"Lucas", "Lc", 6, 23, "Alegraos ese dia y saltad de gozo, porque vuestra recompensa sera grande en el cielo. Eso es lo que hacian vuestros padres con los profetas."},
    {"Lucas", "Lc", 6, 24, "Pero ay de vosotros, los ricos, porque ya habeis recibido vuestro consuelo!"},
    {"Lucas", "Lc", 6, 25, "Ay de vosotros, los que estais saciados, porque tendreis hambre! Ay de los que ahora reis, porque hareis duelo y llorareis!"},
    {"Lucas", "Lc", 6, 26, "Ay si todo el mundo habla bien de vosotros! Eso es lo que vuestros padres hacian con los falsos profetas."},
    {"Lucas", "Lc", 6, 27, "En cambio, a vosotros los que me escuchais os digo: amad a vuestros enemigos, haced el bien a los que os odian,"},
    {"Lucas", "Lc", 6, 28, "bendecid a los que os maldicen, orad por los que os calumnian."},
    {"Lucas", "Lc", 6, 29, "Al que te pegue en una mejilla, presentale la otra; al que te quite la capa, no le impidas que tome tambien la tunica."},
    {"Lucas", "Lc", 6, 30, "A quien te pide, dale; al que se lleve lo tuyo, no se lo reclames."},
    {"Lucas", "Lc", 6, 31, "Tratad a los demas como quereis que ellos os traten."},
    {"Lucas", "Lc", 6, 32, "Pues, si amais a los que os aman, que merito teneis? Tambien los pecadores aman a los que los aman."},
    {"Lucas", "Lc", 6, 33, "Y si haceis bien solo a los que os hacen bien, que merito teneis? Tambien los pecadores hacen lo mismo."},
    {"Lucas", "Lc", 6, 34, "Y si prestais a aquellos de los que esperais cobrar, que merito teneis? Tambien los pecadores prestan a otros pecadores, con intencion de cobrarselo."},
    {"Lucas", "Lc", 6, 35, "Por el contrario, amad a vuestros enemigos, haced el bien y prestad sin esperar nada; sera grande vuestra recompensa y sereis hijos del Altisimo, porque el es bueno con los malvados y desagradecidos."},
    {"Lucas", "Lc", 6, 36, "Sed misericordiosos como vuestro Padre es misericordioso."},
    {"Lucas", "Lc", 6, 37, "No juzgueis, y no sereis juzgados; no condeneis, y no sereis condenados; perdonad, y sereis perdonados;"},
    {"Lucas", "Lc", 6, 38, "dad, y se os dara: os verteran una medida generosa, colmada, remecida, rebosante, pues con la medida con que midiereis se os medira a vosotros\"."},
    {"Lucas", "Lc", 6, 39, "Les dijo tambien una parabola: \"Acaso puede un ciego guiar a otro ciego? No caeran los dos en el hoyo?"},
    {"Lucas", "Lc", 6, 40, "No esta el discipulo sobre su maestro, si bien, cuando termine su aprendizaje, sera como su maestro."},
    {"Lucas", "Lc", 6, 41, "Por que te fijas en la mota que tiene tu hermano en el ojo y no reparas en la viga que llevas en el tuyo?"},
    {"Lucas", "Lc", 6, 42, "Como puedes decirle a tu hermano: \"Hermano, dejame que te saque la mota del ojo\", sin fijarte en la viga que llevas en el tuyo? Hipocrita! Sacate primero la viga de tu ojo, y entonces veras claro para sacar la mota del ojo de tu hermano."},
    {"Lucas", "Lc", 6, 43, "Pues no hay arbol bueno que de fruto malo, ni arbol malo que de fruto bueno;"},
    {"Lucas", "Lc", 6, 44, "por ello, cada arbol se conoce por su fruto; porque no se recogen higos de las zarzas, ni se vendimian racimos de los espinos."},
    {"Lucas", "Lc", 6, 45, "El hombre bueno, de la bondad que atesora en su corazon saca el bien, y el que es malo, de la maldad saca el mal; porque de lo que rebosa el corazon habla la boca."},
    {"Lucas", "Lc", 6, 46, "Por que me llamais \"Se\177or, Se\177or\", y no haceis lo que digo?"},
    {"Lucas", "Lc", 6, 47, "Todo el que viene a mi, escucha mis palabras y las pone en practica, os voy a decir a quien se parece:"},
    {"Lucas", "Lc", 6, 48, "se parece a uno que edifico una casa: cavo, ahondo y puso los cimientos sobre roca; vino una crecida, arremetio el rio contra aquella casa, y no pudo derribarla, porque estaba solidamente construida."},
    {"Lucas", "Lc", 6, 49, "El que escucha y no pone en practica se parece a uno que edifico una casa sobre tierra, sin cimiento; arremetio contra ella el rio, y enseguida se derrumbo desplomandose, y fue grande la ruina de aquella casa\"."},
    {"Lucas", "Lc", 7, 1, "Cuando termino de exponer todas sus ense\177anzas al pueblo, entro en Cafarnaun."},
    {"Lucas", "Lc", 7, 2, "Un centurion tenia enfermo, a punto de morir, a un criado a quien estimaba mucho."},
    {"Lucas", "Lc", 7, 3, "Al oir hablar de Jesus, el centurion le envio unos ancianos de los judios, rogandole que viniese a curar a su criado."},
    {"Lucas", "Lc", 7, 4, "Ellos, presentandose a Jesus, le rogaban encarecidamente: \"Merece que se lo concedas,"},
    {"Lucas", "Lc", 7, 5, "porque tiene afecto a nuestra gente y nos ha construido la sinagoga\"."},
    {"Lucas", "Lc", 7, 6, "Jesus se puso en camino con ellos. No estaba lejos de la casa, cuando el centurion le envio unos amigos a decirle: \"Se\177or, no te molestes, porque no soy digno de que entres bajo mi techo;"},
    {"Lucas", "Lc", 7, 7, "por eso tampoco me crei digno de venir a ti personalmente. Dilo de palabra y mi criado quedara sano."},
    {"Lucas", "Lc", 7, 8, "Porque tambien yo soy un hombre sometido a una autoridad y con soldados a mis ordenes; y le digo a uno: \"Ve\", y va; al otro: \"Ven\", y viene; y a mi criado: \"Haz esto\", y lo hace\"."},
    {"Lucas", "Lc", 7, 9, "Al oir esto, Jesus se admiro de el y, volviendose a la gente que lo seguia, dijo: \"Os digo que ni en Israel he encontrado tanta fe\"."},
    {"Lucas", "Lc", 7, 10, "Y al volver a casa, los enviados encontraron al siervo sano."},
    {"Lucas", "Lc", 7, 11, "Poco tiempo despues iba camino de una ciudad llamada Nain, y caminaban con el sus discipulos y mucho gentio."},
    {"Lucas", "Lc", 7, 12, "Cuando se acercaba a la puerta de la ciudad, resulto que sacaban a enterrar a un muerto, hijo unico de su madre, que era viuda; y un gentio considerable de la ciudad la acompa\177aba."},
    {"Lucas", "Lc", 7, 13, "Al verla el Se\177or, se compadecio de ella y le dijo: \"No llores\"."},
    {"Lucas", "Lc", 7, 14, "Y acercandose al ataud, lo toco (los que lo llevaban se pararon) y dijo: \"Muchacho, a ti te lo digo, levantate!\"."},
    {"Lucas", "Lc", 7, 15, "El muerto se incorporo y empezo a hablar, y se lo entrego a su madre."},
    {"Lucas", "Lc", 7, 16, "Todos, sobrecogidos de temor, daban gloria a Dios diciendo: \"Un gran Profeta ha surgido entre nosotros\", y \"Dios ha visitado a su pueblo\"."},
    {"Lucas", "Lc", 7, 17, "Este hecho se divulgo por toda Judea y por toda la comarca circundante."},
    {"Lucas", "Lc", 7, 18, "Los discipulos de Juan le contaron todo esto. Y Juan, llamando a dos de sus discipulos,"},
    {"Lucas", "Lc", 7, 19, "los envio al Se\177or diciendo: \"Eres tu el que ha de venir, o tenemos que esperar a otro?\"."},
    {"Lucas", "Lc", 7, 20, "Los hombres se presentaron ante el y le dijeron: \"Juan el Bautista nos ha mandado a ti para decirte: \"Eres tu el que ha de venir, o tenemos que esperar a otro?\"\"."},
    {"Lucas", "Lc", 7, 21, "En aquella hora curo a muchos de enfermedades, achaques y malos espiritus, y a muchos ciegos les otorgo la vista."},
    {"Lucas", "Lc", 7, 22, "Y respondiendo, les dijo: \"Id y anunciad a Juan lo que habeis visto y oido: los ciegos ven, los cojos andan, los leprosos quedan limpios y los sordos oyen, los muertos resucitan, los pobres son evangelizados."},
    {"Lucas", "Lc", 7, 23, "Y bienaventurado el que no se escandalice de mi!\"."},
    {"Lucas", "Lc", 7, 24, "Cuando se marcharon los mensajeros de Juan, se puso a hablar a la gente acerca de Juan: \"Que salisteis a contemplar en el desierto? Una ca\177a sacudida por el viento?"},
    {"Lucas", "Lc", 7, 25, "Pues que salisteis a ver? Un hombre vestido con ropas finas? Mirad, los que se visten fastuosamente y viven entre placeres estan en los palacios reales."},
    {"Lucas", "Lc", 7, 26, "Entonces, que salisteis a ver? Un profeta? Si, os digo, y mas que profeta."},
    {"Lucas", "Lc", 7, 27, "Este es de quien esta escrito: \"Yo envio mi mensajero delante de ti, el cual preparara tu camino ante ti\"."},
    {"Lucas", "Lc", 7, 28, "Porque os digo, entre los nacidos de mujer no hay nadie mayor que Juan. Aunque el mas peque\177o en el reino de Dios es mayor que el\"."},
    {"Lucas", "Lc", 7, 29, "Al oir a Juan, todo el pueblo, incluso los publicanos, recibiendo el bautismo de Juan, proclamaron que Dios es justo."},
    {"Lucas", "Lc", 7, 30, "Pero los fariseos y los maestros de la ley, que no habian aceptado su bautismo, frustraron el designio de Dios para con ellos."},
    {"Lucas", "Lc", 7, 31, "\"A quien, pues, comparare los hombres de esta generacion? A quien son semejantes?"},
    {"Lucas", "Lc", 7, 32, "Se asemejan a unos ni\177os, sentados en la plaza, que gritan a otros aquello de: \"Hemos tocado la flauta / y no habeis bailado, / hemos entonado lamentaciones, / y no habeis llorado\""},
    {"Lucas", "Lc", 7, 33, "Porque vino Juan el Bautista, que ni come pan ni bebe vino, y decis: \"Tiene un demonio\";"},
    {"Lucas", "Lc", 7, 34, "vino el Hijo del hombre, que come y bebe, y decis: \"Mirad que hombre mas comilon y borracho, amigo de publicanos y pecadores\"."},
    {"Lucas", "Lc", 7, 35, "Sin embargo, todos los hijos de la sabiduria le han dado la razon\"."},
    {"Lucas", "Lc", 7, 36, "Un fariseo le rogaba que fuera a comer con el y, entrando en casa del fariseo, se recosto a la mesa."},
    {"Lucas", "Lc", 7, 37, "En esto, una mujer que habia en la ciudad, una pecadora, al enterarse de que estaba comiendo en casa del fariseo, vino trayendo un frasco de alabastro lleno de perfume y,"},
    {"Lucas", "Lc", 7, 38, "colocandose detras junto a sus pies, llorando, se puso a regarle los pies con las lagrimas, se los enjugaba con los cabellos de su cabeza, los cubria de besos y se los ungia con el perfume."},
    {"Lucas", "Lc", 7, 39, "Al ver esto, el fariseo que lo habia invitado se dijo: \"Si este fuera profeta, sabria quien y que clase de mujer es la que lo esta tocando, pues es una pecadora\"."},
    {"Lucas", "Lc", 7, 40, "Jesus respondio y le dijo: \"Simon, tengo algo que decirte\". El contesto: \"Dimelo, Maestro\"."},
    {"Lucas", "Lc", 7, 41, "\"Un prestamista tenia dos deudores: uno le debia quinientos denarios y el otro cincuenta."},
    {"Lucas", "Lc", 7, 42, "Como no tenian con que pagar, los perdono a los dos. Cual de ellos le mostrara mas amor?\"."},
    {"Lucas", "Lc", 7, 43, "Respondio Simon y dijo: \"Supongo que aquel a quien le perdono mas\". Y el le dijo: \"Has juzgado rectamente\"."},
    {"Lucas", "Lc", 7, 44, "Y, volviendose a la mujer, dijo a Simon: \"Ves a esta mujer? He entrado en tu casa y no me has dado agua para los pies; ella, en cambio, me ha regado los pies con sus lagrimas y me los ha enjugado con sus cabellos."},
    {"Lucas", "Lc", 7, 45, "Tu no me diste el beso de paz; ella, en cambio, desde que entre, no ha dejado de besarme los pies."},
    {"Lucas", "Lc", 7, 46, "Tu no me ungiste la cabeza con unguento; ella, en cambio, me ha ungido los pies con perfume."},
    {"Lucas", "Lc", 7, 47, "Por eso te digo: sus muchos pecados han quedado perdonados, porque ha amado mucho, pero al que poco se le perdona, ama poco\"."},
    {"Lucas", "Lc", 7, 48, "Y a ella le dijo: \"Han quedado perdonados tus pecados\"."},
    {"Lucas", "Lc", 7, 49, "Los demas convidados empezaron a decir entre ellos: \"Quien es este, que hasta perdona pecados?\"."},
    {"Lucas", "Lc", 7, 50, "Pero el dijo a la mujer: \"Tu fe te ha salvado, vete en paz\"."},
    {"Lucas", "Lc", 8, 1, "Despues de esto iba el caminando de ciudad en ciudad y de pueblo en pueblo, proclamando y anunciando la Buena Noticia del reino de Dios, acompa\177ado por los Doce,"},
    {"Lucas", "Lc", 8, 2, "y por algunas mujeres, que habian sido curadas de espiritus malos y de enfermedades: Maria la Magdalena, de la que habian salido siete demonios;"},
    {"Lucas", "Lc", 8, 3, "Juana, mujer de Cusa, un administrador de Herodes; Susana y otras muchas que les servian con sus bienes."},
    {"Lucas", "Lc", 8, 4, "Habiendose reunido una gran muchedumbre y gente que salia de toda la ciudad, dijo en parabola:"},
    {"Lucas", "Lc", 8, 5, "\"Salio el sembrador a sembrar su semilla. Al sembrarla, algo cayo al borde del camino, lo pisaron, y los pajaros del cielo se lo comieron."},
    {"Lucas", "Lc", 8, 6, "Otra parte cayo en terreno pedregoso, y, despues de brotar, se seco por falta de humedad."},
    {"Lucas", "Lc", 8, 7, "Otra parte cayo entre abrojos, y los abrojos, creciendo al mismo tiempo, la ahogaron."},
    {"Lucas", "Lc", 8, 8, "Y otra parte cayo en tierra buena, y, despues de brotar, dio fruto al ciento por uno\". Dicho esto, exclamo: \"El que tenga oidos para oir, que oiga\"."},
    {"Lucas", "Lc", 8, 9, "Entonces le preguntaron los discipulos que significaba esa parabola."},
    {"Lucas", "Lc", 8, 10, "El dijo: \"A vosotros se os ha otorgado conocer los misterios del reino de Dios; pero a los demas, en parabolas, para que viendo no vean y oyendo no entiendan."},
    {"Lucas", "Lc", 8, 11, "El sentido de la parabola es este: la semilla es la palabra de Dios."},
    {"Lucas", "Lc", 8, 12, "Los del borde del camino son los que escuchan, pero luego viene el diablo y se lleva la palabra de sus corazones, para que no crean y se salven."},
    {"Lucas", "Lc", 8, 13, "Los del terreno pedregoso son los que, al oir, reciben la palabra con alegria, pero no tienen raiz; son los que por algun tiempo creen, pero en el momento de la prueba fallan."},
    {"Lucas", "Lc", 8, 14, "Lo que cayo entre abrojos son los que han oido, pero, dejandose llevar por los afanes, riquezas y placeres de la vida, se quedan sofocados y no llegan a dar fruto maduro."},
    {"Lucas", "Lc", 8, 15, "Lo de la tierra buena son los que escuchan la palabra con un corazon noble y generoso, la guardan y dan fruto con perseverancia."},
    {"Lucas", "Lc", 8, 16, "Nadie que ha encendido una lampara, la tapa con una vasija o la mete debajo de la cama, sino que la pone en el candelero para que los que entren vean la luz."},
    {"Lucas", "Lc", 8, 17, "Pues nada hay oculto que no llegue a descubrirse ni nada secreto que no llegue a saberse y hacerse publico."},
    {"Lucas", "Lc", 8, 18, "Mirad, pues, como ois, pues al que tiene se le dara y al que no tiene se le quitara hasta lo que cree tener\"."},
    {"Lucas", "Lc", 8, 19, "Vinieron a el su madre y sus hermanos, pero con el gentio no lograban llegar hasta el."},
    {"Lucas", "Lc", 8, 20, "Entonces le avisaron: \"Tu madre y tus hermanos estan fuera y quieren verte\"."},
    {"Lucas", "Lc", 8, 21, "El respondio diciendoles: \"Mi madre y mis hermanos son estos: los que escuchan la palabra de Dios y la cumplen\"."},
    {"Lucas", "Lc", 8, 22, "Un dia subio el a una barca junto con sus discipulos y les dijo: \"Vamos a cruzar a la otra orilla del lago\"; y se hicieron a la mar."},
    {"Lucas", "Lc", 8, 23, "Mientras iban navegando, se quedo dormido. E irrumpio sobre el lago un torbellino de viento, se hundian y estaban en peligro."},
    {"Lucas", "Lc", 8, 24, "Entonces se acercan a el y le despiertan diciendo: \"Maestro, Maestro, que perecemos!\". Y el, despertandose, conmino al viento y al oleaje del agua, que se apaciguaron, y sobrevino la calma."},
    {"Lucas", "Lc", 8, 25, "Y les dijo: \"Donde esta vuestra fe?\". Ellos, por su parte, llenos de temor y admiracion, se decian unos a otros: \"Pues quien es este que da ordenes incluso al viento y al agua y lo obedecen?\"."},
    {"Lucas", "Lc", 8, 26, "Y arribaron a la region de los gerasenos, que esta frente a Galilea."},
    {"Lucas", "Lc", 8, 27, "Al saltar a tierra, le salio al encuentro desde la ciudad un hombre poseido de demonios, que durante mucho tiempo no vestia ropa alguna ni moraba en casa, sino en los sepulcros."},
    {"Lucas", "Lc", 8, 28, "Pero, al ver a Jesus, se puso a gritar, se postro ante el y le dijo a voces: \"Que hay entre tu y yo, Jesus, hijo del Dios altisimo? Te ruego que no me atormentes\"."},
    {"Lucas", "Lc", 8, 29, "Porque el estaba mandando al espiritu inmundo que saliera del hombre. Y es que muchas veces se apoderaba de el y tenian que atarlo con cadenas y asegurarlo con grillos, pero, rompiendo las ligaduras, el demonio le empujaba a los despoblados."},
    {"Lucas", "Lc", 8, 30, "Jesus, por su parte, le pregunto: \"Cual es tu nombre?\". El dijo: \"Legion\", porque habian entrado muchos demonios en el."},
    {"Lucas", "Lc", 8, 31, "Y le rogaban que no les mandase irse al abismo."},
    {"Lucas", "Lc", 8, 32, "Como habia alli una piara numerosa de cerdos, paciendo en el monte, le pidieron que les permitiese entrar dentro de ellos y se lo permitio."},
    {"Lucas", "Lc", 8, 33, "Entonces, saliendo los demonios del hombre, entraron en los cerdos y la piara se lanzo, despe\177adero abajo, al lago y se ahogo."},
    {"Lucas", "Lc", 8, 34, "Al ver los porqueros lo sucedido, huyeron y lo contaron por la ciudad y por los cortijos."},
    {"Lucas", "Lc", 8, 35, "Vinieron, pues, a ver lo sucedido. Llegaron junto a Jesus y encontraron al hombre del que habian salido los demonios sentado a sus pies, vestido y en su sano juicio, y se llenaron de temor."},
    {"Lucas", "Lc", 8, 36, "Entonces, los que lo habian visto les contaron como habia sido curado el endemoniado."},
    {"Lucas", "Lc", 8, 37, "Y le rogo toda la gente de la comarca de los gerasenos que se marchase de entre ellos, porque estaban llenos de miedo. El, pues, subio a la barca y regreso."},
    {"Lucas", "Lc", 8, 38, "El hombre de quien habian salido los demonios le pedia quedarse con el, pero lo despidio diciendo:"},
    {"Lucas", "Lc", 8, 39, "\"Vuelve a tu casa y da a conocer cuanto te ha hecho Dios\". Partio, pues, por toda la ciudad proclamando todo cuanto le habia hecho Jesus."},
    {"Lucas", "Lc", 8, 40, "Al regresar Jesus, la gente lo acogio bien, pues todos lo estaban esperando."},
    {"Lucas", "Lc", 8, 41, "Llego entonces un hombre, llamado Jairo, que era jefe de la sinagoga, y echandose a los pies de Jesus le rogaba que entrase en su casa,"},
    {"Lucas", "Lc", 8, 42, "pues tenia una hija unica, de unos doce a\177os, que se estaba muriendo. Cuando caminaba con el, la gente lo apretujaba."},
    {"Lucas", "Lc", 8, 43, "Entonces una mujer que desde hacia doce a\177os sufria flujos de sangre y que habia gastado en medicos todos sus recursos sin que ninguno pudiera curarla,"},
    {"Lucas", "Lc", 8, 44, "acercandose por detras, toco el borde de su manto y, al instante, ceso el flujo de sangre."},
    {"Lucas", "Lc", 8, 45, "Y dijo Jesus: \"Quien es el que me ha tocado?\". Como todos lo negaban, dijo Pedro: \"Maestro, la gente te esta apretujando y estrujando\"."},
    {"Lucas", "Lc", 8, 46, "Pero Jesus dijo: \"Alguien me ha tocado, pues he sentido que una fuerza ha salido de mi\"."},
    {"Lucas", "Lc", 8, 47, "Viendo la mujer que no habia podido pasar inadvertida, se acerco temblorosa y, postrandose a sus pies, conto ante todo el pueblo la causa por la que le habia tocado y como habia sido curada al instante."},
    {"Lucas", "Lc", 8, 48, "Pero Jesus le dijo: \"Hija, tu fe te ha salvado. Vete en paz\"."},
    {"Lucas", "Lc", 8, 49, "Estaba todavia hablando, cuando llega uno de casa del jefe de la sinagoga diciendo: \"Tu hija ha muerto, no molestes mas al Maestro\"."},
    {"Lucas", "Lc", 8, 50, "Pero Jesus, oido esto, le respondio: \"No temas, basta que creas y se salvara\"."},
    {"Lucas", "Lc", 8, 51, "Al llegar a la casa, no dejo entrar con el mas que a Pedro, Santiago y Juan y al padre de la ni\177a y la madre."},
    {"Lucas", "Lc", 8, 52, "Todos lloraban y hacian duelo por ella, pero el dijo: \"No lloreis, porque no ha muerto, sino que esta dormida\"."},
    {"Lucas", "Lc", 8, 53, "Y se reian de el, sabiendo que habia muerto."},
    {"Lucas", "Lc", 8, 54, "Pero el, tomandola de la mano, dijo en voz alta: \"Ni\177a, levantate\"."},
    {"Lucas", "Lc", 8, 55, "Y retorno su espiritu y se levanto al instante. Y ordeno que le dieran de comer."},
    {"Lucas", "Lc", 8, 56, "Sus padres quedaron atonitos, pero Jesus les ordeno que no dijeran a nadie lo sucedido."},
    {"Lucas", "Lc", 9, 1, "Habiendo convocado Jesus a los Doce, les dio poder y autoridad sobre toda clase de demonios y para curar enfermedades."},
    {"Lucas", "Lc", 9, 2, "Luego los envio a proclamar el reino de Dios y a curar a los enfermos,"},
    {"Lucas", "Lc", 9, 3, "diciendoles: \"No lleveis nada para el camino: ni baston ni alforja, ni pan ni dinero; tampoco tengais dos tunicas cada uno."},
    {"Lucas", "Lc", 9, 4, "Quedaos en la casa donde entreis, hasta que os vayais de aquel sitio."},
    {"Lucas", "Lc", 9, 5, "Y si algunos no os reciben, al salir de aquel pueblo sacudios el polvo de vuestros pies, como testimonio contra ellos\"."},
    {"Lucas", "Lc", 9, 6, "Se pusieron en camino y fueron de aldea en aldea, anunciando la Buena Noticia y curando en todas partes."},
    {"Lucas", "Lc", 9, 7, "El tetrarca Herodes se entero de lo que pasaba y no sabia a que atenerse, porque unos decian que Juan habia resucitado de entre los muertos;"},
    {"Lucas", "Lc", 9, 8, "otros, en cambio, que habia aparecido Elias, y otros que habia vuelto a la vida uno de los antiguos profetas."},
    {"Lucas", "Lc", 9, 9, "Herodes se decia: \"A Juan lo mande decapitar yo. Quien es este de quien oigo semejantes cosas?\". Y tenia ganas de verlo."},
    {"Lucas", "Lc", 9, 10, "Al regresar los apostoles, le contaron todo cuanto habian hecho, y tomandolos consigo, se retiro a solas hacia una ciudad llamada Betsaida;"},
    {"Lucas", "Lc", 9, 11, "pero la gente, al darse cuenta, lo siguio. Jesus los acogia, les hablaba del reino y sanaba a los que tenian necesidad de curacion."},
    {"Lucas", "Lc", 9, 12, "El dia comenzaba a declinar. Entonces, acercandose los Doce, le dijeron: \"Despide a la gente; que vayan a las aldeas y cortijos de alrededor a buscar alojamiento y comida, porque aqui estamos en descampado\"."},
    {"Lucas", "Lc", 9, 13, "El les contesto: \"Dadles vosotros de comer\". Ellos replicaron: \"No tenemos mas que cinco panes y dos peces; a no ser que vayamos a comprar de comer para toda esta gente\"."},
    {"Lucas", "Lc", 9, 14, "Porque eran unos cinco mil hombres. Entonces dijo a sus discipulos: \"Haced que se sienten en grupos de unos cincuenta cada uno\"."},
    {"Lucas", "Lc", 9, 15, "Lo hicieron asi y dispusieron que se sentaran todos."},
    {"Lucas", "Lc", 9, 16, "Entonces, tomando el los cinco panes y los dos peces y alzando la mirada al cielo, pronuncio la bendicion sobre ellos, los partio y se los iba dando a los discipulos para que se los sirvieran a la gente."},
    {"Lucas", "Lc", 9, 17, "Comieron todos y se saciaron, y recogieron lo que les habia sobrado: doce cestos de trozos."},
    {"Lucas", "Lc", 9, 18, "Una vez que Jesus estaba orando solo, lo acompa\177aban sus discipulos y les pregunto: \"Quien dice la gente que soy yo?\"."},
    {"Lucas", "Lc", 9, 19, "Ellos contestaron: \"Unos, que Juan el Bautista; otros, que Elias, otros dicen que ha resucitado uno de los antiguos profetas\"."},
    {"Lucas", "Lc", 9, 20, "El les pregunto: \"Y vosotros, quien decis que soy yo?\". Pedro respondio: \"El Mesias de Dios\"."},
    {"Lucas", "Lc", 9, 21, "El les prohibio terminantemente decirselo a nadie."},
    {"Lucas", "Lc", 9, 22, "Porque decia: \"El Hijo del hombre tiene que padecer mucho, ser desechado por los ancianos, sumos sacerdotes y escribas, ser ejecutado y resucitar al tercer dia\"."},
    {"Lucas", "Lc", 9, 23, "Entonces decia a todos: \"Si alguno quiere venir en pos de mi, que se niegue a si mismo, tome su cruz cada dia y me siga."},
    {"Lucas", "Lc", 9, 24, "Pues el que quiera salvar su vida la perdera; pero el que pierda su vida por mi causa la salvara."},
    {"Lucas", "Lc", 9, 25, "De que le sirve a uno ganar el mundo entero si se pierde o se arruina a si mismo?"},
    {"Lucas", "Lc", 9, 26, "Pues si uno se averguenza de mi y de mis palabras, tambien el Hijo del hombre se avergonzara de el cuando venga en su gloria, en la del Padre y en la de los angeles santos."},
    {"Lucas", "Lc", 9, 27, "Pues de verdad os digo que hay algunos de los aqui presentes que no gustaran la muerte hasta que vean el reino de Dios\"."},
    {"Lucas", "Lc", 9, 28, "Unos ocho dias despues de estas palabras, tomo a Pedro, a Juan y a Santiago y subio a lo alto del monte para orar."},
    {"Lucas", "Lc", 9, 29, "Y, mientras oraba, el aspecto de su rostro cambio y sus vestidos brillaban de resplandor."},
    {"Lucas", "Lc", 9, 30, "De repente, dos hombres conversaban con el: eran Moises y Elias,"},
    {"Lucas", "Lc", 9, 31, "que, apareciendo con gloria, hablaban de su exodo, que el iba a consumar en Jerusalen."},
    {"Lucas", "Lc", 9, 32, "Pedro y sus compa\177eros se caian de sue\177o, pero se espabilaron y vieron su gloria y a los dos hombres que estaban con el."},
    {"Lucas", "Lc", 9, 33, "Mientras estos se alejaban de el, dijo Pedro a Jesus: \"Maestro, que bueno es que estemos aqui! Haremos tres tiendas: una para ti, otra para Moises y otra para Elias\". No sabia lo que decia."},
    {"Lucas", "Lc", 9, 34, "Todavia estaba diciendo esto, cuando llego una nube que los cubrio con su sombra. Se llenaron de temor al entrar en la nube."},
    {"Lucas", "Lc", 9, 35, "Y una voz desde la nube decia: \"Este es mi Hijo, el Elegido, escuchadlo\"."},
    {"Lucas", "Lc", 9, 36, "Despues de oirse la voz, se encontro Jesus solo. Ellos guardaron silencio y, por aquellos dias, no contaron a nadie nada de lo que habian visto."},
    {"Lucas", "Lc", 9, 37, "Al dia siguiente, cuando bajaron ellos del monte, le salio al encuentro mucha gente."},
    {"Lucas", "Lc", 9, 38, "Y, de pronto, un hombre de entre la gente se puso a dar voces diciendo: \"Maestro, te ruego que te fijes en mi hijo, que es el unico que tengo,"},
    {"Lucas", "Lc", 9, 39, "pues un espiritu se apodera de el y de repente se pone a gritar y le retuerce echando espumarajos y a duras penas se aleja de el, dejandolo maltrecho."},
    {"Lucas", "Lc", 9, 40, "He pedido a tus discipulos que lo expulsen, pero no han podido\"."},
    {"Lucas", "Lc", 9, 41, "Respondio Jesus y dijo: \"Generacion incredula y perversa, hasta cuando he de estar con vosotros y os tendre que sufrir? Trae aqui a tu hijo\"."},
    {"Lucas", "Lc", 9, 42, "Mientras se acercaba este, lo tiro el demonio al suelo y le dio una violenta sacudida; pero Jesus increpo al espiritu inmundo, curo al ni\177o y lo devolvio a su padre."},
    {"Lucas", "Lc", 9, 43, "Y todos quedaban estupefactos ante la grandeza de Dios. Entre la admiracion general por lo que hacia, dijo a sus discipulos:"},
    {"Lucas", "Lc", 9, 44, "\"Meteos bien en los oidos estas palabras: el Hijo del hombre va a ser entregado en manos de los hombres\"."},
    {"Lucas", "Lc", 9, 45, "Pero ellos no entendian este lenguaje; les resultaba tan oscuro, que no captaban el sentido. Y les daba miedo preguntarle sobre el asunto."},
    {"Lucas", "Lc", 9, 46, "Se suscito entre ellos una discusion sobre quien seria el mas importante."},
    {"Lucas", "Lc", 9, 47, "Entonces Jesus, conociendo los pensamientos de sus corazones, tomo de la mano a un ni\177o, lo puso a su lado"},
    {"Lucas", "Lc", 9, 48, "y les dijo: \"El que acoge a este ni\177o en mi nombre, me acoge a mi; y el que me acoge a mi, acoge al que me ha enviado. Pues el mas peque\177o de vosotros es el mas importante\"."},
    {"Lucas", "Lc", 9, 49, "Entonces Juan tomo la palabra y dijo: \"Maestro, hemos visto a uno que expulsaba demonios en tu nombre y se lo hemos prohibido, porque no anda con nosotros\"."},
    {"Lucas", "Lc", 9, 50, "Jesus le respondio: \"No se lo impidais: el que no esta contra vosotros, esta a favor vuestro\"."},
    {"Lucas", "Lc", 9, 51, "Cuando se completaron los dias en que iba a ser llevado al cielo, Jesus tomo la decision de ir a Jerusalen."},
    {"Lucas", "Lc", 9, 52, "Y envio mensajeros delante de el. Puestos en camino, entraron en una aldea de samaritanos para hacer los preparativos."},
    {"Lucas", "Lc", 9, 53, "Pero no lo recibieron, porque su aspecto era el de uno que caminaba hacia Jerusalen."},
    {"Lucas", "Lc", 9, 54, "Al ver esto, Santiago y Juan, discipulos suyos, le dijeron: \"Se\177or, quieres que digamos que baje fuego del cielo que acabe con ellos?\"."},
    {"Lucas", "Lc", 9, 55, "El se volvio y los rega\177o."},
    {"Lucas", "Lc", 9, 56, "Y se encaminaron hacia otra aldea."},
    {"Lucas", "Lc", 9, 57, "Mientras iban de camino, le dijo uno: \"Te seguire adondequiera que vayas\"."},
    {"Lucas", "Lc", 9, 58, "Jesus le respondio: \"Las zorras tienen madrigueras, y los pajaros del cielo nidos, pero el Hijo del hombre no tiene donde reclinar la cabeza\"."},
    {"Lucas", "Lc", 9, 59, "A otro le dijo: \"Sigueme\". El respondio: \"Se\177or, dejame primero ir a enterrar a mi padre\"."},
    {"Lucas", "Lc", 9, 60, "Le contesto: \"Deja que los muertos entierren a sus muertos; tu vete a anunciar el reino de Dios\"."},
    {"Lucas", "Lc", 9, 61, "Otro le dijo: \"Te seguire, Se\177or. Pero dejame primero despedirme de los de mi casa\"."},
    {"Lucas", "Lc", 9, 62, "Jesus le contesto: \"Nadie que pone la mano en el arado y mira hacia atras vale para el reino de Dios\"."},
    {"Lucas", "Lc", 10, 1, "Despues de esto, designo el Se\177or otros setenta y dos, y los mando delante de el, de dos en dos, a todos los pueblos y lugares adonde pensaba ir el."},
    {"Lucas", "Lc", 10, 2, "Y les decia: \"La mies es abundante y los obreros pocos; rogad, pues, al due\177o de la mies que envie obreros a su mies."},
    {"Lucas", "Lc", 10, 3, "Poneos en camino! Mirad que os envio como corderos en medio de lobos."},
    {"Lucas", "Lc", 10, 4, "No lleveis bolsa, ni alforja, ni sandalias; y no saludeis a nadie por el camino."},
    {"Lucas", "Lc", 10, 5, "Cuando entreis en una casa, decid primero: \"Paz a esta casa\"."},
    {"Lucas", "Lc", 10, 6, "Y si alli hay gente de paz, descansara sobre ellos vuestra paz; si no, volvera a vosotros."},
    {"Lucas", "Lc", 10, 7, "Quedaos en la misma casa, comiendo y bebiendo de lo que tengan: porque el obrero merece su salario. No andeis cambiando de casa en casa."},
    {"Lucas", "Lc", 10, 8, "Si entrais en una ciudad y os reciben, comed lo que os pongan,"},
    {"Lucas", "Lc", 10, 9, "curad a los enfermos que haya en ella, y decidles: \"El reino de Dios ha llegado a vosotros\"."},
    {"Lucas", "Lc", 10, 10, "Pero si entrais en una ciudad y no os reciben, saliendo a sus plazas, decid:"},
    {"Lucas", "Lc", 10, 11, "\"Hasta el polvo de vuestra ciudad, que se nos ha pegado a los pies, nos lo sacudimos sobre vosotros. De todos modos, sabed que el reino de Dios ha llegado\"."},
    {"Lucas", "Lc", 10, 12, "Os digo que aquel dia sera mas llevadero para Sodoma que para esa ciudad."},
    {"Lucas", "Lc", 10, 13, "Ay de ti, Corozain; ay de ti, Betsaida! Pues si en Tiro y en Sidon se hubieran hecho los milagros que en vosotras, hace tiempo que se habrian convertido, vestidos de sayal y sentados en la ceniza."},
    {"Lucas", "Lc", 10, 14, "Por eso el juicio les sera mas llevadero a Tiro y a Sidon que a vosotras."},
    {"Lucas", "Lc", 10, 15, "Y tu, Cafarnaun, piensas escalar el cielo? Bajaras al abismo."},
    {"Lucas", "Lc", 10, 16, "Quien a vosotros escucha, a mi me escucha; quien a vosotros rechaza, a mi me rechaza; y quien me rechaza a mi, rechaza al que me ha enviado\"."},
    {"Lucas", "Lc", 10, 17, "Los setenta y dos volvieron con alegria diciendo: \"Se\177or, hasta los demonios se nos someten en tu nombre\"."},
    {"Lucas", "Lc", 10, 18, "El les dijo: \"Estaba viendo a Satanas caer del cielo como un rayo."},
    {"Lucas", "Lc", 10, 19, "Mirad: os he dado el poder de pisotear serpientes y escorpiones y todo poder del enemigo, y nada os hara da\177o alguno."},
    {"Lucas", "Lc", 10, 20, "Sin embargo, no esteis alegres porque se os someten los espiritus; estad alegres porque vuestros nombres estan inscritos en el cielo\"."},
    {"Lucas", "Lc", 10, 21, "En aquella hora, se lleno de alegria en el Espiritu Santo y dijo: \"Te doy gracias, Padre, Se\177or del cielo y de la tierra, porque has escondido estas cosas a los sabios y entendidos, y las has revelado a los peque\177os. Si, Padre, porque asi te ha parecido bien."},
    {"Lucas", "Lc", 10, 22, "Todo me ha sido entregado por mi Padre, y nadie conoce quien es el Hijo sino el Padre; ni quien es el Padre sino el Hijo y aquel a quien el Hijo se lo quiera revelar\"."},
    {"Lucas", "Lc", 10, 23, "Y, volviendose a sus discipulos, les dijo aparte: \"Bienaventurados los ojos que ven lo que vosotros veis!"},
    {"Lucas", "Lc", 10, 24, "Porque os digo que muchos profetas y reyes quisieron ver lo que vosotros veis, y no lo vieron; y oir lo que vosotros ois, y no lo oyeron\"."},
    {"Lucas", "Lc", 10, 25, "En esto se levanto un maestro de la ley y le pregunto para ponerlo a prueba: \"Maestro, que tengo que hacer para heredar la vida eterna?\"."},
    {"Lucas", "Lc", 10, 26, "El le dijo: \"Que esta escrito en la ley? Que lees en ella?\"."},
    {"Lucas", "Lc", 10, 27, "El respondio: \"Amaras al Se\177or, tu Dios, con todo tu corazon y con toda tu alma y con toda tu fuerza y con toda tu mente. Y a tu projimo como a ti mismo\"."},
    {"Lucas", "Lc", 10, 28, "El le dijo: \"Has respondido correctamente. Haz esto y tendras la vida\"."},
    {"Lucas", "Lc", 10, 29, "Pero el maestro de la ley, queriendo justificarse, dijo a Jesus: \"Y quien es mi projimo?\"."},
    {"Lucas", "Lc", 10, 30, "Respondio Jesus diciendo: \"Un hombre bajaba de Jerusalen a Jerico, cayo en manos de unos bandidos, que lo desnudaron, lo molieron a palos y se marcharon, dejandolo medio muerto."},
    {"Lucas", "Lc", 10, 31, "Por casualidad, un sacerdote bajaba por aquel camino y, al verlo, dio un rodeo y paso de largo."},
    {"Lucas", "Lc", 10, 32, "Y lo mismo hizo un levita que llego a aquel sitio: al verlo dio un rodeo y paso de largo."},
    {"Lucas", "Lc", 10, 33, "Pero un samaritano que iba de viaje llego adonde estaba el y, al verlo, se compadecio,"},
    {"Lucas", "Lc", 10, 34, "y acercandose, le vendo las heridas, echandoles aceite y vino, y, montandolo en su propia cabalgadura, lo llevo a una posada y lo cuido."},
    {"Lucas", "Lc", 10, 35, "Al dia siguiente, sacando dos denarios, se los dio al posadero y le dijo: \"Cuida de el, y lo que gastes de mas yo te lo pagare cuando vuelva\"."},
    {"Lucas", "Lc", 10, 36, "Cual de estos tres te parece que ha sido projimo del que cayo en manos de los bandidos?\"."},
    {"Lucas", "Lc", 10, 37, "El dijo: \"El que practico la misericordia con el\". Jesus le dijo: \"Anda y haz tu lo mismo\"."},
    {"Lucas", "Lc", 10, 38, "Yendo ellos de camino, entro Jesus en una aldea, y una mujer llamada Marta lo recibio en su casa."},
    {"Lucas", "Lc", 10, 39, "Esta tenia una hermana llamada Maria, que, sentada junto a los pies del Se\177or, escuchaba su palabra."},
    {"Lucas", "Lc", 10, 40, "Marta, en cambio, andaba muy afanada con los muchos servicios; hasta que, acercandose, dijo: \"Se\177or, no te importa que mi hermana me haya dejado sola para servir? Dile que me eche una mano\"."},
    {"Lucas", "Lc", 10, 41, "Respondiendo, le dijo el Se\177or: \"Marta, Marta, andas inquieta y preocupada con muchas cosas;"},
    {"Lucas", "Lc", 10, 42, "solo una es necesaria. Maria, pues, ha escogido la parte mejor, y no le sera quitada\"."},
    {"Lucas", "Lc", 11, 1, "Una vez que estaba Jesus orando en cierto lugar, cuando termino, uno de sus discipulos le dijo: \"Se\177or, ense\177anos a orar, como Juan ense\177o a sus discipulos\"."},
    {"Lucas", "Lc", 11, 2, "El les dijo: \"Cuando oreis, decid: \"Padre, santificado sea tu nombre, venga tu reino,"},
    {"Lucas", "Lc", 11, 3, "danos cada dia nuestro pan cotidiano,"},
    {"Lucas", "Lc", 11, 4, "perdonanos nuestros pecados, porque tambien nosotros perdonamos a todo el que nos debe, y no nos dejes caer en tentacion\"\"."},
    {"Lucas", "Lc", 11, 5, "Y les dijo: \"Suponed que alguno de vosotros tiene un amigo, y viene durante la medianoche y le dice: \"Amigo, prestame tres panes,"},
    {"Lucas", "Lc", 11, 6, "pues uno de mis amigos ha venido de viaje y no tengo nada que ofrecerle\";"},
    {"Lucas", "Lc", 11, 7, "y, desde dentro, aquel le responde: \"No me molestes; la puerta ya esta cerrada; mis ni\177os y yo estamos acostados; no puedo levantarme para dartelos\";"},
    {"Lucas", "Lc", 11, 8, "os digo que, si no se levanta y se los da por ser amigo suyo, al menos por su importunidad se levantara y le dara cuanto necesite."},
    {"Lucas", "Lc", 11, 9, "Pues yo os digo a vosotros: pedid y se os dara, buscad y hallareis, llamad y se os abrira;"},
    {"Lucas", "Lc", 11, 10, "porque todo el que pide recibe, y el que busca halla, y al que llama se le abre."},
    {"Lucas", "Lc", 11, 11, "Que padre entre vosotros, si su hijo le pide un pez, le dara una serpiente en lugar del pez?"},
    {"Lucas", "Lc", 11, 12, "O si le pide un huevo, le dara un escorpion?"},
    {"Lucas", "Lc", 11, 13, "Si vosotros, pues, que sois malos, sabeis dar cosas buenas a vuestros hijos, cuanto mas el Padre del cielo dara el Espiritu Santo a los que le piden?\"."},
    {"Lucas", "Lc", 11, 14, "Estaba Jesus echando un demonio que era mudo. Sucedio que, apenas salio el demonio, empezo a hablar el mudo. La multitud se quedo admirada,"},
    {"Lucas", "Lc", 11, 15, "pero algunos de ellos dijeron: \"Por arte de Belzebu, el principe de los demonios, echa los demonios\"."},
    {"Lucas", "Lc", 11, 16, "Otros, para ponerlo a prueba, le pedian un signo del cielo."},
    {"Lucas", "Lc", 11, 17, "El, conociendo sus pensamientos, les dijo: \"Todo reino dividido contra si mismo va a la ruina y cae casa sobre casa."},
    {"Lucas", "Lc", 11, 18, "Si, pues, tambien Satanas se ha dividido contra si mismo, como se mantendra su reino? Pues vosotros decis que yo echo los demonios con el poder de Belzebu."},
    {"Lucas", "Lc", 11, 19, "Pero, si yo echo los demonios con el poder de Belzebu, vuestros hijos, por arte de quien los echan? Por eso, ellos mismos seran vuestros jueces."},
    {"Lucas", "Lc", 11, 20, "Pero, si yo echo los demonios con el dedo de Dios, entonces es que el reino de Dios ha llegado a vosotros."},
    {"Lucas", "Lc", 11, 21, "Cuando un hombre fuerte y bien armado guarda su palacio, sus bienes estan seguros,"},
    {"Lucas", "Lc", 11, 22, "pero, cuando otro mas fuerte lo asalta y lo vence, le quita las armas de que se fiaba y reparte su botin."},
    {"Lucas", "Lc", 11, 23, "El que no esta conmigo esta contra mi; el que no recoge conmigo desparrama."},
    {"Lucas", "Lc", 11, 24, "Cuando el espiritu inmundo sale de un hombre, da vueltas por lugares aridos, buscando un sitio para descansar, y, al no encontrarlo, dice: \"Volvere a mi casa de donde sali\"."},
    {"Lucas", "Lc", 11, 25, "Al volver se la encuentra barrida y arreglada."},
    {"Lucas", "Lc", 11, 26, "Entonces va y toma otros siete espiritus peores que el, y se mete a vivir alli. Y el final de aquel hombre resulta peor que el principio\"."},
    {"Lucas", "Lc", 11, 27, "Mientras el hablaba estas cosas, acontecio que una mujer de entre el gentio, levantando la voz, le dijo: \"Bienaventurado el vientre que te llevo y los pechos que te criaron\"."},
    {"Lucas", "Lc", 11, 28, "Pero el dijo: \"Mejor, bienaventurados los que escuchan la palabra de Dios y la cumplen\"."},
    {"Lucas", "Lc", 11, 29, "Estaba la gente api\177andose alrededor de el y se puso a decirles: \"Esta generacion es una generacion perversa. Pide un signo, pero no se le dara mas signo que el signo de Jonas."},
    {"Lucas", "Lc", 11, 30, "Pues como Jonas fue un signo para los habitantes de Ninive, lo mismo sera el Hijo del hombre para esta generacion."},
    {"Lucas", "Lc", 11, 31, "La reina del Sur se levantara en el juicio contra los hombres de esta generacion y hara que los condenen, porque ella vino desde los confines de la tierra para escuchar la sabiduria de Salomon, y aqui hay uno que es mas que Salomon."},
    {"Lucas", "Lc", 11, 32, "Los hombres de Ninive se alzaran en el juicio contra esta generacion y haran que la condenen; porque ellos se convirtieron con la proclamacion de Jonas, y aqui hay uno que es mas que Jonas."},
    {"Lucas", "Lc", 11, 33, "Nadie enciende una lampara y la pone en un lugar oculto o debajo del celemin, sino sobre el candelero, para que los que entran vean la luz."},
    {"Lucas", "Lc", 11, 34, "La lampara del cuerpo es tu ojo. Cuando tu ojo esta sano, tambien todo tu cuerpo esta iluminado, pero cuando esta enfermo, tambien tu cuerpo esta a oscuras."},
    {"Lucas", "Lc", 11, 35, "Por eso, ten cuidado de que la luz que hay en ti no sea oscuridad."},
    {"Lucas", "Lc", 11, 36, "Por tanto, si todo tu cuerpo esta iluminado, sin tener parte alguna oscura, estara enteramente iluminado, igual que cuando una lampara te ilumina con su resplandor\"."},
    {"Lucas", "Lc", 11, 37, "Cuando termino de hablar, un fariseo le rogo que fuese a comer con el. El entro y se puso a la mesa."},
    {"Lucas", "Lc", 11, 38, "Como el fariseo se sorprendio al ver que no se lavaba las manos antes de comer,"},
    {"Lucas", "Lc", 11, 39, "el Se\177or le dijo: \"Vosotros, los fariseos, limpiais por fuera la copa y el plato, pero por dentro rebosais de rapi\177a y maldad."},
    {"Lucas", "Lc", 11, 40, "Necios! El que hizo lo de fuera, no hizo tambien lo de dentro?"},
    {"Lucas", "Lc", 11, 41, "Con todo, dad limosna de lo que hay dentro, y lo tendreis limpio todo."},
    {"Lucas", "Lc", 11, 42, "Pero ay de vosotros, fariseos, que pagais el diezmo de la hierbabuena, de la ruda y de toda clase de hortalizas, mientras pasais por alto el derecho y el amor de Dios! Esto es lo que habia que practicar, sin descuidar aquello."},
    {"Lucas", "Lc", 11, 43, "Ay de vosotros, fariseos, que os encantan los asientos de honor en las sinagogas y los saludos en las plazas!"},
    {"Lucas", "Lc", 11, 44, "Ay de vosotros, que sois como tumbas no se\177aladas, que la gente pisa sin saberlo!\"."},
    {"Lucas", "Lc", 11, 45, "Le replico un maestro de la ley: \"Maestro, diciendo eso nos ofendes tambien a nosotros\"."},
    {"Lucas", "Lc", 11, 46, "Y el dijo: \"Ay de vosotros tambien, maestros de la ley, que cargais a los hombres cargas insoportables, mientras vosotros no tocais las cargas ni con uno de vuestros dedos!"},
    {"Lucas", "Lc", 11, 47, "Ay de vosotros, que edificais mausoleos a los profetas, a quienes mataron vuestros padres!"},
    {"Lucas", "Lc", 11, 48, "Asi sois testigos de lo que hicieron vuestros padres, y lo aprobais; porque ellos los mataron y vosotros les edificais mausoleos."},
    {"Lucas", "Lc", 11, 49, "Por eso dijo la Sabiduria de Dios: \"Les enviare profetas y apostoles: a algunos de ellos los mataran y perseguiran\";"},
    {"Lucas", "Lc", 11, 50, "y asi a esta generacion se le pedira cuenta de la sangre de todos los profetas derramada desde la creacion del mundo;"},
    {"Lucas", "Lc", 11, 51, "desde la sangre de Abel hasta la sangre de Zacarias, que perecio entre el altar y el santuario. Si, os digo: se le pedira cuenta a esta generacion."},
    {"Lucas", "Lc", 11, 52, "Ay de vosotros, maestros de la ley, que os habeis apoderado de la llave de la ciencia: vosotros no habeis entrado y a los que intentaban entrar se lo habeis impedido!\"."},
    {"Lucas", "Lc", 11, 53, "Al salir de alli, los escribas y fariseos empezaron a acosarlo implacablemente y a tirarle de la lengua con muchas preguntas capciosas,"},
    {"Lucas", "Lc", 11, 54, "tendiendole trampas para cazarlo con alguna palabra de su boca."},
    {"Lucas", "Lc", 12, 1, "Mientras tanto, miles y miles de personas se agolpaban hasta pisarse unos a otros. Jesus empezo a hablar, dirigiendose primero a sus discipulos: \"Cuidado con la levadura de los fariseos, que es la hipocresia,"},
    {"Lucas", "Lc", 12, 2, "pues nada hay cubierto que no llegue a descubrirse, ni nada escondido que no llegue a saberse."},
    {"Lucas", "Lc", 12, 3, "Por eso, lo que digais en la oscuridad sera oido a plena luz, y lo que digais al oido en las recamaras se pregonara desde la azotea."},
    {"Lucas", "Lc", 12, 4, "A vosotros os digo, amigos mios: no tengais miedo a los que matan el cuerpo, y despues de esto no pueden hacer mas."},
    {"Lucas", "Lc", 12, 5, "Os voy a ense\177ar a quien teneis que temer: temed al que, despues de la muerte, tiene poder para arrojar a la gehenna. A ese teneis que temer, os lo digo yo."},
    {"Lucas", "Lc", 12, 6, "No se venden cinco pajaros por dos centimos? Pues ni de uno solo de ellos se olvida Dios."},
    {"Lucas", "Lc", 12, 7, "Mas aun, hasta los cabellos de vuestra cabeza estan contados. No tengais miedo: valeis mas que muchos pajaros."},
    {"Lucas", "Lc", 12, 8, "Os digo, pues: todo aquel que se declare por mi ante los hombres, tambien el Hijo del hombre se declarara por el ante los angeles de Dios,"},
    {"Lucas", "Lc", 12, 9, "pero si uno me niega ante los hombres, sera negado ante los angeles de Dios."},
    {"Lucas", "Lc", 12, 10, "Todo el que diga una palabra contra el Hijo del hombre podra ser perdonado, pero al que blasfeme contra el Espiritu Santo no se le perdonara."},
    {"Lucas", "Lc", 12, 11, "Cuando os conduzcan a las sinagogas, ante los magistrados y las autoridades, no os preocupeis de como o con que razones os defendereis o de lo que vais a decir,"},
    {"Lucas", "Lc", 12, 12, "porque el Espiritu Santo os ense\177ara en aquel momento lo que teneis que decir\"."},
    {"Lucas", "Lc", 12, 13, "Entonces le dijo uno de la gente: \"Maestro, dile a mi hermano que reparta conmigo la herencia\"."},
    {"Lucas", "Lc", 12, 14, "El le dijo: \"Hombre, quien me ha constituido juez o arbitro entre vosotros?\"."},
    {"Lucas", "Lc", 12, 15, "Y les dijo: \"Mirad: guardaos de toda clase de codicia. Pues, aunque uno ande sobrado, su vida no depende de sus bienes\"."},
    {"Lucas", "Lc", 12, 16, "Y les propuso una parabola: \"Las tierras de un hombre rico produjeron una gran cosecha."},
    {"Lucas", "Lc", 12, 17, "Y empezo a echar calculos, diciendose: \"Que hare? No tengo donde almacenar la cosecha\"."},
    {"Lucas", "Lc", 12, 18, "Y se dijo: \"Hare lo siguiente: derribare los graneros y construire otros mas grandes, y almacenare alli todo el trigo y mis bienes."},
    {"Lucas", "Lc", 12, 19, "Y entonces me dire a mi mismo: alma mia, tienes bienes almacenados para muchos a\177os; descansa, come, bebe, banquetea alegremente\"."},
    {"Lucas", "Lc", 12, 20, "Pero Dios le dijo: \"Necio, esta noche te van a reclamar el alma, y de quien sera lo que has preparado?\"."},
    {"Lucas", "Lc", 12, 21, "Asi es el que atesora para si y no es rico ante Dios\"."},
    {"Lucas", "Lc", 12, 22, "Y dijo a sus discipulos: \"Por eso os digo: no os inquieteis por la vida, que vais a comer; ni por el cuerpo, con que os vais a vestir,"},
    {"Lucas", "Lc", 12, 23, "pues la vida es mas que el alimento y el cuerpo mas que el vestido."},
    {"Lucas", "Lc", 12, 24, "Fijaos en los cuervos: ni siembran ni cosechan, no tienen despensa ni granero, y Dios los alimenta; cuanto mas valeis vosotros que los pajaros!"},
    {"Lucas", "Lc", 12, 25, "Quien de vosotros, a fuerza de agobiarse, podra a\177adir una hora al tiempo de su vida?"},
    {"Lucas", "Lc", 12, 26, "Por tanto, si no podeis lo mas peque\177o, por que inquietaros por lo demas?"},
    {"Lucas", "Lc", 12, 27, "Fijaos como crecen los lirios, no se fatigan ni hilan; pues os digo que ni Salomon en todo su esplendor se vistio como uno de ellos."},
    {"Lucas", "Lc", 12, 28, "Pues si Dios viste asi a la hierba que hoy esta en el campo y ma\177ana es arrojada al horno, cuanto mas a vosotros, hombres de poca fe!"},
    {"Lucas", "Lc", 12, 29, "Y vosotros no andeis buscando que vais a comer o que vais a beber, ni esteis preocupados."},
    {"Lucas", "Lc", 12, 30, "La gente del mundo se afana por todas esas cosas, pero vuestro Padre sabe que teneis necesidad de ellas."},
    {"Lucas", "Lc", 12, 31, "Buscad mas bien su reino, y lo demas se os dara por a\177adidura."},
    {"Lucas", "Lc", 12, 32, "No temas, peque\177o reba\177o, porque vuestro Padre ha tenido a bien daros el reino."},
    {"Lucas", "Lc", 12, 33, "Vended vuestros bienes y dad limosna; haceos bolsas que no se estropeen, y un tesoro inagotable en el cielo, adonde no se acercan los ladrones ni roe la polilla."},
    {"Lucas", "Lc", 12, 34, "Porque donde esta vuestro tesoro, alli estara tambien vuestro corazon."},
    {"Lucas", "Lc", 12, 35, "Tened ce\177ida vuestra cintura y encendidas las lamparas."},
    {"Lucas", "Lc", 12, 36, "Vosotros estad como los hombres que aguardan a que su se\177or vuelva de la boda, para abrirle apenas venga y llame."},
    {"Lucas", "Lc", 12, 37, "Bienaventurados aquellos criados a quienes el se\177or, al llegar, los encuentre en vela; en verdad os digo que se ce\177ira, los hara sentar a la mesa y, acercandose, les ira sirviendo."},
    {"Lucas", "Lc", 12, 38, "Y, si llega a la segunda vigilia o a la tercera y los encuentra asi, bienaventurados ellos."},
    {"Lucas", "Lc", 12, 39, "Comprended que si supiera el due\177o de casa a que hora viene el ladron, velaria y no le dejaria abrir un boquete en casa."},
    {"Lucas", "Lc", 12, 40, "Lo mismo vosotros, estad preparados, porque a la hora que menos penseis viene el Hijo del hombre\"."},
    {"Lucas", "Lc", 12, 41, "Pedro le dijo: \"Se\177or, dices esta parabola por nosotros o por todos?\"."},
    {"Lucas", "Lc", 12, 42, "Y el Se\177or dijo: \"Quien es el administrador fiel y prudente a quien el se\177or pondra al frente de su servidumbre para que reparta la racion de alimento a sus horas?"},
    {"Lucas", "Lc", 12, 43, "Bienaventurado aquel criado a quien su se\177or, al llegar, lo encuentre portandose asi."},
    {"Lucas", "Lc", 12, 44, "En verdad os digo que lo pondra al frente de todos sus bienes."},
    {"Lucas", "Lc", 12, 45, "Pero si aquel criado dijere para sus adentros: \"Mi se\177or tarda en llegar\", y empieza a pegarles a los criados y criadas, a comer y beber y emborracharse,"},
    {"Lucas", "Lc", 12, 46, "vendra el se\177or de ese criado el dia que no espera y a la hora que no sabe y lo castigara con rigor, y le hara compartir la suerte de los que no son fieles."},
    {"Lucas", "Lc", 12, 47, "El criado que, conociendo la voluntad de su se\177or, no se prepara ni obra de acuerdo con su voluntad, recibira muchos azotes;"},
    {"Lucas", "Lc", 12, 48, "pero el que, sin conocerla, ha hecho algo digno de azotes, recibira menos. Al que mucho se le dio, mucho se le reclamara; al que mucho se le confio, mas aun se le pedira."},
    {"Lucas", "Lc", 12, 49, "He venido a prender fuego a la tierra, y cuanto deseo que ya este ardiendo!"},
    {"Lucas", "Lc", 12, 50, "Con un bautismo tengo que ser bautizado, y que angustia sufro hasta que se cumpla!"},
    {"Lucas", "Lc", 12, 51, "Pensais que he venido a traer paz a la tierra? No, sino division."},
    {"Lucas", "Lc", 12, 52, "Desde ahora estaran divididos cinco en una casa: tres contra dos y dos contra tres;"},
    {"Lucas", "Lc", 12, 53, "estaran divididos el padre contra el hijo y el hijo contra el padre, la madre contra la hija y la hija contra la madre, la suegra contra su nuera y la nuera contra la suegra\"."},
    {"Lucas", "Lc", 12, 54, "Decia tambien a la gente: \"Cuando veis subir una nube por el poniente, decis enseguida: \"Va a caer un aguacero\", y asi sucede."},
    {"Lucas", "Lc", 12, 55, "Cuando sopla el sur decis: \"Va a hacer bochorno\", y sucede."},
    {"Lucas", "Lc", 12, 56, "Hipocritas: sabeis interpretar el aspecto de la tierra y del cielo, pues como no sabeis interpretar el tiempo presente?"},
    {"Lucas", "Lc", 12, 57, "Como no sabeis juzgar vosotros mismos lo que es justo?"},
    {"Lucas", "Lc", 12, 58, "Por ello, mientras vas con tu adversario al magistrado, haz lo posible en el camino por llegar a un acuerdo con el, no sea que te lleve a la fuerza ante el juez y el juez te entregue al guardia y el guardia te meta en la carcel."},
    {"Lucas", "Lc", 12, 59, "Te digo que no saldras de alli hasta que no pagues la ultima monedilla\"."},
    {"Lucas", "Lc", 13, 1, "En aquel momento se presentaron algunos a contar a Jesus lo de los galileos, cuya sangre habia mezclado Pilato con la de los sacrificios que ofrecian."},
    {"Lucas", "Lc", 13, 2, "Jesus respondio: \"Pensais que esos galileos eran mas pecadores que los demas galileos porque han padecido todo esto?"},
    {"Lucas", "Lc", 13, 3, "Os digo que no; y, si no os convertis, todos perecereis lo mismo."},
    {"Lucas", "Lc", 13, 4, "O aquellos dieciocho sobre los que cayo la torre en Siloe y los mato, pensais que eran mas culpables que los demas habitantes de Jerusalen?"},
    {"Lucas", "Lc", 13, 5, "Os digo que no; y, si no os convertis, todos perecereis de la misma manera\"."},
    {"Lucas", "Lc", 13, 6, "Y les dijo esta parabola: \"Uno tenia una higuera plantada en su vi\177a, y fue a buscar fruto en ella, y no lo encontro."},
    {"Lucas", "Lc", 13, 7, "Dijo entonces al vi\177ador: \"Ya ves, tres a\177os llevo viniendo a buscar fruto en esta higuera, y no lo encuentro. Cortala. Para que va a perjudicar el terreno?\"."},
    {"Lucas", "Lc", 13, 8, "Pero el vi\177ador respondio: \"Se\177or, dejala todavia este a\177o y mientras tanto yo cavare alrededor y le echare estiercol,"},
    {"Lucas", "Lc", 13, 9, "a ver si da fruto en adelante. Si no, la puedes cortar\"\"."},
    {"Lucas", "Lc", 13, 10, "Un sabado, ense\177aba Jesus en una sinagoga."},
    {"Lucas", "Lc", 13, 11, "Habia una mujer que desde hacia dieciocho a\177os estaba enferma por causa de un espiritu, y estaba encorvada, sin poderse enderezar de ningun modo."},
    {"Lucas", "Lc", 13, 12, "Al verla, Jesus la llamo y le dijo: \"Mujer, quedas libre de tu enfermedad\"."},
    {"Lucas", "Lc", 13, 13, "Le impuso las manos, y enseguida se puso derecha. Y glorificaba a Dios."},
    {"Lucas", "Lc", 13, 14, "Pero el jefe de la sinagoga, indignado porque Jesus habia curado en sabado, se puso a decir a la gente: \"Hay seis dias para trabajar; venid, pues, a que os curen en esos dias y no en sabado\"."},
    {"Lucas", "Lc", 13, 15, "Pero el Se\177or le respondio y dijo: \"Hipocritas: cualquiera de vosotros, no desata en sabado su buey o su burro del pesebre, y los lleva a abrevar?"},
    {"Lucas", "Lc", 13, 16, "Y a esta, que es hija de Abrahan, y que Satanas ha tenido atada dieciocho a\177os, no era necesario soltarla de tal ligadura en dia de sabado?\"."},
    {"Lucas", "Lc", 13, 17, "Al decir estas palabras, sus enemigos quedaron abochornados, y toda la gente se alegraba por todas las maravillas que hacia."},
    {"Lucas", "Lc", 13, 18, "Decia, pues: \"A que es semejante el reino de Dios o a que lo comparare?"},
    {"Lucas", "Lc", 13, 19, "Es semejante a un grano de mostaza que un hombre toma y siembra en su huerto; crecio, se hizo un arbol y los pajaros del cielo anidaron en sus ramas\"."},
    {"Lucas", "Lc", 13, 20, "Y dijo de nuevo: \"A que comparare el reino de Dios?"},
    {"Lucas", "Lc", 13, 21, "Es semejante a la levadura que una mujer tomo y metio en tres medidas de harina, hasta que todo fermento\"."},
    {"Lucas", "Lc", 13, 22, "Y pasaba por ciudades y aldeas ense\177ando y se encaminaba hacia Jerusalen."},
    {"Lucas", "Lc", 13, 23, "Uno le pregunto: \"Se\177or, son pocos los que se salvan?\". El les dijo:"},
    {"Lucas", "Lc", 13, 24, "\"Esforzaos en entrar por la puerta estrecha, pues os digo que muchos intentaran entrar y no podran."},
    {"Lucas", "Lc", 13, 25, "Cuando el amo de la casa se levante y cierre la puerta, os quedareis fuera y llamareis a la puerta diciendo: \"Se\177or, abrenos\"; pero el os dira: \"No se quienes sois\"."},
    {"Lucas", "Lc", 13, 26, "Entonces comenzareis a decir: \"Hemos comido y bebido contigo, y tu has ense\177ado en nuestras plazas\"."},
    {"Lucas", "Lc", 13, 27, "Pero el os dira: \"No se de donde sois. Alejaos de mi todos los que obrais la iniquidad\"."},
    {"Lucas", "Lc", 13, 28, "Alli sera el llanto y el rechinar de dientes, cuando veais a Abrahan, a Isaac y a Jacob y a todos los profetas en el reino de Dios, pero vosotros os veais arrojados fuera."},
    {"Lucas", "Lc", 13, 29, "Y vendran de oriente y occidente, del norte y del sur, y se sentaran a la mesa en el reino de Dios."},
    {"Lucas", "Lc", 13, 30, "Mirad: hay ultimos que seran primeros, y primeros que seran ultimos\"."},
    {"Lucas", "Lc", 13, 31, "En aquella misma ocasion, se acercaron unos fariseos a decirle: \"Sal y marcha de aqui, porque Herodes quiere matarte\"."},
    {"Lucas", "Lc", 13, 32, "Y les dijo: \"Id y decid a ese zorro: \"Mira, yo arrojo demonios y realizo curaciones hoy y ma\177ana, y al tercer dia mi obra quedara consumada."},
    {"Lucas", "Lc", 13, 33, "Pero es necesario que camine hoy y ma\177ana y pasado, porque no cabe que un profeta muera fuera de Jerusalen\"."},
    {"Lucas", "Lc", 13, 34, "Jerusalen, Jerusalen, que matas a los profetas y apedreas a los que se te envian! Cuantas veces he querido reunir a tus hijos, como la gallina reune a sus polluelos bajo las alas, y no habeis querido. Mirad, vuestra casa va a ser abandonada."},
    {"Lucas", "Lc", 13, 35, "Os digo que no me vereis hasta el dia en que digais: Bendito el que viene en nombre del Se\177or!\"."},
    {"Lucas", "Lc", 14, 1, "Un sabado, entro el en casa de uno de los principales fariseos para comer y ellos lo estaban espiando."},
    {"Lucas", "Lc", 14, 2, "Habia alli, delante de el, un hombre enfermo de hidropesia,"},
    {"Lucas", "Lc", 14, 3, "y tomando la palabra, dijo a los maestros de la ley y a los fariseos: \"Es licito curar los sabados, o no?\"."},
    {"Lucas", "Lc", 14, 4, "Ellos se quedaron callados. Jesus, tocando al enfermo, lo curo y lo despidio."},
    {"Lucas", "Lc", 14, 5, "Y a ellos les dijo: \"A quien de vosotros se le cae al pozo el asno o el buey y no lo saca enseguida en dia de sabado?\"."},
    {"Lucas", "Lc", 14, 6, "Y no pudieron replicar a esto."},
    {"Lucas", "Lc", 14, 7, "Notando que los convidados escogian los primeros puestos, les decia una parabola:"},
    {"Lucas", "Lc", 14, 8, "\"Cuando te conviden a una boda, no te sientes en el puesto principal, no sea que hayan convidado a otro de mas categoria que tu;"},
    {"Lucas", "Lc", 14, 9, "y venga el que os convido a ti y al otro, y te diga: \"Cedele el puesto a este\". Entonces, avergonzado, iras a ocupar el ultimo puesto."},
    {"Lucas", "Lc", 14, 10, "Al reves, cuando te conviden, vete a sentarte en el ultimo puesto, para que, cuando venga el que te convido, te diga: \"Amigo, sube mas arriba\". Entonces quedaras muy bien ante todos los comensales."},
    {"Lucas", "Lc", 14, 11, "Porque todo el que se enaltece sera humillado; y el que se humilla sera enaltecido\"."},
    {"Lucas", "Lc", 14, 12, "Y dijo al que lo habia invitado: \"Cuando des una comida o una cena, no invites a tus amigos, ni a tus hermanos, ni a tus parientes, ni a los vecinos ricos; porque corresponderan invitandote, y quedaras pagado."},
    {"Lucas", "Lc", 14, 13, "Cuando des un banquete, invita a pobres, lisiados, cojos y ciegos;"},
    {"Lucas", "Lc", 14, 14, "y seras bienaventurado, porque no pueden pagarte; te pagaran en la resurreccion de los justos\"."},
    {"Lucas", "Lc", 14, 15, "Uno de los comensales dijo a Jesus: \"Bienaventurado el que coma en el reino de Dios!\"."},
    {"Lucas", "Lc", 14, 16, "Jesus le contesto: \"Un hombre daba un gran banquete y convido a mucha gente;"},
    {"Lucas", "Lc", 14, 17, "a la hora del banquete mando a su criado a avisar a los convidados: \"Venid, que ya esta preparado\"."},
    {"Lucas", "Lc", 14, 18, "Pero todos a una empezaron a excusarse. El primero le dijo: \"He comprado un campo y necesito ir a verlo. Dispensame, por favor\"."},
    {"Lucas", "Lc", 14, 19, "Otro dijo: \"He comprado cinco yuntas de bueyes y voy a probarlas. Dispensame, por favor\"."},
    {"Lucas", "Lc", 14, 20, "Otro dijo: \"Me acabo de casar y, por ello, no puedo ir\"."},
    {"Lucas", "Lc", 14, 21, "El criado volvio a contarselo a su se\177or. Entonces el due\177o de casa, indignado, dijo a su criado: \"Sal aprisa a las plazas y calles de la ciudad y traete aqui a los pobres, a los lisiados, a los ciegos y a los cojos\"."},
    {"Lucas", "Lc", 14, 22, "El criado dijo: \"Se\177or, se ha hecho lo que mandaste, y todavia queda sitio\"."},
    {"Lucas", "Lc", 14, 23, "Entonces el se\177or dijo al criado: \"Sal por los caminos y senderos, e insisteles hasta que entren y se llene mi casa."},
    {"Lucas", "Lc", 14, 24, "Y os digo que ninguno de aquellos convidados probara mi banquete\"\"."},
    {"Lucas", "Lc", 14, 25, "Mucha gente acompa\177aba a Jesus; el se volvio y les dijo:"},
    {"Lucas", "Lc", 14, 26, "\"Si alguno viene a mi y no pospone a su padre y a su madre, a su mujer y a sus hijos, a sus hermanos y a sus hermanas, e incluso a si mismo, no puede ser discipulo mio."},
    {"Lucas", "Lc", 14, 27, "Quien no carga con su cruz y viene en pos de mi, no puede ser discipulo mio."},
    {"Lucas", "Lc", 14, 28, "Asi, quien de vosotros, si quiere construir una torre, no se sienta primero a calcular los gastos, a ver si tiene para terminarla?"},
    {"Lucas", "Lc", 14, 29, "No sea que, si echa los cimientos y no puede acabarla, se pongan a burlarse de el los que miran,"},
    {"Lucas", "Lc", 14, 30, "diciendo: \"Este hombre empezo a construir y no pudo acabar\"."},
    {"Lucas", "Lc", 14, 31, "O que rey, si va a dar la batalla a otro rey, no se sienta primero a deliberar si con diez mil hombres podra salir al paso del que lo ataca con veinte mil?"},
    {"Lucas", "Lc", 14, 32, "Y si no, cuando el otro esta todavia lejos, envia legados para pedir condiciones de paz."},
    {"Lucas", "Lc", 14, 33, "Asi pues, todo aquel de entre vosotros que no renuncia a todos sus bienes no puede ser discipulo mio."},
    {"Lucas", "Lc", 14, 34, "La sal es buena, pero si la sal se vuelve sosa, con que la salaran?"},
    {"Lucas", "Lc", 14, 35, "No sirve ni para el campo ni para el estercolero, se tira afuera. El que tenga oidos para oir, que oiga\"."},
    {"Lucas", "Lc", 15, 1, "Solian acercarse a Jesus todos los publicanos y los pecadores a escucharlo."},
    {"Lucas", "Lc", 15, 2, "Y los fariseos y los escribas murmuraban diciendo: \"Ese acoge a los pecadores y come con ellos\"."},
    {"Lucas", "Lc", 15, 3, "Jesus les dijo esta parabola:"},
    {"Lucas", "Lc", 15, 4, "\"Quien de vosotros que tiene cien ovejas y pierde una de ellas, no deja las noventa y nueve en el desierto y va tras la descarriada, hasta que la encuentra?"},
    {"Lucas", "Lc", 15, 5, "Y, cuando la encuentra, se la carga sobre los hombros, muy contento;"},
    {"Lucas", "Lc", 15, 6, "y, al llegar a casa, reune a los amigos y a los vecinos, y les dice: \"Alegraos conmigo!, he encontrado la oveja que se me habia perdido\"."},
    {"Lucas", "Lc", 15, 7, "Os digo que asi tambien habra mas alegria en el cielo por un solo pecador que se convierta que por noventa y nueve justos que no necesitan convertirse."},
    {"Lucas", "Lc", 15, 8, "O que mujer que tiene diez monedas, si se le pierde una, no enciende una lampara y barre la casa y busca con cuidado, hasta que la encuentra?"},
    {"Lucas", "Lc", 15, 9, "Y, cuando la encuentra, reune a las amigas y a las vecinas y les dice: \"Alegraos conmigo!, he encontrado la moneda que se me habia perdido\"."},
    {"Lucas", "Lc", 15, 10, "Os digo que la misma alegria tendran los angeles de Dios por un solo pecador que se convierta\"."},
    {"Lucas", "Lc", 15, 11, "Tambien les dijo: \"Un hombre tenia dos hijos;"},
    {"Lucas", "Lc", 15, 12, "el menor de ellos dijo a su padre: \"Padre, dame la parte que me toca de la fortuna\". El padre les repartio los bienes."},
    {"Lucas", "Lc", 15, 13, "No muchos dias despues, el hijo menor, juntando todo lo suyo, se marcho a un pais lejano, y alli derrocho su fortuna viviendo perdidamente."},
    {"Lucas", "Lc", 15, 14, "Cuando lo habia gastado todo, vino por aquella tierra un hambre terrible, y empezo el a pasar necesidad."},
    {"Lucas", "Lc", 15, 15, "Fue entonces y se contrato con uno de los ciudadanos de aquel pais que lo mando a sus campos a apacentar cerdos."},
    {"Lucas", "Lc", 15, 16, "Deseaba saciarse de las algarrobas que comian los cerdos, pero nadie le daba nada."},
    {"Lucas", "Lc", 15, 17, "Recapacitando entonces, se dijo: \"Cuantos jornaleros de mi padre tienen abundancia de pan, mientras yo aqui me muero de hambre."},
    {"Lucas", "Lc", 15, 18, "Me levantare, me pondre en camino adonde esta mi padre, y le dire: Padre, he pecado contra el cielo y contra ti;"},
    {"Lucas", "Lc", 15, 19, "ya no merezco llamarme hijo tuyo: tratame como a uno de tus jornaleros\"."},
    {"Lucas", "Lc", 15, 20, "Se levanto y vino adonde estaba su padre; cuando todavia estaba lejos, su padre lo vio y se le conmovieron las entra\177as; y, echando a correr, se le echo al cuello y lo cubrio de besos."},
    {"Lucas", "Lc", 15, 21, "Su hijo le dijo: \"Padre, he pecado contra el cielo y contra ti; ya no merezco llamarme hijo tuyo\"."},
    {"Lucas", "Lc", 15, 22, "Pero el padre dijo a sus criados: \"Sacad enseguida la mejor tunica y vestidsela; ponedle un anillo en la mano y sandalias en los pies;"},
    {"Lucas", "Lc", 15, 23, "traed el ternero cebado y sacrificadlo; comamos y celebremos un banquete,"},
    {"Lucas", "Lc", 15, 24, "porque este hijo mio estaba muerto y ha revivido; estaba perdido y lo hemos encontrado\". Y empezaron a celebrar el banquete."},
    {"Lucas", "Lc", 15, 25, "Su hijo mayor estaba en el campo. Cuando al volver se acercaba a la casa, oyo la musica y la danza,"},
    {"Lucas", "Lc", 15, 26, "y llamando a uno de los criados, le pregunto que era aquello."},
    {"Lucas", "Lc", 15, 27, "Este le contesto: \"Ha vuelto tu hermano; y tu padre ha sacrificado el ternero cebado, porque lo ha recobrado con salud\"."},
    {"Lucas", "Lc", 15, 28, "El se indigno y no queria entrar, pero su padre salio e intentaba persuadirlo."},
    {"Lucas", "Lc", 15, 29, "Entonces el respondio a su padre: \"Mira: en tantos a\177os como te sirvo, sin desobedecer nunca una orden tuya, a mi nunca me has dado un cabrito para tener un banquete con mis amigos;"},
    {"Lucas", "Lc", 15, 30, "en cambio, cuando ha venido ese hijo tuyo que se ha comido tus bienes con malas mujeres, le matas el ternero cebado\"."},
    {"Lucas", "Lc", 15, 31, "El le dijo: \"Hijo, tu estas siempre conmigo, y todo lo mio es tuyo;"},
    {"Lucas", "Lc", 15, 32, "pero era preciso celebrar un banquete y alegrarse, porque este hermano tuyo estaba muerto y ha revivido; estaba perdido y lo hemos encontrado\"\"."},
    {"Lucas", "Lc", 16, 1, "Decia tambien a sus discipulos: \"Un hombre rico tenia un administrador, a quien acusaron ante el de derrochar sus bienes."},
    {"Lucas", "Lc", 16, 2, "Entonces lo llamo y le dijo: \"Que es eso que estoy oyendo de ti? Dame cuenta de tu administracion, porque en adelante no podras seguir administrando\"."},
    {"Lucas", "Lc", 16, 3, "El administrador se puso a decir para si: \"Que voy a hacer, pues mi se\177or me quita la administracion? Para cavar no tengo fuerzas; mendigar me da verguenza."},
    {"Lucas", "Lc", 16, 4, "Ya se lo que voy a hacer para que, cuando me echen de la administracion, encuentre quien me reciba en su casa\"."},
    {"Lucas", "Lc", 16, 5, "Fue llamando uno a uno a los deudores de su amo y dijo al primero:"},
    {"Lucas", "Lc", 16, 6, "\"Cuanto debes a mi amo?\". Este respondio: \"Cien barriles de aceite\". El le dijo: \"Toma tu recibo; aprisa, sientate y escribe cincuenta\"."},
    {"Lucas", "Lc", 16, 7, "Luego dijo a otro: \"Y tu, cuanto debes?\". El dijo: \"Cien fanegas de trigo\". Le dice: \"Toma tu recibo y escribe ochenta\"."},
    {"Lucas", "Lc", 16, 8, "Y el amo alabo al administrador injusto, porque habia actuado con astucia. Ciertamente, los hijos de este mundo son mas astutos con su propia gente que los hijos de la luz."},
    {"Lucas", "Lc", 16, 9, "Y yo os digo: ganaos amigos con el dinero de iniquidad, para que, cuando os falte, os reciban en las moradas eternas."},
    {"Lucas", "Lc", 16, 10, "El que es fiel en lo poco, tambien en lo mucho es fiel; el que es injusto en lo poco, tambien en lo mucho es injusto."},
    {"Lucas", "Lc", 16, 11, "Pues, si no fuisteis fieles en la riqueza injusta, quien os confiara la verdadera?"},
    {"Lucas", "Lc", 16, 12, "Si no fuisteis fieles en lo ajeno, lo vuestro, quien os lo dara?"},
    {"Lucas", "Lc", 16, 13, "Ningun siervo puede servir a dos se\177ores, porque, o bien aborrecera a uno y amara al otro, o bien se dedicara al primero y no hara caso del segundo. No podeis servir a Dios y al dinero\"."},
    {"Lucas", "Lc", 16, 14, "Los fariseos, que eran amigos del dinero, estaban escuchando todo esto y se burlaban de el."},
    {"Lucas", "Lc", 16, 15, "Y les dijo: \"Vosotros os las dais de justos delante de los hombres, pero Dios conoce vuestros corazones, pues lo que es sublime entre los hombres es abominable ante Dios."},
    {"Lucas", "Lc", 16, 16, "La Ley y los Profetas llegan hasta Juan; desde entonces se anuncia la buena noticia del reino de Dios y todos se esfuerzan por entrar en el."},
    {"Lucas", "Lc", 16, 17, "Es mas facil que pasen el cielo y la tierra que no que caiga un apice de la ley."},
    {"Lucas", "Lc", 16, 18, "Todo el que repudia a su mujer y se casa con otra comete adulterio, y el que se casa con una repudiada por su marido comete adulterio."},
    {"Lucas", "Lc", 16, 19, "Habia un hombre rico que se vestia de purpura y de lino y banqueteaba cada dia."},
    {"Lucas", "Lc", 16, 20, "Y un mendigo llamado Lazaro estaba echado en su portal, cubierto de llagas,"},
    {"Lucas", "Lc", 16, 21, "y con ganas de saciarse de lo que caia de la mesa del rico. Y hasta los perros venian y le lamian las llagas."},
    {"Lucas", "Lc", 16, 22, "Sucedio que murio el mendigo, y fue llevado por los angeles al seno de Abrahan. Murio tambien el rico y fue enterrado."},
    {"Lucas", "Lc", 16, 23, "Y, estando en el infierno, en medio de los tormentos, levanto los ojos y vio de lejos a Abrahan, y a Lazaro en su seno,"},
    {"Lucas", "Lc", 16, 24, "y gritando, dijo: \"Padre Abrahan, ten piedad de mi y manda a Lazaro que moje en agua la punta del dedo y me refresque la lengua, porque me torturan estas llamas\"."},
    {"Lucas", "Lc", 16, 25, "Pero Abrahan le dijo: \"Hijo, recuerda que recibiste tus bienes en tu vida, y Lazaro, a su vez, males: por eso ahora el es aqui consolado, mientras que tu eres atormentado."},
    {"Lucas", "Lc", 16, 26, "Y, ademas, entre nosotros y vosotros se abre un abismo inmenso, para que los que quieran cruzar desde aqui hacia vosotros no puedan hacerlo, ni tampoco pasar de ahi hasta nosotros\"."},
    {"Lucas", "Lc", 16, 27, "El dijo: \"Te ruego, entonces, padre, que le mandes a casa de mi padre,"},
    {"Lucas", "Lc", 16, 28, "pues tengo cinco hermanos: que les de testimonio de estas cosas, no sea que tambien ellos vengan a este lugar de tormento\"."},
    {"Lucas", "Lc", 16, 29, "Abrahan le dice: \"Tienen a Moises y a los profetas: que los escuchen\"."},
    {"Lucas", "Lc", 16, 30, "Pero el le dijo: \"No, padre Abrahan. Pero si un muerto va a ellos, se arrepentiran\"."},
    {"Lucas", "Lc", 16, 31, "Abrahan le dijo: \"Si no escuchan a Moises y a los profetas, no se convenceran ni aunque resucite un muerto\"\"."},
    {"Lucas", "Lc", 17, 1, "Dijo, pues, a sus discipulos: \"Es imposible que no haya escandalos; pero ay de quien los provoca!"},
    {"Lucas", "Lc", 17, 2, "Al que escandaliza a uno de estos peque\177os, mas le valdria que le ataran al cuello una piedra de molino y lo arrojasen al mar."},
    {"Lucas", "Lc", 17, 3, "Tened cuidado. Si tu hermano te ofende, reprendelo, y si se arrepiente, perdonalo;"},
    {"Lucas", "Lc", 17, 4, "si te ofende siete veces en un dia, y siete veces vuelve a decirte: \"Me arrepiento\", lo perdonaras\"."},
    {"Lucas", "Lc", 17, 5, "Los apostoles le dijeron al Se\177or: \"Aumentanos la fe\"."},
    {"Lucas", "Lc", 17, 6, "El Se\177or dijo: \"Si tuvierais fe como un granito de mostaza, diriais a esa morera: \"Arrancate de raiz y plantate en el mar\", y os obedeceria."},
    {"Lucas", "Lc", 17, 7, "Quien de vosotros, si tiene un criado labrando o pastoreando, le dice cuando vuelve del campo: \"Enseguida, ven y ponte a la mesa\"?"},
    {"Lucas", "Lc", 17, 8, "No le direis mas bien: \"Preparame de cenar, ci\177ete y sirveme mientras como y bebo, y despues comeras y beberas tu\"?"},
    {"Lucas", "Lc", 17, 9, "Acaso teneis que estar agradecidos al criado porque ha hecho lo mandado?"},
    {"Lucas", "Lc", 17, 10, "Lo mismo vosotros: cuando hayais hecho todo lo que se os ha mandado, decid: \"Somos siervos inutiles, hemos hecho lo que teniamos que hacer\"\"."},
    {"Lucas", "Lc", 17, 11, "Una vez, yendo camino de Jerusalen, pasaba entre Samaria y Galilea."},
    {"Lucas", "Lc", 17, 12, "Cuando iba a entrar en una ciudad, vinieron a su encuentro diez hombres leprosos, que se pararon a lo lejos"},
    {"Lucas", "Lc", 17, 13, "y a gritos le decian: \"Jesus, maestro, ten compasion de nosotros\"."},
    {"Lucas", "Lc", 17, 14, "Al verlos, les dijo: \"Id a presentaros a los sacerdotes\". Y sucedio que, mientras iban de camino, quedaron limpios."},
    {"Lucas", "Lc", 17, 15, "Uno de ellos, viendo que estaba curado, se volvio alabando a Dios a grandes gritos"},
    {"Lucas", "Lc", 17, 16, "y se postro a los pies de Jesus, rostro en tierra, dandole gracias. Este era un samaritano."},
    {"Lucas", "Lc", 17, 17, "Jesus, tomo la palabra y dijo: \"No han quedado limpios los diez?; los otros nueve, donde estan?"},
    {"Lucas", "Lc", 17, 18, "No ha habido quien volviera a dar gloria a Dios mas que este extranjero?\"."},
    {"Lucas", "Lc", 17, 19, "Y le dijo: \"Levantate, vete; tu fe te ha salvado\"."},
    {"Lucas", "Lc", 17, 20, "Los fariseos le preguntaron: \"Cuando va a llegar el reino de Dios?\". El les contesto: \"El reino de Dios no viene aparatosamente,"},
    {"Lucas", "Lc", 17, 21, "ni diran: \"Esta aqui\" o \"Esta alli\", porque, mirad, el reino de Dios esta en medio de vosotros\"."},
    {"Lucas", "Lc", 17, 22, "Dijo a sus discipulos: \"Vendran dias en que deseareis ver un solo dia del Hijo del hombre, y no lo vereis."},
    {"Lucas", "Lc", 17, 23, "Entonces se os dira: \"Esta aqui\" o \"Esta alli\"; no vayais ni corrais detras,"},
    {"Lucas", "Lc", 17, 24, "pues como el fulgor del relampago brilla de un extremo al otro del cielo, asi sera el Hijo del hombre en su dia."},
    {"Lucas", "Lc", 17, 25, "Pero primero es necesario que padezca mucho y sea reprobado por esta generacion."},
    {"Lucas", "Lc", 17, 26, "Como sucedio en los dias de Noe, asi sera tambien en los dias del Hijo del hombre:"},
    {"Lucas", "Lc", 17, 27, "comian, bebian, se casaban los hombres y las mujeres tomaban esposo, hasta el dia en que Noe entro en el arca; entonces llego el diluvio y acabo con todos."},
    {"Lucas", "Lc", 17, 28, "Asimismo, como sucedio en los dias de Lot: comian, bebian, compraban, vendian, sembraban, construian;"},
    {"Lucas", "Lc", 17, 29, "pero el dia que Lot salio de Sodoma, llovio fuego y azufre del cielo y acabo con todos."},
    {"Lucas", "Lc", 17, 30, "Asi sucedera el dia que se revele el Hijo del hombre."},
    {"Lucas", "Lc", 17, 31, "Aquel dia, el que este en la azotea y tenga sus cosas en casa no baje a recogerlas; igualmente, el que este en el campo, no vuelva atras."},
    {"Lucas", "Lc", 17, 32, "Acordaos de la mujer de Lot."},
    {"Lucas", "Lc", 17, 33, "El que pretenda guardar su vida, la perdera; y el que la pierda, la recobrara."},
    {"Lucas", "Lc", 17, 34, "Os digo que aquella noche estaran dos juntos: a uno se lo llevaran y al otro lo dejaran;"},
    {"Lucas", "Lc", 17, 35, "estaran dos moliendo juntas: a una se la llevaran y a la otra la dejaran\"."},
    {"Lucas", "Lc", 17, 36, "[\"Dos estaran en el campo: a uno se lo llevaran y a otro lo dejaran\".]"},
    {"Lucas", "Lc", 17, 37, "Ellos le preguntaron: \"Donde, Se\177or?\". El les dijo: \"Donde esta el cadaver, alli se reuniran los buitres\"."},
    {"Lucas", "Lc", 18, 1, "Les decia una parabola para ense\177arles que es necesario orar siempre, sin desfallecer."},
    {"Lucas", "Lc", 18, 2, "\"Habia un juez en una ciudad que ni temia a Dios ni le importaban los hombres."},
    {"Lucas", "Lc", 18, 3, "En aquella ciudad habia una viuda que solia ir a decirle: \"Hazme justicia frente a mi adversario\"."},
    {"Lucas", "Lc", 18, 4, "Por algun tiempo se estuvo negando, pero despues se dijo a si mismo: \"Aunque ni temo a Dios ni me importan los hombres,"},
    {"Lucas", "Lc", 18, 5, "como esta viuda me esta molestando, le voy a hacer justicia, no sea que siga viniendo a cada momento a importunarme\"\"."},
    {"Lucas", "Lc", 18, 6, "Y el Se\177or a\177adio: \"Fijaos en lo que dice el juez injusto;"},
    {"Lucas", "Lc", 18, 7, "pues Dios, no hara justicia a sus elegidos que claman ante el dia y noche?; o les dara largas?"},
    {"Lucas", "Lc", 18, 8, "Os digo que les hara justicia sin tardar. Pero, cuando venga el Hijo del hombre, encontrara esta fe en la tierra?\"."},
    {"Lucas", "Lc", 18, 9, "Dijo tambien esta parabola a algunos que confiaban en si mismos por considerarse justos y despreciaban a los demas:"},
    {"Lucas", "Lc", 18, 10, "\"Dos hombres subieron al templo a orar. Uno era fariseo; el otro, publicano."},
    {"Lucas", "Lc", 18, 11, "El fariseo, erguido, oraba asi en su interior: \"Oh Dios!, te doy gracias porque no soy como los demas hombres: ladrones, injustos, adulteros; ni tampoco como ese publicano."},
    {"Lucas", "Lc", 18, 12, "Ayuno dos veces por semana y pago el diezmo de todo lo que tengo\"."},
    {"Lucas", "Lc", 18, 13, "El publicano, en cambio, quedandose atras, no se atrevia ni a levantar los ojos al cielo, sino que se golpeaba el pecho diciendo: \"Oh Dios!, ten compasion de este pecador\"."},
    {"Lucas", "Lc", 18, 14, "Os digo que este bajo a su casa justificado, y aquel no. Porque todo el que se enaltece sera humillado, y el que se humilla sera enaltecido\"."},
    {"Lucas", "Lc", 18, 15, "Le llevaban tambien los ni\177os peque\177os para que los tocara, pero, al verlo los discipulos, los rega\177aban."},
    {"Lucas", "Lc", 18, 16, "En cambio, Jesus hizo que se los acercaran, diciendo: \"Dejad que los ni\177os vengan a mi y no se lo impidais, porque de los que son como ellos es el reino de Dios."},
    {"Lucas", "Lc", 18, 17, "En verdad os digo, el que no reciba el reino de Dios como un ni\177o, no entrara en el\"."},
    {"Lucas", "Lc", 18, 18, "Uno de los jefes le pregunto: \"Maestro bueno, que he de hacer para heredar la vida eterna?\"."},
    {"Lucas", "Lc", 18, 19, "Jesus le dijo: \"Por que me llamas bueno? Nadie es bueno sino solo Dios."},
    {"Lucas", "Lc", 18, 20, "Ya sabes los mandamientos: No cometeras adulterio, No mataras, No robaras, No daras falso testimonio, Honra a tu padre y a tu madre\"."},
    {"Lucas", "Lc", 18, 21, "Y el dijo: \"He observado todo esto desde mi juventud\"."},
    {"Lucas", "Lc", 18, 22, "Al oir esto, Jesus le dijo: \"Todavia te falta una cosa: vende todo cuanto tienes y distribuyelo a los pobres -y tendras un tesoro en los cielos-; luego, ven y sigueme\"."},
    {"Lucas", "Lc", 18, 23, "Pero el, al oir esto, se puso muy triste, porque era muy rico."},
    {"Lucas", "Lc", 18, 24, "Cuando Jesus vio que se habia entristecido, dijo: \"Que dificil es para los que tienen riquezas entrar en el reino de Dios!"},
    {"Lucas", "Lc", 18, 25, "Es mas facil que un camello entre por el ojo de una aguja que entre un rico en el reino de Dios\"."},
    {"Lucas", "Lc", 18, 26, "Los que lo oyeron, dijeron: \"Entonces, quien se puede salvar?\"."},
    {"Lucas", "Lc", 18, 27, "Y el dijo: \"Lo que es imposible para los hombres es posible para Dios\"."},
    {"Lucas", "Lc", 18, 28, "Entonces dijo Pedro: \"Nosotros hemos dejado nuestras cosas y te hemos seguido\"."},
    {"Lucas", "Lc", 18, 29, "Jesus les dijo: \"En verdad os digo que no hay nadie que haya dejado casa o mujer o hermanos o padres o hijos por el reino de Dios,"},
    {"Lucas", "Lc", 18, 30, "que no reciba mucho mas en el tiempo presente y en la edad venidera vida eterna\"."},
    {"Lucas", "Lc", 18, 31, "Tomando consigo a los Doce, les dijo: \"Mirad, estamos subiendo a Jerusalen y se cumplira en el Hijo del hombre todo lo escrito por los profetas,"},
    {"Lucas", "Lc", 18, 32, "pues sera entregado a los gentiles y sera escarnecido, insultado y escupido,"},
    {"Lucas", "Lc", 18, 33, "y despues de azotarlo lo mataran, y al tercer dia resucitara\"."},
    {"Lucas", "Lc", 18, 34, "Pero ellos no entendieron nada de esto, este lenguaje era misterioso para ellos y no comprendieron lo que les decia."},
    {"Lucas", "Lc", 18, 35, "Cuando se acercaba a Jerico, habia un ciego sentado al borde del camino pidiendo limosna."},
    {"Lucas", "Lc", 18, 36, "Al oir que pasaba gente, preguntaba que era aquello;"},
    {"Lucas", "Lc", 18, 37, "y le informaron: \"Pasa Jesus el Nazareno\"."},
    {"Lucas", "Lc", 18, 38, "Entonces empezo a gritar: \"Jesus, hijo de David, ten compasion de mi!\"."},
    {"Lucas", "Lc", 18, 39, "Los que iban delante lo rega\177aban para que se callara, pero el gritaba mas fuerte: \"Hijo de David, ten compasion de mi!\"."},
    {"Lucas", "Lc", 18, 40, "Jesus se paro y mando que se lo trajeran. Cuando estuvo cerca, le pregunto:"},
    {"Lucas", "Lc", 18, 41, "\"Que quieres que haga por ti?\". El dijo: \"Se\177or, que recobre la vista\"."},
    {"Lucas", "Lc", 18, 42, "Jesus le dijo: \"Recobra la vista, tu fe te ha salvado\"."},
    {"Lucas", "Lc", 18, 43, "Y enseguida recobro la vista y lo seguia, glorificando a Dios. Y todo el pueblo, al ver esto, alabo a Dios."},
    {"Lucas", "Lc", 19, 1, "Entro en Jerico e iba atravesando la ciudad."},
    {"Lucas", "Lc", 19, 2, "En esto, un hombre llamado Zaqueo, jefe de publicanos y rico,"},
    {"Lucas", "Lc", 19, 3, "trataba de ver quien era Jesus, pero no lo lograba a causa del gentio, porque era peque\177o de estatura."},
    {"Lucas", "Lc", 19, 4, "Corriendo mas adelante, se subio a un sicomoro para verlo, porque tenia que pasar por alli."},
    {"Lucas", "Lc", 19, 5, "Jesus, al llegar a aquel sitio, levanto los ojos y le dijo: \"Zaqueo, date prisa y baja, porque es necesario que hoy me quede en tu casa\"."},
    {"Lucas", "Lc", 19, 6, "El se dio prisa en bajar y lo recibio muy contento."},
    {"Lucas", "Lc", 19, 7, "Al ver esto, todos murmuraban diciendo: \"Ha entrado a hospedarse en casa de un pecador\"."},
    {"Lucas", "Lc", 19, 8, "Pero Zaqueo, de pie, dijo al Se\177or: \"Mira, Se\177or, la mitad de mis bienes se la doy a los pobres; y si he defraudado a alguno, le restituyo cuatro veces mas\"."},
    {"Lucas", "Lc", 19, 9, "Jesus le dijo: \"Hoy ha sido la salvacion de esta casa, pues tambien este es hijo de Abrahan."},
    {"Lucas", "Lc", 19, 10, "Porque el Hijo del hombre ha venido a buscar y a salvar lo que estaba perdido\"."},
    {"Lucas", "Lc", 19, 11, "Mientras ellos escuchaban todo esto, a\177adio una parabola, porque el estaba cerca de Jerusalen y pensaban que el reino de Dios iba a manifestarse enseguida."},
    {"Lucas", "Lc", 19, 12, "Dijo, pues: \"Un hombre noble se marcho a un pais lejano para conseguirse el titulo de rey, y volver despues."},
    {"Lucas", "Lc", 19, 13, "Llamo a diez siervos suyos y les repartio diez minas de oro, diciendoles: \"Negociad mientras vuelvo\"."},
    {"Lucas", "Lc", 19, 14, "Pero sus conciudadanos lo aborrecian y enviaron tras de el una embajada diciendo: \"No queremos que este llegue a reinar sobre nosotros\"."},
    {"Lucas", "Lc", 19, 15, "Cuando regreso de conseguir el titulo real, mando llamar a su presencia a los siervos a quienes habia dado el dinero, para enterarse de lo que habia ganado cada uno."},
    {"Lucas", "Lc", 19, 16, "El primero se presento y dijo: \"Se\177or, tu mina ha producido diez\"."},
    {"Lucas", "Lc", 19, 17, "El le dijo: \"Muy bien, siervo bueno; ya que has sido fiel en lo peque\177o, recibe el gobierno de diez ciudades\"."},
    {"Lucas", "Lc", 19, 18, "El segundo llego y dijo: \"Tu mina, se\177or, ha rendido cinco\"."},
    {"Lucas", "Lc", 19, 19, "A ese le dijo tambien: \"Pues toma tu el mando de cinco ciudades\"."},
    {"Lucas", "Lc", 19, 20, "El otro llego y dijo: \"Se\177or, aqui esta tu mina; la he tenido guardada en un pa\177uelo,"},
    {"Lucas", "Lc", 19, 21, "porque tenia miedo, pues eres un hombre exigente que retiras lo que no has depositado y siegas lo que no has sembrado\"."},
    {"Lucas", "Lc", 19, 22, "El le dijo: \"Por tu boca te juzgo, siervo malo. Conque sabias que soy exigente, que retiro lo que no he depositado y siego lo que no he sembrado?"},
    {"Lucas", "Lc", 19, 23, "Pues por que no pusiste mi dinero en el banco? Al volver yo, lo habria cobrado con los intereses\"."},
    {"Lucas", "Lc", 19, 24, "Entonces dijo a los presentes: \"Quitadle a este la mina y dadsela al que tiene diez minas\"."},
    {"Lucas", "Lc", 19, 25, "Le dijeron: \"Se\177or, ya tiene diez minas\"."},
    {"Lucas", "Lc", 19, 26, "\"Os digo: al que tiene se le dara, pero al que no tiene se le quitara hasta lo que tiene."},
    {"Lucas", "Lc", 19, 27, "Y en cuanto a esos enemigos mios, que no querian que llegase a reinar sobre ellos, traedlos aca y degolladlos en mi presencia\"\"."},
    {"Lucas", "Lc", 19, 28, "Dicho esto, caminaba delante de ellos, subiendo hacia Jerusalen."},
    {"Lucas", "Lc", 19, 29, "Al acercarse a Betfage y Betania, junto al monte llamado de los Olivos, mando a dos discipulos,"},
    {"Lucas", "Lc", 19, 30, "diciendoles: \"Id a la aldea de enfrente; al entrar en ella, encontrareis un pollino atado, que nadie ha montado nunca. Desatadlo y traedlo."},
    {"Lucas", "Lc", 19, 31, "Y si alguien os pregunta: \"Por que lo desatais?\", le direis asi: \"El Se\177or lo necesita\"\"."},
    {"Lucas", "Lc", 19, 32, "Fueron, pues, los enviados y lo encontraron como les habia dicho."},
    {"Lucas", "Lc", 19, 33, "Mientras desataban el pollino, los due\177os les dijeron: \"Por que desatais el pollino?\"."},
    {"Lucas", "Lc", 19, 34, "Ellos dijeron: \"El Se\177or lo necesita\"."},
    {"Lucas", "Lc", 19, 35, "Se lo llevaron a Jesus y, despues de poner sus mantos sobre el pollino, ayudaron a Jesus a montar sobre el."},
    {"Lucas", "Lc", 19, 36, "Mientras el iba avanzando, extendian sus mantos por el camino."},
    {"Lucas", "Lc", 19, 37, "Y, cuando se acercaba ya a la bajada del monte de los Olivos, la multitud de los discipulos, llenos de alegria, comenzaron a alabar a Dios a grandes voces por todos los milagros que habian visto,"},
    {"Lucas", "Lc", 19, 38, "diciendo: \"Bendito el rey que viene en nombre del Se\177or! Paz en el cielo y gloria en las alturas\"."},
    {"Lucas", "Lc", 19, 39, "Algunos fariseos de entre la gente le dijeron: \"Maestro, reprende a tus discipulos\"."},
    {"Lucas", "Lc", 19, 40, "Y respondiendo, dijo: \"Os digo que, si estos callan, gritaran las piedras\"."},
    {"Lucas", "Lc", 19, 41, "Al acercarse y ver la ciudad, lloro sobre ella,"},
    {"Lucas", "Lc", 19, 42, "mientras decia: \"Si reconocieras tu tambien en este dia lo que conduce a la paz! Pero ahora esta escondido a tus ojos."},
    {"Lucas", "Lc", 19, 43, "Pues vendran dias sobre ti en que tus enemigos te rodearan de trincheras, te sitiaran, apretaran el cerco de todos lados,"},
    {"Lucas", "Lc", 19, 44, "te arrasaran con tus hijos dentro, y no dejaran piedra sobre piedra. Porque no reconociste el tiempo de tu visita\"."},
    {"Lucas", "Lc", 19, 45, "Despues entro en el templo y se puso a echar a los vendedores,"},
    {"Lucas", "Lc", 19, 46, "diciendoles: \"Escrito esta: \"Mi casa sera casa de oracion\"; pero vosotros la habeis hecho una \"cueva de bandidos\"\"."},
    {"Lucas", "Lc", 19, 47, "Todos los dias ense\177aba en el templo. Por su parte, los sumos sacerdotes, los escribas y los principales del pueblo buscaban acabar con el,"},
    {"Lucas", "Lc", 19, 48, "pero no sabian que hacer, porque todo el pueblo estaba pendiente de el, escuchandolo."},
    {"Lucas", "Lc", 20, 1, "Uno de aquellos dias, cuando estaba el en el templo ense\177ando al pueblo y anunciando la Buena Noticia, se acercaron los sumos sacerdotes y escribas junto con los ancianos"},
    {"Lucas", "Lc", 20, 2, "y le hablaron diciendo: \"Dinos, con que autoridad haces estas cosas? Quien te ha dado esta autoridad?\"."},
    {"Lucas", "Lc", 20, 3, "Les contesto: \"Yo tambien os voy a hacer una pregunta, respondedmela:"},
    {"Lucas", "Lc", 20, 4, "\"El bautismo de Juan, era del cielo o de los hombres?\"\"."},
    {"Lucas", "Lc", 20, 5, "Ellos reflexionaban entre si diciendo: \"Si decimos: \"Del cielo\", dira: \"Por que no le creisteis?\";"},
    {"Lucas", "Lc", 20, 6, "pero si decimos: \"De los hombres\", todo el pueblo nos apedreara, porque estan convencidos de que Juan era un profeta\"."},
    {"Lucas", "Lc", 20, 7, "Y respondieron que no sabian de donde."},
    {"Lucas", "Lc", 20, 8, "Entonces Jesus les dijo: \"Pues tampoco yo os digo con que autoridad hago estas cosas\"."},
    {"Lucas", "Lc", 20, 9, "Entonces se puso a decir al pueblo esta parabola: \"Un hombre planto una vi\177a, la arrendo a unos labradores y se ausento bastante tiempo."},
    {"Lucas", "Lc", 20, 10, "En el tiempo apropiado envio un siervo a los labradores para que le diesen su parte del fruto de la vi\177a; pero los labradores, despues de azotarlo, lo despidieron con las manos vacias."},
    {"Lucas", "Lc", 20, 11, "Volvio a enviar a otro siervo, pero ellos, despues de azotar y humillar tambien a este, lo despidieron con las manos vacias."},
    {"Lucas", "Lc", 20, 12, "Y volvio a enviar un tercero, pero ellos, despues de haberlo herido, tambien lo echaron."},
    {"Lucas", "Lc", 20, 13, "Entonces dijo el due\177o de la vi\177a: \"Que voy a hacer? Voy a enviar a mi hijo querido. Quiza a este lo respetaran\"."},
    {"Lucas", "Lc", 20, 14, "Pero, al verlo, los labradores se decian entre si: \"Este es el heredero. Matemoslo para que la herencia sea nuestra\"."},
    {"Lucas", "Lc", 20, 15, "Y echandolo fuera de la vi\177a, lo mataron. Pues que hara con ellos el due\177o de la vi\177a?"},
    {"Lucas", "Lc", 20, 16, "Vendra, hara perecer a estos labradores y dara la vi\177a a otros\". Los que lo oyeron, dijeron: \"No suceda tal cosa!\"."},
    {"Lucas", "Lc", 20, 17, "Pero el, fijando los ojos en ellos, dijo: \"Pues que significa lo que esta escrito: \"La piedra que desecharon los arquitectos es ahora la piedra angular\"?"},
    {"Lucas", "Lc", 20, 18, "Todo el que caiga sobre la piedra se destrozara, y a aquel sobre quien ella caiga, lo aplastara\"."},
    {"Lucas", "Lc", 20, 19, "Los sumos sacerdotes y los escribas, comprendiendo que habia dicho la parabola por ellos, intentaban echarle mano en aquel mismo momento, pero tuvieron miedo al pueblo."},
    {"Lucas", "Lc", 20, 20, "Y, manteniendose ellos al acecho, le mandaron unos espias que simulaban ser justos, con el fin de sorprenderlo en alguna palabra y asi poder entregarlo al poder y autoridad del gobernador."},
    {"Lucas", "Lc", 20, 21, "Le preguntaron, pues: \"Maestro, sabemos que hablas y ense\177as con rectitud y no tienes acepcion de personas, sino que ense\177as segun verdad el camino de Dios."},
    {"Lucas", "Lc", 20, 22, "Es licito que nosotros paguemos tributo al Cesar o no?\"."},
    {"Lucas", "Lc", 20, 23, "Habiendo advertido su astucia, les dijo:"},
    {"Lucas", "Lc", 20, 24, "\"Mostradme un denario. De quien es la imagen y la inscripcion?\". Le dijeron: \"Del Cesar\"."},
    {"Lucas", "Lc", 20, 25, "Y el les dijo: \"Pues bien, dad al Cesar lo que es del Cesar y a Dios lo que es de Dios\"."},
    {"Lucas", "Lc", 20, 26, "Y no pudieron acusarlo ante el pueblo de nada de lo que decia; y se quedaron mudos, admirados de su respuesta."},
    {"Lucas", "Lc", 20, 27, "Se acercaron algunos saduceos, los que dicen que no hay resurreccion, y le preguntaron:"},
    {"Lucas", "Lc", 20, 28, "\"Maestro, Moises nos dejo escrito: \"Si a uno se le muere su hermano, dejando mujer pero sin hijos, que tome la mujer como esposa y de descendencia a su hermano\"."},
    {"Lucas", "Lc", 20, 29, "Pues bien, habia siete hermanos; el primero se caso y murio sin hijos."},
    {"Lucas", "Lc", 20, 30, "El segundo"},
    {"Lucas", "Lc", 20, 31, "y el tercero se casaron con ella, y asi los siete, y murieron todos sin dejar hijos."},
    {"Lucas", "Lc", 20, 32, "Por ultimo, tambien murio la mujer."},
    {"Lucas", "Lc", 20, 33, "Cuando llegue la resurreccion, de cual de ellos sera la mujer? Porque los siete la tuvieron como mujer\"."},
    {"Lucas", "Lc", 20, 34, "Jesus les dijo: \"En este mundo los hombres se casan y las mujeres toman esposo,"},
    {"Lucas", "Lc", 20, 35, "pero los que sean juzgados dignos de tomar parte en el mundo futuro y en la resurreccion de entre los muertos no se casaran ni ellas seran dadas en matrimonio."},
    {"Lucas", "Lc", 20, 36, "Pues ya no pueden morir, ya que son como angeles; y son hijos de Dios, porque son hijos de la resurreccion."},
    {"Lucas", "Lc", 20, 37, "Y que los muertos resucitan, lo indico el mismo Moises en el episodio de la zarza, cuando llama al Se\177or: \"Dios de Abrahan, Dios de Isaac, Dios de Jacob\"."},
    {"Lucas", "Lc", 20, 38, "No es Dios de muertos, sino de vivos: porque para el todos estan vivos\"."},
    {"Lucas", "Lc", 20, 39, "Intervinieron unos escribas: \"Bien dicho, Maestro\"."},
    {"Lucas", "Lc", 20, 40, "Y ya no se atrevian a hacerle mas preguntas."},
    {"Lucas", "Lc", 20, 41, "Entonces les dijo: \"Como dicen que el Mesias es hijo de David,"},
    {"Lucas", "Lc", 20, 42, "si el mismo David dice en el libro de los Salmos: \"Dijo el Se\177or a mi Se\177or: Sientate a mi derecha,"},
    {"Lucas", "Lc", 20, 43, "y hare de tus enemigos estrado de tus pies\"?"},
    {"Lucas", "Lc", 20, 44, "David, pues, lo llama Se\177or; entonces, como puede ser hijo suyo?\"."},
    {"Lucas", "Lc", 20, 45, "Y oyendolo todo el pueblo, dijo a sus discipulos:"},
    {"Lucas", "Lc", 20, 46, "\"Guardaos de los escribas, que gustan de pasear con amplias y ricas tunicas y son amigos de ser saludados en las plazas y de ocupar los primeros asientos en las sinagogas y los primeros puestos en los banquetes;"},
    {"Lucas", "Lc", 20, 47, "devoran las casas de las viudas y aparentan hacer largas oraciones. Estos recibiran una condenacion mas rigurosa\"."},
    {"Lucas", "Lc", 21, 1, "Alzando los ojos, vio a unos ricos que echaban donativos en el tesoro del templo;"},
    {"Lucas", "Lc", 21, 2, "vio tambien una viuda pobre que echaba dos monedillas,"},
    {"Lucas", "Lc", 21, 3, "y dijo: \"En verdad os digo que esa pobre viuda ha echado mas que todos,"},
    {"Lucas", "Lc", 21, 4, "porque todos esos han contribuido a los donativos con lo que les sobra, pero ella, que pasa necesidad, ha echado todo lo que tenia para vivir\"."},
    {"Lucas", "Lc", 21, 5, "Y como algunos hablaban del templo, de lo bellamente adornado que estaba con piedra de calidad y exvotos, Jesus les dijo:"},
    {"Lucas", "Lc", 21, 6, "\"Esto que contemplais, llegaran dias en que no quedara piedra sobre piedra que no sea destruida\"."},
    {"Lucas", "Lc", 21, 7, "Ellos le preguntaron: \"Maestro, cuando va a ser eso?, y cual sera la se\177al de que todo eso esta para suceder?\"."},
    {"Lucas", "Lc", 21, 8, "El dijo: \"Mirad que nadie os enga\177e. Porque muchos vendran en mi nombre diciendo: \"Yo soy\", o bien: \"Esta llegando el tiempo\"; no vayais tras ellos."},
    {"Lucas", "Lc", 21, 9, "Cuando oigais noticias de guerras y de revoluciones, no tengais panico. Porque es necesario que eso ocurra primero, pero el fin no sera enseguida\"."},
    {"Lucas", "Lc", 21, 10, "Entonces les decia: \"Se alzara pueblo contra pueblo y reino contra reino,"},
    {"Lucas", "Lc", 21, 11, "habra grandes terremotos, y en diversos paises, hambres y pestes. Habra tambien fenomenos espantosos y grandes signos en el cielo."},
    {"Lucas", "Lc", 21, 12, "Pero antes de todo eso os echaran mano, os perseguiran, entregandoos a las sinagogas y a las carceles, y haciendoos comparecer ante reyes y gobernadores, por causa de mi nombre."},
    {"Lucas", "Lc", 21, 13, "Esto os servira de ocasion para dar testimonio."},
    {"Lucas", "Lc", 21, 14, "Por ello, meteos bien en la cabeza que no teneis que preparar vuestra defensa,"},
    {"Lucas", "Lc", 21, 15, "porque yo os dare palabras y sabiduria a las que no podra hacer frente ni contradecir ningun adversario vuestro."},
    {"Lucas", "Lc", 21, 16, "Y hasta vuestros padres, y parientes, y hermanos, y amigos os entregaran, y mataran a algunos de vosotros,"},
    {"Lucas", "Lc", 21, 17, "y todos os odiaran a causa de mi nombre."},
    {"Lucas", "Lc", 21, 18, "Pero ni un cabello de vuestra cabeza perecera;"},
    {"Lucas", "Lc", 21, 19, "con vuestra perseverancia salvareis vuestras almas."},
    {"Lucas", "Lc", 21, 20, "Y cuando veais a Jerusalen sitiada por ejercitos, sabed que entonces esta cerca su destruccion."},
    {"Lucas", "Lc", 21, 21, "Entonces los que esten en Judea, que huyan a los montes; los que esten en medio de Jerusalen, que se alejen; los que esten en los campos, que no entren en ella;"},
    {"Lucas", "Lc", 21, 22, "porque estos son dias de venganza para que se cumpla todo lo que esta escrito."},
    {"Lucas", "Lc", 21, 23, "Ay de las que esten encintas o criando en aquellos dias! Porque habra una gran calamidad en esta tierra y un castigo para este pueblo."},
    {"Lucas", "Lc", 21, 24, "Caeran a filo de espada, los llevaran cautivos a todas las naciones, y Jerusalen sera pisoteada por gentiles, hasta que alcancen su plenitud los tiempos de los gentiles."},
    {"Lucas", "Lc", 21, 25, "Habra signos en el sol y la luna y las estrellas, y en la tierra angustia de las gentes, perplejas por el estruendo del mar y el oleaje,"},
    {"Lucas", "Lc", 21, 26, "desfalleciendo los hombres por el miedo y la ansiedad ante lo que se le viene encima al mundo, pues las potencias del cielo seran sacudidas."},
    {"Lucas", "Lc", 21, 27, "Entonces veran al Hijo del hombre venir en una nube, con gran poder y gloria."},
    {"Lucas", "Lc", 21, 28, "Cuando empiece a suceder esto, levantaos, alzad la cabeza; se acerca vuestra liberacion\"."},
    {"Lucas", "Lc", 21, 29, "Y les dijo una parabola: \"Fijaos en la higuera y en todos los demas arboles:"},
    {"Lucas", "Lc", 21, 30, "cuando veis que ya echan brotes, conoceis por vosotros mismos que ya esta llegando el verano."},
    {"Lucas", "Lc", 21, 31, "Igualmente vosotros, cuando veais que suceden estas cosas, sabed que esta cerca el reino de Dios."},
    {"Lucas", "Lc", 21, 32, "En verdad os digo que no pasara esta generacion sin que todo suceda."},
    {"Lucas", "Lc", 21, 33, "El cielo y la tierra pasaran, pero mis palabras no pasaran."},
    {"Lucas", "Lc", 21, 34, "Tened cuidado de vosotros, no sea que se emboten vuestros corazones con juergas, borracheras y las inquietudes de la vida, y se os eche encima de repente aquel dia;"},
    {"Lucas", "Lc", 21, 35, "porque caera como un lazo sobre todos los habitantes de la tierra."},
    {"Lucas", "Lc", 21, 36, "Estad, pues, despiertos en todo tiempo, pidiendo que podais escapar de todo lo que esta por suceder y manteneros en pie ante el Hijo del hombre\"."},
    {"Lucas", "Lc", 21, 37, "Estaba durante el dia ense\177ando en el templo, pero de noche se marchaba y pernoctaba en el monte llamado de los Olivos."},
    {"Lucas", "Lc", 21, 38, "Y todo el pueblo madrugaba para venir en su busca a escucharlo en el templo."},
    {"Lucas", "Lc", 22, 1, "Estaba muy cerca la fiesta de los Acimos llamada Pascua."},
    {"Lucas", "Lc", 22, 2, "Y andaban buscando los sumos sacerdotes y los escribas como quitarlo de en medio, porque temian al pueblo."},
    {"Lucas", "Lc", 22, 3, "Entonces entro Satanas en Judas, llamado Iscariote, que era del numero de los Doce,"},
    {"Lucas", "Lc", 22, 4, "y se fue a tratar con los sumos sacerdotes y oficiales del templo el modo de entregarselo."},
    {"Lucas", "Lc", 22, 5, "Ellos se alegraron y acordaron darle dinero."},
    {"Lucas", "Lc", 22, 6, "El acepto y buscaba una ocasion propicia para entregarlo sin la presencia del pueblo."},
    {"Lucas", "Lc", 22, 7, "Llego, pues, el dia de los Acimos, en que se debia sacrificar la Pascua."},
    {"Lucas", "Lc", 22, 8, "Y envio a Pedro y a Juan, diciendoles: \"Id a prepararnos la Pascua para que la comamos\"."},
    {"Lucas", "Lc", 22, 9, "Ellos le dijeron: \"Donde quieres que la preparemos?\"."},
    {"Lucas", "Lc", 22, 10, "Y el les dijo: \"Mirad, cuando entreis en la ciudad, os saldra al paso un hombre llevando un cantaro de agua. Seguidlo hasta la casa en que entre"},
    {"Lucas", "Lc", 22, 11, "y direis al due\177o de la casa: \"El Maestro te pregunta: Donde esta la habitacion en la que voy a comer la Pascua con mis discipulos?\"."},
    {"Lucas", "Lc", 22, 12, "El os mostrara en el piso superior una habitacion grande amueblada con divanes. Preparadla alli\"."},
    {"Lucas", "Lc", 22, 13, "Fueron y lo encontraron como les habia dicho y prepararon la Pascua."},
    {"Lucas", "Lc", 22, 14, "Y cuando llego la hora, se sento a la mesa y los apostoles con el"},
    {"Lucas", "Lc", 22, 15, "y les dijo: \"Ardientemente he deseado comer esta Pascua con vosotros, antes de padecer,"},
    {"Lucas", "Lc", 22, 16, "porque os digo que ya no la volvere a comer hasta que se cumpla en el reino de Dios\"."},
    {"Lucas", "Lc", 22, 17, "Y, tomando un caliz, despues de pronunciar la accion de gracias, dijo: \"Tomad esto, repartidlo entre vosotros;"},
    {"Lucas", "Lc", 22, 18, "porque os digo que no bebere desde ahora del fruto de la vid hasta que venga el reino de Dios\"."},
    {"Lucas", "Lc", 22, 19, "Y, tomando pan, despues de pronunciar la accion de gracias, lo partio y se lo dio diciendo: \"Esto es mi cuerpo, que se entrega por vosotros; haced esto en memoria mia\"."},
    {"Lucas", "Lc", 22, 20, "Despues de cenar, hizo lo mismo con el caliz diciendo: \"Este caliz es la nueva alianza en mi sangre, que es derramada por vosotros."},
    {"Lucas", "Lc", 22, 21, "Pero mirad: la mano del que me entrega esta conmigo, en la mesa."},
    {"Lucas", "Lc", 22, 22, "Porque el Hijo del hombre se va, segun lo establecido; pero ay de aquel hombre por quien es entregado!\"."},
    {"Lucas", "Lc", 22, 23, "Ellos empezaron a preguntarse unos a otros sobre quien de ellos podia ser el que iba a hacer eso."},
    {"Lucas", "Lc", 22, 24, "Se produjo tambien un altercado a proposito de quien de ellos debia ser tenido como el mayor."},
    {"Lucas", "Lc", 22, 25, "Pero el les dijo: \"Los reyes de las naciones las dominan, y los que ejercen la autoridad se hacen llamar bienhechores."},
    {"Lucas", "Lc", 22, 26, "Vosotros no hagais asi, sino que el mayor entre vosotros se ha de hacer como el menor, y el que gobierna, como el que sirve."},
    {"Lucas", "Lc", 22, 27, "Porque quien es mas, el que esta a la mesa o el que sirve? Verdad que el que esta a la mesa? Pues yo estoy en medio de vosotros como el que sirve."},
    {"Lucas", "Lc", 22, 28, "Vosotros sois los que habeis perseverado conmigo en mis pruebas,"},
    {"Lucas", "Lc", 22, 29, "y yo preparo para vosotros el reino como me lo preparo mi Padre a mi,"},
    {"Lucas", "Lc", 22, 30, "de forma que comais y bebais a mi mesa en mi reino, y os senteis en tronos para juzgar a las doce tribus de Israel."},
    {"Lucas", "Lc", 22, 31, "Simon, Simon, mira que Satanas os ha reclamado para cribaros como trigo."},
    {"Lucas", "Lc", 22, 32, "Pero yo he pedido por ti, para que tu fe no se apague. Y tu, cuando te hayas convertido, confirma a tus hermanos\"."},
    {"Lucas", "Lc", 22, 33, "El le dijo: \"Se\177or, contigo estoy dispuesto a ir incluso a la carcel y a la muerte\"."},
    {"Lucas", "Lc", 22, 34, "Pero el le dijo: \"Te digo, Pedro, que no cantara hoy el gallo antes de que tres veces hayas negado conocerme\"."},
    {"Lucas", "Lc", 22, 35, "Y les dijo: \"Cuando os envie sin bolsa, ni alforja, ni sandalias, os falto algo?\". Dijeron: \"Nada\"."},
    {"Lucas", "Lc", 22, 36, "\"Pero ahora, el que tenga bolsa, que la lleve consigo, y lo mismo la alforja; y el que no tenga espada, que venda su manto y compre una."},
    {"Lucas", "Lc", 22, 37, "Porque os digo que es necesario que se cumpla en mi lo que esta escrito: \"Fue contado entre los pecadores\", pues lo que se refiere a mi toca a su fin\"."},
    {"Lucas", "Lc", 22, 38, "Ellos dijeron: \"Se\177or, aqui hay dos espadas\". El les dijo: \"Basta\"."},
    {"Lucas", "Lc", 22, 39, "Salio y se encamino, como de costumbre, al monte de los Olivos, y lo siguieron los discipulos."},
    {"Lucas", "Lc", 22, 40, "Al llegar al sitio, les dijo: \"Orad, para no caer en tentacion\"."},
    {"Lucas", "Lc", 22, 41, "Y se aparto de ellos como a un tiro de piedra y, arrodillado, oraba"},
    {"Lucas", "Lc", 22, 42, "diciendo: \"Padre, si quieres, aparta de mi este caliz; pero que no se haga mi voluntad, sino la tuya\"."},
    {"Lucas", "Lc", 22, 43, "Y se le aparecio un angel del cielo, que lo confortaba."},
    {"Lucas", "Lc", 22, 44, "En medio de su angustia, oraba con mas intensidad. Y le entro un sudor que caia hasta el suelo como si fueran gotas espesas de sangre."},
    {"Lucas", "Lc", 22, 45, "Y, levantandose de la oracion, fue hacia sus discipulos, los encontro dormidos por la tristeza,"},
    {"Lucas", "Lc", 22, 46, "y les dijo: \"Por que dormis? Levantaos y orad, para no caer en tentacion\"."},
    {"Lucas", "Lc", 22, 47, "Todavia estaba hablando, cuando aparecio una turba; iba a la cabeza el llamado Judas, uno de los Doce. Y se acerco a besar a Jesus."},
    {"Lucas", "Lc", 22, 48, "Jesus le dijo: \"Judas, con un beso entregas al Hijo del hombre?\"."},
    {"Lucas", "Lc", 22, 49, "Viendo los que estaban con el lo que iba a pasar, dijeron: \"Se\177or, herimos con la espada?\"."},
    {"Lucas", "Lc", 22, 50, "Y uno de ellos hirio al criado del sumo sacerdote y le corto la oreja derecha."},
    {"Lucas", "Lc", 22, 51, "Jesus intervino diciendo: \"Dejadlo, basta\". Y, tocandole la oreja, lo curo."},
    {"Lucas", "Lc", 22, 52, "Jesus dijo a los sumos sacerdotes y a los oficiales del templo, y a los ancianos que habian venido contra el: \"Habeis salido con espadas y palos como en busca de un bandido?"},
    {"Lucas", "Lc", 22, 53, "Estando a diario en el templo con vosotros, no me prendisteis. Pero esta es vuestra hora y la del poder de las tinieblas\"."},
    {"Lucas", "Lc", 22, 54, "Despues de prenderlo, se lo llevaron y lo hicieron entrar en casa del sumo sacerdote. Pedro lo seguia desde lejos."},
    {"Lucas", "Lc", 22, 55, "Ellos encendieron fuego en medio del patio, se sentaron alrededor, y Pedro estaba sentado entre ellos."},
    {"Lucas", "Lc", 22, 56, "Al verlo una criada sentado junto a la lumbre, se lo quedo mirando y dijo: \"Tambien este estaba con el\"."},
    {"Lucas", "Lc", 22, 57, "Pero el lo nego diciendo: \"No lo conozco, mujer\"."},
    {"Lucas", "Lc", 22, 58, "Poco despues, lo vio otro y le dijo: \"Tu tambien eres uno de ellos\". Pero Pedro replico: \"Hombre, no lo soy\"."},
    {"Lucas", "Lc", 22, 59, "Y pasada cosa de una hora, otro insistia diciendo: \"Sin duda, este tambien estaba con el, porque es galileo\"."},
    {"Lucas", "Lc", 22, 60, "Pedro dijo: \"Hombre, no se de que me hablas\". Y enseguida, estando todavia el hablando, canto un gallo."},
    {"Lucas", "Lc", 22, 61, "El Se\177or, volviendose, le echo una mirada a Pedro, y Pedro se acordo de la palabra que el Se\177or le habia dicho: \"Antes de que cante hoy el gallo, me negaras tres veces\"."},
    {"Lucas", "Lc", 22, 62, "Y, saliendo afuera, lloro amargamente."},
    {"Lucas", "Lc", 22, 63, "Y los hombres que tenian preso a Jesus se burlaban de el, dandole golpes."},
    {"Lucas", "Lc", 22, 64, "Y, tapandole la cara, le preguntaban diciendo: \"Haz de profeta: quien te ha pegado?\"."},
    {"Lucas", "Lc", 22, 65, "E, insultandolo, proferian contra el otras muchas cosas."},
    {"Lucas", "Lc", 22, 66, "Cuando se hizo de dia, se reunieron los ancianos del pueblo, con los jefes de los sacerdotes y los escribas; lo condujeron ante su Sanedrin,"},
    {"Lucas", "Lc", 22, 67, "y le dijeron: \"Si tu eres el Mesias, dinoslo\". El les dijo: \"Si os lo digo, no lo vais a creer;"},
    {"Lucas", "Lc", 22, 68, "y si os pregunto, no me vais a responder."},
    {"Lucas", "Lc", 22, 69, "Pero, desde ahora, el Hijo del hombre estara sentado a la derecha del poder de Dios\"."},
    {"Lucas", "Lc", 22, 70, "Dijeron todos: \"Entonces, tu eres el Hijo de Dios?\". El les dijo: \"Vosotros lo decis, yo lo soy\"."},
    {"Lucas", "Lc", 22, 71, "Ellos dijeron: \"Que necesidad tenemos ya de testimonios? Nosotros mismos lo hemos oido de su boca\"."},
    {"Lucas", "Lc", 23, 1, "Y levantandose toda la asamblea, lo llevaron a presencia de Pilato."},
    {"Lucas", "Lc", 23, 2, "Y se pusieron a acusarlo diciendo: \"Hemos encontrado que este anda amotinando a nuestra nacion, y oponiendose a que se paguen tributos al Cesar, y diciendo que el es el Mesias rey\"."},
    {"Lucas", "Lc", 23, 3, "Pilato le pregunto: \"Eres tu el rey de los judios?\". El le responde: \"Tu lo dices\"."},
    {"Lucas", "Lc", 23, 4, "Pilato dijo a los sumos sacerdotes y a la gente: \"No encuentro ninguna culpa en este hombre\"."},
    {"Lucas", "Lc", 23, 5, "Pero ellos insistian con mas fuerza, diciendo: \"Solivianta al pueblo ense\177ando por toda Judea, desde que comenzo en Galilea hasta llegar aqui\"."},
    {"Lucas", "Lc", 23, 6, "Pilato, al oirlo, pregunto si el hombre era galileo;"},
    {"Lucas", "Lc", 23, 7, "y, al enterarse de que era de la jurisdiccion de Herodes, que estaba precisamente en Jerusalen por aquellos dias, se lo remitio."},
    {"Lucas", "Lc", 23, 8, "Herodes, al ver a Jesus, se puso muy contento, pues hacia bastante tiempo que deseaba verlo, porque oia hablar de el y esperaba verle hacer algun milagro."},
    {"Lucas", "Lc", 23, 9, "Le hacia muchas preguntas con abundante verborrea; pero el no le contesto nada."},
    {"Lucas", "Lc", 23, 10, "Estaban alli los sumos sacerdotes y los escribas acusandolo con ahinco."},
    {"Lucas", "Lc", 23, 11, "Herodes, con sus soldados, lo trato con desprecio y, despues de burlarse de el, poniendole una vestidura blanca, se lo remitio a Pilato."},
    {"Lucas", "Lc", 23, 12, "Aquel mismo dia se hicieron amigos entre si Herodes y Pilato, porque antes estaban enemistados entre si."},
    {"Lucas", "Lc", 23, 13, "Pilato, despues de convocar a los sumos sacerdotes, a los magistrados y al pueblo,"},
    {"Lucas", "Lc", 23, 14, "les dijo: \"Me habeis traido a este hombre como agitador del pueblo; y resulta que yo lo he interrogado delante de vosotros y no he encontrado en este hombre ninguna de las culpas de que lo acusais;"},
    {"Lucas", "Lc", 23, 15, "pero tampoco Herodes, porque nos lo ha devuelto: ya veis que no ha hecho nada digno de muerte."},
    {"Lucas", "Lc", 23, 16, "Asi que le dare un escarmiento y lo soltare\"."},
    {"Lucas", "Lc", 23, 17, "[\"Por la fiesta tenia que soltarles a uno\"]"},
    {"Lucas", "Lc", 23, 18, "Ellos vociferaron en masa: \"Quita de en medio a ese! Sueltanos a Barrabas\"."},
    {"Lucas", "Lc", 23, 19, "Este habia sido metido en la carcel por una revuelta acaecida en la ciudad y un homicidio."},
    {"Lucas", "Lc", 23, 20, "Pilato volvio a dirigirles la palabra queriendo soltar a Jesus,"},
    {"Lucas", "Lc", 23, 21, "pero ellos seguian gritando: \"Crucificalo, crucificalo!\"."},
    {"Lucas", "Lc", 23, 22, "Por tercera vez les dijo: \"Pues que mal ha hecho este? No he encontrado en el ninguna culpa que merezca la muerte. Asi que le dare un escarmiento y lo soltare\"."},
    {"Lucas", "Lc", 23, 23, "Pero ellos se le echaban encima, pidiendo a gritos que lo crucificara; e iba creciendo su griterio."},
    {"Lucas", "Lc", 23, 24, "Pilato entonces sentencio que se realizara lo que pedian:"},
    {"Lucas", "Lc", 23, 25, "solto al que le reclamaban (al que habia metido en la carcel por revuelta y homicidio), y a Jesus se lo entrego a su voluntad."},
    {"Lucas", "Lc", 23, 26, "Mientras lo conducian, echaron mano de un cierto Simon de Cirene, que volvia del campo, y le cargaron la cruz, para que la llevase detras de Jesus."},
    {"Lucas", "Lc", 23, 27, "Lo seguia un gran gentio del pueblo, y de mujeres que se golpeaban el pecho y lanzaban lamentos por el."},
    {"Lucas", "Lc", 23, 28, "Jesus se volvio hacia ellas y les dijo: \"Hijas de Jerusalen, no lloreis por mi, llorad por vosotras y por vuestros hijos,"},
    {"Lucas", "Lc", 23, 29, "porque mirad que vienen dias en los que diran: \"Bienaventuradas las esteriles y los vientres que no han dado a luz y los pechos que no han criado\"."},
    {"Lucas", "Lc", 23, 30, "Entonces empezaran a decirles a los montes: \"Caed sobre nosotros\", y a las colinas: \"Cubridnos\";"},
    {"Lucas", "Lc", 23, 31, "porque, si esto hacen con el le\177o verde, que haran con el seco?\"."},
    {"Lucas", "Lc", 23, 32, "Conducian tambien a otros dos malhechores para ajusticiarlos con el."},
    {"Lucas", "Lc", 23, 33, "Y cuando llegaron al lugar llamado \"La Calavera\", lo crucificaron alli, a el y a los malhechores, uno a la derecha y otro a la izquierda."},
    {"Lucas", "Lc", 23, 34, "Jesus decia: \"Padre, perdonalos, porque no saben lo que hacen\". Hicieron lotes con sus ropas y los echaron a suerte."},
    {"Lucas", "Lc", 23, 35, "El pueblo estaba mirando, pero los magistrados le hacian muecas diciendo: \"A otros ha salvado; que se salve a si mismo, si el es el Mesias de Dios, el Elegido\"."},
    {"Lucas", "Lc", 23, 36, "Se burlaban de el tambien los soldados, que se acercaban y le ofrecian vinagre,"},
    {"Lucas", "Lc", 23, 37, "diciendo: \"Si eres tu el rey de los judios, salvate a ti mismo\"."},
    {"Lucas", "Lc", 23, 38, "Habia tambien por encima de el un letrero: \"Este es el rey de los judios\"."},
    {"Lucas", "Lc", 23, 39, "Uno de los malhechores crucificados lo insultaba diciendo: \"No eres tu el Mesias? Salvate a ti mismo y a nosotros\"."},
    {"Lucas", "Lc", 23, 40, "Pero el otro, respondiendole e increpandolo, le decia: \"Ni siquiera temes tu a Dios, estando en la misma condena?"},
    {"Lucas", "Lc", 23, 41, "Nosotros, en verdad, lo estamos justamente, porque recibimos el justo pago de lo que hicimos; en cambio, este no ha hecho nada malo\"."},
    {"Lucas", "Lc", 23, 42, "Y decia: \"Jesus, acuerdate de mi cuando llegues a tu reino\"."},
    {"Lucas", "Lc", 23, 43, "Jesus le dijo: \"En verdad te digo: hoy estaras conmigo en el paraiso\"."},
    {"Lucas", "Lc", 23, 44, "Era ya como la hora sexta, y vinieron las tinieblas sobre toda la tierra, hasta la hora nona,"},
    {"Lucas", "Lc", 23, 45, "porque se oscurecio el sol. El velo del templo se rasgo por medio."},
    {"Lucas", "Lc", 23, 46, "Y Jesus, clamando con voz potente, dijo: \"Padre, a tus manos encomiendo mi espiritu\". Y, dicho esto, expiro."},
    {"Lucas", "Lc", 23, 47, "El centurion, al ver lo ocurrido, daba gloria a Dios diciendo: \"Realmente, este hombre era justo\"."},
    {"Lucas", "Lc", 23, 48, "Toda la muchedumbre que habia concurrido a este espectaculo, al ver las cosas que habian ocurrido, se volvia dandose golpes de pecho."},
    {"Lucas", "Lc", 23, 49, "Todos sus conocidos y las mujeres que lo habian seguido desde Galilea se mantenian a distancia, viendo todo esto."},
    {"Lucas", "Lc", 23, 50, "Habia un hombre, llamado Jose, que era miembro del Sanedrin, hombre bueno y justo"},
    {"Lucas", "Lc", 23, 51, "(este no habia dado su asentimiento ni a la decision ni a la actuacion de ellos); era natural de Arimatea, ciudad de los judios, y aguardaba el reino de Dios."},
    {"Lucas", "Lc", 23, 52, "Este acudio a Pilato y le pidio el cuerpo de Jesus."},
    {"Lucas", "Lc", 23, 53, "Y, bajandolo, lo envolvio en una sabana y lo coloco en un sepulcro excavado en la roca, donde nadie habia sido puesto todavia."},
    {"Lucas", "Lc", 23, 54, "Era el dia de la Preparacion y estaba para empezar el sabado."},
    {"Lucas", "Lc", 23, 55, "Las mujeres que lo habian acompa\177ado desde Galilea lo siguieron, y vieron el sepulcro y como habia sido colocado su cuerpo."},
    {"Lucas", "Lc", 23, 56, "Al regresar, prepararon aromas y mirra. Y el sabado descansaron de acuerdo con el precepto."},
    {"Lucas", "Lc", 24, 1, "El primer dia de la semana, de madrugada, las mujeres fueron al sepulcro llevando los aromas que habian preparado."},
    {"Lucas", "Lc", 24, 2, "Encontraron corrida la piedra del sepulcro."},
    {"Lucas", "Lc", 24, 3, "Y, entrando, no encontraron el cuerpo del Se\177or Jesus."},
    {"Lucas", "Lc", 24, 4, "Mientras estaban desconcertadas por esto, se les presentaron dos hombres con vestidos refulgentes."},
    {"Lucas", "Lc", 24, 5, "Ellas quedaron despavoridas y con las caras mirando al suelo y ellos les dijeron: \"Por que buscais entre los muertos al que vive?"},
    {"Lucas", "Lc", 24, 6, "No esta aqui. Ha resucitado. Recordad como os hablo estando todavia en Galilea,"},
    {"Lucas", "Lc", 24, 7, "cuando dijo que el Hijo del hombre tiene que ser entregado en manos de hombres pecadores, ser crucificado y al tercer dia resucitar\"."},
    {"Lucas", "Lc", 24, 8, "Y recordaron sus palabras."},
    {"Lucas", "Lc", 24, 9, "Habiendo vuelto del sepulcro, anunciaron todo esto a los Once y a todos los demas."},
    {"Lucas", "Lc", 24, 10, "Eran Maria la Magdalena, Juana y Maria, la de Santiago. Tambien las demas, que estaban con ellas, contaban esto mismo a los apostoles."},
    {"Lucas", "Lc", 24, 11, "Ellos lo tomaron por un delirio y no las creyeron."},
    {"Lucas", "Lc", 24, 12, "Pedro, sin embargo, se levanto y fue corriendo al sepulcro. Asomandose, ve solo los lienzos. Y se volvio a su casa, admirandose de lo sucedido."},
    {"Lucas", "Lc", 24, 13, "Aquel mismo dia, dos de ellos iban caminando a una aldea llamada Emaus, distante de Jerusalen unos sesenta estadios;"},
    {"Lucas", "Lc", 24, 14, "iban conversando entre ellos de todo lo que habia sucedido."},
    {"Lucas", "Lc", 24, 15, "Mientras conversaban y discutian, Jesus en persona se acerco y se puso a caminar con ellos."},
    {"Lucas", "Lc", 24, 16, "Pero sus ojos no eran capaces de reconocerlo."},
    {"Lucas", "Lc", 24, 17, "El les dijo: \"Que conversacion es esa que traeis mientras vais de camino?\". Ellos se detuvieron con aire entristecido."},
    {"Lucas", "Lc", 24, 18, "Y uno de ellos, que se llamaba Cleofas, le respondio: \"Eres tu el unico forastero en Jerusalen que no sabes lo que ha pasado alli estos dias?\"."},
    {"Lucas", "Lc", 24, 19, "El les dijo: \"Que?\". Ellos le contestaron: \"Lo de Jesus el Nazareno, que fue un profeta poderoso en obras y palabras, ante Dios y ante todo el pueblo;"},
    {"Lucas", "Lc", 24, 20, "como lo entregaron los sumos sacerdotes y nuestros jefes para que lo condenaran a muerte, y lo crucificaron."},
    {"Lucas", "Lc", 24, 21, "Nosotros esperabamos que el iba a liberar a Israel, pero, con todo esto, ya estamos en el tercer dia desde que esto sucedio."},
    {"Lucas", "Lc", 24, 22, "Es verdad que algunas mujeres de nuestro grupo nos han sobresaltado, pues habiendo ido muy de ma\177ana al sepulcro,"},
    {"Lucas", "Lc", 24, 23, "y no habiendo encontrado su cuerpo, vinieron diciendo que incluso habian visto una aparicion de angeles, que dicen que esta vivo."},
    {"Lucas", "Lc", 24, 24, "Algunos de los nuestros fueron tambien al sepulcro y lo encontraron como habian dicho las mujeres; pero a el no lo vieron\"."},
    {"Lucas", "Lc", 24, 25, "Entonces el les dijo: \"Que necios y torpes sois para creer lo que dijeron los profetas!"},
    {"Lucas", "Lc", 24, 26, "No era necesario que el Mesias padeciera esto y entrara asi en su gloria?\"."},
    {"Lucas", "Lc", 24, 27, "Y, comenzando por Moises y siguiendo por todos los profetas, les explico lo que se referia a el en todas las Escrituras."},
    {"Lucas", "Lc", 24, 28, "Llegaron cerca de la aldea adonde iban y el simulo que iba a seguir caminando;"},
    {"Lucas", "Lc", 24, 29, "pero ellos lo apremiaron, diciendo: \"Quedate con nosotros, porque atardece y el dia va de caida\". Y entro para quedarse con ellos."},
    {"Lucas", "Lc", 24, 30, "Sentado a la mesa con ellos, tomo el pan, pronuncio la bendicion, lo partio y se lo iba dando."},
    {"Lucas", "Lc", 24, 31, "A ellos se les abrieron los ojos y lo reconocieron. Pero el desaparecio de su vista."},
    {"Lucas", "Lc", 24, 32, "Y se dijeron el uno al otro: \"No ardia nuestro corazon mientras nos hablaba por el camino y nos explicaba las Escrituras?\"."},
    {"Lucas", "Lc", 24, 33, "Y, levantandose en aquel momento, se volvieron a Jerusalen, donde encontraron reunidos a los Once con sus compa\177eros,"},
    {"Lucas", "Lc", 24, 34, "que estaban diciendo: \"Era verdad, ha resucitado el Se\177or y se ha aparecido a Simon\"."},
    {"Lucas", "Lc", 24, 35, "Y ellos contaron lo que les habia pasado por el camino y como lo habian reconocido al partir el pan."},
    {"Lucas", "Lc", 24, 36, "Estaban hablando de estas cosas, cuando el se presento en medio de ellos y les dice: \"Paz a vosotros\"."},
    {"Lucas", "Lc", 24, 37, "Pero ellos, aterrorizados y llenos de miedo, creian ver un espiritu."},
    {"Lucas", "Lc", 24, 38, "Y el les dijo: \"Por que os alarmais?, por que surgen dudas en vuestro corazon?"},
    {"Lucas", "Lc", 24, 39, "Mirad mis manos y mis pies: soy yo en persona. Palpadme y daos cuenta de que un espiritu no tiene carne y huesos, como veis que yo tengo\"."},
    {"Lucas", "Lc", 24, 40, "Dicho esto, les mostro las manos y los pies."},
    {"Lucas", "Lc", 24, 41, "Pero como no acababan de creer por la alegria, y seguian atonitos, les dijo: \"Teneis ahi algo de comer?\"."},
    {"Lucas", "Lc", 24, 42, "Ellos le ofrecieron un trozo de pez asado."},
    {"Lucas", "Lc", 24, 43, "El lo tomo y comio delante de ellos."},
    {"Lucas", "Lc", 24, 44, "Y les dijo: \"Esto es lo que os dije mientras estaba con vosotros: que era necesario que se cumpliera todo lo escrito en la Ley de Moises y en los Profetas y Salmos acerca de mi\"."},
    {"Lucas", "Lc", 24, 45, "Entonces les abrio el entendimiento para comprender las Escrituras."},
    {"Lucas", "Lc", 24, 46, "Y les dijo: \"Asi esta escrito: el Mesias padecera, resucitara de entre los muertos al tercer dia"},
    {"Lucas", "Lc", 24, 47, "y en su nombre se proclamara la conversion para el perdon de los pecados a todos los pueblos, comenzando por Jerusalen."},
    {"Lucas", "Lc", 24, 48, "Vosotros sois testigos de esto."},
    {"Lucas", "Lc", 24, 49, "Mirad, yo voy a enviar sobre vosotros la promesa de mi Padre; vosotros, por vuestra parte, quedaos en la ciudad hasta que os revistais de la fuerza que viene de lo alto\"."},
    {"Lucas", "Lc", 24, 50, "Y los saco hasta cerca de Betania y, levantando sus manos, los bendijo."},
    {"Lucas", "Lc", 24, 51, "Y mientras los bendecia, se separo de ellos, y fue llevado hacia el cielo."},
    {"Lucas", "Lc", 24, 52, "Ellos se postraron ante el y se volvieron a Jerusalen con gran alegria;"},
    {"Lucas", "Lc", 24, 53, "y estaban siempre en el templo bendiciendo a Dios."},
    {"Juan", "Jn", 1, 1, "En el principio existia el Verbo, y el Verbo estaba junto a Dios, y el Verbo era Dios."},
    {"Juan", "Jn", 1, 2, "El estaba en el principio junto a Dios."},
    {"Juan", "Jn", 1, 3, "Por medio de el se hizo todo, y sin el no se hizo nada de cuanto se ha hecho."},
    {"Juan", "Jn", 1, 4, "En el estaba la vida, y la vida era la luz de los hombres."},
    {"Juan", "Jn", 1, 5, "Y la luz brilla en la tiniebla, y la tiniebla no lo recibio."},
    {"Juan", "Jn", 1, 6, "Surgio un hombre enviado por Dios, que se llamaba Juan:"},
    {"Juan", "Jn", 1, 7, "este venia como testigo, para dar testimonio de la luz, para que todos creyeran por medio de el."},
    {"Juan", "Jn", 1, 8, "No era el la luz, sino el que daba testimonio de la luz."},
    {"Juan", "Jn", 1, 9, "El Verbo era la luz verdadera, que alumbra a todo hombre, viniendo al mundo."},
    {"Juan", "Jn", 1, 10, "En el mundo estaba; / el mundo se hizo por medio de el, y el mundo no lo conocio."},
    {"Juan", "Jn", 1, 11, "Vino a su casa, y los suyos no lo recibieron."},
    {"Juan", "Jn", 1, 12, "Pero a cuantos lo recibieron, les dio poder de ser hijos de Dios, a los que creen en su nombre."},
    {"Juan", "Jn", 1, 13, "Estos no han nacido de sangre, ni de deseo de carne, / ni de deseo de varon, sino que han nacido de Dios."},
    {"Juan", "Jn", 1, 14, "Y el Verbo se hizo carne y habito entre nosotros, y hemos contemplado su gloria: gloria como del Unigenito del Padre, lleno de gracia y de verdad."},
    {"Juan", "Jn", 1, 15, "Juan da testimonio de el y grita diciendo: \"Este es de quien dije: el que viene detras de mi se ha puesto delante de mi, porque existia antes que yo\"."},
    {"Juan", "Jn", 1, 16, "Pues de su plenitud todos hemos recibido, gracia tras gracia."},
    {"Juan", "Jn", 1, 17, "Porque la ley se dio por medio de Moises, la gracia y la verdad nos han llegado por medio de Jesucristo."},
    {"Juan", "Jn", 1, 18, "A Dios nadie lo ha visto jamas: Dios unigenito, que esta en el seno del Padre, es quien lo ha dado a conocer."},
    {"Juan", "Jn", 1, 19, "Y este es el testimonio de Juan, cuando los judios enviaron desde Jerusalen sacerdotes y levitas a que le preguntaran: \"Tu quien eres?\"."},
    {"Juan", "Jn", 1, 20, "El confeso y no nego; confeso: \"Yo no soy el Mesias\"."},
    {"Juan", "Jn", 1, 21, "Le preguntaron: \"Entonces, que? Eres tu Elias?\". El dijo: \"No lo soy\". \"Eres tu el Profeta?\". Respondio: \"No\"."},
    {"Juan", "Jn", 1, 22, "Y le dijeron: \"Quien eres, para que podamos dar una respuesta a los que nos han enviado? Que dices de ti mismo?\"."},
    {"Juan", "Jn", 1, 23, "El contesto: \"Yo soy la voz que grita en el desierto: \"Allanad el camino del Se\177or\", como dijo el profeta Isaias\"."},
    {"Juan", "Jn", 1, 24, "Entre los enviados habia fariseos"},
    {"Juan", "Jn", 1, 25, "y le preguntaron: \"Entonces, por que bautizas si tu no eres el Mesias, ni Elias, ni el Profeta?\"."},
    {"Juan", "Jn", 1, 26, "Juan les respondio: \"Yo bautizo con agua; en medio de vosotros hay uno que no conoceis,"},
    {"Juan", "Jn", 1, 27, "el que viene detras de mi, y al que no soy digno de desatar la correa de la sandalia\"."},
    {"Juan", "Jn", 1, 28, "Esto pasaba en Betania, en la otra orilla del Jordan, donde Juan estaba bautizando."},
    {"Juan", "Jn", 1, 29, "Al dia siguiente, al ver Juan a Jesus que venia hacia el, exclamo: \"Este es el Cordero de Dios, que quita el pecado del mundo."},
    {"Juan", "Jn", 1, 30, "Este es aquel de quien yo dije: \"Tras de mi viene un hombre que esta por delante de mi, porque existia antes que yo\"."},
    {"Juan", "Jn", 1, 31, "Yo no lo conocia, pero he salido a bautizar con agua, para que sea manifestado a Israel\"."},
    {"Juan", "Jn", 1, 32, "Y Juan dio testimonio diciendo: \"He contemplado al Espiritu que bajaba del cielo como una paloma, y se poso sobre el."},
    {"Juan", "Jn", 1, 33, "Yo no lo conocia, pero el que me envio a bautizar con agua me dijo: \"Aquel sobre quien veas bajar el Espiritu y posarse sobre el, ese es el que bautiza con Espiritu Santo\"."},
    {"Juan", "Jn", 1, 34, "Y yo lo he visto y he dado testimonio de que este es el Hijo de Dios\"."},
    {"Juan", "Jn", 1, 35, "Al dia siguiente, estaba Juan con dos de sus discipulos y,"},
    {"Juan", "Jn", 1, 36, "fijandose en Jesus que pasaba, dice: \"Este es el Cordero de Dios\"."},
    {"Juan", "Jn", 1, 37, "Los dos discipulos oyeron sus palabras y siguieron a Jesus."},
    {"Juan", "Jn", 1, 38, "Jesus se volvio y, al ver que lo seguian, les pregunta: \"Que buscais?\". Ellos le contestaron: \"Rabi (que significa Maestro), donde vives?\"."},
    {"Juan", "Jn", 1, 39, "El les dijo: \"Venid y vereis\". Entonces fueron, vieron donde vivia y se quedaron con el aquel dia; era como la hora decima."},
    {"Juan", "Jn", 1, 40, "Andres, hermano de Simon Pedro, era uno de los dos que oyeron a Juan y siguieron a Jesus;"},
    {"Juan", "Jn", 1, 41, "encuentra primero a su hermano Simon y le dice: \"Hemos encontrado al Mesias (que significa Cristo)\"."},
    {"Juan", "Jn", 1, 42, "Y lo llevo a Jesus. Jesus se le quedo mirando y le dijo: \"Tu eres Simon, el hijo de Juan; tu te llamaras Cefas (que se traduce: Pedro)\"."},
    {"Juan", "Jn", 1, 43, "Al dia siguiente, determino Jesus salir para Galilea; encuentra a Felipe y le dice: \"Sigueme\"."},
    {"Juan", "Jn", 1, 44, "Felipe era de Betsaida, ciudad de Andres y de Pedro."},
    {"Juan", "Jn", 1, 45, "Felipe encuentra a Natanael y le dice: \"Aquel de quien escribieron Moises en la ley y los profetas, lo hemos encontrado: Jesus, hijo de Jose, de Nazaret\"."},
    {"Juan", "Jn", 1, 46, "Natanael le replico: \"De Nazaret puede salir algo bueno?\". Felipe le contesto: \"Ven y veras\"."},
    {"Juan", "Jn", 1, 47, "Vio Jesus que se acercaba Natanael y dijo de el: \"Ahi teneis a un israelita de verdad, en quien no hay enga\177o\"."},
    {"Juan", "Jn", 1, 48, "Natanael le contesta: \"De que me conoces?\". Jesus le responde: \"Antes de que Felipe te llamara, cuando estabas debajo de la higuera, te vi\"."},
    {"Juan", "Jn", 1, 49, "Natanael respondio: \"Rabi, tu eres el Hijo de Dios, tu eres el Rey de Israel\"."},
    {"Juan", "Jn", 1, 50, "Jesus le contesto: \"Por haberte dicho que te vi debajo de la higuera, crees? Has de ver cosas mayores\"."},
    {"Juan", "Jn", 1, 51, "Y le a\177adio: \"En verdad, en verdad os digo: vereis el cielo abierto y a los angeles de Dios subir y bajar sobre el Hijo del hombre\"."},
    {"Juan", "Jn", 2, 1, "A los tres dias habia una boda en Cana de Galilea, y la madre de Jesus estaba alli."},
    {"Juan", "Jn", 2, 2, "Jesus y sus discipulos estaban tambien invitados a la boda."},
    {"Juan", "Jn", 2, 3, "Falto el vino, y la madre de Jesus le dice: \"No tienen vino\"."},
    {"Juan", "Jn", 2, 4, "Jesus le dice: \"Mujer, que tengo yo que ver contigo? Todavia no ha llegado mi hora\"."},
    {"Juan", "Jn", 2, 5, "Su madre dice a los sirvientes: \"Haced lo que el os diga\"."},
    {"Juan", "Jn", 2, 6, "Habia alli colocadas seis tinajas de piedra, para las purificaciones de los judios, de unos cien litros cada una."},
    {"Juan", "Jn", 2, 7, "Jesus les dice: \"Llenad las tinajas de agua\". Y las llenaron hasta arriba."},
    {"Juan", "Jn", 2, 8, "Entonces les dice: \"Sacad ahora y llevadlo al mayordomo\". Ellos se lo llevaron."},
    {"Juan", "Jn", 2, 9, "El mayordomo probo el agua convertida en vino sin saber de donde venia (los sirvientes si lo sabian, pues habian sacado el agua), y entonces llama al esposo"},
    {"Juan", "Jn", 2, 10, "y le dice: \"Todo el mundo pone primero el vino bueno y, cuando ya estan bebidos, el peor; tu, en cambio, has guardado el vino bueno hasta ahora\"."},
    {"Juan", "Jn", 2, 11, "Este fue el primero de los signos que Jesus realizo en Cana de Galilea; asi manifesto su gloria y sus discipulos creyeron en el."},
    {"Juan", "Jn", 2, 12, "Despues bajo a Cafarnaun con su madre y sus hermanos y sus discipulos, pero no se quedaron alli muchos dias."},
    {"Juan", "Jn", 2, 13, "Se acercaba la Pascua de los judios y Jesus subio a Jerusalen."},
    {"Juan", "Jn", 2, 14, "Y encontro en el templo a los vendedores de bueyes, ovejas y palomas, y a los cambistas sentados; y,"},
    {"Juan", "Jn", 2, 15, "haciendo un azote de cordeles, los echo a todos del templo, ovejas y bueyes; y a los cambistas les esparcio las monedas y les volco las mesas;"},
    {"Juan", "Jn", 2, 16, "y a los que vendian palomas les dijo: \"Quitad esto de aqui: no convirtais en un mercado la casa de mi Padre\"."},
    {"Juan", "Jn", 2, 17, "Sus discipulos se acordaron de lo que esta escrito: \"El celo de tu casa me devora\"."},
    {"Juan", "Jn", 2, 18, "Entonces intervinieron los judios y le preguntaron: \"Que signos nos muestras para obrar asi?\"."},
    {"Juan", "Jn", 2, 19, "Jesus contesto: \"Destruid este templo, y en tres dias lo levantare\"."},
    {"Juan", "Jn", 2, 20, "Los judios replicaron: \"Cuarenta y seis a\177os ha costado construir este templo, y tu lo vas a levantar en tres dias?\"."},
    {"Juan", "Jn", 2, 21, "Pero el hablaba del templo de su cuerpo."},
    {"Juan", "Jn", 2, 22, "Y cuando resucito de entre los muertos, los discipulos se acordaron de que lo habia dicho, y creyeron a la Escritura y a la palabra que habia dicho Jesus."},
    {"Juan", "Jn", 2, 23, "Mientras estaba en Jerusalen por las fiestas de Pascua, muchos creyeron en su nombre, viendo los signos que hacia;"},
    {"Juan", "Jn", 2, 24, "pero Jesus no se confiaba a ellos, porque los conocia a todos"},
    {"Juan", "Jn", 2, 25, "y no necesitaba el testimonio de nadie sobre un hombre, porque el sabia lo que hay dentro de cada hombre."},
    {"Juan", "Jn", 3, 1, "Habia un hombre del grupo de los fariseos llamado Nicodemo, jefe judio."},
    {"Juan", "Jn", 3, 2, "Este fue a ver a Jesus de noche y le dijo: \"Rabi, sabemos que has venido de parte de Dios, como maestro; porque nadie puede hacer los signos que tu haces si Dios no esta con el\"."},
    {"Juan", "Jn", 3, 3, "Jesus le contesto: \"En verdad, en verdad te digo: el que no nazca de nuevo no puede ver el reino de Dios\"."},
    {"Juan", "Jn", 3, 4, "Nicodemo le pregunta: \"Como puede nacer un hombre siendo viejo? Acaso puede por segunda vez entrar en el vientre de su madre y nacer?\"."},
    {"Juan", "Jn", 3, 5, "Jesus le contesto: \"En verdad, en verdad te digo: el que no nazca de agua y de Espiritu no puede entrar en el reino de Dios."},
    {"Juan", "Jn", 3, 6, "Lo que nace de la carne es carne, lo que nace del Espiritu es espiritu."},
    {"Juan", "Jn", 3, 7, "No te extra\177es de que te haya dicho: \"Teneis que nacer de nuevo\";"},
    {"Juan", "Jn", 3, 8, "el viento sopla donde quiere y oyes su ruido, pero no sabes de donde viene ni adonde va. Asi es todo el que ha nacido del Espiritu\"."},
    {"Juan", "Jn", 3, 9, "Nicodemo le pregunto: \"Como puede suceder eso?\"."},
    {"Juan", "Jn", 3, 10, "Le contesto Jesus: \"Tu eres maestro en Israel, y no lo entiendes?"},
    {"Juan", "Jn", 3, 11, "En verdad, en verdad te digo: hablamos de lo que sabemos y damos testimonio de lo que hemos visto, pero no recibis nuestro testimonio."},
    {"Juan", "Jn", 3, 12, "Si os hablo de las cosas terrenas y no me creeis, como creereis si os hablo de las cosas celestiales?"},
    {"Juan", "Jn", 3, 13, "Nadie ha subido al cielo sino el que bajo del cielo, el Hijo del hombre."},
    {"Juan", "Jn", 3, 14, "Lo mismo que Moises elevo la serpiente en el desierto, asi tiene que ser elevado el Hijo del hombre,"},
    {"Juan", "Jn", 3, 15, "para que todo el que cree en el tenga vida eterna."},
    {"Juan", "Jn", 3, 16, "Porque tanto amo Dios al mundo, que entrego a su Unigenito, para que todo el que cree en el no perezca, sino que tenga vida eterna."},
    {"Juan", "Jn", 3, 17, "Porque Dios no envio a su Hijo al mundo para juzgar al mundo, sino para que el mundo se salve por el."},
    {"Juan", "Jn", 3, 18, "El que cree en el no sera juzgado; el que no cree ya esta juzgado, porque no ha creido en el nombre del Unigenito de Dios."},
    {"Juan", "Jn", 3, 19, "Este es el juicio: que la luz vino al mundo, y los hombres prefirieron la tiniebla a la luz, porque sus obras eran malas."},
    {"Juan", "Jn", 3, 20, "Pues todo el que obra el mal detesta la luz, y no se acerca a la luz, para no verse acusado por sus obras."},
    {"Juan", "Jn", 3, 21, "En cambio, el que obra la verdad se acerca a la luz, para que se vea que sus obras estan hechas segun Dios\"."},
    {"Juan", "Jn", 3, 22, "Despues de esto, fue Jesus con sus discipulos a Judea, se quedo alli con ellos y bautizaba."},
    {"Juan", "Jn", 3, 23, "Tambien Juan estaba bautizando en Enon, cerca de Salin, porque habia alli agua abundante; la gente acudia y se bautizaba."},
    {"Juan", "Jn", 3, 24, "A Juan todavia no le habian metido en la carcel."},
    {"Juan", "Jn", 3, 25, "Se origino entonces una discusion entre un judio y los discipulos de Juan acerca de la purificacion;"},
    {"Juan", "Jn", 3, 26, "ellos fueron a Juan y le dijeron: \"Rabi, el que estaba contigo en la otra orilla del Jordan, de quien tu has dado testimonio, ese esta bautizando, y todo el mundo acude a el\"."},
    {"Juan", "Jn", 3, 27, "Contesto Juan: \"Nadie puede tomarse algo para si si no se lo dan desde el cielo."},
    {"Juan", "Jn", 3, 28, "Vosotros mismos sois testigos de que yo dije: \"Yo no soy el Mesias, sino que he sido enviado delante de el\"."},
    {"Juan", "Jn", 3, 29, "El que tiene la esposa es el esposo; en cambio, el amigo del esposo, que asiste y lo oye, se alegra con la voz del esposo; pues esta alegria mia esta colmada."},
    {"Juan", "Jn", 3, 30, "El tiene que crecer, y yo tengo que menguar."},
    {"Juan", "Jn", 3, 31, "El que viene de lo alto esta por encima de todos. El que es de la tierra es de la tierra y habla de la tierra. El que viene del cielo esta por encima de todos."},
    {"Juan", "Jn", 3, 32, "De lo que ha visto y ha oido da testimonio, y nadie acepta su testimonio."},
    {"Juan", "Jn", 3, 33, "El que acepta su testimonio certifica que Dios es veraz."},
    {"Juan", "Jn", 3, 34, "El que Dios envio habla las palabras de Dios, porque no da el Espiritu con medida."},
    {"Juan", "Jn", 3, 35, "El Padre ama al Hijo y todo lo ha puesto en su mano."},
    {"Juan", "Jn", 3, 36, "El que cree en el Hijo posee la vida eterna; el que no crea al Hijo no vera la vida, sino que la ira de Dios pesa sobre el\"."},
    {"Juan", "Jn", 4, 1, "Cuando supo Jesus que habian oido los fariseos que Jesus hacia mas discipulos que Juan y que bautizaba"},
    {"Juan", "Jn", 4, 2, "(aunque Jesus no bautizaba, sino sus discipulos),"},
    {"Juan", "Jn", 4, 3, "dejo Judea y partio de nuevo para Galilea."},
    {"Juan", "Jn", 4, 4, "Era necesario que el pasara a traves de Samaria."},
    {"Juan", "Jn", 4, 5, "Llego Jesus a una ciudad de Samaria llamada Sicar, cerca del campo que dio Jacob a su hijo Jose;"},
    {"Juan", "Jn", 4, 6, "alli estaba el pozo de Jacob. Jesus, cansado del camino, estaba alli sentado junto al pozo. Era hacia la hora sexta."},
    {"Juan", "Jn", 4, 7, "Llega una mujer de Samaria a sacar agua, y Jesus le dice: \"Dame de beber\"."},
    {"Juan", "Jn", 4, 8, "Sus discipulos se habian ido al pueblo a comprar comida."},
    {"Juan", "Jn", 4, 9, "La samaritana le dice: \"Como tu, siendo judio, me pides de beber a mi, que soy samaritana?\" (porque los judios no se tratan con los samaritanos)."},
    {"Juan", "Jn", 4, 10, "Jesus le contesto: \"Si conocieras el don de Dios y quien es el que te dice \"dame de beber\", le pedirias tu, y el te daria agua viva\"."},
    {"Juan", "Jn", 4, 11, "La mujer le dice: \"Se\177or, si no tienes cubo, y el pozo es hondo, de donde sacas el agua viva?;"},
    {"Juan", "Jn", 4, 12, "eres tu mas que nuestro padre Jacob, que nos dio este pozo, y de el bebieron el y sus hijos y sus ganados?\"."},
    {"Juan", "Jn", 4, 13, "Jesus le contesto: \"El que bebe de esta agua vuelve a tener sed;"},
    {"Juan", "Jn", 4, 14, "pero el que beba del agua que yo le dare nunca mas tendra sed: el agua que yo le dare se convertira dentro de el en un surtidor de agua que salta hasta la vida eterna\"."},
    {"Juan", "Jn", 4, 15, "La mujer le dice: \"Se\177or, dame esa agua: asi no tendre mas sed, ni tendre que venir aqui a sacarla\"."},
    {"Juan", "Jn", 4, 16, "El le dice: \"Anda, llama a tu marido y vuelve\"."},
    {"Juan", "Jn", 4, 17, "La mujer le contesta: \"No tengo marido\". Jesus le dice: \"Tienes razon, que no tienes marido:"},
    {"Juan", "Jn", 4, 18, "has tenido ya cinco, y el de ahora no es tu marido. En eso has dicho la verdad\"."},
    {"Juan", "Jn", 4, 19, "La mujer le dice: \"Se\177or, veo que tu eres un profeta."},
    {"Juan", "Jn", 4, 20, "Nuestros padres dieron culto en este monte, y vosotros decis que el sitio donde se debe dar culto esta en Jerusalen\"."},
    {"Juan", "Jn", 4, 21, "Jesus le dice: \"Creeme, mujer: se acerca la hora en que ni en este monte ni en Jerusalen adorareis al Padre."},
    {"Juan", "Jn", 4, 22, "Vosotros adorais a uno que no conoceis; nosotros adoramos a uno que conocemos, porque la salvacion viene de los judios."},
    {"Juan", "Jn", 4, 23, "Pero se acerca la hora, ya esta aqui, en que los verdaderos adoradores adoraran al Padre en espiritu y verdad, porque el Padre desea que lo adoren asi."},
    {"Juan", "Jn", 4, 24, "Dios es espiritu, y los que lo adoran deben hacerlo en espiritu y verdad\"."},
    {"Juan", "Jn", 4, 25, "La mujer le dice: \"Se que va a venir el Mesias, el Cristo; cuando venga, el nos lo dira todo\"."},
    {"Juan", "Jn", 4, 26, "Jesus le dice: \"Soy yo, el que habla contigo\"."},
    {"Juan", "Jn", 4, 27, "En esto llegaron sus discipulos y se extra\177aban de que estuviera hablando con una mujer, aunque ninguno le dijo: \"Que le preguntas o de que le hablas?\"."},
    {"Juan", "Jn", 4, 28, "La mujer entonces dejo su cantaro, se fue al pueblo y dijo a la gente:"},
    {"Juan", "Jn", 4, 29, "\"Venid a ver un hombre que me ha dicho todo lo que he hecho; sera este el Mesias?\"."},
    {"Juan", "Jn", 4, 30, "Salieron del pueblo y se pusieron en camino adonde estaba el."},
    {"Juan", "Jn", 4, 31, "Mientras tanto sus discipulos le insistian: \"Maestro, come\"."},
    {"Juan", "Jn", 4, 32, "El les dijo: \"Yo tengo un alimento que vosotros no conoceis\"."},
    {"Juan", "Jn", 4, 33, "Los discipulos comentaban entre ellos: \"Le habra traido alguien de comer?\"."},
    {"Juan", "Jn", 4, 34, "Jesus les dice: \"Mi alimento es hacer la voluntad del que me envio y llevar a termino su obra."},
    {"Juan", "Jn", 4, 35, "No decis vosotros que faltan todavia cuatro meses para la cosecha? Yo os digo esto: levantad los ojos y contemplad los campos, que estan ya dorados para la siega;"},
    {"Juan", "Jn", 4, 36, "el segador ya esta recibiendo salario y almacenando fruto para la vida eterna: y asi, se alegran lo mismo sembrador y segador."},
    {"Juan", "Jn", 4, 37, "Con todo, tiene razon el proverbio: uno siembra y otro siega."},
    {"Juan", "Jn", 4, 38, "Yo os envie a segar lo que no habeis trabajado. Otros trabajaron y vosotros entrasteis en el fruto de sus trabajos\"."},
    {"Juan", "Jn", 4, 39, "En aquel pueblo muchos samaritanos creyeron en el por el testimonio que habia dado la mujer: \"Me ha dicho todo lo que he hecho\"."},
    {"Juan", "Jn", 4, 40, "Asi, cuando llegaron a verlo los samaritanos, le rogaban que se quedara con ellos. Y se quedo alli dos dias."},
    {"Juan", "Jn", 4, 41, "Todavia creyeron muchos mas por su predicacion,"},
    {"Juan", "Jn", 4, 42, "y decian a la mujer: \"Ya no creemos por lo que tu dices; nosotros mismos lo hemos oido y sabemos que el es de verdad el Salvador del mundo\"."},
    {"Juan", "Jn", 4, 43, "Despues de dos dias, salio Jesus de Samaria para Galilea."},
    {"Juan", "Jn", 4, 44, "Jesus mismo habia atestiguado: \"Un profeta no es estimado en su propia patria\"."},
    {"Juan", "Jn", 4, 45, "Cuando llego a Galilea, los galileos lo recibieron bien, porque habian visto todo lo que habia hecho en Jerusalen durante la fiesta, pues tambien ellos habian ido a la fiesta."},
    {"Juan", "Jn", 4, 46, "Fue Jesus otra vez a Cana de Galilea, donde habia convertido el agua en vino. Habia un funcionario real que tenia un hijo enfermo en Cafarnaun."},
    {"Juan", "Jn", 4, 47, "Oyendo que Jesus habia llegado de Judea a Galilea, fue a verlo, y le pedia que bajase a curar a su hijo que estaba muriendose."},
    {"Juan", "Jn", 4, 48, "Jesus le dijo: \"Si no veis signos y prodigios, no creeis\"."},
    {"Juan", "Jn", 4, 49, "El funcionario insiste: \"Se\177or, baja antes de que se muera mi ni\177o\"."},
    {"Juan", "Jn", 4, 50, "Jesus le contesta: \"Anda, tu hijo vive\". El hombre creyo en la palabra de Jesus y se puso en camino."},
    {"Juan", "Jn", 4, 51, "Iba ya bajando, cuando sus criados vinieron a su encuentro diciendole que su hijo vivia."},
    {"Juan", "Jn", 4, 52, "El les pregunto a que hora habia empezado la mejoria. Y le contestaron: \"Ayer a la hora septima lo dejo la fiebre\"."},
    {"Juan", "Jn", 4, 53, "El padre cayo en la cuenta de que esa era la hora en que Jesus le habia dicho: \"Tu hijo vive\". Y creyo el con toda su familia."},
    {"Juan", "Jn", 4, 54, "Este segundo signo lo hizo Jesus al llegar de Judea a Galilea."},
    {"Juan", "Jn", 5, 1, "Despues de esto, se celebraba una fiesta de los judios, y Jesus subio a Jerusalen."},
    {"Juan", "Jn", 5, 2, "Hay en Jerusalen, junto a la Puerta de las Ovejas, una piscina que llaman en hebreo Betesda. Esta tiene cinco soportales,"},
    {"Juan", "Jn", 5, 3, "y alli estaban echados muchos enfermos, ciegos, cojos, paraliticos."},
    {"Juan", "Jn", 5, 4, "[\"que esperaban el movimiento de las aguas; pues el angel del Se\177or bajaba de tiempo en tiempo a la piscina y se movia el agua y el primero que descendia a la piscina tras el movimiento de agua quedaba sano de cualquier enfermedad que tuviera\".]"},
    {"Juan", "Jn", 5, 5, "Estaba tambien alli un hombre que llevaba treinta y ocho a\177os enfermo."},
    {"Juan", "Jn", 5, 6, "Jesus, al verlo echado, y sabiendo que ya llevaba mucho tiempo, le dice: \"Quieres quedar sano?\"."},
    {"Juan", "Jn", 5, 7, "El enfermo le contesto: \"Se\177or, no tengo a nadie que me meta en la piscina cuando se remueve el agua; para cuando llego yo, otro se me ha adelantado\"."},
    {"Juan", "Jn", 5, 8, "Jesus le dice: \"Levantate, toma tu camilla y echa a andar\"."},
    {"Juan", "Jn", 5, 9, "Y al momento el hombre quedo sano, tomo su camilla y echo a andar. Aquel dia era sabado,"},
    {"Juan", "Jn", 5, 10, "y los judios dijeron al hombre que habia quedado sano: \"Hoy es sabado, y no se puede llevar la camilla\"."},
    {"Juan", "Jn", 5, 11, "El les contesto: \"El que me ha curado es quien me ha dicho: \"Toma tu camilla y echa a andar\"\"."},
    {"Juan", "Jn", 5, 12, "Ellos le preguntaron: \"Quien es el que te ha dicho que tomes la camilla y eches a andar?\"."},
    {"Juan", "Jn", 5, 13, "Pero el que habia quedado sano no sabia quien era, porque Jesus, a causa del gentio que habia en aquel sitio, se habia alejado."},
    {"Juan", "Jn", 5, 14, "Mas tarde lo encuentra Jesus en el templo y le dice: \"Mira, has quedado sano; no peques mas, no sea que te ocurra algo peor\"."},
    {"Juan", "Jn", 5, 15, "Se marcho aquel hombre y dijo a los judios que era Jesus quien lo habia sanado."},
    {"Juan", "Jn", 5, 16, "Por esto los judios perseguian a Jesus, porque hacia tales cosas en sabado."},
    {"Juan", "Jn", 5, 17, "Jesus les dijo: \"Mi Padre sigue actuando, y yo tambien actuo\"."},
    {"Juan", "Jn", 5, 18, "Por eso los judios tenian mas ganas de matarlo: porque no solo quebrantaba el sabado, sino tambien llamaba a Dios Padre suyo, haciendose igual a Dios."},
    {"Juan", "Jn", 5, 19, "Jesus tomo la palabra y les dijo: \"En verdad, en verdad os digo: el Hijo no puede hacer nada por su cuenta sino lo que viere hacer al Padre. Lo que hace este, eso mismo hace tambien el Hijo,"},
    {"Juan", "Jn", 5, 20, "pues el Padre ama al Hijo y le muestra todo lo que el hace, y le mostrara obras mayores que esta, para vuestro asombro."},
    {"Juan", "Jn", 5, 21, "Lo mismo que el Padre resucita a los muertos y les da vida, asi tambien el Hijo da vida a los que quiere."},
    {"Juan", "Jn", 5, 22, "Porque el Padre no juzga a nadie, sino que ha confiado al Hijo todo el juicio,"},
    {"Juan", "Jn", 5, 23, "para que todos honren al Hijo como honran al Padre. El que no honra al Hijo, no honra al Padre que lo envio."},
    {"Juan", "Jn", 5, 24, "En verdad, en verdad os digo: quien escucha mi palabra y cree al que me envio posee la vida eterna y no incurre en juicio, sino que ha pasado ya de la muerte a la vida."},
    {"Juan", "Jn", 5, 25, "En verdad, en verdad os digo: llega la hora, y ya esta aqui, en que los muertos oiran la voz del Hijo de Dios, y los que hayan oido viviran."},
    {"Juan", "Jn", 5, 26, "Porque, igual que el Padre tiene vida en si mismo, asi ha dado tambien al Hijo tener vida en si mismo."},
    {"Juan", "Jn", 5, 27, "Y le ha dado potestad de juzgar, porque es el Hijo del hombre."},
    {"Juan", "Jn", 5, 28, "No os sorprenda esto, porque viene la hora en que los que estan en el sepulcro oiran su voz:"},
    {"Juan", "Jn", 5, 29, "los que hayan hecho el bien saldran a una resurreccion de vida; los que hayan hecho el mal, a una resurreccion de juicio."},
    {"Juan", "Jn", 5, 30, "Yo no puedo hacer nada por mi mismo; segun le oigo, juzgo, y mi juicio es justo, porque no busco mi voluntad, sino la voluntad del que me envio."},
    {"Juan", "Jn", 5, 31, "Si yo doy testimonio de mi mismo, mi testimonio no es verdadero."},
    {"Juan", "Jn", 5, 32, "Hay otro que da testimonio de mi, y se que es verdadero el testimonio que da de mi."},
    {"Juan", "Jn", 5, 33, "Vosotros enviasteis mensajeros a Juan, y el ha dado testimonio en favor de la verdad."},
    {"Juan", "Jn", 5, 34, "No es que yo dependa del testimonio de un hombre; si digo esto es para que vosotros os salveis."},
    {"Juan", "Jn", 5, 35, "Juan era la lampara que ardia y brillaba, y vosotros quisisteis gozar un instante de su luz."},
    {"Juan", "Jn", 5, 36, "Pero el testimonio que yo tengo es mayor que el de Juan: las obras que el Padre me ha concedido llevar a cabo, esas obras que hago dan testimonio de mi: que el Padre me ha enviado."},
    {"Juan", "Jn", 5, 37, "Y el Padre que me envio, el mismo ha dado testimonio de mi. Nunca habeis escuchado su voz, ni visto su rostro,"},
    {"Juan", "Jn", 5, 38, "y su palabra no habita en vosotros, porque al que el envio no lo creeis."},
    {"Juan", "Jn", 5, 39, "Estudiais las Escrituras pensando encontrar en ellas vida eterna; pues ellas estan dando testimonio de mi,"},
    {"Juan", "Jn", 5, 40, "y no quereis venir a mi para tener vida!"},
    {"Juan", "Jn", 5, 41, "No recibo gloria de los hombres;"},
    {"Juan", "Jn", 5, 42, "ademas, os conozco y se que el amor de Dios no esta en vosotros."},
    {"Juan", "Jn", 5, 43, "Yo he venido en nombre de mi Padre, y no me recibisteis; si otro viene en nombre propio, a ese si lo recibireis."},
    {"Juan", "Jn", 5, 44, "Como podreis creer vosotros, que aceptais gloria unos de otros y no buscais la gloria que viene del unico Dios?"},
    {"Juan", "Jn", 5, 45, "No penseis que yo os voy a acusar ante el Padre, hay uno que os acusa: Moises, en quien teneis vuestra esperanza."},
    {"Juan", "Jn", 5, 46, "Si creyerais a Moises, me creeriais a mi, porque de mi escribio el."},
    {"Juan", "Jn", 5, 47, "Pero, si no creeis en sus escritos, como vais a creer en mis palabras?\"."},
    {"Juan", "Jn", 6, 1, "Despues de esto, Jesus se marcho a la otra parte del mar de Galilea (o de Tiberiades)."},
    {"Juan", "Jn", 6, 2, "Lo seguia mucha gente, porque habian visto los signos que hacia con los enfermos."},
    {"Juan", "Jn", 6, 3, "Subio Jesus entonces a la monta\177a y se sento alli con sus discipulos."},
    {"Juan", "Jn", 6, 4, "Estaba cerca la Pascua, la fiesta de los judios."},
    {"Juan", "Jn", 6, 5, "Jesus entonces levanto los ojos y, al ver que acudia mucha gente, dice a Felipe: \"Con que compraremos panes para que coman estos?\"."},
    {"Juan", "Jn", 6, 6, "Lo decia para probarlo, pues bien sabia el lo que iba a hacer."},
    {"Juan", "Jn", 6, 7, "Felipe le contesto: \"Doscientos denarios de pan no bastan para que a cada uno le toque un pedazo\"."},
    {"Juan", "Jn", 6, 8, "Uno de sus discipulos, Andres, el hermano de Simon Pedro, le dice:"},
    {"Juan", "Jn", 6, 9, "\"Aqui hay un muchacho que tiene cinco panes de cebada y dos peces; pero que es eso para tantos?\"."},
    {"Juan", "Jn", 6, 10, "Jesus dijo: \"Decid a la gente que se siente en el suelo\". Habia mucha hierba en aquel sitio. Se sentaron; solo los hombres eran unos cinco mil."},
    {"Juan", "Jn", 6, 11, "Jesus tomo los panes, dijo la accion de gracias y los repartio a los que estaban sentados, y lo mismo todo lo que quisieron del pescado."},
    {"Juan", "Jn", 6, 12, "Cuando se saciaron, dice a sus discipulos: \"Recoged los pedazos que han sobrado; que nada se pierda\"."},
    {"Juan", "Jn", 6, 13, "Los recogieron y llenaron doce canastos con los pedazos de los cinco panes de cebada que sobraron a los que habian comido."},
    {"Juan", "Jn", 6, 14, "La gente entonces, al ver el signo que habia hecho, decia: \"Este es verdaderamente el Profeta que va a venir al mundo\"."},
    {"Juan", "Jn", 6, 15, "Jesus, sabiendo que iban a llevarselo para proclamarlo rey, se retiro otra vez a la monta\177a el solo."},
    {"Juan", "Jn", 6, 16, "Al oscurecer, los discipulos de Jesus bajaron al mar,"},
    {"Juan", "Jn", 6, 17, "embarcaron y empezaron la travesia hacia Cafarnaun. Era ya noche cerrada, y todavia Jesus no los habia alcanzado;"},
    {"Juan", "Jn", 6, 18, "soplaba un viento fuerte, y el lago se iba encrespando."},
    {"Juan", "Jn", 6, 19, "Habian remado unos veinticinco o treinta estadios, cuando vieron a Jesus que se acercaba a la barca, caminando sobre el mar, y se asustaron."},
    {"Juan", "Jn", 6, 20, "Pero el les dijo: \"Soy yo, no temais\"."},
    {"Juan", "Jn", 6, 21, "Querian recogerlo a bordo, pero la barca toco tierra en seguida, en el sitio a donde iban."},
    {"Juan", "Jn", 6, 22, "Al dia siguiente, la gente que se habia quedado al otro lado del mar noto que alli no habia habido mas que una barca y que Jesus no habia embarcado con sus discipulos, sino que sus discipulos se habian marchado solos."},
    {"Juan", "Jn", 6, 23, "Entretanto, unas barcas de Tiberiades llegaron cerca del sitio donde habian comido el pan despues que el Se\177or habia dado gracias."},
    {"Juan", "Jn", 6, 24, "Cuando la gente vio que ni Jesus ni sus discipulos estaban alli, se embarcaron y fueron a Cafarnaun en busca de Jesus."},
    {"Juan", "Jn", 6, 25, "Al encontrarlo en la otra orilla del lago, le preguntaron: \"Maestro, cuando has venido aqui?\"."},
    {"Juan", "Jn", 6, 26, "Jesus les contesto: \"En verdad, en verdad os digo: me buscais no porque habeis visto signos, sino porque comisteis pan hasta saciaros."},
    {"Juan", "Jn", 6, 27, "Trabajad no por el alimento que perece, sino por el alimento que perdura para la vida eterna, el que os dara el Hijo del hombre; pues a este lo ha sellado el Padre, Dios\"."},
    {"Juan", "Jn", 6, 28, "Ellos le preguntaron: \"Y que tenemos que hacer para realizar las obras de Dios?\"."},
    {"Juan", "Jn", 6, 29, "Respondio Jesus: \"La obra de Dios es esta: que creais en el que el ha enviado\"."},
    {"Juan", "Jn", 6, 30, "Le replicaron: \"Y que signo haces tu, para que veamos y creamos en ti? Cual es tu obra?"},
    {"Juan", "Jn", 6, 31, "Nuestros padres comieron el mana en el desierto, como esta escrito: \"Pan del cielo les dio a comer\"\"."},
    {"Juan", "Jn", 6, 32, "Jesus les replico: \"En verdad, en verdad os digo: no fue Moises quien os dio pan del cielo, sino que es mi Padre el que os da el verdadero pan del cielo."},
    {"Juan", "Jn", 6, 33, "Porque el pan de Dios es el que baja del cielo y da vida al mundo\"."},
    {"Juan", "Jn", 6, 34, "Entonces le dijeron: \"Se\177or, danos siempre de este pan\"."},
    {"Juan", "Jn", 6, 35, "Jesus les contesto: \"Yo soy el pan de vida. El que viene a mi no tendra hambre, y el que cree en mi no tendra sed jamas;"},
    {"Juan", "Jn", 6, 36, "pero, como os he dicho, me habeis visto y no creeis."},
    {"Juan", "Jn", 6, 37, "Todo lo que me da el Padre vendra a mi, y al que venga a mi no lo echare afuera,"},
    {"Juan", "Jn", 6, 38, "porque he bajado del cielo no para hacer mi voluntad, sino la voluntad del que me ha enviado."},
    {"Juan", "Jn", 6, 39, "Esta es la voluntad del que me ha enviado: que no pierda nada de lo que me dio, sino que lo resucite en el ultimo dia."},
    {"Juan", "Jn", 6, 40, "Esta es la voluntad de mi Padre: que todo el que ve al Hijo y cree en el tenga vida eterna, y yo lo resucitare en el ultimo dia\"."},
    {"Juan", "Jn", 6, 41, "Los judios murmuraban de el porque habia dicho: \"Yo soy el pan bajado del cielo\","},
    {"Juan", "Jn", 6, 42, "y decian: \"No es este Jesus, el hijo de Jose? No conocemos a su padre y a su madre? Como dice ahora que ha bajado del cielo?\"."},
    {"Juan", "Jn", 6, 43, "Jesus tomo la palabra y les dijo: \"No critiqueis."},
    {"Juan", "Jn", 6, 44, "Nadie puede venir a mi si no lo atrae el Padre que me ha enviado. Y yo lo resucitare en el ultimo dia."},
    {"Juan", "Jn", 6, 45, "Esta escrito en los profetas: \"Seran todos discipulos de Dios\". Todo el que escucha al Padre y aprende, viene a mi."},
    {"Juan", "Jn", 6, 46, "No es que alguien haya visto al Padre, a no ser el que esta junto a Dios: ese ha visto al Padre."},
    {"Juan", "Jn", 6, 47, "En verdad, en verdad os digo: el que cree tiene vida eterna."},
    {"Juan", "Jn", 6, 48, "Yo soy el pan de la vida."},
    {"Juan", "Jn", 6, 49, "Vuestros padres comieron en el desierto el mana y murieron;"},
    {"Juan", "Jn", 6, 50, "este es el pan que baja del cielo, para que el hombre coma de el y no muera."},
    {"Juan", "Jn", 6, 51, "Yo soy el pan vivo que ha bajado del cielo; el que coma de este pan vivira para siempre. Y el pan que yo dare es mi carne por la vida del mundo\"."},
    {"Juan", "Jn", 6, 52, "Disputaban los judios entre si: \"Como puede este darnos a comer su carne?\"."},
    {"Juan", "Jn", 6, 53, "Entonces Jesus les dijo: \"En verdad, en verdad os digo: si no comeis la carne del Hijo del hombre y no bebeis su sangre, no teneis vida en vosotros."},
    {"Juan", "Jn", 6, 54, "El que come mi carne y bebe mi sangre tiene vida eterna, y yo lo resucitare en el ultimo dia."},
    {"Juan", "Jn", 6, 55, "Mi carne es verdadera comida, y mi sangre es verdadera bebida."},
    {"Juan", "Jn", 6, 56, "El que come mi carne y bebe mi sangre habita en mi y yo en el."},
    {"Juan", "Jn", 6, 57, "Como el Padre que vive me ha enviado, y yo vivo por el Padre, asi, del mismo modo, el que me come vivira por mi."},
    {"Juan", "Jn", 6, 58, "Este es el pan que ha bajado del cielo: no como el de vuestros padres, que lo comieron y murieron; el que come este pan vivira para siempre\"."},
    {"Juan", "Jn", 6, 59, "Esto lo dijo Jesus en la sinagoga, cuando ense\177aba en Cafarnaun."},
    {"Juan", "Jn", 6, 60, "Muchos de sus discipulos, al oirlo, dijeron: \"Este modo de hablar es duro, quien puede hacerle caso?\"."},
    {"Juan", "Jn", 6, 61, "Sabiendo Jesus que sus discipulos lo criticaban, les dijo: \"Esto os escandaliza?,"},
    {"Juan", "Jn", 6, 62, "y si vierais al Hijo del hombre subir adonde estaba antes?"},
    {"Juan", "Jn", 6, 63, "El Espiritu es quien da vida; la carne no sirve para nada. Las palabras que os he dicho son espiritu y vida."},
    {"Juan", "Jn", 6, 64, "Y, con todo, hay algunos de entre vosotros que no creen\". Pues Jesus sabia desde el principio quienes no creian y quien lo iba a entregar."},
    {"Juan", "Jn", 6, 65, "Y dijo: \"Por eso os he dicho que nadie puede venir a mi si el Padre no se lo concede\"."},
    {"Juan", "Jn", 6, 66, "Desde entonces, muchos discipulos suyos se echaron atras y no volvieron a ir con el."},
    {"Juan", "Jn", 6, 67, "Entonces Jesus les dijo a los Doce: \"Tambien vosotros quereis marcharos?\"."},
    {"Juan", "Jn", 6, 68, "Simon Pedro le contesto: \"Se\177or, a quien vamos a acudir? Tu tienes palabras de vida eterna;"},
    {"Juan", "Jn", 6, 69, "nosotros creemos y sabemos que tu eres el Santo de Dios\"."},
    {"Juan", "Jn", 6, 70, "Jesus le contesto: \"Acaso no os he escogido yo a vosotros, los Doce? Y uno de vosotros es un diablo\"."},
    {"Juan", "Jn", 6, 71, "Lo decia por Judas, el hijo de Simon Iscariote, pues este lo iba a entregar, uno de los Doce."},
    {"Juan", "Jn", 7, 1, "Despues de estas cosas, recorria Jesus Galilea, pues no queria andar por Judea porque los judios trataban de matarlo."},
    {"Juan", "Jn", 7, 2, "Se acercaba la fiesta judia de las Tiendas."},
    {"Juan", "Jn", 7, 3, "Le decian sus hermanos: \"Sal de aqui y marcha a Judea para que tambien tus discipulos vean las obras que haces,"},
    {"Juan", "Jn", 7, 4, "pues nadie obra nada en secreto, sino que busca estar a la luz publica. Si haces estas cosas, manifiestate al mundo\"."},
    {"Juan", "Jn", 7, 5, "Y es que tampoco sus hermanos creian en el."},
    {"Juan", "Jn", 7, 6, "Jesus les dice: \"Mi tiempo no ha llegado todavia, el vuestro esta siempre dispuesto."},
    {"Juan", "Jn", 7, 7, "El mundo no puede odiaros a vosotros, a mi si me odia porque doy testimonio contra el de que sus obras son malas."},
    {"Juan", "Jn", 7, 8, "Subid vosotros a la fiesta. Yo no subo a esta fiesta, porque mi tiempo no se ha cumplido todavia\"."},
    {"Juan", "Jn", 7, 9, "Despues de decir estas cosas, permanecio en Galilea."},
    {"Juan", "Jn", 7, 10, "Una vez que sus hermanos se hubieron marchado a la fiesta, entonces subio el tambien, no abiertamente, sino a escondidas."},
    {"Juan", "Jn", 7, 11, "Los judios lo buscaban en la fiesta y decian: \"Donde esta?\","},
    {"Juan", "Jn", 7, 12, "y habia muchos comentarios acerca de el entre las turbas. Unos decian: \"Es bueno\"; otros decian: \"No, sino que enga\177a a la gente\"."},
    {"Juan", "Jn", 7, 13, "Pero nadie hablaba de el en publico por miedo a los judios."},
    {"Juan", "Jn", 7, 14, "A mitad de la fiesta, subio Jesus al templo y se puso a ense\177ar."},
    {"Juan", "Jn", 7, 15, "Los judios preguntaban extra\177ados: \"Como es este tan instruido si no ha estudiado?\"."},
    {"Juan", "Jn", 7, 16, "Jesus entonces les contesto: \"Mi doctrina no es mia, sino del que me ha enviado;"},
    {"Juan", "Jn", 7, 17, "el que este dispuesto a hacer la voluntad de Dios podra apreciar si mi doctrina viene de Dios o si hablo en mi nombre."},
    {"Juan", "Jn", 7, 18, "Quien habla en su propio nombre busca su propia gloria; en cambio, el que busca la gloria del que lo ha enviado, ese es veraz y en el no hay injusticia."},
    {"Juan", "Jn", 7, 19, "Acaso no os dio Moises la ley, y ninguno de vosotros cumple la ley? Por que quereis matarme?\"."},
    {"Juan", "Jn", 7, 20, "Respondio la gente: \"Tienes un demonio, quien quiere matarte?\"."},
    {"Juan", "Jn", 7, 21, "Jesus les contesto: \"He hecho una obra y todos os admirais"},
    {"Juan", "Jn", 7, 22, "por ello. Moises os dio la circuncision -aunque no es de Moises, sino de los patriarcas- y vosotros circuncidais a un hombre en sabado."},
    {"Juan", "Jn", 7, 23, "Si un hombre recibe la circuncision en sabado para que no se quebrante la ley de Moises, por que os enojais contra mi porque he curado en sabado a un hombre enteramente?"},
    {"Juan", "Jn", 7, 24, "No juzgueis segun apariencia, sino juzgad segun un juicio justo\"."},
    {"Juan", "Jn", 7, 25, "Entonces algunos que eran de Jerusalen dijeron: \"No es este el que intentan matar?"},
    {"Juan", "Jn", 7, 26, "Pues mirad como habla abiertamente, y no le dicen nada. Sera que los jefes se han convencido de que este es el Mesias?"},
    {"Juan", "Jn", 7, 27, "Pero este sabemos de donde viene, mientras que el Mesias, cuando llegue, nadie sabra de donde viene\"."},
    {"Juan", "Jn", 7, 28, "Entonces Jesus, mientras ense\177aba en el templo, grito: \"A mi me conoceis, y conoceis de donde vengo. Sin embargo, yo no vengo por mi cuenta, sino que el Verdadero es el que me envia; a ese vosotros no lo conoceis;"},
    {"Juan", "Jn", 7, 29, "yo lo conozco, porque procedo de el y el me ha enviado\"."},
    {"Juan", "Jn", 7, 30, "Entonces intentaban agarrarlo; pero nadie le pudo echar mano, porque todavia no habia llegado su hora."},
    {"Juan", "Jn", 7, 31, "De la gente, muchos creyeron en el y decian: \"Cuando venga el Mesias, acaso hara obras mayores que las que ha hecho este?\"."},
    {"Juan", "Jn", 7, 32, "Oyeron los fariseos que la gente comentaba estas cosas sobre el, y los sumos sacerdotes y los fariseos enviaron guardias para apresarlo."},
    {"Juan", "Jn", 7, 33, "Jesus dijo: \"Todavia un poco de tiempo estoy con vosotros y despues voy al que me ha enviado."},
    {"Juan", "Jn", 7, 34, "Me buscareis y no me encontrareis, y donde yo estoy vosotros no podeis venir\"."},
    {"Juan", "Jn", 7, 35, "Decian los judios unos a otros: \"Adonde va a marchar este que no podamos encontrarlo? Acaso va a marchar a la diaspora para instruir a los griegos?"},
    {"Juan", "Jn", 7, 36, "Que significa esta palabra que dijo: \"Me buscareis y no me encontrareis, y donde yo estoy no podeis venir vosotros\"?\"."},
    {"Juan", "Jn", 7, 37, "El ultimo dia, el mas solemne de la fiesta, Jesus en pie grito: \"El que tenga sed, que venga a mi y beba"},
    {"Juan", "Jn", 7, 38, "el que cree en mi; como dice la Escritura: \"de sus entra\177as manaran rios de agua viva\"\"."},
    {"Juan", "Jn", 7, 39, "Dijo esto refiriendose al Espiritu, que habian de recibir los que creyeran en el. Todavia no se habia dado el Espiritu, porque Jesus no habia sido glorificado."},
    {"Juan", "Jn", 7, 40, "Algunos de entre la gente, que habian oido los discursos de Jesus, decian: \"Este es de verdad el profeta\"."},
    {"Juan", "Jn", 7, 41, "Otros decian: \"Este es el Mesias\". Pero otros decian: \"Es que de Galilea va a venir el Mesias?"},
    {"Juan", "Jn", 7, 42, "No dice la Escritura que el Mesias vendra del linaje de David, y de Belen, el pueblo de David?\"."},
    {"Juan", "Jn", 7, 43, "Y asi surgio entre la gente una discordia por su causa."},
    {"Juan", "Jn", 7, 44, "Algunos querian prenderlo, pero nadie le puso la mano encima."},
    {"Juan", "Jn", 7, 45, "Los guardias del templo acudieron a los sumos sacerdotes y fariseos, y estos les dijeron: \"Por que no lo habeis traido?\"."},
    {"Juan", "Jn", 7, 46, "Los guardias respondieron: \"Jamas ha hablado nadie como ese hombre\"."},
    {"Juan", "Jn", 7, 47, "Los fariseos les replicaron: \"Tambien vosotros os habeis dejado embaucar?"},
    {"Juan", "Jn", 7, 48, "Hay algun jefe o fariseo que haya creido en el?"},
    {"Juan", "Jn", 7, 49, "Esa gente que no entiende de la ley son unos malditos\"."},
    {"Juan", "Jn", 7, 50, "Nicodemo, el que habia ido en otro tiempo a visitarlo y que era fariseo, les dijo:"},
    {"Juan", "Jn", 7, 51, "\"Acaso nuestra ley permite juzgar a nadie sin escucharlo primero y averiguar lo que ha hecho?\"."},
    {"Juan", "Jn", 7, 52, "Ellos le replicaron: \"Tambien tu eres galileo? Estudia y veras que de Galilea no salen profetas\"."},
    {"Juan", "Jn", 7, 53, "Y se volvieron cada uno a su casa."},
    {"Juan", "Jn", 8, 1, "Por su parte, Jesus se retiro al monte de los Olivos."},
    {"Juan", "Jn", 8, 2, "Al amanecer se presento de nuevo en el templo, y todo el pueblo acudia a el, y, sentandose, les ense\177aba."},
    {"Juan", "Jn", 8, 3, "Los escribas y los fariseos le traen una mujer sorprendida en adulterio, y, colocandola en medio,"},
    {"Juan", "Jn", 8, 4, "le dijeron: \"Maestro, esta mujer ha sido sorprendida en flagrante adulterio."},
    {"Juan", "Jn", 8, 5, "La ley de Moises nos manda apedrear a las adulteras; tu, que dices?\"."},
    {"Juan", "Jn", 8, 6, "Le preguntaban esto para comprometerlo y poder acusarlo. Pero Jesus, inclinandose, escribia con el dedo en el suelo."},
    {"Juan", "Jn", 8, 7, "Como insistian en preguntarle, se incorporo y les dijo: \"El que este sin pecado, que le tire la primera piedra\"."},
    {"Juan", "Jn", 8, 8, "E inclinandose otra vez, siguio escribiendo."},
    {"Juan", "Jn", 8, 9, "Ellos, al oirlo, se fueron escabullendo uno a uno, empezando por los mas viejos. Y quedo solo Jesus, con la mujer en medio, que seguia alli delante."},
    {"Juan", "Jn", 8, 10, "Jesus se incorporo y le pregunto: \"Mujer, donde estan tus acusadores?; ninguno te ha condenado?\"."},
    {"Juan", "Jn", 8, 11, "Ella contesto: \"Ninguno, Se\177or\". Jesus dijo: \"Tampoco yo te condeno. Anda, y en adelante no peques mas\"."},
    {"Juan", "Jn", 8, 12, "Jesus les hablo de nuevo diciendo: \"Yo soy la luz del mundo; el que me sigue no camina en tinieblas, sino que tendra la luz de la vida\"."},
    {"Juan", "Jn", 8, 13, "Le dijeron los fariseos: \"Tu das testimonio de ti mismo; tu testimonio no es verdadero\"."},
    {"Juan", "Jn", 8, 14, "Jesus les contesto: \"Aunque yo doy testimonio de mi mismo, mi testimonio es verdadero, porque se de donde he venido y adonde voy; en cambio, vosotros no sabeis de donde vengo ni adonde voy."},
    {"Juan", "Jn", 8, 15, "Vosotros juzgais segun la carne; yo no juzgo a nadie;"},
    {"Juan", "Jn", 8, 16, "y, si juzgo yo, mi juicio es legitimo, porque no estoy yo solo, sino yo y el que me ha enviado, el Padre;"},
    {"Juan", "Jn", 8, 17, "y en vuestra ley esta escrito que el testimonio de dos hombres es verdadero."},
    {"Juan", "Jn", 8, 18, "Yo doy testimonio de mi mismo, y ademas da testimonio de mi el que me ha enviado, el Padre\"."},
    {"Juan", "Jn", 8, 19, "Ellos le preguntaban: \"Donde esta tu Padre?\". Jesus contesto: \"Ni me conoceis a mi ni a mi Padre; si me conocierais a mi, conoceriais tambien a mi Padre\"."},
    {"Juan", "Jn", 8, 20, "Jesus tuvo esta conversacion junto al arca de las ofrendas, cuando ense\177aba en el templo. Y nadie le echo mano, porque todavia no habia llegado su hora."},
    {"Juan", "Jn", 8, 21, "De nuevo les dijo: \"Yo me voy y me buscareis, y morireis por vuestro pecado. Donde yo voy no podeis venir vosotros\"."},
    {"Juan", "Jn", 8, 22, "Y los judios comentaban: \"Sera que va a suicidarse, y por eso dice: \"Donde yo voy no podeis venir vosotros\"?\"."},
    {"Juan", "Jn", 8, 23, "Y el les dijo: \"Vosotros sois de aqui abajo, yo soy de alla arriba: vosotros sois de este mundo, yo no soy de este mundo."},
    {"Juan", "Jn", 8, 24, "Con razon os he dicho que morireis en vuestros pecados: pues, si no creeis que \"Yo soy\", morireis en vuestros pecados\"."},
    {"Juan", "Jn", 8, 25, "Ellos le decian: \"Quien eres tu?\". Jesus les contesto: \"Lo que os estoy diciendo desde el principio."},
    {"Juan", "Jn", 8, 26, "Podria decir y condenar muchas cosas en vosotros; pero el que me ha enviado es veraz, y yo comunico al mundo lo que he aprendido de el\"."},
    {"Juan", "Jn", 8, 27, "Ellos no comprendieron que les hablaba del Padre."},
    {"Juan", "Jn", 8, 28, "Y entonces dijo Jesus: \"Cuando levanteis en alto al Hijo del hombre, sabreis que \"Yo soy\", y que no hago nada por mi cuenta, sino que hablo como el Padre me ha ense\177ado."},
    {"Juan", "Jn", 8, 29, "El que me envio esta conmigo, no me ha dejado solo; porque yo hago siempre lo que le agrada\"."},
    {"Juan", "Jn", 8, 30, "Cuando les exponia esto, muchos creyeron en el."},
    {"Juan", "Jn", 8, 31, "Dijo Jesus a los judios que habian creido en el: \"Si permaneceis en mi palabra, sereis de verdad discipulos mios;"},
    {"Juan", "Jn", 8, 32, "conocereis la verdad, y la verdad os hara libres\"."},
    {"Juan", "Jn", 8, 33, "Le replicaron: \"Somos linaje de Abrahan y nunca hemos sido esclavos de nadie. Como dices tu: \"Sereis libres\"?\"."},
    {"Juan", "Jn", 8, 34, "Jesus les contesto: \"En verdad, en verdad os digo: todo el que comete pecado es esclavo."},
    {"Juan", "Jn", 8, 35, "El esclavo no se queda en la casa para siempre, el hijo se queda para siempre."},
    {"Juan", "Jn", 8, 36, "Y si el Hijo os hace libres, sereis realmente libres."},
    {"Juan", "Jn", 8, 37, "Ya se que sois linaje de Abrahan; sin embargo, tratais de matarme, porque mi palabra no cala en vosotros."},
    {"Juan", "Jn", 8, 38, "Yo hablo de lo que he visto junto a mi Padre, pero vosotros haceis lo que le habeis oido a vuestro padre\"."},
    {"Juan", "Jn", 8, 39, "Ellos replicaron: \"Nuestro padre es Abrahan\". Jesus les dijo: \"Si fuerais hijos de Abrahan, hariais lo que hizo Abrahan."},
    {"Juan", "Jn", 8, 40, "Sin embargo, tratais de matarme a mi, que os he hablado de la verdad que le escuche a Dios; y eso no lo hizo Abrahan."},
    {"Juan", "Jn", 8, 41, "Vosotros haceis lo que hace vuestro padre\". Le replicaron: \"Nosotros no somos hijos de prostitucion; tenemos un solo padre: Dios\"."},
    {"Juan", "Jn", 8, 42, "Jesus les contesto: \"Si Dios fuera vuestro padre, me amariais, porque yo sali de Dios, y he venido. Pues no he venido por mi cuenta, sino que el me envio."},
    {"Juan", "Jn", 8, 43, "Por que no reconoceis mi lenguaje? Porque no podeis escuchar mi palabra."},
    {"Juan", "Jn", 8, 44, "Vosotros sois de vuestro padre el diablo y quereis cumplir los deseos de vuestro padre. El era homicida desde el principio y no se mantuvo en la verdad porque no hay verdad en el. Cuando dice la mentira, habla de lo suyo porque es mentiroso y padre de la mentira."},
    {"Juan", "Jn", 8, 45, "En cambio, a mi, porque os digo la verdad, no me creeis."},
    {"Juan", "Jn", 8, 46, "Quien de vosotros puede acusarme de pecado? Si digo la verdad, por que no me creeis?"},
    {"Juan", "Jn", 8, 47, "El que es de Dios escucha las palabras de Dios; por eso vosotros no escuchais, porque no sois de Dios\"."},
    {"Juan", "Jn", 8, 48, "Le respondieron los judios: \"No decimos bien nosotros que eres samaritano y que tienes un demonio?\"."},
    {"Juan", "Jn", 8, 49, "Contesto Jesus: \"Yo no tengo demonio, sino que honro a mi Padre y vosotros me deshonrais a mi."},
    {"Juan", "Jn", 8, 50, "Yo no busco mi gloria; hay quien la busca y juzga."},
    {"Juan", "Jn", 8, 51, "En verdad, en verdad os digo: quien guarda mi palabra no vera la muerte para siempre\"."},
    {"Juan", "Jn", 8, 52, "Los judios le dijeron: \"Ahora vemos claro que estas endemoniado; Abrahan murio, los profetas tambien, y tu dices: \"Quien guarde mi palabra no gustara la muerte para siempre\"?"},
    {"Juan", "Jn", 8, 53, "Eres tu mas que nuestro padre Abrahan, que murio? Tambien los profetas murieron, por quien te tienes?\"."},
    {"Juan", "Jn", 8, 54, "Jesus contesto: \"Si yo me glorificara a mi mismo, mi gloria no valdria nada. El que me glorifica es mi Padre, de quien vosotros decis: \"Es nuestro Dios\","},
    {"Juan", "Jn", 8, 55, "aunque no lo conoceis. Yo si lo conozco, y si dijera \"No lo conozco\" seria, como vosotros, un embustero; pero yo lo conozco y guardo su palabra."},
    {"Juan", "Jn", 8, 56, "Abrahan, vuestro padre, saltaba de gozo pensando ver mi dia; lo vio, y se lleno de alegria\"."},
    {"Juan", "Jn", 8, 57, "Los judios le dijeron: \"No tienes todavia cincuenta a\177os, y has visto a Abrahan?\"."},
    {"Juan", "Jn", 8, 58, "Jesus les dijo: \"En verdad, en verdad os digo: antes de que Abrahan existiera, yo soy\"."},
    {"Juan", "Jn", 8, 59, "Entonces cogieron piedras para tirarselas, pero Jesus se escondio y salio del templo."},
    {"Juan", "Jn", 9, 1, "Y al pasar, vio Jesus a un hombre ciego de nacimiento."},
    {"Juan", "Jn", 9, 2, "Y sus discipulos le preguntaron: \"Maestro, quien peco: este o sus padres, para que naciera ciego?\"."},
    {"Juan", "Jn", 9, 3, "Jesus contesto: \"Ni este peco ni sus padres, sino para que se manifiesten en el las obras de Dios."},
    {"Juan", "Jn", 9, 4, "Mientras es de dia tengo que hacer las obras del que me ha enviado: viene la noche y nadie podra hacerlas."},
    {"Juan", "Jn", 9, 5, "Mientras estoy en el mundo, soy la luz del mundo\"."},
    {"Juan", "Jn", 9, 6, "Dicho esto, escupio en la tierra, hizo barro con la saliva, se lo unto en los ojos al ciego,"},
    {"Juan", "Jn", 9, 7, "y le dijo: \"Ve a lavarte a la piscina de Siloe (que significa Enviado)\". El fue, se lavo, y volvio con vista."},
    {"Juan", "Jn", 9, 8, "Y los vecinos y los que antes solian verlo pedir limosna preguntaban: \"No es ese el que se sentaba a pedir?\"."},
    {"Juan", "Jn", 9, 9, "Unos decian: \"El mismo\". Otros decian: \"No es el, pero se le parece\". El respondia: \"Soy yo\"."},
    {"Juan", "Jn", 9, 10, "Y le preguntaban: \"Y como se te han abierto los ojos?\"."},
    {"Juan", "Jn", 9, 11, "El contesto: \"Ese hombre que se llama Jesus hizo barro, me lo unto en los ojos y me dijo que fuese a Siloe y que me lavase. Entonces fui, me lave, y empece a ver\"."},
    {"Juan", "Jn", 9, 12, "Le preguntaron: \"Donde esta el?\". Contesto: \"No lo se\"."},
    {"Juan", "Jn", 9, 13, "Llevaron ante los fariseos al que habia sido ciego."},
    {"Juan", "Jn", 9, 14, "Era sabado el dia que Jesus hizo barro y le abrio los ojos."},
    {"Juan", "Jn", 9, 15, "Tambien los fariseos le preguntaban como habia adquirido la vista. El les contesto: \"Me puso barro en los ojos, me lave y veo\"."},
    {"Juan", "Jn", 9, 16, "Algunos de los fariseos comentaban: \"Este hombre no viene de Dios, porque no guarda el sabado\". Otros replicaban: \"Como puede un pecador hacer semejantes signos?\". Y estaban divididos."},
    {"Juan", "Jn", 9, 17, "Y volvieron a preguntarle al ciego: \"Y tu, que dices del que te ha abierto los ojos?\". El contesto: \"Que es un profeta\"."},
    {"Juan", "Jn", 9, 18, "Pero los judios no se creyeron que aquel habia sido ciego y que habia comenzado a ver, hasta que llamaron a sus padres"},
    {"Juan", "Jn", 9, 19, "y les preguntaron: \"Es este vuestro hijo, de quien decis vosotros que nacio ciego? Como es que ahora ve?\"."},
    {"Juan", "Jn", 9, 20, "Sus padres contestaron: \"Sabemos que este es nuestro hijo y que nacio ciego;"},
    {"Juan", "Jn", 9, 21, "pero como ve ahora, no lo sabemos; y quien le ha abierto los ojos, nosotros tampoco lo sabemos. Preguntadselo a el, que es mayor y puede explicarse\"."},
    {"Juan", "Jn", 9, 22, "Sus padres respondieron asi porque tenian miedo a los judios: porque los judios ya habian acordado excluir de la sinagoga a quien reconociera a Jesus por Mesias."},
    {"Juan", "Jn", 9, 23, "Por eso sus padres dijeron: \"Ya es mayor, preguntadselo a el\"."},
    {"Juan", "Jn", 9, 24, "Llamaron por segunda vez al hombre que habia sido ciego y le dijeron: \"Da gloria a Dios: nosotros sabemos que ese hombre es un pecador\"."},
    {"Juan", "Jn", 9, 25, "Contesto el: \"Si es un pecador, no lo se; solo se que yo era ciego y ahora veo\"."},
    {"Juan", "Jn", 9, 26, "Le preguntan de nuevo: \"Que te hizo, como te abrio los ojos?\"."},
    {"Juan", "Jn", 9, 27, "Les contesto: \"Os lo he dicho ya, y no me habeis hecho caso: para que quereis oirlo otra vez?, tambien vosotros quereis haceros discipulos suyos?\"."},
    {"Juan", "Jn", 9, 28, "Ellos lo llenaron de improperios y le dijeron: \"Discipulo de ese lo seras tu; nosotros somos discipulos de Moises."},
    {"Juan", "Jn", 9, 29, "Nosotros sabemos que a Moises le hablo Dios, pero ese no sabemos de donde viene\"."},
    {"Juan", "Jn", 9, 30, "Replico el: \"Pues eso es lo raro: que vosotros no sabeis de donde viene, y, sin embargo, me ha abierto los ojos."},
    {"Juan", "Jn", 9, 31, "Sabemos que Dios no escucha a los pecadores, sino al que es piadoso y hace su voluntad."},
    {"Juan", "Jn", 9, 32, "Jamas se oyo decir que nadie le abriera los ojos a un ciego de nacimiento;"},
    {"Juan", "Jn", 9, 33, "si este no viniera de Dios, no tendria ningun poder\"."},
    {"Juan", "Jn", 9, 34, "Le replicaron: \"Has nacido completamente empecatado, y nos vas a dar lecciones a nosotros?\". Y lo expulsaron."},
    {"Juan", "Jn", 9, 35, "Oyo Jesus que lo habian expulsado, lo encontro y le dijo: \"Crees tu en el Hijo del hombre?\"."},
    {"Juan", "Jn", 9, 36, "El contesto: \"Y quien es, Se\177or, para que crea en el?\"."},
    {"Juan", "Jn", 9, 37, "Jesus le dijo: \"Lo estas viendo: el que te esta hablando, ese es\"."},
    {"Juan", "Jn", 9, 38, "El dijo: \"Creo, Se\177or\". Y se postro ante el."},
    {"Juan", "Jn", 9, 39, "Dijo Jesus: \"Para un juicio he venido yo a este mundo: para que los que no ven, vean, y los que ven, se queden ciegos\"."},
    {"Juan", "Jn", 9, 40, "Los fariseos que estaban con el oyeron esto y le preguntaron: \"Tambien nosotros estamos ciegos?\"."},
    {"Juan", "Jn", 9, 41, "Jesus les contesto: \"Si estuvierais ciegos, no tendriais pecado; pero como decis \"vemos\", vuestro pecado permanece."},
    {"Juan", "Jn", 10, 1, "En verdad, en verdad os digo: el que no entra por la puerta en el aprisco de las ovejas, sino que salta por otra parte, ese es ladron y bandido;"},
    {"Juan", "Jn", 10, 2, "pero el que entra por la puerta es pastor de las ovejas."},
    {"Juan", "Jn", 10, 3, "A este le abre el guarda y las ovejas atienden a su voz, y el va llamando por el nombre a sus ovejas y las saca fuera."},
    {"Juan", "Jn", 10, 4, "Cuando ha sacado todas las suyas camina delante de ellas, y las ovejas lo siguen, porque conocen su voz:"},
    {"Juan", "Jn", 10, 5, "a un extra\177o no lo seguiran, sino que huiran de el, porque no conocen la voz de los extra\177os\"."},
    {"Juan", "Jn", 10, 6, "Jesus les puso esta comparacion, pero ellos no entendieron de que les hablaba."},
    {"Juan", "Jn", 10, 7, "Por eso a\177adio Jesus: \"En verdad, en verdad os digo: yo soy la puerta de las ovejas."},
    {"Juan", "Jn", 10, 8, "Todos los que han venido antes de mi son ladrones y bandidos; pero las ovejas no los escucharon."},
    {"Juan", "Jn", 10, 9, "Yo soy la puerta: quien entre por mi se salvara y podra entrar y salir, y encontrara pastos."},
    {"Juan", "Jn", 10, 10, "El ladron no entra sino para robar y matar y hacer estragos; yo he venido para que tengan vida y la tengan abundante."},
    {"Juan", "Jn", 10, 11, "Yo soy el Buen Pastor. El buen pastor da su vida por las ovejas;"},
    {"Juan", "Jn", 10, 12, "el asalariado, que no es pastor ni due\177o de las ovejas, ve venir al lobo, abandona las ovejas y huye; y el lobo las roba y las dispersa;"},
    {"Juan", "Jn", 10, 13, "y es que a un asalariado no le importan las ovejas."},
    {"Juan", "Jn", 10, 14, "Yo soy el Buen Pastor, que conozco a las mias, y las mias me conocen,"},
    {"Juan", "Jn", 10, 15, "igual que el Padre me conoce, y yo conozco al Padre; yo doy mi vida por las ovejas."},
    {"Juan", "Jn", 10, 16, "Tengo, ademas, otras ovejas que no son de este redil; tambien a esas las tengo que traer, y escucharan mi voz, y habra un solo reba\177o y un solo Pastor."},
    {"Juan", "Jn", 10, 17, "Por esto me ama el Padre, porque yo entrego mi vida para poder recuperarla."},
    {"Juan", "Jn", 10, 18, "Nadie me la quita, sino que yo la entrego libremente. Tengo poder para entregarla y tengo poder para recuperarla: este mandato he recibido de mi Padre\"."},
    {"Juan", "Jn", 10, 19, "De nuevo se produjo una escision entre los judios por causa de estas palabras."},
    {"Juan", "Jn", 10, 20, "Muchos de ellos decian: \"Tiene un demonio y esta loco, por que lo escuchais?\"."},
    {"Juan", "Jn", 10, 21, "Otros decian: \"Estas no son palabras de un endemoniado; como puede un demonio abrir los ojos a los ciegos?\"."},
    {"Juan", "Jn", 10, 22, "Se celebraba entonces en Jerusalen la fiesta de la Dedicacion del templo. Era invierno,"},
    {"Juan", "Jn", 10, 23, "y Jesus se paseaba en el templo por el portico de Salomon."},
    {"Juan", "Jn", 10, 24, "Los judios, rodeandolo, le preguntaban: \"Hasta cuando nos vas a tener en suspenso? Si tu eres el Mesias, dinoslo francamente\"."},
    {"Juan", "Jn", 10, 25, "Jesus les respondio: \"Os lo he dicho, y no creeis; las obras que yo hago en nombre de mi Padre, esas dan testimonio de mi."},
    {"Juan", "Jn", 10, 26, "Pero vosotros no creeis, porque no sois de mis ovejas."},
    {"Juan", "Jn", 10, 27, "Mis ovejas escuchan mi voz, y yo las conozco, y ellas me siguen,"},
    {"Juan", "Jn", 10, 28, "y yo les doy la vida eterna; no pereceran para siempre, y nadie las arrebatara de mi mano."},
    {"Juan", "Jn", 10, 29, "Lo que mi Padre me ha dado es mas que todas las cosas, y nadie puede arrebatar nada de la mano de mi Padre."},
    {"Juan", "Jn", 10, 30, "Yo y el Padre somos uno\"."},
    {"Juan", "Jn", 10, 31, "Los judios agarraron de nuevo piedras para apedrearlo."},
    {"Juan", "Jn", 10, 32, "Jesus les replico: \"Os he hecho ver muchas obras buenas por encargo de mi Padre: por cual de ellas me apedreais?\"."},
    {"Juan", "Jn", 10, 33, "Los judios le contestaron: \"No te apedreamos por una obra buena, sino por una blasfemia: porque tu, siendo un hombre, te haces Dios\"."},
    {"Juan", "Jn", 10, 34, "Jesus les replico: \"No esta escrito en vuestra ley: \"Yo os digo: sois dioses\"?"},
    {"Juan", "Jn", 10, 35, "Si la Escritura llama dioses a aquellos a quienes vino la palabra de Dios, y no puede fallar la Escritura,"},
    {"Juan", "Jn", 10, 36, "a quien el Padre consagro y envio al mundo, decis vosotros: \"Blasfemas!\" Porque he dicho: \"Soy Hijo de Dios\"?"},
    {"Juan", "Jn", 10, 37, "Si no hago las obras de mi Padre, no me creais,"},
    {"Juan", "Jn", 10, 38, "pero si las hago, aunque no me creais a mi, creed a las obras, para que comprendais y sepais que el Padre esta en mi, y yo en el Padre\"."},
    {"Juan", "Jn", 10, 39, "Intentaron de nuevo detenerlo, pero se les escabullo de las manos."},
    {"Juan", "Jn", 10, 40, "Se marcho de nuevo al otro lado del Jordan, al lugar donde antes habia bautizado Juan, y se quedo alli."},
    {"Juan", "Jn", 10, 41, "Muchos acudieron a el y decian: \"Juan no hizo ningun signo; pero todo lo que Juan dijo de este era verdad\"."},
    {"Juan", "Jn", 10, 42, "Y muchos creyeron en el alli."},
    {"Juan", "Jn", 11, 1, "Habia caido enfermo un cierto Lazaro, de Betania, la aldea de Maria y de Marta, su hermana."},
    {"Juan", "Jn", 11, 2, "Maria era la que ungio al Se\177or con perfume y le enjugo los pies con su cabellera; el enfermo era su hermano Lazaro."},
    {"Juan", "Jn", 11, 3, "Las hermanas le mandaron recado a Jesus diciendo: \"Se\177or, el que tu amas esta enfermo\"."},
    {"Juan", "Jn", 11, 4, "Jesus, al oirlo, dijo: \"Esta enfermedad no es para la muerte, sino que servira para la gloria de Dios, para que el Hijo de Dios sea glorificado por ella\"."},
    {"Juan", "Jn", 11, 5, "Jesus amaba a Marta, a su hermana y a Lazaro."},
    {"Juan", "Jn", 11, 6, "Cuando se entero de que estaba enfermo se quedo todavia dos dias donde estaba."},
    {"Juan", "Jn", 11, 7, "Solo entonces dijo a sus discipulos: \"Vamos otra vez a Judea\"."},
    {"Juan", "Jn", 11, 8, "Los discipulos le replicaron: \"Maestro, hace poco intentaban apedrearte los judios, y vas a volver de nuevo alli?\"."},
    {"Juan", "Jn", 11, 9, "Jesus contesto: \"No tiene el dia doce horas? Si uno camina de dia no tropieza, porque ve la luz de este mundo;"},
    {"Juan", "Jn", 11, 10, "pero si camina de noche tropieza, porque la luz no esta en el\"."},
    {"Juan", "Jn", 11, 11, "Dicho esto, a\177adio: \"Lazaro, nuestro amigo, esta dormido: voy a despertarlo\"."},
    {"Juan", "Jn", 11, 12, "Entonces le dijeron sus discipulos: \"Se\177or, si duerme, se salvara\"."},
    {"Juan", "Jn", 11, 13, "Jesus se referia a su muerte; en cambio, ellos creyeron que hablaba del sue\177o natural."},
    {"Juan", "Jn", 11, 14, "Entonces Jesus les replico claramente: \"Lazaro ha muerto,"},
    {"Juan", "Jn", 11, 15, "y me alegro por vosotros de que no hayamos estado alli, para que creais. Y ahora vamos a su encuentro\"."},
    {"Juan", "Jn", 11, 16, "Entonces Tomas, apodado el Mellizo, dijo a los demas discipulos: \"Vamos tambien nosotros y muramos con el\"."},
    {"Juan", "Jn", 11, 17, "Cuando Jesus llego, Lazaro llevaba ya cuatro dias enterrado."},
    {"Juan", "Jn", 11, 18, "Betania distaba poco de Jerusalen: unos quince estadios;"},
    {"Juan", "Jn", 11, 19, "y muchos judios habian ido a ver a Marta y a Maria para darles el pesame por su hermano."},
    {"Juan", "Jn", 11, 20, "Cuando Marta se entero de que llegaba Jesus, salio a su encuentro, mientras Maria se quedo en casa."},
    {"Juan", "Jn", 11, 21, "Y dijo Marta a Jesus: \"Se\177or, si hubieras estado aqui no habria muerto mi hermano."},
    {"Juan", "Jn", 11, 22, "Pero aun ahora se que todo lo que pidas a Dios, Dios te lo concedera\"."},
    {"Juan", "Jn", 11, 23, "Jesus le dijo: \"Tu hermano resucitara\"."},
    {"Juan", "Jn", 11, 24, "Marta respondio: \"Se que resucitara en la resurreccion en el ultimo dia\"."},
    {"Juan", "Jn", 11, 25, "Jesus le dijo: \"Yo soy la resurreccion y la vida: el que cree en mi, aunque haya muerto, vivira;"},
    {"Juan", "Jn", 11, 26, "y el que esta vivo y cree en mi, no morira para siempre. Crees esto?\"."},
    {"Juan", "Jn", 11, 27, "Ella le contesto: \"Si, Se\177or: yo creo que tu eres el Cristo, el Hijo de Dios, el que tenia que venir al mundo\"."},
    {"Juan", "Jn", 11, 28, "Y dicho esto, fue a llamar a su hermana Maria, diciendole en voz baja: \"El Maestro esta ahi y te llama\"."},
    {"Juan", "Jn", 11, 29, "Apenas lo oyo, se levanto y salio adonde estaba el:"},
    {"Juan", "Jn", 11, 30, "porque Jesus no habia entrado todavia en la aldea, sino que estaba aun donde Marta lo habia encontrado."},
    {"Juan", "Jn", 11, 31, "Los judios que estaban con ella en casa consolandola, al ver que Maria se levantaba y salia deprisa, la siguieron, pensando que iba al sepulcro a llorar alli."},
    {"Juan", "Jn", 11, 32, "Cuando llego Maria adonde estaba Jesus, al verlo se echo a sus pies diciendole: \"Se\177or, si hubieras estado aqui no habria muerto mi hermano\"."},
    {"Juan", "Jn", 11, 33, "Jesus, viendola llorar a ella y viendo llorar a los judios que la acompa\177aban, se conmovio en su espiritu, se estremecio"},
    {"Juan", "Jn", 11, 34, "y pregunto: \"Donde lo habeis enterrado?\". Le contestaron: \"Se\177or, ven a verlo\"."},
    {"Juan", "Jn", 11, 35, "Jesus se echo a llorar."},
    {"Juan", "Jn", 11, 36, "Los judios comentaban: \"Como lo queria!\"."},
    {"Juan", "Jn", 11, 37, "Pero algunos dijeron: \"Y uno que le ha abierto los ojos a un ciego, no podia haber impedido que este muriera?\"."},
    {"Juan", "Jn", 11, 38, "Jesus, conmovido de nuevo en su interior, llego a la tumba. Era una cavidad cubierta con una losa."},
    {"Juan", "Jn", 11, 39, "Dijo Jesus: \"Quitad la losa\". Marta, la hermana del muerto, le dijo: \"Se\177or, ya huele mal porque lleva cuatro dias\"."},
    {"Juan", "Jn", 11, 40, "Jesus le replico: \"No te he dicho que si crees veras la gloria de Dios?\"."},
    {"Juan", "Jn", 11, 41, "Entonces quitaron la losa. Jesus, levantando los ojos a lo alto, dijo: \"Padre, te doy gracias porque me has escuchado;"},
    {"Juan", "Jn", 11, 42, "yo se que tu me escuchas siempre; pero lo digo por la gente que me rodea, para que crean que tu me has enviado\"."},
    {"Juan", "Jn", 11, 43, "Y dicho esto, grito con voz potente: \"Lazaro, sal afuera\"."},
    {"Juan", "Jn", 11, 44, "El muerto salio, los pies y las manos atados con vendas, y la cara envuelta en un sudario. Jesus les dijo: \"Desatadlo y dejadlo andar\"."},
    {"Juan", "Jn", 11, 45, "Y muchos judios que habian venido a casa de Maria, al ver lo que habia hecho Jesus, creyeron en el."},
    {"Juan", "Jn", 11, 46, "Pero algunos acudieron a los fariseos y les contaron lo que habia hecho Jesus."},
    {"Juan", "Jn", 11, 47, "Los sumos sacerdotes y los fariseos convocaron el Sanedrin y dijeron: \"Que hacemos? Este hombre hace muchos signos."},
    {"Juan", "Jn", 11, 48, "Si lo dejamos seguir, todos creeran en el, y vendran los romanos y nos destruiran el lugar santo y la nacion\"."},
    {"Juan", "Jn", 11, 49, "Uno de ellos, Caifas, que era sumo sacerdote aquel a\177o, les dijo: \"Vosotros no entendeis ni palabra;"},
    {"Juan", "Jn", 11, 50, "no comprendeis que os conviene que uno muera por el pueblo, y que no perezca la nacion entera\"."},
    {"Juan", "Jn", 11, 51, "Esto no lo dijo por propio impulso, sino que, por ser sumo sacerdote aquel a\177o, hablo profeticamente, anunciando que Jesus iba a morir por la nacion;"},
    {"Juan", "Jn", 11, 52, "y no solo por la nacion, sino tambien para reunir a los hijos de Dios dispersos."},
    {"Juan", "Jn", 11, 53, "Y aquel dia decidieron darle muerte."},
    {"Juan", "Jn", 11, 54, "Por eso Jesus ya no andaba publicamente entre los judios, sino que se retiro a la region vecina al desierto, a una ciudad llamada Efrain, y pasaba alli el tiempo con los discipulos."},
    {"Juan", "Jn", 11, 55, "Se acercaba la Pascua de los judios, y muchos de aquella region subian a Jerusalen, antes de la Pascua, para purificarse."},
    {"Juan", "Jn", 11, 56, "Buscaban a Jesus y, estando en el templo, se preguntaban: \"Que os parece? Vendra a la fiesta?\"."},
    {"Juan", "Jn", 11, 57, "Los sumos sacerdotes y fariseos habian mandado que el que se enterase de donde estaba les avisara para prenderlo."},
    {"Juan", "Jn", 12, 1, "Seis dias antes de la Pascua, fue Jesus a Betania, donde vivia Lazaro, a quien habia resucitado de entre los muertos."},
    {"Juan", "Jn", 12, 2, "Alli le ofrecieron una cena; Marta servia, y Lazaro era uno de los que estaban con el a la mesa."},
    {"Juan", "Jn", 12, 3, "Maria tomo una libra de perfume de nardo, autentico y costoso, le ungio a Jesus los pies y se los enjugo con su cabellera. Y la casa se lleno de la fragancia del perfume."},
    {"Juan", "Jn", 12, 4, "Judas Iscariote, uno de sus discipulos, el que lo iba a entregar, dice:"},
    {"Juan", "Jn", 12, 5, "\"Por que no se ha vendido este perfume por trescientos denarios para darselos a los pobres?\"."},
    {"Juan", "Jn", 12, 6, "Esto lo dijo no porque le importasen los pobres, sino porque era un ladron; y como tenia la bolsa, se llevaba de lo que iban echando."},
    {"Juan", "Jn", 12, 7, "Jesus dijo: \"Dejala; lo tenia guardado para el dia de mi sepultura;"},
    {"Juan", "Jn", 12, 8, "porque a los pobres los teneis siempre con vosotros, pero a mi no siempre me teneis\"."},
    {"Juan", "Jn", 12, 9, "Una muchedumbre de judios se entero de que estaba alli y fueron no solo por Jesus, sino tambien para ver a Lazaro, al que habia resucitado de entre los muertos."},
    {"Juan", "Jn", 12, 10, "Los sumos sacerdotes decidieron matar tambien a Lazaro,"},
    {"Juan", "Jn", 12, 11, "porque muchos judios, por su causa, se les iban y creian en Jesus."},
    {"Juan", "Jn", 12, 12, "Al dia siguiente, la gran multitud de gente que habia venido a la fiesta, al oir que Jesus venia a Jerusalen,"},
    {"Juan", "Jn", 12, 13, "tomaron ramos de palmeras y salieron a su encuentro gritando: \"Hosanna! Bendito el que viene en nombre del Se\177or, el Rey de Israel\"."},
    {"Juan", "Jn", 12, 14, "Encontrando Jesus un pollino monto sobre el, como esta escrito:"},
    {"Juan", "Jn", 12, 15, "\"No temas, hija de Sion; he aqui que viene tu Rey, sentado sobre un pollino de asna\"."},
    {"Juan", "Jn", 12, 16, "Estas cosas no las comprendieron sus discipulos al principio, pero cuando Jesus fue glorificado, entonces se acordaron de que esto estaba escrito acerca de el y que asi lo habian hecho para con el."},
    {"Juan", "Jn", 12, 17, "Entre la gente que daba testimonio se encontraban los que habian estado con el cuando llamo a Lazaro del sepulcro y lo resucito de entre los muertos."},
    {"Juan", "Jn", 12, 18, "Por esto, tambien le salio al encuentro la muchedumbre porque habian oido que el habia hecho este signo."},
    {"Juan", "Jn", 12, 19, "Por su parte, los fariseos se dijeron a si mismos: \"Veis que no adelantais nada. He aqui que todo el mundo le sigue\"."},
    {"Juan", "Jn", 12, 20, "Entre los que habian venido a celebrar la fiesta habia algunos griegos;"},
    {"Juan", "Jn", 12, 21, "estos, acercandose a Felipe, el de Betsaida de Galilea, le rogaban: \"Se\177or, queremos ver a Jesus\"."},
    {"Juan", "Jn", 12, 22, "Felipe fue a decirselo a Andres; y Andres y Felipe fueron a decirselo a Jesus."},
    {"Juan", "Jn", 12, 23, "Jesus les contesto: \"Ha llegado la hora de que sea glorificado el Hijo del hombre."},
    {"Juan", "Jn", 12, 24, "En verdad, en verdad os digo: si el grano de trigo no cae en tierra y muere, queda infecundo; pero si muere, da mucho fruto."},
    {"Juan", "Jn", 12, 25, "El que se ama a si mismo, se pierde, y el que se aborrece a si mismo en este mundo, se guardara para la vida eterna."},
    {"Juan", "Jn", 12, 26, "El que quiera servirme, que me siga, y donde este yo, alli tambien estara mi servidor; a quien me sirva, el Padre lo honrara."},
    {"Juan", "Jn", 12, 27, "Ahora mi alma esta agitada, y que dire? Padre, librame de esta hora? Pero si por esto he venido, para esta hora:"},
    {"Juan", "Jn", 12, 28, "Padre, glorifica tu nombre\". Entonces vino una voz del cielo: \"Lo he glorificado y volvere a glorificarlo\"."},
    {"Juan", "Jn", 12, 29, "La gente que estaba alli y lo oyo, decia que habia sido un trueno; otros decian que le habia hablado un angel."},
    {"Juan", "Jn", 12, 30, "Jesus tomo la palabra y dijo: \"Esta voz no ha venido por mi, sino por vosotros."},
    {"Juan", "Jn", 12, 31, "Ahora va a ser juzgado el mundo; ahora el principe de este mundo va a ser echado fuera."},
    {"Juan", "Jn", 12, 32, "Y cuando yo sea elevado sobre la tierra, atraere a todos hacia mi\"."},
    {"Juan", "Jn", 12, 33, "Esto lo decia dando a entender la muerte de que iba a morir."},
    {"Juan", "Jn", 12, 34, "La gente le replico: \"La Escritura nos dice que el Mesias permanecera para siempre; como dices tu que el Hijo del hombre tiene que ser levantado en alto? Quien es ese Hijo de hombre?\"."},
    {"Juan", "Jn", 12, 35, "Jesus les contesto: \"Todavia os queda un poco de luz; caminad mientras teneis luz, antes de que os sorprendan las tinieblas. El que camina en tinieblas no sabe adonde va;"},
    {"Juan", "Jn", 12, 36, "mientras hay luz, creed en la luz, para que seais hijos de la luz\". Esto dijo Jesus y se fue y se escondio de ellos."},
    {"Juan", "Jn", 12, 37, "Habiendo hecho tantos signos delante de ellos, no creian en el"},
    {"Juan", "Jn", 12, 38, "para que se cumpliera el oraculo de Isaias que dijo: \"Se\177or, quien ha creido nuestro anuncio? y el brazo del Se\177or a quien ha sido revelado?\"."},
    {"Juan", "Jn", 12, 39, "Por ello no podian creer, porque de nuevo dijo Isaias:"},
    {"Juan", "Jn", 12, 40, "\"Ha cegado sus ojos y ha endurecido sus corazones, para que no vean con sus ojos y entiendan en su corazon y se conviertan y yo los cure\"."},
    {"Juan", "Jn", 12, 41, "Esto dijo Isaias cuando vio su gloria y hablo acerca de el."},
    {"Juan", "Jn", 12, 42, "Sin embargo, incluso muchos de los principales creyeron en el, pero, a causa de los fariseos, no lo confesaban publicamente para no ser expulsados de la sinagoga,"},
    {"Juan", "Jn", 12, 43, "pues prefirieron la gloria de los hombres a la gloria de Dios."},
    {"Juan", "Jn", 12, 44, "Jesus grito diciendo: \"El que cree en mi, no cree en mi, sino en el que me ha enviado."},
    {"Juan", "Jn", 12, 45, "Y el que me ve a mi, ve al que me ha enviado."},
    {"Juan", "Jn", 12, 46, "Yo he venido al mundo como luz, y asi, el que cree en mi no quedara en tinieblas."},
    {"Juan", "Jn", 12, 47, "Al que oiga mis palabras y no las cumpla, yo no lo juzgo, porque no he venido para juzgar al mundo, sino para salvar al mundo."},
    {"Juan", "Jn", 12, 48, "El que me rechaza y no acepta mis palabras tiene quien lo juzgue: la palabra que yo he pronunciado, esa lo juzgara en el ultimo dia."},
    {"Juan", "Jn", 12, 49, "Porque yo no he hablado por cuenta mia; el Padre que me envio es quien me ha ordenado lo que he de decir y como he de hablar."},
    {"Juan", "Jn", 12, 50, "Y se que su mandato es vida eterna. Por tanto, lo que yo hablo, lo hablo como me ha encargado el Padre\"."},
    {"Juan", "Jn", 13, 1, "Antes de la fiesta de la Pascua, sabiendo Jesus que habia llegado su hora de pasar de este mundo al Padre, habiendo amado a los suyos que estaban en el mundo, los amo hasta el extremo."},
    {"Juan", "Jn", 13, 2, "Estaban cenando; ya el diablo habia suscitado en el corazon de Judas, hijo de Simon Iscariote, la intencion de entregarlo;"},
    {"Juan", "Jn", 13, 3, "y Jesus, sabiendo que el Padre habia puesto todo en sus manos, que venia de Dios y a Dios volvia,"},
    {"Juan", "Jn", 13, 4, "se levanta de la cena, se quita el manto y, tomando una toalla, se la ci\177e;"},
    {"Juan", "Jn", 13, 5, "luego echa agua en la jofaina y se pone a lavarles los pies a los discipulos, secandoselos con la toalla que se habia ce\177ido."},
    {"Juan", "Jn", 13, 6, "Llego a Simon Pedro y este le dice: \"Se\177or, lavarme los pies tu a mi?\"."},
    {"Juan", "Jn", 13, 7, "Jesus le replico: \"Lo que yo hago, tu no lo entiendes ahora, pero lo comprenderas mas tarde\"."},
    {"Juan", "Jn", 13, 8, "Pedro le dice: \"No me lavaras los pies jamas\". Jesus le contesto: \"Si no te lavo, no tienes parte conmigo\"."},
    {"Juan", "Jn", 13, 9, "Simon Pedro le dice: \"Se\177or, no solo los pies, sino tambien las manos y la cabeza\"."},
    {"Juan", "Jn", 13, 10, "Jesus le dice: \"Uno que se ha ba\177ado no necesita lavarse mas que los pies, porque todo el esta limpio. Tambien vosotros estais limpios, aunque no todos\"."},
    {"Juan", "Jn", 13, 11, "Porque sabia quien lo iba a entregar, por eso dijo: \"No todos estais limpios\"."},
    {"Juan", "Jn", 13, 12, "Cuando acabo de lavarles los pies, tomo el manto, se lo puso otra vez y les dijo: \"Comprendeis lo que he hecho con vosotros?"},
    {"Juan", "Jn", 13, 13, "Vosotros me llamais \"el Maestro\" y \"el Se\177or\", y decis bien, porque lo soy."},
    {"Juan", "Jn", 13, 14, "Pues si yo, el Maestro y el Se\177or, os he lavado los pies, tambien vosotros debeis lavaros los pies unos a otros:"},
    {"Juan", "Jn", 13, 15, "os he dado ejemplo para que lo que yo he hecho con vosotros, vosotros tambien lo hagais."},
    {"Juan", "Jn", 13, 16, "En verdad, en verdad os digo: el criado no es mas que su amo, ni el enviado es mas que el que lo envia."},
    {"Juan", "Jn", 13, 17, "Puesto que sabeis esto, dichosos vosotros si lo poneis en practica."},
    {"Juan", "Jn", 13, 18, "No lo digo por todos vosotros; yo se bien a quienes he elegido, pero tiene que cumplirse la Escritura: \"El que compartia mi pan me ha traicionado\"."},
    {"Juan", "Jn", 13, 19, "Os lo digo ahora, antes de que suceda, para que cuando suceda creais que yo soy."},
    {"Juan", "Jn", 13, 20, "En verdad, en verdad os digo: el que recibe a quien yo envie me recibe a mi; y el que me recibe a mi recibe al que me ha enviado\"."},
    {"Juan", "Jn", 13, 21, "Diciendo esto, Jesus se turbo en su espiritu y dio testimonio diciendo: \"En verdad, en verdad os digo: uno de vosotros me va a entregar\"."},
    {"Juan", "Jn", 13, 22, "Los discipulos se miraron unos a otros perplejos, por no saber de quien lo decia."},
    {"Juan", "Jn", 13, 23, "Uno de ellos, el que Jesus amaba, estaba reclinado a la mesa en el seno de Jesus."},
    {"Juan", "Jn", 13, 24, "Simon Pedro le hizo se\177as para que averiguase por quien lo decia."},
    {"Juan", "Jn", 13, 25, "Entonces el, apoyandose en el pecho de Jesus, le pregunto: \"Se\177or, quien es?\"."},
    {"Juan", "Jn", 13, 26, "Le contesto Jesus: \"Aquel a quien yo le de este trozo de pan untado\". Y, untando el pan, se lo dio a Judas, hijo de Simon el Iscariote."},
    {"Juan", "Jn", 13, 27, "Detras del pan, entro en el Satanas. Entonces Jesus le dijo: \"Lo que vas a hacer, hazlo pronto\"."},
    {"Juan", "Jn", 13, 28, "Ninguno de los comensales entendio a que se referia."},
    {"Juan", "Jn", 13, 29, "Como Judas guardaba la bolsa, algunos suponian que Jesus le encargaba comprar lo necesario para la fiesta o dar algo a los pobres."},
    {"Juan", "Jn", 13, 30, "Judas, despues de tomar el pan, salio inmediatamente. Era de noche."},
    {"Juan", "Jn", 13, 31, "Cuando salio, dijo Jesus: \"Ahora es glorificado el Hijo del hombre, y Dios es glorificado en el."},
    {"Juan", "Jn", 13, 32, "Si Dios es glorificado en el, tambien Dios lo glorificara en si mismo: pronto lo glorificara."},
    {"Juan", "Jn", 13, 33, "Hijitos, me queda poco de estar con vosotros. Me buscareis, pero lo que dije a los judios os lo digo ahora a vosotros: \"Donde yo voy no podeis venir vosotros\"."},
    {"Juan", "Jn", 13, 34, "Os doy un mandamiento nuevo: que os ameis unos a otros; como yo os he amado, amaos tambien unos a otros."},
    {"Juan", "Jn", 13, 35, "En esto conoceran todos que sois discipulos mios: si os amais unos a otros\"."},
    {"Juan", "Jn", 13, 36, "Simon Pedro le dijo: \"Se\177or, adonde vas?\". Jesus le respondio: \"Adonde yo voy no me puedes seguir ahora, me seguiras mas tarde\"."},
    {"Juan", "Jn", 13, 37, "Pedro replico: \"Se\177or, por que no puedo seguirte ahora? Dare mi vida por ti\"."},
    {"Juan", "Jn", 13, 38, "Jesus le contesto: \"Conque daras tu vida por mi? En verdad, en verdad te digo: no cantara el gallo antes de que me hayas negado tres veces."},
    {"Juan", "Jn", 14, 1, "No se turbe vuestro corazon, creed en Dios y creed tambien en mi."},
    {"Juan", "Jn", 14, 2, "En la casa de mi Padre hay muchas moradas; si no, os lo habria dicho, porque me voy a prepararos un lugar."},
    {"Juan", "Jn", 14, 3, "Cuando vaya y os prepare un lugar, volvere y os llevare conmigo, para que donde estoy yo esteis tambien vosotros."},
    {"Juan", "Jn", 14, 4, "Y adonde yo voy, ya sabeis el camino\"."},
    {"Juan", "Jn", 14, 5, "Tomas le dice: \"Se\177or, no sabemos adonde vas, como podemos saber el camino?\"."},
    {"Juan", "Jn", 14, 6, "Jesus le responde: \"Yo soy el camino y la verdad y la vida. Nadie va al Padre sino por mi."},
    {"Juan", "Jn", 14, 7, "Si me conocierais a mi, conoceriais tambien a mi Padre. Ahora ya lo conoceis y lo habeis visto\"."},
    {"Juan", "Jn", 14, 8, "Felipe le dice: \"Se\177or, muestranos al Padre y nos basta\"."},
    {"Juan", "Jn", 14, 9, "Jesus le replica: \"Hace tanto que estoy con vosotros, y no me conoces, Felipe? Quien me ha visto a mi ha visto al Padre. Como dices tu: \"Muestranos al Padre\"?"},
    {"Juan", "Jn", 14, 10, "No crees que yo estoy en el Padre, y el Padre en mi? Lo que yo os digo no lo hablo por cuenta propia. El Padre, que permanece en mi, el mismo hace las obras."},
    {"Juan", "Jn", 14, 11, "Creedme: yo estoy en el Padre y el Padre en mi. Si no, creed a las obras."},
    {"Juan", "Jn", 14, 12, "En verdad, en verdad os digo: el que cree en mi, tambien el hara las obras que yo hago, y aun mayores, porque yo me voy al Padre."},
    {"Juan", "Jn", 14, 13, "Y lo que pidais en mi nombre, yo lo hare, para que el Padre sea glorificado en el Hijo."},
    {"Juan", "Jn", 14, 14, "Si me pedis algo en mi nombre, yo lo hare."},
    {"Juan", "Jn", 14, 15, "Si me amais, guardareis mis mandamientos."},
    {"Juan", "Jn", 14, 16, "Y yo le pedire al Padre que os de otro Paraclito, que este siempre con vosotros,"},
    {"Juan", "Jn", 14, 17, "el Espiritu de la verdad. El mundo no puede recibirlo, porque no lo ve ni lo conoce; vosotros, en cambio, lo conoceis, porque mora con vosotros y esta en vosotros."},
    {"Juan", "Jn", 14, 18, "No os dejare huerfanos, volvere a vosotros."},
    {"Juan", "Jn", 14, 19, "Dentro de poco el mundo no me vera, pero vosotros me vereis y vivireis, porque yo sigo viviendo."},
    {"Juan", "Jn", 14, 20, "Entonces sabreis que yo estoy en mi Padre, y vosotros en mi y yo en vosotros."},
    {"Juan", "Jn", 14, 21, "El que acepta mis mandamientos y los guarda, ese me ama; y el que me ama sera amado por mi Padre, y yo tambien lo amare y me manifestare a el\"."},
    {"Juan", "Jn", 14, 22, "Le dijo Judas, no el Iscariote: \"Se\177or, que ha sucedido para que te reveles a nosotros y no al mundo?\"."},
    {"Juan", "Jn", 14, 23, "Respondio Jesus y le dijo: \"El que me ama guardara mi palabra, y mi Padre lo amara, y vendremos a el y haremos morada en el."},
    {"Juan", "Jn", 14, 24, "El que no me ama no guarda mis palabras. Y la palabra que estais oyendo no es mia, sino del Padre que me envio."},
    {"Juan", "Jn", 14, 25, "Os he hablado de esto ahora que estoy a vuestro lado,"},
    {"Juan", "Jn", 14, 26, "pero el Paraclito, el Espiritu Santo, que enviara el Padre en mi nombre, sera quien os lo ense\177e todo y os vaya recordando todo lo que os he dicho."},
    {"Juan", "Jn", 14, 27, "La paz os dejo, mi paz os doy; no os la doy yo como la da el mundo. Que no se turbe vuestro corazon ni se acobarde."},
    {"Juan", "Jn", 14, 28, "Me habeis oido decir: \"Me voy y vuelvo a vuestro lado\". Si me amarais, os alegrariais de que vaya al Padre, porque el Padre es mayor que yo."},
    {"Juan", "Jn", 14, 29, "Os lo he dicho ahora, antes de que suceda, para que cuando suceda creais."},
    {"Juan", "Jn", 14, 30, "Ya no hablare mucho con vosotros, pues se acerca el principe de este mundo; no es que el tenga poder sobre mi,"},
    {"Juan", "Jn", 14, 31, "pero es necesario que el mundo comprenda que yo amo al Padre, y que, como el Padre me ha ordenado, asi actuo. Levantaos, vamonos de aqui."},
    {"Juan", "Jn", 15, 1, "Yo soy la verdadera vid, y mi Padre es el labrador."},
    {"Juan", "Jn", 15, 2, "A todo sarmiento que no da fruto en mi lo arranca, y a todo el que da fruto lo poda, para que de mas fruto."},
    {"Juan", "Jn", 15, 3, "Vosotros ya estais limpios por la palabra que os he hablado;"},
    {"Juan", "Jn", 15, 4, "permaneced en mi, y yo en vosotros. Como el sarmiento no puede dar fruto por si, si no permanece en la vid, asi tampoco vosotros, si no permaneceis en mi."},
    {"Juan", "Jn", 15, 5, "Yo soy la vid, vosotros los sarmientos; el que permanece en mi y yo en el, ese da fruto abundante; porque sin mi no podeis hacer nada."},
    {"Juan", "Jn", 15, 6, "Al que no permanece en mi lo tiran fuera, como el sarmiento, y se seca; luego los recogen y los echan al fuego, y arden."},
    {"Juan", "Jn", 15, 7, "Si permaneceis en mi y mis palabras permanecen en vosotros, pedid lo que deseais, y se realizara."},
    {"Juan", "Jn", 15, 8, "Con esto recibe gloria mi Padre, con que deis fruto abundante; asi sereis discipulos mios."},
    {"Juan", "Jn", 15, 9, "Como el Padre me ha amado, asi os he amado yo; permaneced en mi amor."},
    {"Juan", "Jn", 15, 10, "Si guardais mis mandamientos, permanecereis en mi amor; lo mismo que yo he guardado los mandamientos de mi Padre y permanezco en su amor."},
    {"Juan", "Jn", 15, 11, "Os he hablado de esto para que mi alegria este en vosotros, y vuestra alegria llegue a plenitud."},
    {"Juan", "Jn", 15, 12, "Este es mi mandamiento: que os ameis unos a otros como yo os he amado."},
    {"Juan", "Jn", 15, 13, "Nadie tiene amor mas grande que el que da la vida por sus amigos."},
    {"Juan", "Jn", 15, 14, "Vosotros sois mis amigos si haceis lo que yo os mando."},
    {"Juan", "Jn", 15, 15, "Ya no os llamo siervos, porque el siervo no sabe lo que hace su se\177or: a vosotros os llamo amigos, porque todo lo que he oido a mi Padre os lo he dado a conocer."},
    {"Juan", "Jn", 15, 16, "No sois vosotros los que me habeis elegido, soy yo quien os he elegido y os he destinado para que vayais y deis fruto, y vuestro fruto permanezca. De modo que lo que pidais al Padre en mi nombre os lo de."},
    {"Juan", "Jn", 15, 17, "Esto os mando: que os ameis unos a otros."},
    {"Juan", "Jn", 15, 18, "Si el mundo os odia, sabed que me ha odiado a mi antes que a vosotros."},
    {"Juan", "Jn", 15, 19, "Si fuerais del mundo, el mundo os amaria como cosa suya, pero como no sois del mundo, sino que yo os he escogido sacandoos del mundo, por eso el mundo os odia."},
    {"Juan", "Jn", 15, 20, "Recordad lo que os dije: \"No es el siervo mas que su amo\". Si a mi me han perseguido, tambien a vosotros os perseguiran; si han guardado mi palabra, tambien guardaran la vuestra."},
    {"Juan", "Jn", 15, 21, "Y todo eso lo haran con vosotros a causa de mi nombre, porque no conocen al que me envio."},
    {"Juan", "Jn", 15, 22, "Si yo no hubiera venido y no les hubiera hablado, no tendrian pecado, pero ahora no tienen excusa de su pecado."},
    {"Juan", "Jn", 15, 23, "El que me odia a mi, odia tambien a mi Padre."},
    {"Juan", "Jn", 15, 24, "Si yo no hubiera hecho en medio de ellos obras que ningun otro ha hecho, no tendrian pecado, pero ahora las han visto y me han odiado a mi y a mi Padre,"},
    {"Juan", "Jn", 15, 25, "para que se cumpla la palabra escrita en su ley: \"Me han odiado sin motivo\"."},
    {"Juan", "Jn", 15, 26, "Cuando venga el Paraclito, que os enviare desde el Padre, el Espiritu de la verdad, que procede del Padre, el dara testimonio de mi;"},
    {"Juan", "Jn", 15, 27, "y tambien vosotros dareis testimonio, porque desde el principio estais conmigo."},
    {"Juan", "Jn", 16, 1, "Os he hablado de esto, para que no os escandaliceis."},
    {"Juan", "Jn", 16, 2, "Os excomulgaran de la sinagoga; mas aun, llegara incluso una hora cuando el que os de muerte pensara que da culto a Dios."},
    {"Juan", "Jn", 16, 3, "Y esto lo haran porque no han conocido ni al Padre ni a mi."},
    {"Juan", "Jn", 16, 4, "Os he hablado de esto para que, cuando llegue la hora, os acordeis de que yo os lo habia dicho. No os dije estas cosas desde el principio porque estaba con vosotros."},
    {"Juan", "Jn", 16, 5, "Ahora me voy al que me envio, y ninguno de vosotros me pregunta: \"Adonde vas?\"."},
    {"Juan", "Jn", 16, 6, "Sino que, por haberos dicho esto, la tristeza os ha llenado el corazon."},
    {"Juan", "Jn", 16, 7, "Sin embargo, os digo la verdad: os conviene que yo me vaya; porque si no me voy, no vendra a vosotros el Paraclito. En cambio, si me voy, os lo enviare."},
    {"Juan", "Jn", 16, 8, "Y cuando venga, dejara convicto al mundo acerca de un pecado, de una justicia y de una condena."},
    {"Juan", "Jn", 16, 9, "De un pecado, porque no creen en mi;"},
    {"Juan", "Jn", 16, 10, "de una justicia, porque me voy al Padre, y no me vereis;"},
    {"Juan", "Jn", 16, 11, "de una condena, porque el principe de este mundo esta condenado."},
    {"Juan", "Jn", 16, 12, "Muchas cosas me quedan por deciros, pero no podeis cargar con ellas por ahora;"},
    {"Juan", "Jn", 16, 13, "cuando venga el, el Espiritu de la verdad, os guiara hasta la verdad plena. Pues no hablara por cuenta propia, sino que hablara de lo que oye y os comunicara lo que esta por venir."},
    {"Juan", "Jn", 16, 14, "El me glorificara, porque recibira de lo mio y os lo anunciara."},
    {"Juan", "Jn", 16, 15, "Todo lo que tiene el Padre es mio. Por eso os he dicho que recibira y tomara de lo mio y os lo anunciara."},
    {"Juan", "Jn", 16, 16, "Dentro de poco ya no me vereis, pero dentro de otro poco me volvereis a ver\"."},
    {"Juan", "Jn", 16, 17, "Comentaron entonces algunos discipulos: \"Que significa eso de \"dentro de poco ya no me vereis, pero dentro de otro poco me volvereis a ver\", y eso de \"me voy al Padre\"?\"."},
    {"Juan", "Jn", 16, 18, "Y se preguntaban: \"Que significa ese \"poco\"? No entendemos lo que dice\"."},
    {"Juan", "Jn", 16, 19, "Comprendio Jesus que querian preguntarle y les dijo: \"Estais discutiendo de eso que os he dicho: \"Dentro de poco ya no me vereis y dentro de otro poco me volvereis a ver\"?"},
    {"Juan", "Jn", 16, 20, "En verdad, en verdad os digo: vosotros llorareis y os lamentareis, mientras el mundo estara alegre; vosotros estareis tristes, pero vuestra tristeza se convertira en alegria."},
    {"Juan", "Jn", 16, 21, "La mujer, cuando va a dar a luz, siente tristeza, porque ha llegado su hora; pero, en cuanto da a luz al ni\177o, ni se acuerda del apuro, por la alegria de que al mundo le ha nacido un hombre."},
    {"Juan", "Jn", 16, 22, "Tambien vosotros ahora sentis tristeza; pero volvere a veros, y se alegrara vuestro corazon, y nadie os quitara vuestra alegria."},
    {"Juan", "Jn", 16, 23, "Ese dia no me preguntareis nada. En verdad, en verdad os digo: si pedis algo al Padre en mi nombre, os lo dara."},
    {"Juan", "Jn", 16, 24, "Hasta ahora no habeis pedido nada en mi nombre; pedid, y recibireis, para que vuestra alegria sea completa."},
    {"Juan", "Jn", 16, 25, "Os he hablado de esto en comparaciones; viene la hora en que ya no hablare en comparaciones, sino que os hablare del Padre claramente."},
    {"Juan", "Jn", 16, 26, "Aquel dia pedireis en mi nombre, y no os digo que yo rogare al Padre por vosotros,"},
    {"Juan", "Jn", 16, 27, "pues el Padre mismo os quiere, porque vosotros me quereis y creeis que yo sali de Dios."},
    {"Juan", "Jn", 16, 28, "Sali del Padre y he venido al mundo, otra vez dejo el mundo y me voy al Padre\"."},
    {"Juan", "Jn", 16, 29, "Le dicen sus discipulos: \"Ahora si que hablas claro y no usas comparaciones."},
    {"Juan", "Jn", 16, 30, "Ahora vemos que lo sabes todo y no necesitas que te pregunten; por ello creemos que has salido de Dios\"."},
    {"Juan", "Jn", 16, 31, "Les contesto Jesus: \"Ahora creeis?"},
    {"Juan", "Jn", 16, 32, "Pues mirad: esta para llegar la hora, mejor, ya ha llegado, en que os disperseis cada cual por su lado y a mi me dejeis solo. Pero no estoy solo, porque esta conmigo el Padre."},
    {"Juan", "Jn", 16, 33, "Os he hablado de esto, para que encontreis la paz en mi. En el mundo tendreis luchas; pero tened valor: yo he vencido al mundo\"."},
    {"Juan", "Jn", 17, 1, "Asi hablo Jesus y, levantando los ojos al cielo, dijo: \"Padre, ha llegado la hora, glorifica a tu Hijo, para que tu Hijo te glorifique a ti"},
    {"Juan", "Jn", 17, 2, "y, por el poder que tu le has dado sobre toda carne, de la vida eterna a todos los que le has dado."},
    {"Juan", "Jn", 17, 3, "Esta es la vida eterna: que te conozcan a ti, unico Dios verdadero, y a tu enviado, Jesucristo."},
    {"Juan", "Jn", 17, 4, "Yo te he glorificado sobre la tierra, he llevado a cabo la obra que me encomendaste."},
    {"Juan", "Jn", 17, 5, "Y ahora, Padre, glorificame junto a ti, con la gloria que yo tenia junto a ti antes que el mundo existiese."},
    {"Juan", "Jn", 17, 6, "He manifestado tu nombre a los que me diste de en medio del mundo. Tuyos eran, y tu me los diste, y ellos han guardado tu palabra."},
    {"Juan", "Jn", 17, 7, "Ahora han conocido que todo lo que me diste procede de ti,"},
    {"Juan", "Jn", 17, 8, "porque yo les he comunicado las palabras que tu me diste, y ellos las han recibido, y han conocido verdaderamente que yo sali de ti, y han creido que tu me has enviado."},
    {"Juan", "Jn", 17, 9, "Te ruego por ellos; no ruego por el mundo, sino por estos que tu me diste, porque son tuyos."},
    {"Juan", "Jn", 17, 10, "Y todo lo mio es tuyo, y lo tuyo mio; y en ellos he sido glorificado."},
    {"Juan", "Jn", 17, 11, "Ya no voy a estar en el mundo, pero ellos estan en el mundo, mientras yo voy a ti. Padre santo, guardalos en tu nombre, a los que me has dado, para que sean uno, como nosotros."},
    {"Juan", "Jn", 17, 12, "Cuando estaba con ellos, yo guardaba en tu nombre a los que me diste, y los custodiaba, y ninguno se perdio, sino el hijo de la perdicion, para que se cumpliera la Escritura."},
    {"Juan", "Jn", 17, 13, "Ahora voy a ti, y digo esto en el mundo para que tengan en si mismos mi alegria cumplida."},
    {"Juan", "Jn", 17, 14, "Yo les he dado tu palabra, y el mundo los ha odiado porque no son del mundo, como tampoco yo soy del mundo."},
    {"Juan", "Jn", 17, 15, "No ruego que los retires del mundo, sino que los guardes del maligno."},
    {"Juan", "Jn", 17, 16, "No son del mundo, como tampoco yo soy del mundo."},
    {"Juan", "Jn", 17, 17, "Santificalos en la verdad: tu palabra es verdad."},
    {"Juan", "Jn", 17, 18, "Como tu me enviaste al mundo, asi yo los envio tambien al mundo."},
    {"Juan", "Jn", 17, 19, "Y por ellos yo me santifico a mi mismo, para que tambien ellos sean santificados en la verdad."},
    {"Juan", "Jn", 17, 20, "No solo por ellos ruego, sino tambien por los que crean en mi por la palabra de ellos,"},
    {"Juan", "Jn", 17, 21, "para que todos sean uno, como tu, Padre, en mi, y yo en ti, que ellos tambien sean uno en nosotros, para que el mundo crea que tu me has enviado."},
    {"Juan", "Jn", 17, 22, "Yo les he dado la gloria que tu me diste, para que sean uno, como nosotros somos uno;"},
    {"Juan", "Jn", 17, 23, "yo en ellos, y tu en mi, para que sean completamente uno, de modo que el mundo sepa que tu me has enviado y que los has amado a ellos como me has amado a mi."},
    {"Juan", "Jn", 17, 24, "Padre, este es mi deseo: que los que me has dado esten conmigo donde yo estoy y contemplen mi gloria, la que me diste, porque me amabas, antes de la fundacion del mundo."},
    {"Juan", "Jn", 17, 25, "Padre justo, si el mundo no te ha conocido, yo te he conocido, y estos han conocido que tu me enviaste."},
    {"Juan", "Jn", 17, 26, "Les he dado a conocer y les dare a conocer tu nombre, para que el amor que me tenias este en ellos, y yo en ellos\"."},
    {"Juan", "Jn", 18, 1, "Despues de decir esto, salio Jesus con sus discipulos al otro lado del torrente Cedron, donde habia un huerto, y entraron alli el y sus discipulos."},
    {"Juan", "Jn", 18, 2, "Judas, el que lo iba a entregar, conocia tambien el sitio, porque Jesus se reunia a menudo alli con sus discipulos."},
    {"Juan", "Jn", 18, 3, "Judas entonces, tomando una cohorte y unos guardias de los sumos sacerdotes y de los fariseos, entro alla con faroles, antorchas y armas."},
    {"Juan", "Jn", 18, 4, "Jesus, sabiendo todo lo que venia sobre el, se adelanto y les dijo: \"A quien buscais?\"."},
    {"Juan", "Jn", 18, 5, "Le contestaron: \"A Jesus, el Nazareno\". Les dijo Jesus: \"Yo soy\". Estaba tambien con ellos Judas, el que lo iba a entregar."},
    {"Juan", "Jn", 18, 6, "Al decirles: \"Yo soy\", retrocedieron y cayeron a tierra."},
    {"Juan", "Jn", 18, 7, "Les pregunto otra vez: \"A quien buscais?\". Ellos dijeron: \"A Jesus, el Nazareno\"."},
    {"Juan", "Jn", 18, 8, "Jesus contesto: \"Os he dicho que soy yo. Si me buscais a mi, dejad marchar a estos\"."},
    {"Juan", "Jn", 18, 9, "Y asi se cumplio lo que habia dicho: \"No he perdido a ninguno de los que me diste\"."},
    {"Juan", "Jn", 18, 10, "Entonces Simon Pedro, que llevaba una espada, la saco e hirio al criado del sumo sacerdote, cortandole la oreja derecha. Este criado se llamaba Malco."},
    {"Juan", "Jn", 18, 11, "Dijo entonces Jesus a Pedro: \"Mete la espada en la vaina. El caliz que me ha dado mi Padre, no lo voy a beber?\"."},
    {"Juan", "Jn", 18, 12, "La cohorte, el tribuno y los guardias de los judios prendieron a Jesus, lo ataron"},
    {"Juan", "Jn", 18, 13, "y lo llevaron primero a Anas, porque era suegro de Caifas, sumo sacerdote aquel a\177o;"},
    {"Juan", "Jn", 18, 14, "Caifas era el que habia dado a los judios este consejo: \"Conviene que muera un solo hombre por el pueblo\"."},
    {"Juan", "Jn", 18, 15, "Simon Pedro y otro discipulo seguian a Jesus. Este discipulo era conocido del sumo sacerdote y entro con Jesus en el palacio del sumo sacerdote,"},
    {"Juan", "Jn", 18, 16, "mientras Pedro se quedo fuera a la puerta. Salio el otro discipulo, el conocido del sumo sacerdote, hablo a la portera e hizo entrar a Pedro."},
    {"Juan", "Jn", 18, 17, "La criada portera dijo entonces a Pedro: \"No eres tu tambien de los discipulos de ese hombre?\". El dijo: \"No lo soy\"."},
    {"Juan", "Jn", 18, 18, "Los criados y los guardias habian encendido un brasero, porque hacia frio, y se calentaban. Tambien Pedro estaba con ellos de pie, calentandose."},
    {"Juan", "Jn", 18, 19, "El sumo sacerdote interrogo a Jesus acerca de sus discipulos y de su doctrina."},
    {"Juan", "Jn", 18, 20, "Jesus le contesto: \"Yo he hablado abiertamente al mundo; yo he ense\177ado continuamente en la sinagoga y en el templo, donde se reunen todos los judios, y no he dicho nada a escondidas."},
    {"Juan", "Jn", 18, 21, "Por que me preguntas a mi? Pregunta a los que me han oido de que les he hablado. Ellos saben lo que yo he dicho\"."},
    {"Juan", "Jn", 18, 22, "Apenas dijo esto, uno de los guardias que estaba alli le dio una bofetada a Jesus, diciendo: \"Asi contestas al sumo sacerdote?\"."},
    {"Juan", "Jn", 18, 23, "Jesus respondio: \"Si he faltado al hablar, muestra en que he faltado; pero si he hablado como se debe, por que me pegas?\"."},
    {"Juan", "Jn", 18, 24, "Entonces Anas lo envio atado a Caifas, sumo sacerdote."},
    {"Juan", "Jn", 18, 25, "Simon Pedro estaba de pie, calentandose, y le dijeron: \"No eres tu tambien de sus discipulos?\". El lo nego, diciendo: \"No lo soy\"."},
    {"Juan", "Jn", 18, 26, "Uno de los criados del sumo sacerdote, pariente de aquel a quien Pedro le corto la oreja, le dijo: \"No te he visto yo en el huerto con el?\"."},
    {"Juan", "Jn", 18, 27, "Pedro volvio a negar, y enseguida canto un gallo."},
    {"Juan", "Jn", 18, 28, "Llevaron a Jesus de casa de Caifas al pretorio. Era el amanecer, y ellos no entraron en el pretorio para no incurrir en impureza y poder asi comer la Pascua."},
    {"Juan", "Jn", 18, 29, "Salio Pilato afuera, adonde estaban ellos, y dijo: \"Que acusacion presentais contra este hombre?\"."},
    {"Juan", "Jn", 18, 30, "Le contestaron: \"Si este no fuera un malhechor, no te lo entregariamos\"."},
    {"Juan", "Jn", 18, 31, "Pilato les dijo: \"Llevaoslo vosotros y juzgadlo segun vuestra ley\". Los judios le dijeron: \"No estamos autorizados para dar muerte a nadie\"."},
    {"Juan", "Jn", 18, 32, "Y asi se cumplio lo que habia dicho Jesus, indicando de que muerte iba a morir."},
    {"Juan", "Jn", 18, 33, "Entro otra vez Pilato en el pretorio, llamo a Jesus y le dijo: \"Eres tu el rey de los judios?\"."},
    {"Juan", "Jn", 18, 34, "Jesus le contesto: \"Dices eso por tu cuenta o te lo han dicho otros de mi?\"."},
    {"Juan", "Jn", 18, 35, "Pilato replico: \"Acaso soy yo judio? Tu gente y los sumos sacerdotes te han entregado a mi; que has hecho?\"."},
    {"Juan", "Jn", 18, 36, "Jesus le contesto: \"Mi reino no es de este mundo. Si mi reino fuera de este mundo, mi guardia habria luchado para que no cayera en manos de los judios. Pero mi reino no es de aqui\"."},
    {"Juan", "Jn", 18, 37, "Pilato le dijo: \"Entonces, tu eres rey?\". Jesus le contesto: \"Tu lo dices: soy rey. Yo para esto he nacido y para esto he venido al mundo: para dar testimonio de la verdad. Todo el que es de la verdad escucha mi voz\"."},
    {"Juan", "Jn", 18, 38, "Pilato le dijo: \"Y que es la verdad?\". Dicho esto, salio otra vez adonde estaban los judios y les dijo: \"Yo no encuentro en el ninguna culpa."},
    {"Juan", "Jn", 18, 39, "Es costumbre entre vosotros que por Pascua ponga a uno en libertad. Quereis que os suelte al rey de los judios?\"."},
    {"Juan", "Jn", 18, 40, "Volvieron a gritar: \"A ese no, a Barrabas\". El tal Barrabas era un bandido."},
    {"Juan", "Jn", 19, 1, "Entonces Pilato tomo a Jesus y lo mando azotar."},
    {"Juan", "Jn", 19, 2, "Y los soldados trenzaron una corona de espinas, se la pusieron en la cabeza y le echaron por encima un manto color purpura;"},
    {"Juan", "Jn", 19, 3, "y, acercandose a el, le decian: \"Salve, rey de los judios!\". Y le daban bofetadas."},
    {"Juan", "Jn", 19, 4, "Pilato salio otra vez afuera y les dijo: \"Mirad, os lo saco afuera para que sepais que no encuentro en el ninguna culpa\"."},
    {"Juan", "Jn", 19, 5, "Y salio Jesus afuera, llevando la corona de espinas y el manto color purpura. Pilato les dijo: \"He aqui al hombre\"."},
    {"Juan", "Jn", 19, 6, "Cuando lo vieron los sumos sacerdotes y los guardias, gritaron: \"Crucificalo, crucificalo!\". Pilato les dijo: \"Llevaoslo vosotros y crucificadlo, porque yo no encuentro culpa en el\"."},
    {"Juan", "Jn", 19, 7, "Los judios le contestaron: \"Nosotros tenemos una ley, y segun esa ley tiene que morir, porque se ha hecho Hijo de Dios\"."},
    {"Juan", "Jn", 19, 8, "Cuando Pilato oyo estas palabras, se asusto aun mas."},
    {"Juan", "Jn", 19, 9, "Entro otra vez en el pretorio y dijo a Jesus: \"De donde eres tu?\". Pero Jesus no le dio respuesta."},
    {"Juan", "Jn", 19, 10, "Y Pilato le dijo: \"A mi no me hablas? No sabes que tengo autoridad para soltarte y autoridad para crucificarte?\"."},
    {"Juan", "Jn", 19, 11, "Jesus le contesto: \"No tendrias ninguna autoridad sobre mi si no te la hubieran dado de lo alto. Por eso el que me ha entregado a ti tiene un pecado mayor\"."},
    {"Juan", "Jn", 19, 12, "Desde este momento Pilato trataba de soltarlo, pero los judios gritaban: \"Si sueltas a ese, no eres amigo del Cesar. Todo el que se hace rey esta contra el Cesar\"."},
    {"Juan", "Jn", 19, 13, "Pilato entonces, al oir estas palabras, saco afuera a Jesus y se sento en el tribunal, en el sitio que llaman \"el Enlosado\" (en hebreo Gabbata)."},
    {"Juan", "Jn", 19, 14, "Era el dia de la Preparacion de la Pascua, hacia el mediodia. Y dijo Pilato a los judios: \"He aqui a vuestro rey\"."},
    {"Juan", "Jn", 19, 15, "Ellos gritaron: \"Fuera, fuera; crucificalo!\". Pilato les dijo: \"A vuestro rey voy a crucificar?\". Contestaron los sumos sacerdotes: \"No tenemos mas rey que al Cesar\"."},
    {"Juan", "Jn", 19, 16, "Entonces se lo entrego para que lo crucificaran. Tomaron a Jesus,"},
    {"Juan", "Jn", 19, 17, "y, cargando el mismo con la cruz, salio al sitio llamado \"de la Calavera\" (que en hebreo se dice Golgota),"},
    {"Juan", "Jn", 19, 18, "donde lo crucificaron; y con el a otros dos, uno a cada lado, y en medio, Jesus."},
    {"Juan", "Jn", 19, 19, "Y Pilato escribio un letrero y lo puso encima de la cruz; en el estaba escrito: \"Jesus, el Nazareno, el rey de los judios\"."},
    {"Juan", "Jn", 19, 20, "Leyeron el letrero muchos judios, porque estaba cerca el lugar donde crucificaron a Jesus, y estaba escrito en hebreo, latin y griego."},
    {"Juan", "Jn", 19, 21, "Entonces los sumos sacerdotes de los judios dijeron a Pilato: \"No escribas \"El rey de los judios\", sino: \"Este ha dicho: soy el rey de los judios\"\"."},
    {"Juan", "Jn", 19, 22, "Pilato les contesto: \"Lo escrito, escrito esta\"."},
    {"Juan", "Jn", 19, 23, "Los soldados, cuando crucificaron a Jesus, cogieron su ropa, haciendo cuatro partes, una para cada soldado, y apartaron la tunica. Era una tunica sin costura, tejida toda de una pieza de arriba abajo."},
    {"Juan", "Jn", 19, 24, "Y se dijeron: \"No la rasguemos, sino echemosla a suerte, a ver a quien le toca\". Asi se cumplio la Escritura: \"Se repartieron mis ropas y echaron a suerte mi tunica\". Esto hicieron los soldados."},
    {"Juan", "Jn", 19, 25, "Junto a la cruz de Jesus estaban su madre, la hermana de su madre, Maria, la de Cleofas, y Maria, la Magdalena."},
    {"Juan", "Jn", 19, 26, "Jesus, al ver a su madre y junto a ella al discipulo al que amaba, dijo a su madre: \"Mujer, ahi tienes a tu hijo\"."},
    {"Juan", "Jn", 19, 27, "Luego, dijo al discipulo: \"Ahi tienes a tu madre\". Y desde aquella hora, el discipulo la recibio como algo propio."},
    {"Juan", "Jn", 19, 28, "Despues de esto, sabiendo Jesus que ya todo estaba cumplido, para que se cumpliera la Escritura, dijo: \"Tengo sed\"."},
    {"Juan", "Jn", 19, 29, "Habia alli un jarro lleno de vinagre. Y, sujetando una esponja empapada en vinagre a una ca\177a de hisopo, se la acercaron a la boca."},
    {"Juan", "Jn", 19, 30, "Jesus, cuando tomo el vinagre, dijo: \"Esta cumplido\". E, inclinando la cabeza, entrego el espiritu."},
    {"Juan", "Jn", 19, 31, "Los judios entonces, como era el dia de la Preparacion, para que no se quedaran los cuerpos en la cruz el sabado, porque aquel sabado era un dia grande, pidieron a Pilato que les quebraran las piernas y que los quitaran."},
    {"Juan", "Jn", 19, 32, "Fueron los soldados, le quebraron las piernas al primero y luego al otro que habian crucificado con el;"},
    {"Juan", "Jn", 19, 33, "pero al llegar a Jesus, viendo que ya habia muerto, no le quebraron las piernas,"},
    {"Juan", "Jn", 19, 34, "sino que uno de los soldados, con la lanza, le traspaso el costado, y al punto salio sangre y agua."},
    {"Juan", "Jn", 19, 35, "El que lo vio da testimonio, y su testimonio es verdadero, y el sabe que dice verdad, para que tambien vosotros creais."},
    {"Juan", "Jn", 19, 36, "Esto ocurrio para que se cumpliera la Escritura: \"No le quebraran un hueso\";"},
    {"Juan", "Jn", 19, 37, "y en otro lugar la Escritura dice: \"Miraran al que traspasaron\"."},
    {"Juan", "Jn", 19, 38, "Despues de esto, Jose de Arimatea, que era discipulo de Jesus aunque oculto por miedo a los judios, pidio a Pilato que le dejara llevarse el cuerpo de Jesus. Y Pilato lo autorizo. El fue entonces y se llevo el cuerpo."},
    {"Juan", "Jn", 19, 39, "Llego tambien Nicodemo, el que habia ido a verlo de noche, y trajo unas cien libras de una mixtura de mirra y aloe."},
    {"Juan", "Jn", 19, 40, "Tomaron el cuerpo de Jesus y lo envolvieron en los lienzos con los aromas, segun se acostumbra a enterrar entre los judios."},
    {"Juan", "Jn", 19, 41, "Habia un huerto en el sitio donde lo crucificaron, y en el huerto, un sepulcro nuevo donde nadie habia sido enterrado todavia."},
    {"Juan", "Jn", 19, 42, "Y como para los judios era el dia de la Preparacion, y el sepulcro estaba cerca, pusieron alli a Jesus."},
    {"Juan", "Jn", 20, 1, "El primer dia de la semana, Maria la Magdalena fue al sepulcro al amanecer, cuando aun estaba oscuro, y vio la losa quitada del sepulcro."},
    {"Juan", "Jn", 20, 2, "Echo a correr y fue donde estaban Simon Pedro y el otro discipulo, a quien Jesus amaba, y les dijo: \"Se han llevado del sepulcro al Se\177or y no sabemos donde lo han puesto\"."},
    {"Juan", "Jn", 20, 3, "Salieron Pedro y el otro discipulo camino del sepulcro."},
    {"Juan", "Jn", 20, 4, "Los dos corrian juntos, pero el otro discipulo corria mas que Pedro; se adelanto y llego primero al sepulcro;"},
    {"Juan", "Jn", 20, 5, "e, inclinandose, vio los lienzos tendidos; pero no entro."},
    {"Juan", "Jn", 20, 6, "Llego tambien Simon Pedro detras de el y entro en el sepulcro: vio los lienzos tendidos"},
    {"Juan", "Jn", 20, 7, "y el sudario con que le habian cubierto la cabeza, no con los lienzos, sino enrollado en un sitio aparte."},
    {"Juan", "Jn", 20, 8, "Entonces entro tambien el otro discipulo, el que habia llegado primero al sepulcro; vio y creyo."},
    {"Juan", "Jn", 20, 9, "Pues hasta entonces no habian entendido la Escritura: que el habia de resucitar de entre los muertos."},
    {"Juan", "Jn", 20, 10, "Los dos discipulos se volvieron a casa."},
    {"Juan", "Jn", 20, 11, "Estaba Maria fuera, junto al sepulcro, llorando. Mientras lloraba, se asomo al sepulcro"},
    {"Juan", "Jn", 20, 12, "y vio dos angeles vestidos de blanco, sentados, uno a la cabecera y otro a los pies, donde habia estado el cuerpo de Jesus."},
    {"Juan", "Jn", 20, 13, "Ellos le preguntan: \"Mujer, por que lloras?\". Ella les contesta: \"Porque se han llevado a mi Se\177or y no se donde lo han puesto\"."},
    {"Juan", "Jn", 20, 14, "Dicho esto, se vuelve y ve a Jesus, de pie, pero no sabia que era Jesus."},
    {"Juan", "Jn", 20, 15, "Jesus le dice: \"Mujer, por que lloras?, a quien buscas?\". Ella, tomandolo por el hortelano, le contesta: \"Se\177or, si tu te lo has llevado, dime donde lo has puesto y yo lo recogere\"."},
    {"Juan", "Jn", 20, 16, "Jesus le dice: \"Maria!\". Ella se vuelve y le dice: \"Rabbuni!\", que significa: \"Maestro!\"."},
    {"Juan", "Jn", 20, 17, "Jesus le dice: \"No me retengas, que todavia no he subido al Padre. Pero, anda, ve a mis hermanos y diles: \"Subo al Padre mio y Padre vuestro, al Dios mio y Dios vuestro\"\"."},
    {"Juan", "Jn", 20, 18, "Maria la Magdalena fue y anuncio a los discipulos: \"He visto al Se\177or y ha dicho esto\"."},
    {"Juan", "Jn", 20, 19, "Al anochecer de aquel dia, el primero de la semana, estaban los discipulos en una casa, con las puertas cerradas por miedo a los judios. Y en esto entro Jesus, se puso en medio y les dijo: \"Paz a vosotros\"."},
    {"Juan", "Jn", 20, 20, "Y, diciendo esto, les ense\177o las manos y el costado. Y los discipulos se llenaron de alegria al ver al Se\177or."},
    {"Juan", "Jn", 20, 21, "Jesus repitio: \"Paz a vosotros. Como el Padre me ha enviado, asi tambien os envio yo\"."},
    {"Juan", "Jn", 20, 22, "Y, dicho esto, soplo sobre ellos y les dijo: \"Recibid el Espiritu Santo;"},
    {"Juan", "Jn", 20, 23, "a quienes les perdoneis los pecados, les quedan perdonados; a quienes se los retengais, les quedan retenidos\"."},
    {"Juan", "Jn", 20, 24, "Tomas, uno de los Doce, llamado el Mellizo, no estaba con ellos cuando vino Jesus."},
    {"Juan", "Jn", 20, 25, "Y los otros discipulos le decian: \"Hemos visto al Se\177or\". Pero el les contesto: \"Si no veo en sus manos la se\177al de los clavos, si no meto el dedo en el agujero de los clavos y no meto la mano en su costado, no lo creo\"."},
    {"Juan", "Jn", 20, 26, "A los ocho dias, estaban otra vez dentro los discipulos y Tomas con ellos. Llego Jesus, estando cerradas las puertas, se puso en medio y dijo: \"Paz a vosotros\"."},
    {"Juan", "Jn", 20, 27, "Luego dijo a Tomas: \"Trae tu dedo, aqui tienes mis manos; trae tu mano y metela en mi costado; y no seas incredulo, sino creyente\"."},
    {"Juan", "Jn", 20, 28, "Contesto Tomas: \"Se\177or mio y Dios mio!\"."},
    {"Juan", "Jn", 20, 29, "Jesus le dijo: \"Porque me has visto has creido? Bienaventurados los que crean sin haber visto\"."},
    {"Juan", "Jn", 20, 30, "Muchos otros signos, que no estan escritos en este libro, hizo Jesus a la vista de los discipulos."},
    {"Juan", "Jn", 20, 31, "Estos han sido escritos para que creais que Jesus es el Mesias, el Hijo de Dios, y para que, creyendo, tengais vida en su nombre."},
    {"Juan", "Jn", 21, 1, "Despues de esto Jesus se aparecio otra vez a los discipulos junto al lago de Tiberiades. Y se aparecio de esta manera:"},
    {"Juan", "Jn", 21, 2, "Estaban juntos Simon Pedro, Tomas, apodado el Mellizo; Natanael, el de Cana de Galilea; los Zebedeos y otros dos discipulos suyos."},
    {"Juan", "Jn", 21, 3, "Simon Pedro les dice: \"Me voy a pescar\". Ellos contestan: \"Vamos tambien nosotros contigo\". Salieron y se embarcaron; y aquella noche no cogieron nada."},
    {"Juan", "Jn", 21, 4, "Estaba ya amaneciendo, cuando Jesus se presento en la orilla; pero los discipulos no sabian que era Jesus."},
    {"Juan", "Jn", 21, 5, "Jesus les dice: \"Muchachos, teneis pescado?\". Ellos contestaron: \"No\"."},
    {"Juan", "Jn", 21, 6, "El les dice: \"Echad la red a la derecha de la barca y encontrareis\". La echaron, y no podian sacarla, por la multitud de peces."},
    {"Juan", "Jn", 21, 7, "Y aquel discipulo a quien Jesus amaba le dice a Pedro: \"Es el Se\177or\". Al oir que era el Se\177or, Simon Pedro, que estaba desnudo, se ato la tunica y se echo al agua."},
    {"Juan", "Jn", 21, 8, "Los demas discipulos se acercaron en la barca, porque no distaban de tierra mas que unos doscientos codos, remolcando la red con los peces."},
    {"Juan", "Jn", 21, 9, "Al saltar a tierra, ven unas brasas con un pescado puesto encima y pan."},
    {"Juan", "Jn", 21, 10, "Jesus les dice: \"Traed de los peces que acabais de coger\"."},
    {"Juan", "Jn", 21, 11, "Simon Pedro subio a la barca y arrastro hasta la orilla la red repleta de peces grandes: ciento cincuenta y tres. Y aunque eran tantos, no se rompio la red."},
    {"Juan", "Jn", 21, 12, "Jesus les dice: \"Vamos, almorzad\". Ninguno de los discipulos se atrevia a preguntarle quien era, porque sabian bien que era el Se\177or."},
    {"Juan", "Jn", 21, 13, "Jesus se acerca, toma el pan y se lo da, y lo mismo el pescado."},
    {"Juan", "Jn", 21, 14, "Esta fue la tercera vez que Jesus se aparecio a los discipulos despues de resucitar de entre los muertos."},
    {"Juan", "Jn", 21, 15, "Despues de comer, dice Jesus a Simon Pedro: \"Simon, hijo de Juan, me amas mas que estos?\". El le contesto: \"Si, Se\177or, tu sabes que te quiero\". Jesus le dice: \"Apacienta mis corderos\"."},
    {"Juan", "Jn", 21, 16, "Por segunda vez le pregunta: \"Simon, hijo de Juan, me amas?\". El le contesta: \"Si, Se\177or, tu sabes que te quiero\". El le dice: \"Pastorea mis ovejas\"."},
    {"Juan", "Jn", 21, 17, "Por tercera vez le pregunta: \"Simon, hijo de Juan, me quieres?\". Se entristecio Pedro de que le preguntara por tercera vez: \"Me quieres?\" y le contesto: \"Se\177or, tu conoces todo, tu sabes que te quiero\". Jesus le dice: \"Apacienta mis ovejas."},
    {"Juan", "Jn", 21, 18, "En verdad, en verdad te digo: cuando eras joven, tu mismo te ce\177ias e ibas adonde querias; pero, cuando seas viejo, extenderas las manos, otro te ce\177ira y te llevara adonde no quieras\"."},
    {"Juan", "Jn", 21, 19, "Esto dijo aludiendo a la muerte con que iba a dar gloria a Dios. Dicho esto, a\177adio: \"Sigueme\"."},
    {"Juan", "Jn", 21, 20, "Pedro, volviendose, vio que les seguia el discipulo a quien Jesus amaba, el mismo que en la cena se habia apoyado en su pecho y le habia preguntado: \"Se\177or, quien es el que te va a entregar?\"."},
    {"Juan", "Jn", 21, 21, "Al verlo, Pedro dice a Jesus: \"Se\177or, y este, que?\"."},
    {"Juan", "Jn", 21, 22, "Jesus le contesta: \"Si quiero que se quede hasta que yo venga, a ti que? Tu sigueme\"."},
    {"Juan", "Jn", 21, 23, "Entonces se empezo a correr entre los hermanos el rumor de que ese discipulo no moriria. Pero no le dijo Jesus que no moriria, sino: \"Si quiero que se quede hasta que yo venga, a ti que?\"."},
    {"Juan", "Jn", 21, 24, "Este es el discipulo que da testimonio de todo esto y lo ha escrito; y nosotros sabemos que su testimonio es verdadero."},
    {"Juan", "Jn", 21, 25, "Muchas otras cosas hizo Jesus. Si se escribieran una por una, pienso que ni el mundo entero podria contener los libros que habria que escribir."},
};

int gospel_find_verse(int book_index, int chapter, int verse)
{
    if (book_index < 0 || book_index >= gospel_book_count)
        return -1;

    const GospelBook *book = &gospel_books[book_index];
    if (chapter < 1 || chapter > book->chapter_count)
        return -1;
    if (verse < 1 || verse > book->verses_per_chapter[chapter - 1])
        return -1;

    int index = book->first_verse;
    for (int ch = 1; ch < chapter; ch++)
        index += book->verses_per_chapter[ch - 1];
    return index + verse - 1;
}

int gospel_first_verse_in_chapter(int book_index, int chapter)
{
    return gospel_find_verse(book_index, chapter, 1);
}

int gospel_next_verse_index(int verse_index)
{
    if (verse_index < 0)
        return 0;
    return (verse_index + 1) % gospel_verse_count;
}

int gospel_prev_verse_index(int verse_index)
{
    if (verse_index <= 0)
        return gospel_verse_count - 1;
    return verse_index - 1;
}
